function isAmazonBotProtectionError(error: string) {
  return /bot protection|captcha/i.test(error);
}

function getLiveFetchBlockerMessage(error: string) {
  return isAmazonBotProtectionError(error)
    ? "Amazon temporarily blocked the live PDP fetch. Use manual overrides for this pass or retry later."
    : error;
}

function uniqueNonEmpty(items: string[]) {
  return Array.from(new Set(items.map((item) => item.trim()).filter(Boolean)));
}

function splitRuntimeNotes(value: string) {
  return value
    .split(/[\n.;|]+/)
    .map((item) => item.trim())
    .filter(Boolean);
}

function countKeywordMatches(value: string, patterns: RegExp[]) {
  return patterns.reduce((sum, pattern) => sum + (pattern.test(value) ? 1 : 0), 0);
}

function getSearchParam(searchParams: ReturnType<typeof useSearchParams>, key: string) {
  return searchParams.get(key)?.trim() ?? "";
}

function buildShopifyHandoffPath(
  locale: SupportedLocale,
  slug: string,
  entries: Array<[string, string | undefined]>,
) {
  const query = new URLSearchParams();
  for (const [key, value] of entries) {
    if (value?.trim()) {
      query.set(key, value.trim());
    }
  }

  const basePath = getLocalizedPath(locale, `/shopify/${slug}`);
  const queryString = query.toString();
  return queryString ? `${basePath}?${queryString}` : basePath;
}

