function getEffectiveListingImageCount(snapshot: AmazonListingSnapshot | null) {
  if (!snapshot) {
    return 0;
  }

  const liveCount = snapshot.imageUrls.length;
  if (liveCount <= 0) {
    return 0;
  }

  // Amazon gallery extraction can include extra variant or derived assets.
  // Keep decision logic anchored to a believable PDP image count range.
  return Math.min(liveCount, 12);
}

function inferComplianceDocumentDraft({
  category,
  materialProfile,
  claimsProfile,
  ageGroup,
}: {
  category: string;
  materialProfile: string;
  claimsProfile: string;
  ageGroup: string;
}) {
  const categoryText = category.toLowerCase();
  const materialText = materialProfile.toLowerCase();
  const claimsText = claimsProfile.toLowerCase();
  const recommended: string[] = ["Product specification sheet"];

  if (/battery|electrical|charger|wireless|rechargeable/.test(materialText + " " + claimsText)) {
    recommended.push("Battery or electrical safety report", "User manual or warning label draft");
  }
  if (/chemical|cosmetic|supplement|spray|fragrance|alcohol|latex/.test(materialText + " " + claimsText)) {
    recommended.push("SDS / MSDS", "Ingredient or formulation statement");
  }
  if (ageGroup === "children" || /toy|kids|baby|toddler|child/.test(categoryText + " " + claimsText)) {
    recommended.push("Children's product test report", "CPC / GCC");
  }
  if (/medical|health|therapeutic/.test(claimsText)) {
    recommended.push("Claims substantiation file");
  }
  if (/food|pet|topical|beauty/.test(categoryText)) {
    recommended.push("Packaging label artwork");
  }

  return uniqueNonEmpty(recommended);
}

function inferCompliancePlan(snapshot: AmazonListingSnapshot | null, category: string) {
  if (!snapshot) {
    return {
      materialProfile: "",
      claimsProfile: "",
      ageGroup: "general",
      documents: ["Product specification sheet"],
    };
  }

  const titleAndBullets = [snapshot.title, ...snapshot.bulletPoints].filter(Boolean).join(". ");
  const claimsProfile = uniqueNonEmpty(
    titleAndBullets
      .split(/[.;|]/)
      .map((item) => item.trim())
      .filter((item) => item.length >= 8),
  )
    .slice(0, 3)
    .join("; ");

  const materialProfile = uniqueNonEmpty(
    [
      snapshot.brand,
      ...snapshot.bulletPoints.filter((item) =>
        /material|plastic|metal|wood|glass|battery|wireless|cotton|silicone|steel|ceramic|ingredient|fabric/i.test(item),
      ),
    ].filter(Boolean),
  )
    .slice(0, 2)
    .join("; ");

  const ageGroup = inferAgeGroupFromListing(snapshot);
  const documents = inferComplianceDocumentDraft({
    category,
    materialProfile,
    claimsProfile,
    ageGroup,
  });

  return {
    materialProfile,
    claimsProfile,
    ageGroup,
    documents,
  };
}

