function DeliverablePanel({
  deliverable,
  locale,
}: {
  deliverable: NonNullable<ToolEvaluation["deliverable"]>;
  locale: SupportedLocale;
}) {
  const [copied, setCopied] = useState(false);
  const lines = deliverable.body
    .split("\n")
    .map((line) => line.trim())
    .filter(Boolean);
  const takeaway = lines.slice(0, 2).join(" ");
  const openingLines = lines.slice(0, 3);
  const detailLines = lines.slice(3);
  const commercialSummaryLines = [
    openingLines[0],
    openingLines[1],
    detailLines.find((line) => /^(First move|Execution call|Go \/ hold call|Approval gate|Route rule|Assignment rule|Cadence map|Board order|Stop-loss rule|Owner call)/i.test(line)) ?? detailLines[0],
  ].filter(Boolean) as string[];
  const forwardableArtifact = [
    deliverable.title,
    "",
    localeText(locale, "Commercial summary", "商业摘要"),
    ...commercialSummaryLines,
    "",
    localeText(locale, "Full handoff", "完整交付稿"),
    ...lines,
  ].join("\n");

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(forwardableArtifact);
      setCopied(true);
      window.setTimeout(() => setCopied(false), 1600);
    } catch {
      setCopied(false);
    }
  };

  return (
    <div className="mt-4 rounded-[24px] border border-slate-200 bg-[linear-gradient(180deg,#f8fafc_0%,#f1f5f9_100%)] px-5 py-5 text-slate-900">
      <div className="mb-4 rounded-[22px] border border-slate-950 bg-[linear-gradient(135deg,#020617_0%,#111827_58%,#134e4a_100%)] px-5 py-5 text-white shadow-[0_18px_48px_rgba(2,6,23,0.22)]">
        <p className="text-[11px] font-semibold uppercase tracking-[0.18em] text-teal-200">
          {localeText(locale, "Paid handoff artifact", "付费交付件")}
        </p>
        <div className="mt-2 flex flex-col gap-3 lg:flex-row lg:items-start lg:justify-between">
          <div className="max-w-3xl">
            <p className="text-xl font-semibold tracking-tight text-white">{deliverable.title}</p>
            <p className="mt-2 text-sm leading-6 text-white/78">
              {locale === "zh"
                ? "这不是页面里的说明文字，而是一份可以被转发、被复盘、被下游继续执行的交付稿。"
                : "This is the paid handoff artifact the next owner should be able to forward, review in a meeting, and keep using without rewriting."}
            </p>
          </div>
          <button
            type="button"
            onClick={handleCopy}
            className="inline-flex h-10 items-center justify-center rounded-full border border-white/14 bg-white/8 px-4 text-sm font-semibold text-white transition hover:border-white/24 hover:bg-white/12"
          >
            {copied
              ? localeText(locale, "Copied forwardable handoff", "已复制可转发交付稿")
              : localeText(locale, "Copy forwardable handoff", "复制可转发交付稿")}
          </button>
        </div>
        {takeaway ? <p className="mt-4 text-sm font-semibold leading-6 text-white/90">{takeaway}</p> : null}
      </div>
      {commercialSummaryLines.length ? (
        <div className="mb-4 rounded-[22px] border border-teal-200 bg-[linear-gradient(180deg,#ffffff_0%,#ecfeff_100%)] px-5 py-5 shadow-[0_14px_36px_rgba(13,148,136,0.08)]">
          <div className="flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between">
            <div>
              <p className="text-[11px] font-semibold uppercase tracking-[0.18em] text-teal-700">
                {localeText(locale, "Commercial summary", "商业摘要")}
              </p>
              <p className="mt-2 text-sm leading-6 text-slate-600">
                {locale === "zh"
                  ? "这一屏给老板、协作方和下游执行人快速读结论。读完这几条，再决定要不要展开完整交付稿。"
                  : "This is the fast commercial readout for founders, collaborators, and downstream owners. Read these lines first, then expand into the full handoff only if needed."}
              </p>
            </div>
            <div className="rounded-full border border-teal-200 bg-white px-3 py-1 text-[11px] font-semibold uppercase tracking-[0.16em] text-teal-700">
              {localeText(locale, "Ready to forward", "可直接转发")}
            </div>
          </div>
          <div className="mt-4 grid gap-3 xl:grid-cols-3">
            {commercialSummaryLines.map((line) => {
              const [key, ...rest] = line.split(":");
              const hasValue = rest.length > 0;
              return (
                <div key={line} className="rounded-[18px] border border-teal-100 bg-white px-4 py-4">
                  {hasValue ? (
                    <>
                      <p className="text-[11px] font-semibold uppercase tracking-[0.16em] text-slate-500">{key}</p>
                      <p className="mt-2 text-sm leading-6 text-slate-800">{rest.join(":").trim()}</p>
                    </>
                  ) : (
                    <p className="text-sm leading-6 text-slate-800">{line}</p>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      ) : null}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
        <div>
          <p className="text-[11px] font-semibold uppercase tracking-[0.18em] text-slate-500">
            {localeText(locale, "Meeting-ready summary", "会议可读摘要")}
          </p>
          <p className="mt-2 text-sm leading-6 text-slate-600">
            {locale === "zh"
              ? "先用这一屏快速过会，再把完整交付稿发给下一个执行角色。"
              : "Use this screen for the quick readout first, then forward the full artifact to the next execution owner."}
          </p>
        </div>
      </div>
      <div className="mt-4 grid gap-3 xl:grid-cols-3">
        {openingLines.map((line) => {
          const [key, ...rest] = line.split(":");
          const hasValue = rest.length > 0;
          return (
            <div key={line} className="rounded-[18px] border border-black/8 bg-white px-4 py-4">
              {hasValue ? (
                <>
                  <p className="text-[11px] font-semibold uppercase tracking-[0.16em] text-slate-500">{key}</p>
                  <p className="mt-2 text-sm leading-6 text-slate-800">{rest.join(":").trim()}</p>
                </>
              ) : (
                <p className="text-sm leading-6 text-slate-800">{line}</p>
              )}
            </div>
          );
        })}
      </div>
      {detailLines.length ? (
        <div className="mt-4 rounded-[22px] border border-black/8 bg-white px-5 py-5">
          <p className="text-[11px] font-semibold uppercase tracking-[0.18em] text-slate-500">
            {localeText(locale, "Full execution notes", "完整执行说明")}
          </p>
          <div className="mt-4 grid gap-2">
            {detailLines.map((line) => {
              const [key, ...rest] = line.split(":");
              const hasValue = rest.length > 0;
              return (
                <div key={line} className="rounded-[18px] border border-black/8 bg-slate-50 px-4 py-3">
                  {hasValue ? (
                    <>
                      <p className="text-[11px] font-semibold uppercase tracking-[0.16em] text-slate-500">{key}</p>
                      <p className="mt-2 text-sm leading-6 text-slate-800">{rest.join(":").trim()}</p>
                    </>
                  ) : (
                    <p className="text-sm leading-6 text-slate-800">{line}</p>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      ) : null}
    </div>
  );
}

