function BrowseSearchKeywordCheckerRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [category, setCategory] = useState("pet__root-pet-supplies");
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("");
  const [listingTitle, setListingTitle] = useState("");
  const [backendTerms, setBackendTerms] = useState("");
  const [coreKeywords, setCoreKeywords] = useState("");
  const [itemType, setItemType] = useState("");
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [showOverrides, setShowOverrides] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const browsePlan = useMemo(() => inferBrowseKeywordPlan(snapshot), [snapshot]);

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }

      setSnapshot(payload);
      setListingTitle(payload.title);
      const nextPlan = inferBrowseKeywordPlan(payload);
      setItemType(nextPlan.itemType);
      setBackendTerms(nextPlan.backendTerms);
      setCoreKeywords(nextPlan.coreKeywords);
      const matchedOption = inferCategoryOption(payload, complianceCategoryOptionGroups);
      if (matchedOption) {
        setCategory(matchedOption);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(() => {
    const keywordTerms = coreKeywords.split(/[\n,]+/).map((item) => item.trim()).filter(Boolean);
    const titleWords = Array.from(new Set(listingTitle.toLowerCase().split(/[^a-z0-9]+/).filter((word) => word.length > 2)));
    const backendWords = Array.from(new Set(backendTerms.toLowerCase().split(/[^a-z0-9]+/).filter((word) => word.length > 2)));
    const keywordWords = Array.from(new Set(keywordTerms.flatMap((phrase) => phrase.toLowerCase().split(/[^a-z0-9]+/).filter((word) => word.length > 2))));
    const missingWords = keywordWords.filter((word) => !titleWords.includes(word) && !backendWords.includes(word));
    const overlapWords = backendWords.filter((word) => titleWords.includes(word));
    const executionOwner =
      !snapshot
        ? "SEO / listing owner"
        : overlapWords.length >= Math.max(6, missingWords.length * 2)
          ? "Backend keyword owner"
          : missingWords.length
            ? "SEO / indexing owner"
            : !itemType.trim()
              ? "Browse / catalog owner"
              : "PDP optimization owner";
    const executionCall =
      !snapshot
        ? "Load the live listing first"
        : overlapWords.length >= Math.max(6, missingWords.length * 2)
          ? "Trim backend duplicates"
          : missingWords.length
            ? "Place missing demand terms"
            : !itemType.trim()
              ? "Fix browse wording"
              : "Pressure-test one cleaner title version";

    if (!snapshot || !listingTitle.trim() || !isCustomSnapshotDecisionGrade(snapshot, ["title", "breadcrumbs", "bullets"])) {
      return {
        headline: !snapshot
          ? "Browse-keyword check is waiting on the live PDP"
          : "Browse-keyword check needs a stronger listing baseline",
        summary:
          "Use this browse-keyword read to decide whether the first move is loading the live PDP, fixing browse wording, or clearing duplicated term placement before copy changes spread wider.",
        metrics: [
          {
            label: "Current result",
            value: !snapshot ? "Live listing baseline missing" : "Live listing evidence is still thin",
            detail: !snapshot
              ? "Load the ASIN or Amazon URL so title, bullets, and browse path come from the real page."
              : "Title, category path, and bullet support are not complete enough yet for a confident browse-keyword call.",
          },
          {
            label: "Execution call",
            value: executionCall,
            detail: `${executionOwner} owns the first discoverability blocker until the live discoverability baseline is decision-grade.`,
          },
          {
            label: "First move",
            value: executionCall,
            detail: !snapshot
              ? "Do not invent browse wording or backend terms before reading the real PDP."
              : "Fix the first discoverability blocker before broadening the keyword set.",
          },
          {
            label: "Execution owner",
            value: executionOwner,
            detail: "One owner clears the first indexing blocker before more terms get piled on.",
          },
        ],
        recommendations: [
          !snapshot
            ? "Load the live listing first so the checker starts from the actual PDP wording."
            : "Fix the first browse-keyword blocker before polishing phrasing.",
          "Do not treat keyword expansion as progress if browse wording and title coverage are still unclear.",
        ],
        status: {
          label: !snapshot ? "Browse-keyword baseline is incomplete" : "Browse-keyword evidence needs review",
          tone: "warning",
        },
        missingItems: [
          !snapshot ? "Live listing baseline" : "",
          !listingTitle.trim() ? "Live title wording" : "",
          !itemType.trim() ? "Browse wording" : "",
        ].filter(Boolean),
        nextSteps: [
          !snapshot ? "Load the live PDP first." : executionCall,
          "Keep one SEO owner on the first cleanup pass until the discoverability baseline is rechecked.",
          "Re-run once the discoverability baseline is decision-grade.",
        ],
        actionStance: {
          label: !snapshot ? "Do not optimize discoverability from memory" : "Do not trust a thin browse-keyword read",
          tone: "warning",
          detail: !snapshot
            ? "Keep discoverability work closed until the checker is reading the live PDP instead of asking the operator to recreate it."
            : "Weak listing evidence makes it too easy to confuse keyword quantity with genuine discoverability quality.",
        },
      } satisfies ToolEvaluation;
    }

    return evaluateBrowseSearchKeywordChecker({
      category,
      title: listingTitle,
      backendTerms,
      coreKeywords,
      itemType,
    });
  }, [backendTerms, category, coreKeywords, itemType, listingTitle, snapshot]);

  const detectedCategoryLabel = useMemo(() => {
    for (const group of complianceCategoryOptionGroups) {
      const option = group.options.find((item) => item.value === category);
      if (option) {
        return option.label;
      }
    }
    return "Not matched yet";
  }, [category]);

  const keywordAuditRows = useMemo(
    () => [
      {
        label: "Detected category",
        value: detectedCategoryLabel,
        detail: snapshot?.breadcrumbs.length ? snapshot.breadcrumbs.join(" / ") : "Using current category mapping",
      },
      {
        label: "Item type wording",
        value: itemType || "Missing",
        detail: snapshot ? "Pulled from the last breadcrumb on the live page" : "Load a live listing to detect browse wording",
      },
      {
        label: "Keyword seed count",
        value: `${coreKeywords.split(",").map((item) => item.trim()).filter(Boolean).length}`,
        detail: coreKeywords || "Add your priority terms if you want to test a new keyword set",
      },
      {
        label: "Backend term source",
        value: backendTerms ? "Loaded" : "Missing",
        detail: backendTerms ? "Brand, bullets, and browse wording were condensed into a starter backend term set." : "No backend term set loaded yet",
      },
    ],
    [backendTerms, coreKeywords, detectedCategoryLabel, itemType, snapshot],
  );

  const keywordAuditLines = useMemo(() => {
    const lines = [];
    if (snapshot) {
      const evidenceStatus = getCustomSnapshotEvidenceStatus(snapshot, [
        "title",
        "breadcrumbs",
        "bullets",
      ]);
      lines.push(`Detected category path: ${snapshot.breadcrumbs.length ? snapshot.breadcrumbs.join(" / ") : detectedCategoryLabel}.`);
      lines.push("Title, item type, and backend term starter copy were pulled from the live listing baseline.");
      lines.push(`System draft: ${browsePlan.keywordCount} keyword phrases, browse wording "${browsePlan.itemType || "missing"}", posture "${browsePlan.duplicatePressure}".`);
      lines.push(`Evidence quality: ${evidenceStatus.label}. ${evidenceStatus.detail}`);
      if (evidenceStatus.level !== "complete") {
        lines.push("Treat this as browse-keyword draft assist only until title, category path, and bullet support are all present.");
      }
    }
    lines.push("Only use manual overrides when you want to test alternate keyword sets or a rewritten title.");
    return lines;
  }, [browsePlan.duplicatePressure, browsePlan.itemType, browsePlan.keywordCount, detectedCategoryLabel, snapshot]);

  const browseDecisionRows = useMemo(
    () =>
      buildBrowseDecisionRows({
        snapshot,
        categoryLabel: detectedCategoryLabel,
        itemType,
        listingTitle,
        backendTerms,
        coreKeywords,
      }),
    [backendTerms, coreKeywords, detectedCategoryLabel, itemType, listingTitle, snapshot],
  );

  const browseActionQueueRows = useMemo(() => {
    const keywordTerms = coreKeywords.split(/[\n,]+/).map((item) => item.trim()).filter(Boolean);
    const titleWords = Array.from(new Set(listingTitle.toLowerCase().split(/[^a-z0-9]+/).filter((word) => word.length > 2)));
    const backendWords = Array.from(new Set(backendTerms.toLowerCase().split(/[^a-z0-9]+/).filter((word) => word.length > 2)));
    const keywordWords = Array.from(new Set(keywordTerms.flatMap((phrase) => phrase.toLowerCase().split(/[^a-z0-9]+/).filter((word) => word.length > 2))));
    const missingWords = keywordWords.filter((word) => !titleWords.includes(word) && !backendWords.includes(word));
    const overlapWords = backendWords.filter((word) => titleWords.includes(word));

    const firstMove =
      !snapshot
        ? {
            label: "First move",
            value: "Load the live listing first",
            detail: "Browse and keyword cleanup is weaker when the title, bullets, and category path are not anchored to the real PDP.",
          }
        : overlapWords.length >= Math.max(6, missingWords.length * 2)
          ? {
              label: "First move",
              value: "Trim backend duplicates",
              detail: "Wasted backend bytes are the cleanest immediate win when the title is already carrying too much repeated language.",
            }
          : missingWords.length
            ? {
                label: "First move",
                value: "Place missing demand terms",
                detail: "The keyword set still contains uncovered buyer language, so title/backend distribution needs cleanup before nuance work.",
              }
            : !itemType.trim()
              ? {
                  label: "First move",
                  value: "Fix browse wording",
                  detail: "Weak or missing item-type language can blunt discoverability even when the keyword seed looks acceptable.",
                }
              : {
                  label: "First move",
                  value: "Pressure-test one cleaner title version",
                  detail: "The baseline is workable enough that the next gain comes from sharper phrasing, not another round of broad keyword stuffing.",
                };

    return [
      firstMove,
      {
        label: "Execution owner",
        value:
          !snapshot
            ? "SEO / listing owner"
            : overlapWords.length >= Math.max(6, missingWords.length * 2)
              ? "Backend keyword owner"
              : missingWords.length
                ? "SEO / indexing owner"
                : !itemType.trim()
                  ? "Browse / catalog owner"
                  : "PDP optimization owner",
        detail: "The first browse-keyword fix should sit with whoever owns backend bytes, demand-term placement, or browse wording.",
      },
      {
        label: "Do not cross",
        value:
          !snapshot
            ? "Do not optimize discoverability from memory"
            : overlapWords.length >= Math.max(6, missingWords.length * 2)
              ? "Do not add more terms while backend waste is still obvious"
              : missingWords.length
                ? "Do not rewrite nuance before covering missing demand terms"
                : "Do not stuff terms until the title stops sounding like a product page",
        detail:
          !snapshot
            ? "Keep browse-keyword work closed until the checker is reading the live PDP instead of asking the operator to recreate it."
            : overlapWords.length >= Math.max(6, missingWords.length * 2)
              ? "Duplicate-heavy backend copy burns limited bytes without improving indexing quality."
              : missingWords.length
                ? "If core demand language is still absent, polishing phrasing is the wrong order of work."
                : "Discoverability work loses value when coverage gains turn the listing into a search-term dump.",
      },
      {
        label: "Then do",
        value: "Re-read title and backend together",
        detail: "After the first cleanup, make sure the listing still sounds like a product page instead of a search-term dump.",
      },
      {
        label: "Watch",
        value: "Coverage-vs-duplication drift",
        detail: "It is easy to solve missing demand terms by creating a new duplication problem somewhere else in the listing surface.",
      },
    ];
  }, [backendTerms, coreKeywords, itemType, listingTitle, snapshot]);

  const browseInputRows = useMemo(
    () => [
      ...keywordAuditRows,
      {
        label: "Execution call",
        value: browseActionQueueRows[0]?.value ?? "Browse-keyword decision pending",
        detail: browseActionQueueRows[1]?.value
          ? `${browseActionQueueRows[1].value} owns the first discoverability fix until title, backend, and browse wording read clean together.`
          : "Put one SEO owner on the first browse-keyword cleanup before more terms get added.",
      },
    ],
    [browseActionQueueRows, keywordAuditRows],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 md:grid-cols-[1.4fr_0.8fr_auto] xl:grid-cols-[1.6fr_0.8fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput
            value={asinOrUrl}
            onChange={(e) => setAsinOrUrl(e.target.value)}
            placeholder="Paste an ASIN or Amazon URL"
            spellCheck={false}
          />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote lines={keywordAuditLines} />
      <DistributionPanel title="Live browse and keyword analysis" rows={browseInputRows} />
      <DistributionPanel title="This browse call" rows={browseActionQueueRows} />
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title="Search verdict" rows={browseDecisionRows.verdictRows} />
        <DistributionPanel title="Coverage gaps" rows={browseDecisionRows.gapRows} />
        <DistributionPanel title="Cleanup order" rows={browseDecisionRows.actionRows} />
      </div>
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">{manualOverridesHeading(locale)}</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Use this only when you want to test alternative keywords, browse wording, or a rewritten title.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {manualOverridesToggle(locale, showOverrides)}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-4">
              <Field label="Product category or browse path">
                <SelectInput value={category} onChange={(e) => setCategory(e.target.value)}>
                  {renderOptionGroups(complianceCategoryOptionGroups)}
                </SelectInput>
              </Field>
              <Field label="Item type wording">
                <TextInput value={itemType} onChange={(e) => setItemType(e.target.value)} />
              </Field>
              <Field label="Core target keywords">
                <TextInput value={coreKeywords} onChange={(e) => setCoreKeywords(e.target.value)} />
              </Field>
            </div>
            <div className="grid gap-2.5 md:grid-cols-2">
              <Field label="Draft title">
                <TextInput value={listingTitle} onChange={(e) => setListingTitle(e.target.value)} />
              </Field>
              <Field label="Backend search terms">
                <TextInput value={backendTerms} onChange={(e) => setBackendTerms(e.target.value)} />
              </Field>
            </div>
          </div>
        ) : null}
      </div>
    </RuntimeShell>
  );
}

function CategoryUngatingRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [asinOrUrl, setAsinOrUrl] = useState("");
  const [marketplace, setMarketplace] = useState("US");
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [category, setCategory] = useState("");
  const [supplyPath, setSupplyPath] = useState("authorized-distributor");
  const [packetStage, setPacketStage] = useState("partial");
  const [brandRelationship, setBrandRelationship] = useState("authorized");
  const [invoiceCount, setInvoiceCount] = useState(0);
  const [invoiceUnits, setInvoiceUnits] = useState(0);
  const [brandAuthorization, setBrandAuthorization] = useState(false);
  const [sellerAgeMonths, setSellerAgeMonths] = useState(0);
  const [priorRejection, setPriorRejection] = useState(false);
  const [invoiceRecent, setInvoiceRecent] = useState(false);
  const [hasProductPhotos, setHasProductPhotos] = useState(false);
  const [hasSafetyDocs, setHasSafetyDocs] = useState(false);
  const [restrictionLevel, setRestrictionLevel] = useState("category");
  const [showAdvanced, setShowAdvanced] = useState(false);
  const inferredCategory = snapshot ? inferCategoryOption(snapshot, ungatingCategoryOptionGroups) : "";
  const effectiveCategory = category || inferredCategory;
  const ungatingPlan = useMemo(
    () =>
      inferUngatingPacketPlan({
        snapshot,
        category: effectiveCategory,
        restrictionLevel,
        supplyPath,
        packetStage,
        brandRelationship,
      }),
    [brandRelationship, effectiveCategory, packetStage, restrictionLevel, snapshot, supplyPath],
  );
  const ungatingExecutionPlan = useMemo(
    () =>
      inferUngatingExecutionPlan({
        effectiveCategory,
        supplyPath,
        invoiceCount,
        invoiceUnits,
        invoiceRecent,
        restrictionLevel,
        brandAuthorization,
        hasProductPhotos,
        hasSafetyDocs,
        priorRejection,
      }),
    [
      brandAuthorization,
      effectiveCategory,
      hasProductPhotos,
      hasSafetyDocs,
      invoiceCount,
      invoiceRecent,
      invoiceUnits,
      priorRejection,
      restrictionLevel,
      supplyPath,
    ],
  );

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Unable to load Amazon listing.");
      }
      setSnapshot(payload);
      const nextCategory = inferCategoryOption(payload, ungatingCategoryOptionGroups);
      setCategory((current) => current || nextCategory);
      if (!showAdvanced) {
        const nextPlan = inferUngatingPacketPlan({
          snapshot: payload,
          category: nextCategory,
          restrictionLevel,
          supplyPath,
          packetStage,
          brandRelationship,
        });
        setInvoiceCount(nextPlan.invoiceCount);
        setInvoiceUnits(nextPlan.invoiceUnits);
        setBrandAuthorization(nextPlan.brandAuthorization);
        setSellerAgeMonths(nextPlan.sellerAgeMonths);
        setPriorRejection(nextPlan.priorRejection);
        setInvoiceRecent(nextPlan.invoiceRecent);
        setHasProductPhotos(nextPlan.hasProductPhotos);
        setHasSafetyDocs(nextPlan.hasSafetyDocs);
      }
    } catch (loadError) {
      setSnapshot(null);
      setError(loadError instanceof Error ? loadError.message : "Unable to load Amazon listing.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(() => {
    if (!effectiveCategory) {
      return {
        headline: "Ungating check is waiting on a real category target",
        summary:
          "Use this ungating read to decide whether the next job is category identification, packet repair, or proof collection before more documents get gathered blindly.",
        metrics: [
          {
            label: "Current result",
            value: "Target category missing",
            detail: snapshot
              ? "The live listing loaded, but the category inference is not strong enough yet."
              : "Load a live ASIN or pick the target category manually before trusting the approval path.",
          },
          {
            label: "Execution call",
            value: ungatingExecutionPlan.ungatingDecision,
            detail: `${ungatingExecutionPlan.proofPriority} | ${ungatingExecutionPlan.submissionCadence}`,
          },
          {
            label: "First move",
            value: snapshot ? "Confirm the target category first" : "Load a live ASIN or set the target category",
            detail: "Do not build an approval packet until the category target is explicit.",
          },
          {
            label: "Execution owner",
            value: ungatingExecutionPlan.owner,
            detail: "One packet owner should clear the category ambiguity before more evidence gets collected.",
          },
        ],
        recommendations: [
          "Start from a live ASIN whenever possible so the category and brand clues come from the actual page.",
          "Do not gather invoices and photos into a packet for the wrong category target.",
        ],
        status: {
          label: "Ungating baseline is incomplete",
          tone: "warning",
        },
        missingItems: ["Target category"],
        nextSteps: [
          snapshot ? "Confirm the target category manually." : "Load a live listing or pick the target category.",
          "Assign one packet owner before collecting more proof.",
          "Re-run the ungating call once the target lane is explicit.",
        ],
        actionStance: {
          label: "Do not build an ungating packet against a vague target",
          tone: "warning",
          detail: "The most expensive ungating mistake is often not a missing document, but building the right packet for the wrong lane.",
        },
      } satisfies ToolEvaluation;
    }

    return evaluateUngating({
      category: effectiveCategory,
      marketplace,
      invoiceCount,
      invoiceUnits,
      brandAuthorization,
      sellerAgeMonths,
      priorRejection,
      invoiceRecent,
      hasProductPhotos,
      hasSafetyDocs,
      restrictionLevel,
      source: snapshot ? "live" : "manual",
    });
  }, [
    effectiveCategory,
    marketplace,
    invoiceCount,
    invoiceUnits,
    brandAuthorization,
    sellerAgeMonths,
    priorRejection,
    invoiceRecent,
    hasProductPhotos,
    hasSafetyDocs,
    restrictionLevel,
    snapshot,
    ungatingExecutionPlan,
  ]);

  const ungatingAuditRows = useMemo(
    () =>
      snapshot
        ? [
            { label: "Live ASIN", value: snapshot.asin, detail: snapshot.title },
            {
              label: "Inferred category",
              value: inferredCategory ? inferredCategory.split("__")[0] : "Needs manual pick",
              detail: snapshot.breadcrumbs.length ? snapshot.breadcrumbs.join(" / ") : "Breadcrumb path not detected",
            },
            {
              label: "Packet posture",
              value: `${packetStage} / ${supplyPath}`,
              detail: `${brandRelationship} brand relationship`,
            },
            {
              label: "Brand signal",
              value: snapshot.brand || "Unknown",
              detail: restrictionLevel === "brand" ? "Brand-level restriction selected" : "Brand restriction not selected",
            },
            {
              label: "Image proof",
              value: `${snapshot.imageUrls.length} images`,
              detail: snapshot.mainImageUrl ? "Live product imagery loaded" : "No main image detected",
            },
          ]
        : [
            {
              label: "Packet posture",
              value: `${packetStage} / ${supplyPath}`,
              detail: `${brandRelationship} brand relationship`,
            },
            {
              label: "Submission call",
              value: ungatingExecutionPlan.ungatingDecision,
              detail: `${ungatingExecutionPlan.proofPriority} | ${ungatingExecutionPlan.submissionCadence}`,
            },
          ],
    [brandRelationship, inferredCategory, packetStage, restrictionLevel, snapshot, supplyPath, ungatingExecutionPlan],
  );

  const auditLines = useMemo(() => {
    const lines: string[] = [];
    if (snapshot) {
      lines.push(
        inferredCategory
          ? "Live listing loaded. Category and brand signals were inferred from the Amazon page."
          : "Live listing loaded, but category inference was weak. Pick the target category manually before trusting the approval path.",
      );
    } else {
      lines.push("Start with a live ASIN or Amazon URL when possible so category and brand clues are not guessed manually.");
    }
    if (restrictionLevel === "brand") {
      lines.push("Brand-level restrictions usually require authorization on top of invoice proof.");
    }
    if (priorRejection) {
      lines.push("A prior rejection changes the job: fix the packet first, then resubmit.");
    }
    if (snapshot) {
      lines.push(
        `System draft: ${ungatingPlan.invoiceCount} invoices, ${ungatingPlan.invoiceUnits} units, ${ungatingPlan.hasProductPhotos ? "product photos ready" : "photo gap"}, ${ungatingPlan.hasSafetyDocs ? "compliance docs likely needed" : "no extra compliance docs inferred"}.`,
      );
    }
    return lines;
  }, [snapshot, inferredCategory, restrictionLevel, priorRejection, ungatingPlan]);

  const ungatingActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: ungatingExecutionPlan.ungatingDecision,
        detail: ungatingExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: ungatingExecutionPlan.owner,
        detail: `${ungatingExecutionPlan.proofPriority} should sit with the operator who can actually clear the next approval blocker.`,
      },
      {
        label: "Do not cross",
        value:
          !snapshot
            ? "Do not build an ungating packet from memory"
            : priorRejection
              ? "Do not resubmit the same weak packet again"
              : restrictionLevel === "brand"
                ? "Do not treat brand restriction like plain category ungating"
                : "Do not gather documents without a proof trail",
        detail:
          !snapshot
            ? "The approval path is more reliable when category and brand clues come from the live listing."
            : priorRejection
              ? "A repeat submission without fixing the packet usually burns more time than it saves."
              : restrictionLevel === "brand"
                ? "Brand-gated paths usually need authorization logic on top of invoice proof."
                : "Invoices, photos, and support docs only help when they map to one clean approval story.",
      },
      {
        label: "Then do",
        value: ungatingExecutionPlan.submissionCadence,
        detail: "Map invoices, photos, and supporting docs into one proof trail before the next submission decision.",
      },
      {
        label: "Watch",
        value: ungatingExecutionPlan.proofPriority,
        detail: ungatingExecutionPlan.watchout,
      },
    ],
    [priorRejection, restrictionLevel, snapshot, ungatingExecutionPlan],
  );

  const ungatingInputRows = useMemo(
    () => [
      ...ungatingAuditRows,
      {
        label: localeText(locale, "Execution call", "执行判断"),
        value: ungatingActionRows[0]?.value ?? "Ungating decision pending",
        detail: ungatingActionRows[1]?.value
          ? `${ungatingActionRows[1].value} owns the first evidence gap until the same packet is rechecked.`
          : "Name one packet owner before more documents get gathered without a clear gating plan.",
      },
    ],
    [locale, ungatingActionRows, ungatingAuditRows],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1.4fr_0.8fr_0.8fr_0.8fr]">
        <Field label="ASIN or Amazon URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} placeholder="Optional: load a live listing first" />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <Field label="Restriction level">
          <SelectInput value={restrictionLevel} onChange={(e) => setRestrictionLevel(e.target.value)}>
            <option value="category">Category-level</option>
            <option value="subcategory">Sub-category-level</option>
            <option value="brand">Brand-level</option>
            <option value="asin">ASIN-level</option>
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {runtimeActionButtonLabel(locale, loading, "Load listing and generate ungating result", "加载商品并生成解封结果")}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote lines={auditLines} />
      <div className="rounded-xl border border-teal-200 bg-teal-50 px-3 py-3 text-sm text-teal-950">
        {runtimeResultHint(locale)}
      </div>
      <div className="grid gap-3 xl:grid-cols-[1fr_1fr]">
        <DistributionPanel title={runtimeResultTitle(locale)} rows={ungatingInputRows} />
        <DistributionPanel title={runtimeActionPlanTitle(locale)} rows={ungatingActionRows} />
      </div>
      <div className="flex justify-end">
        <button
          type="button"
          onClick={() => setShowAdvanced((current) => !current)}
          className="text-sm font-medium text-teal-700 transition hover:text-teal-800"
        >
          {showAdvanced ? "Hide evidence assumptions" : "Adjust evidence assumptions"}
        </button>
      </div>
      {showAdvanced ? (
        <div className="grid gap-4">
          <div className="grid gap-2.5 xl:grid-cols-[1fr_1fr_1fr]">
            <Field label="Supply path">
              <SelectInput value={supplyPath} onChange={(e) => setSupplyPath(e.target.value)}>
                <option value="authorized-distributor">Authorized distributor</option>
                <option value="wholesale-supplier">Wholesale supplier</option>
                <option value="manufacturer">Manufacturer</option>
                <option value="retail-arbitrage">Retail / receipt-led sourcing</option>
              </SelectInput>
            </Field>
            <Field label="Packet stage">
              <SelectInput value={packetStage} onChange={(e) => setPacketStage(e.target.value)}>
                <option value="idea">Still gathering proof</option>
                <option value="partial">Partial packet</option>
                <option value="ready">Ready to submit</option>
              </SelectInput>
            </Field>
            <Field label="Brand relationship">
              <SelectInput value={brandRelationship} onChange={(e) => setBrandRelationship(e.target.value)}>
                <option value="authorized">Authorized reseller</option>
                <option value="owner">Brand owner</option>
                <option value="unknown">Unknown / no direct authorization</option>
              </SelectInput>
            </Field>
          </div>
          <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-2">
            <Field label="Target category">
              <SelectInput value={effectiveCategory} onChange={(e) => setCategory(e.target.value)}>
                <option value="">Select category</option>
                {renderOptionGroups(ungatingCategoryOptionGroups)}
              </SelectInput>
            </Field>
            <Field label="Seller account age (months)">
              <NumberInput value={sellerAgeMonths} min="0" step="1" onChange={(e) => setSellerAgeMonths(Number(e.target.value))} />
            </Field>
          </div>
          <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-3 2xl:grid-cols-6">
            <Field label="Supplier invoice count">
              <NumberInput value={invoiceCount} min="0" step="1" onChange={(e) => setInvoiceCount(Number(e.target.value))} />
            </Field>
            <Field label="Units across invoices">
              <NumberInput value={invoiceUnits} min="0" step="1" onChange={(e) => setInvoiceUnits(Number(e.target.value))} />
            </Field>
            <Checkbox label="Brand authorization is available" checked={brandAuthorization} onChange={setBrandAuthorization} />
            <Checkbox label="This category has already been rejected once" checked={priorRejection} onChange={setPriorRejection} />
            <Checkbox label="Invoices are within 180 days" checked={invoiceRecent} onChange={setInvoiceRecent} />
            <Checkbox label="Clear product photos are ready" checked={hasProductPhotos} onChange={setHasProductPhotos} />
            <Checkbox label="Safety or compliance documents are ready" checked={hasSafetyDocs} onChange={setHasSafetyDocs} />
          </div>
        </div>
      ) : null}
    </RuntimeShell>
  );
}

function BrandRegistryRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [asinOrUrl, setAsinOrUrl] = useState("");
  const [targetMarketplace, setTargetMarketplace] = useState("US");
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [filingCountry, setFilingCountry] = useState("US");
  const [filingBasis, setFilingBasis] = useState<"none" | "pending" | "registered">("pending");
  const [launchStage, setLaunchStage] = useState("launch");
  const [brandName, setBrandName] = useState("");
  const [trademarkStatus, setTrademarkStatus] = useState<"none" | "pending" | "registered">("pending");
  const [logoOnProduct, setLogoOnProduct] = useState(false);
  const [logoOnPackaging, setLogoOnPackaging] = useState(false);
  const [listingsLive, setListingsLive] = useState(0);
  const [sellerAgeMonths, setSellerAgeMonths] = useState(0);
  const [exactBrandMatch, setExactBrandMatch] = useState(true);
  const [genericBrandRuleOk, setGenericBrandRuleOk] = useState(true);
  const [showAdvanced, setShowAdvanced] = useState(false);
  const registryPlan = useMemo(
    () =>
      inferBrandApplicationPlan({
        snapshot,
        targetMarketplace,
        filingCountry,
        filingBasis,
        launchStage,
      }),
    [filingBasis, filingCountry, launchStage, snapshot, targetMarketplace],
  );
  const registryExecutionPlan = useMemo(
    () =>
      inferBrandRegistryExecutionPlan({
        trademarkStatus,
        logoOnProduct,
        logoOnPackaging,
        exactBrandMatch,
        genericBrandRuleOk,
        hasBrandAnchor: Boolean((brandName || snapshot?.brand || "").trim()),
        crossBorderMismatch: registryPlan.crossBorderMismatch,
        targetMarketplace,
      }),
    [
      brandName,
      exactBrandMatch,
      genericBrandRuleOk,
      logoOnPackaging,
      logoOnProduct,
      registryPlan.crossBorderMismatch,
      snapshot,
      targetMarketplace,
      trademarkStatus,
    ],
  );

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(targetMarketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Unable to load Amazon listing.");
      }
      setSnapshot(payload);
      if (!showAdvanced) {
        const nextPlan = inferBrandApplicationPlan({
          snapshot: payload,
          targetMarketplace,
          filingCountry,
          filingBasis,
          launchStage,
        });
        setBrandName((current) => current || nextPlan.brandName || payload.brand || "");
        setTrademarkStatus(nextPlan.trademarkStatus);
        setLogoOnProduct(nextPlan.logoOnProduct);
        setLogoOnPackaging(nextPlan.logoOnPackaging);
        setListingsLive(nextPlan.listingsLive);
        setSellerAgeMonths(nextPlan.sellerAgeMonths);
        setExactBrandMatch(nextPlan.exactBrandMatch);
        setGenericBrandRuleOk(nextPlan.genericBrandRuleOk);
      } else {
        setBrandName((current) => current || payload.brand || "");
        setListingsLive((current) => (current > 0 ? current : 1));
      }
    } catch (loadError) {
      setSnapshot(null);
      setError(loadError instanceof Error ? loadError.message : "Unable to load Amazon listing.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(() => {
    if (!(brandName || snapshot)) {
      return {
        headline: "Brand Registry check is waiting on a brand anchor",
        summary:
          "Use this registry read to decide whether the next job is loading the real brand listing, closing filing proof, or changing registry posture before timing gets debated.",
        metrics: [
          {
            label: "Current result",
            value: "Brand anchor missing",
            detail: "Load a live ASIN or enter the filing brand name before trusting any registry posture.",
          },
          {
            label: "Execution call",
            value: registryExecutionPlan.registryDecision,
            detail: `${registryExecutionPlan.proofPriority} | ${registryExecutionPlan.filingCadence}`,
          },
          {
            label: "First move",
            value: "Load a live listing or set the brand anchor",
            detail: "Do not polish packaging or listing assets before the brand identity is explicit and consistent.",
          },
          {
            label: "Execution owner",
            value: registryExecutionPlan.owner,
            detail: "One registry owner should clear the first filing blocker before asset work sprawls.",
          },
        ],
        recommendations: [
          "Start with a live ASIN whenever possible so brand spelling and listing proof come from the actual page.",
          "Do not confuse nice creative assets with a registry-ready packet.",
        ],
        status: {
          label: "Registry baseline is incomplete",
          tone: "warning",
        },
        missingItems: ["Brand anchor"],
        nextSteps: [
          "Load a live listing or enter the brand name used in filing.",
          "Assign one registry owner to the next filing blocker.",
          "Re-run once the brand anchor is explicit.",
        ],
        actionStance: {
          label: "Do not start registry work from a vague brand baseline",
          tone: "warning",
          detail: "Registry work becomes expensive when the legal name, listing name, and asset proof are still drifting.",
        },
      } satisfies ToolEvaluation;
    }

    return evaluateBrandRegistry({
      trademarkStatus,
      logoOnProduct,
      logoOnPackaging,
      listingsLive,
      sellerAgeMonths,
      targetMarketplace,
      exactBrandMatch,
      genericBrandRuleOk,
      brandName,
      liveBrand: snapshot?.brand,
      hasLiveListing: Boolean(snapshot),
    });
  }, [
    trademarkStatus,
    logoOnProduct,
    logoOnPackaging,
    listingsLive,
    sellerAgeMonths,
    targetMarketplace,
    exactBrandMatch,
    genericBrandRuleOk,
    brandName,
    snapshot,
    registryExecutionPlan,
  ]);

  const registryAuditRows = useMemo(
    () =>
      snapshot
        ? [
            { label: "Live ASIN", value: snapshot.asin, detail: snapshot.title },
            {
              label: "Live brand",
              value: snapshot.brand || "Unknown",
              detail: snapshot.brandStoreLink ? "Brand store link detected" : "No brand store link detected",
            },
            {
              label: "Application posture",
              value: `${launchStage} / ${filingCountry}`,
              detail: `${filingBasis} filing basis for ${targetMarketplace}`,
            },
            {
              label: "Live listing assets",
              value: `${snapshot.imageUrls.length} images`,
              detail: snapshot.hasAPlus ? "A+ already visible on page" : "No A+ signal on page",
            },
            {
              label: "Browse path",
              value: snapshot.breadcrumbs[0] || "Unknown",
              detail: snapshot.breadcrumbs.length ? snapshot.breadcrumbs.join(" / ") : "Breadcrumbs not detected",
            },
          ]
        : [
            {
              label: "Application posture",
              value: `${launchStage} / ${filingCountry}`,
              detail: `${filingBasis} filing basis for ${targetMarketplace}`,
            },
            {
              label: "Filing call",
              value: registryExecutionPlan.registryDecision,
              detail: `${registryExecutionPlan.proofPriority} | ${registryExecutionPlan.filingCadence}`,
            },
          ],
    [filingBasis, filingCountry, launchStage, registryExecutionPlan, snapshot, targetMarketplace],
  );

  const registryActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: registryExecutionPlan.registryDecision,
        detail: registryExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: registryExecutionPlan.owner,
        detail: `${registryExecutionPlan.proofPriority} should be owned by the person who can actually change the filing outcome.`,
      },
      {
        label: "Then do",
        value: registryExecutionPlan.filingCadence,
        detail: "Keep listing, packaging, and filing proof aligned while the next gating move is cleared.",
      },
      {
        label: "Watch",
        value: registryExecutionPlan.proofPriority,
        detail: registryExecutionPlan.watchout,
      },
    ],
    [registryExecutionPlan],
  );

  const registryInputRows = useMemo(
    () => [
      ...registryAuditRows,
      {
        label: "Execution call",
        value: registryActionRows[0]?.value ?? "Registry decision pending",
        detail: registryActionRows[1]?.value
          ? `${registryActionRows[1].value} should own the next filing blocker.`
          : "Put one registry owner on the next filing step before more asset polishing happens.",
      },
    ],
    [registryActionRows, registryAuditRows],
  );

  const auditLines = useMemo(() => {
    const lines: string[] = [];
    if (snapshot) {
      lines.push("Live Amazon listing loaded. Brand and asset signals are being read from the page instead of guessed.");
    } else {
      lines.push("Load a live ASIN or Amazon URL when possible so the tool can verify brand spelling and listing proof.");
    }
    lines.push(`Application draft: ${launchStage} stage, ${filingBasis} filing basis, ${filingCountry} filing geography.`);
    if (trademarkStatus !== "registered") {
      lines.push("Trademark posture is still the hardest gate. Weak filing status lowers confidence even if the listing looks polished.");
    }
    if (registryPlan.crossBorderMismatch) {
      lines.push("The current filing geography does not fit the target market well enough yet, so legal posture is still ahead of packaging polish.");
    }
    if (!logoOnProduct || !logoOnPackaging) {
      lines.push("Registry packets usually get cleaner when both product and packaging show the same permanent brand mark.");
    }
    if (snapshot) {
      lines.push(
        `System draft: ${registryPlan.trademarkStatus} mark posture, ${registryPlan.logoOnProduct ? "product logo signal present" : "product logo gap"}, ${registryPlan.logoOnPackaging ? "packaging logo signal present" : "packaging logo gap"}, ${registryPlan.listingsLive} live listing.`,
      );
    }
    return lines;
  }, [filingBasis, filingCountry, launchStage, logoOnPackaging, logoOnProduct, registryPlan, snapshot, trademarkStatus]);

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1.4fr_0.75fr_0.75fr_0.75fr_0.8fr]">
        <Field label="ASIN or Amazon URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} placeholder="Optional: load a live listing first" />
        </Field>
        <Field label="Target marketplace">
          <SelectInput value={targetMarketplace} onChange={(e) => setTargetMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <Field label="Launch stage">
          <SelectInput value={launchStage} onChange={(e) => setLaunchStage(e.target.value)}>
            <option value="prelaunch">Pre-launch</option>
            <option value="launch">Launch</option>
            <option value="scale">Scaling brand</option>
          </SelectInput>
        </Field>
        <Field label="Filing geography">
          <TextInput value={filingCountry} onChange={(e) => setFilingCountry(e.target.value)} placeholder="US / EU / UK" />
        </Field>
        <Field label="Filing basis">
          <SelectInput value={filingBasis} onChange={(e) => setFilingBasis(e.target.value as "none" | "pending" | "registered")}>
            <option value="none">No filing yet</option>
            <option value="pending">Pending</option>
            <option value="registered">Registered</option>
          </SelectInput>
        </Field>
      </div>
      <div className="grid gap-2.5 xl:grid-cols-[1.2fr_0.8fr_0.8fr]">
        <Field label="Trademark status">
          <SelectInput value={trademarkStatus} onChange={(e) => setTrademarkStatus(e.target.value as "none" | "pending" | "registered")}>
            <option value="none">No filing yet</option>
            <option value="pending">Pending</option>
            <option value="registered">Registered</option>
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {loading ? "Loading listing..." : "Load listing"}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote lines={auditLines} />
      <div className="grid gap-3 xl:grid-cols-[1fr_1fr]">
        <DistributionPanel title="Live registry inputs" rows={registryInputRows} />
        <DistributionPanel title="This registry call" rows={registryActionRows} />
      </div>
      <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-4">
        <Field label="Brand name on filing or asset pack">
          <TextInput value={brandName} onChange={(e) => setBrandName(e.target.value)} placeholder="Required if no live listing is loaded" />
        </Field>
        <Field label="Live listings count">
          <NumberInput value={listingsLive} min="0" step="1" onChange={(e) => setListingsLive(Number(e.target.value))} />
        </Field>
        <Field label="Seller account age (months)">
          <NumberInput value={sellerAgeMonths} min="0" step="1" onChange={(e) => setSellerAgeMonths(Number(e.target.value))} />
        </Field>
      </div>
      <div className="flex justify-end">
        <button
          type="button"
          onClick={() => setShowAdvanced((current) => !current)}
          className="text-sm font-medium text-teal-700 transition hover:text-teal-800"
        >
          {showAdvanced ? "Hide evidence assumptions" : "Adjust evidence assumptions"}
        </button>
      </div>
      {showAdvanced ? (
        <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-4">
          <Checkbox label="Brand mark is permanently visible on the product" checked={logoOnProduct} onChange={setLogoOnProduct} />
          <Checkbox label="Brand mark is visible on the packaging" checked={logoOnPackaging} onChange={setLogoOnPackaging} />
          <Checkbox label="Brand spelling matches exactly across assets" checked={exactBrandMatch} onChange={setExactBrandMatch} />
          <Checkbox label='If unbranded, the listing uses "generic" correctly' checked={genericBrandRuleOk} onChange={setGenericBrandRuleOk} />
        </div>
      ) : null}
    </RuntimeShell>
  );
}

function FbaPrepRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [productType, setProductType] = useState("single");
  const [productProfile, setProductProfile] = useState("rechargeable kitchen scale with lithium battery");
  const [shipmentStage, setShipmentStage] = useState("draft");
  const [prepOwnership, setPrepOwnership] = useState("3pl");
  const [inboundLane, setInboundLane] = useState("import");
  const [packagingFormat, setPackagingFormat] = useState("box");
  const [labelingMode, setLabelingMode] = useState("fnsuk");
  const [prepProvider, setPrepProvider] = useState("in-house");
  const [isFragile, setIsFragile] = useState(false);
  const [isLiquid, setIsLiquid] = useState(false);
  const [hasBattery, setHasBattery] = useState(false);
  const [hasSds, setHasSds] = useState(false);
  const [hazmatUnknown, setHazmatUnknown] = useState(false);
  const [hasExpiration, setHasExpiration] = useState(false);
  const [shippingTerm, setShippingTerm] = useState("ddp");
  const [showOverrides, setShowOverrides] = useState(false);
  const prepPlan = useMemo(
    () =>
      inferFbaPrepPlan({
        productProfile,
        shipmentStage,
        prepOwnership,
        inboundLane,
      }),
    [inboundLane, prepOwnership, productProfile, shipmentStage],
  );

  useEffect(() => {
    if (showOverrides) {
      return;
    }
    setPackagingFormat(prepPlan.packagingFormat);
    setLabelingMode(prepPlan.labelingMode);
    setPrepProvider(prepPlan.prepProvider);
    setIsFragile(prepPlan.isFragile);
    setIsLiquid(prepPlan.isLiquid);
    setHasBattery(prepPlan.hasBattery);
    setHasSds(prepPlan.hasSds);
    setHazmatUnknown(prepPlan.hazmatUnknown);
    setHasExpiration(prepPlan.hasExpiration);
    setShippingTerm(prepPlan.shippingTerm);
  }, [prepPlan, showOverrides]);

  const result = useMemo(
    () =>
      evaluateFbaPrep({
        productType,
        packagingFormat,
        labelingMode,
        prepProvider,
        isFragile,
        isLiquid,
        hasBattery,
        hasSds,
        hazmatUnknown,
        hasExpiration,
        shippingTerm,
      }),
    [
      productType,
      packagingFormat,
      labelingMode,
      prepProvider,
      isFragile,
      isLiquid,
      hasBattery,
      hasSds,
      hazmatUnknown,
      hasExpiration,
      shippingTerm,
    ],
  );

  const prepAuditRows = useMemo(
    () => [
      {
        label: "Shipment brief",
        value: `${shipmentStage} / ${inboundLane}`,
        detail: `${productType} | ${prepOwnership} prep ownership`,
      },
      {
        label: "Product profile",
        value: productProfile,
        detail: `${labelingMode === "fnsuk" ? "Amazon FNSKU" : "Manufacturer barcode"} | ${prepProvider}`,
      },
      {
        label: "Hazmat pressure",
        value: `${hasBattery || isLiquid ? "Elevated" : "Standard"} / ${hazmatUnknown ? "Unknown classification" : "Classified"}`,
        detail: `${hasBattery ? "Battery" : "No battery"} | ${isLiquid ? "Liquid" : "Non-liquid"} | ${hasSds ? "SDS ready" : "SDS gap"}`,
      },
      {
        label: "Handling flags",
        value: `${isFragile ? "Fragile" : "Not fragile"} / ${hasExpiration ? "Expiration-dated" : "No expiration"}`,
        detail: `${shippingTerm.toUpperCase()} inbound term sets the handoff and liability posture`,
      },
    ],
    [hasBattery, hasExpiration, hasSds, hazmatUnknown, inboundLane, isFragile, isLiquid, labelingMode, packagingFormat, prepOwnership, prepProvider, productProfile, productType, shipmentStage, shippingTerm],
  );

  const prepActionRows = useMemo(() => {
    const firstMove =
      hazmatUnknown
        ? {
            label: "First move",
            value: "Classify hazmat status before shipment prep",
            detail: "Unknown hazmat posture can invalidate the rest of the inbound plan no matter how tidy the packaging checklist looks.",
          }
        : (hasBattery || isLiquid) && !hasSds
          ? {
              label: "First move",
              value: "Complete SDS or exemption paperwork",
                detail: "Special-category inventory needs the documentation layer settled before you trust any prep-center handoff plan.",
            }
          : isFragile && packagingFormat === "polybag"
            ? {
                label: "First move",
                value: "Upgrade protective packaging",
                detail: "The current pack choice is too weak for fragile inventory and will likely turn into avoidable damage or check-in issues.",
              }
            : hasExpiration && labelingMode !== "fnsuk"
              ? {
                  label: "First move",
                  value: "Tighten labeling control",
                  detail: "Expiration-dated products need cleaner unit-level labeling discipline than a loose manufacturer-barcode path usually provides.",
                }
              : {
                  label: "First move",
                  value: "Run a single inbound prep SOP",
                  detail: "The major risk flags are known, so the next gain comes from executing one consistent unit-prep standard.",
                };

    return [
      firstMove,
      hazmatUnknown
        ? {
            label: "Execution owner",
            value: "Hazmat / compliance owner",
            detail: "Unknown hazmat posture should be resolved by the person who can classify the product formally before inbound starts.",
          }
        : (hasBattery || isLiquid) && !hasSds
          ? {
              label: "Execution owner",
              value: "Documentation owner",
              detail: "Battery or liquid paperwork gaps belong to the team collecting SDS or exemption evidence.",
            }
          : isFragile && packagingFormat === "polybag"
            ? {
                label: "Execution owner",
                value: "Packaging owner",
                detail: "Fragile-unit protection needs a packaging decision from the operator who controls unit prep standards.",
              }
            : hasExpiration && labelingMode !== "fnsuk"
              ? {
                  label: "Execution owner",
                  value: "Labeling owner",
                  detail: "Expiration-dated inventory should have one owner accountable for unit-level labeling discipline.",
                }
              : {
                  label: "Execution owner",
                  value: "Inbound prep owner",
                  detail: "When the major flags are known, one operator should own the single prep SOP from unit prep through handoff.",
                },
      {
        label: "Then do",
        value: "Assign carton, label, and document ownership",
        detail: "Prep failures usually happen at the handoff between supplier, prep center, and inbound booking rather than inside one isolated task.",
      },
      {
        label: "Watch",
        value: "Hidden inbound rework",
        detail: "When packaging, hazmat docs, and labeling are only mostly right, Amazon often turns the difference into delays, fees, or damaged sellable stock.",
      },
    ];
  }, [hasBattery, hasExpiration, hasSds, hazmatUnknown, isFragile, isLiquid, labelingMode, packagingFormat]);

  const prepInputRows = useMemo(
    () => [
      ...prepAuditRows,
      {
        label: "Execution call",
        value: prepActionRows[0]?.value ?? "Prep decision pending",
        detail: prepActionRows[1]?.value
          ? `${prepActionRows[1].value} owns the first inbound blocker until the same handoff path is rechecked.`
          : "Put one prep owner on the first blocked handoff before the shipment books.",
      },
    ],
    [prepActionRows, prepAuditRows],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <DistributionPanel title="Live prep inputs" rows={prepInputRows} />
      <DistributionPanel title="This prep call" rows={prepActionRows} />
      <AuditNote
        lines={[
          "Use this prep read to decide whether the shipment is safe to create now, which prep blocker still stops it, and which owner must clear that blocker first.",
          `System draft: ${prepPlan.packagingFormat} pack, ${prepPlan.labelingMode} labels, ${prepPlan.hasSds ? "SDS covered" : "SDS gap"}, ${prepPlan.shippingTerm.toUpperCase()} inbound term.`,
          "Open overrides only when the real unit-prep facts differ from the shipment brief.",
        ]}
      />
      <div className="grid gap-2.5 xl:grid-cols-[1.4fr_0.8fr_0.8fr_0.8fr]">
        <Field label="Product profile">
          <TextInput value={productProfile} onChange={(e) => setProductProfile(e.target.value)} placeholder="What is shipping into FBA?" />
        </Field>
        <Field label="Shipment stage">
          <SelectInput value={shipmentStage} onChange={(e) => setShipmentStage(e.target.value)}>
            <option value="draft">Drafting shipment</option>
            <option value="sample">Testing prep flow</option>
            <option value="ready">Ready to book</option>
          </SelectInput>
        </Field>
        <Field label="Prep ownership">
          <SelectInput value={prepOwnership} onChange={(e) => setPrepOwnership(e.target.value)}>
            <option value="supplier">Supplier</option>
            <option value="3pl">3PL / prep center</option>
            <option value="warehouse">Own warehouse</option>
          </SelectInput>
        </Field>
        <Field label="Inbound lane">
          <SelectInput value={inboundLane} onChange={(e) => setInboundLane(e.target.value)}>
            <option value="import">Import to FBA</option>
            <option value="domestic">Domestic replenishment</option>
          </SelectInput>
        </Field>
      </div>
      <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-3">
        <Field label="Product type">
          <SelectInput value={productType} onChange={(e) => setProductType(e.target.value)}>
            <option value="single">Single item</option>
            <option value="bundle">Bundle</option>
            <option value="multi-pack">Multi-pack</option>
          </SelectInput>
        </Field>
        <Field label="Packaging format">
          <SelectInput value={packagingFormat} onChange={(e) => setPackagingFormat(e.target.value)}>
            <option value="box">Box</option>
            <option value="polybag">Polybag</option>
            <option value="shrink-wrap">Shrink wrap</option>
          </SelectInput>
        </Field>
        <Field label="Labeling mode">
          <SelectInput value={labelingMode} onChange={(e) => setLabelingMode(e.target.value)}>
            <option value="fnsuk">Amazon FNSKU</option>
            <option value="manufacturer">Manufacturer barcode</option>
          </SelectInput>
        </Field>
        <Field label="Prep provider">
          <SelectInput value={prepProvider} onChange={(e) => setPrepProvider(e.target.value)}>
            <option value="in-house">In-house prep</option>
            <option value="3pl">3PL or prep center</option>
          </SelectInput>
        </Field>
        <Field label="Inbound shipping term">
          <SelectInput value={shippingTerm} onChange={(e) => setShippingTerm(e.target.value)}>
            <option value="ddp">DDP</option>
            <option value="dap">DAP</option>
            <option value="exw">EXW</option>
          </SelectInput>
        </Field>
      </div>
      <div className="flex justify-end">
        <button
          type="button"
          onClick={() => setShowOverrides((current) => !current)}
          className="text-sm font-medium text-teal-700 transition hover:text-teal-800"
        >
          {showOverrides ? "Hide prep overrides" : "Adjust prep assumptions"}
        </button>
      </div>
      {showOverrides ? (
        <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-3 2xl:grid-cols-6">
          <Checkbox label="Fragile" checked={isFragile} onChange={setIsFragile} />
          <Checkbox label="Liquid" checked={isLiquid} onChange={setIsLiquid} />
          <Checkbox label="Contains battery" checked={hasBattery} onChange={setHasBattery} />
          <Checkbox label="SDS or exemption sheet is ready" checked={hasSds} onChange={setHasSds} />
          <Checkbox label="Hazmat classification is still unclear" checked={hazmatUnknown} onChange={setHazmatUnknown} />
          <Checkbox label="Product has expiration dating" checked={hasExpiration} onChange={setHasExpiration} />
        </div>
      ) : null}
    </RuntimeShell>
  );
}

function InventoryPlannerRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [planningMode, setPlanningMode] = useState("balanced-reorder");
  const [demandStage, setDemandStage] = useState("normal");
  const [inventoryPosture, setInventoryPosture] = useState("balanced");
  const [executionPressure, setExecutionPressure] = useState("watch");
  const [currentInventory, setCurrentInventory] = useState(1200);
  const [dailyVelocity, setDailyVelocity] = useState(24);
  const [leadTimeDays, setLeadTimeDays] = useState(38);
  const [inboundUnits, setInboundUnits] = useState(600);
  const [safetyStockDays, setSafetyStockDays] = useState(21);
  const [seasonalityMultiplier, setSeasonalityMultiplier] = useState(1.1);
  const [sellThroughRate, setSellThroughRate] = useState(1.4);
  const [storageUtilizationWeeks, setStorageUtilizationWeeks] = useState(18);
  const [professionalSeller, setProfessionalSeller] = useState(true);
  const [hasStrandedInventory, setHasStrandedInventory] = useState(false);
  const [newSellerWithin365Days, setNewSellerWithin365Days] = useState(false);
  const [awdWaiverEligible, setAwdWaiverEligible] = useState(false);
  const [showAdvanced, setShowAdvanced] = useState(false);
  const inventoryPlan = useMemo(
    () =>
      inferInventoryPlan({
        planningMode,
        demandStage,
        inventoryPosture,
        executionPressure,
      }),
    [demandStage, executionPressure, inventoryPosture, planningMode],
  );

  useEffect(() => {
    if (showAdvanced) {
      return;
    }
    setSafetyStockDays(inventoryPlan.safetyStockDays);
    setSeasonalityMultiplier(inventoryPlan.seasonalityMultiplier);
    setSellThroughRate(inventoryPlan.sellThroughRate);
    setStorageUtilizationWeeks(inventoryPlan.storageUtilizationWeeks);
  }, [
    inventoryPlan.safetyStockDays,
    inventoryPlan.seasonalityMultiplier,
    inventoryPlan.sellThroughRate,
    inventoryPlan.storageUtilizationWeeks,
    showAdvanced,
  ]);

  const result = useMemo(
    () =>
      evaluateInventoryPlanner({
        currentInventory,
        dailyVelocity,
        leadTimeDays,
        inboundUnits,
        safetyStockDays,
        seasonalityMultiplier,
        sellThroughRate,
        storageUtilizationWeeks,
        professionalSeller,
        hasStrandedInventory,
        newSellerWithin365Days,
        awdWaiverEligible,
      }),
    [
      awdWaiverEligible,
      currentInventory,
      dailyVelocity,
      hasStrandedInventory,
      leadTimeDays,
      inboundUnits,
      newSellerWithin365Days,
      professionalSeller,
      safetyStockDays,
      sellThroughRate,
      seasonalityMultiplier,
      storageUtilizationWeeks,
    ],
  );

  const adjustedVelocity = useMemo(
    () => dailyVelocity * seasonalityMultiplier,
    [dailyVelocity, seasonalityMultiplier],
  );

  const reorderPoint = useMemo(
    () => adjustedVelocity * (leadTimeDays + safetyStockDays),
    [adjustedVelocity, leadTimeDays, safetyStockDays],
  );

  const inventoryPosition = useMemo(
    () => currentInventory + inboundUnits,
    [currentInventory, inboundUnits],
  );

  const daysOfCover = useMemo(
    () => (adjustedVelocity > 0 ? inventoryPosition / adjustedVelocity : inventoryPosition),
    [adjustedVelocity, inventoryPosition],
  );

  const inventoryAuditRows = useMemo(
    () => [
      {
        label: "Inventory position",
        value: `${inventoryPosition.toLocaleString("en-US")} units`,
        detail: `${currentInventory.toLocaleString("en-US")} on hand + ${inboundUnits.toLocaleString("en-US")} inbound`,
      },
      {
        label: "Adjusted velocity",
        value: `${roundNumber(adjustedVelocity, 1)} units/day`,
        detail: `${roundNumber(seasonalityMultiplier, 2)}x seasonal multiplier on ${roundNumber(dailyVelocity, 1)} baseline`,
      },
      {
        label: "Reorder point",
        value: `${Math.ceil(reorderPoint).toLocaleString("en-US")} units`,
        detail: `${leadTimeDays} lead-time days + ${safetyStockDays} safety days`,
      },
      {
        label: "Days of cover",
        value: `${roundNumber(daysOfCover, 1)} days`,
        detail: daysOfCover < 28 ? "Inside low-inventory-fee pressure band" : "Outside low-inventory-fee pressure band",
      },
      {
        label: "Storage / sell-through",
        value: `${roundNumber(storageUtilizationWeeks, 1)} weeks / ${roundNumber(sellThroughRate, 2)}`,
        detail: `${planningMode.replace(/-/g, " ")} mode with ${demandStage} demand and ${inventoryPosture} posture`,
      },
    ],
    [
      adjustedVelocity,
      currentInventory,
      dailyVelocity,
      daysOfCover,
      inboundUnits,
      leadTimeDays,
      demandStage,
      inventoryPosture,
      planningMode,
      reorderPoint,
      safetyStockDays,
      seasonalityMultiplier,
      sellThroughRate,
      storageUtilizationWeeks,
    ],
  );

  const inventoryExecutionPlan = useMemo(
    () =>
      inferInventoryExecutionPlan({
        inventoryPosition,
        reorderPoint,
        daysOfCover,
        sellThroughRate,
      }),
    [daysOfCover, inventoryPosition, reorderPoint, sellThroughRate],
  );

  const inventoryPressureRows = useMemo(
    () => [
      {
        label: "Stockout pressure",
        value: inventoryPosition <= reorderPoint ? "High" : "Contained",
        detail: inventoryPosition <= reorderPoint
          ? "Current position is already inside the reorder zone"
          : "Current position still sits above the reorder threshold",
      },
      {
        label: "Low-cover fee risk",
        value: daysOfCover < 28 ? "Visible" : "Low",
        detail: "Amazon starts punishing very thin FBA cover with low-inventory-fee pressure",
      },
      {
        label: "Excess pressure",
        value: daysOfCover > 90 || sellThroughRate < 1 ? "Visible" : "Low",
        detail: "Too much cover or weak sell-through can drag storage economics and IPI posture",
      },
      {
        label: "Storage surcharge pressure",
        value:
          professionalSeller &&
          storageUtilizationWeeks > 22 &&
          !newSellerWithin365Days &&
          !awdWaiverEligible
            ? "Visible"
            : "Low",
        detail: "High storage utilization without relief flags is where surcharge risk starts to matter",
      },
    ],
    [
      awdWaiverEligible,
      daysOfCover,
      inventoryPosition,
      newSellerWithin365Days,
      professionalSeller,
      reorderPoint,
      sellThroughRate,
      storageUtilizationWeeks,
    ],
  );

  const inventoryAuditLines = useMemo(
    () => [
      "This planner is only decision-grade when daily velocity, lead time, and inbound units are grounded in reality rather than hope.",
      `System brief: ${inventoryPlan.planningFocus}`,
      inventoryPosition <= reorderPoint
        ? "You are already inside the reorder zone, so delay is now an active decision."
        : "You still have cover, but the useful job is watching for demand or lead-time drift before the next buy window closes.",
      sellThroughRate < 1
        ? "Weak sell-through is colliding with replenishment math. Do not solve that with a blind reorder."
        : "Sell-through is not the main problem on this run, so focus on cover and storage posture.",
      inventoryPlan.executionAdvice,
    ],
    [inventoryPlan.executionAdvice, inventoryPlan.planningFocus, inventoryPosition, reorderPoint, sellThroughRate],
  );

  const inventoryActionRows = useMemo(() => {
    return [
      {
        label: "First move",
        value: inventoryExecutionPlan.decision,
        detail: inventoryExecutionPlan.nextMove,
      },
      {
        label: "Planning brief",
        value: inventoryPlan.planningFocus,
        detail: inventoryPlan.executionAdvice,
      },
      {
        label: "Execution owner",
        value: inventoryExecutionPlan.owner,
        detail: `${inventoryExecutionPlan.proofPriority} is the proof to watch while this owner carries the decision.`,
      },
      {
        label: "Do not cross",
        value:
          inventoryPosition <= reorderPoint
            ? "Do not delay once you are already inside the reorder zone"
            : sellThroughRate < 1
              ? "Do not solve weak sell-through with a blind reorder"
              : "Do not trust clean inventory math that ignores inbound reality",
        detail:
          inventoryPosition <= reorderPoint
            ? "At this point, waiting is itself an active inventory decision with stockout consequences."
            : sellThroughRate < 1
              ? "More units do not fix weak movement when the real bottleneck is sell-through quality."
              : "Inbound timing, stranded units, and storage pressure can break an otherwise tidy plan.",
      },
      {
        label: "Then do",
        value: inventoryExecutionPlan.cadence,
        detail: inventoryExecutionPlan.watchout,
      },
      {
        label: "Watch",
        value: "Inventory math without operational reality",
        detail: "Forecasts break when inbound timing, stranded units, or storage pressure are cleaner on paper than in the warehouse.",
      },
    ];
  }, [inventoryExecutionPlan, inventoryPlan.executionAdvice, inventoryPlan.planningFocus]);

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[0.85fr_0.85fr_0.85fr_0.85fr_0.8fr_0.8fr_auto]">
        <Field label="Current inventory units">
          <NumberInput value={currentInventory} min="0" step="1" onChange={(e) => setCurrentInventory(Number(e.target.value))} />
        </Field>
        <Field label="Average daily sales velocity">
          <NumberInput value={dailyVelocity} min="0" step="0.1" onChange={(e) => setDailyVelocity(Number(e.target.value))} />
        </Field>
        <Field label="Supplier lead time (days)">
          <NumberInput value={leadTimeDays} min="0" step="1" onChange={(e) => setLeadTimeDays(Number(e.target.value))} />
        </Field>
        <Field label="Inbound units">
          <NumberInput value={inboundUnits} min="0" step="1" onChange={(e) => setInboundUnits(Number(e.target.value))} />
        </Field>
        <Field label="Planning mode">
          <SelectInput value={planningMode} onChange={(e) => setPlanningMode(e.target.value)}>
            <option value="balanced-reorder">Balanced reorder</option>
            <option value="protect-stock">Protect stock</option>
            <option value="inventory-reduction">Inventory reduction</option>
          </SelectInput>
        </Field>
        <Field label="Demand stage">
          <SelectInput value={demandStage} onChange={(e) => setDemandStage(e.target.value)}>
            <option value="normal">Normal</option>
            <option value="peak">Peak</option>
            <option value="soft">Soft</option>
          </SelectInput>
        </Field>
        <Field label="Inventory posture">
          <SelectInput value={inventoryPosture} onChange={(e) => setInventoryPosture(e.target.value)}>
            <option value="balanced">Balanced</option>
            <option value="lean">Lean</option>
            <option value="heavy">Heavy</option>
          </SelectInput>
        </Field>
        <Field label="Execution pressure">
          <SelectInput value={executionPressure} onChange={(e) => setExecutionPressure(e.target.value)}>
            <option value="watch">Watch</option>
            <option value="urgent">Urgent</option>
            <option value="stable">Stable</option>
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowAdvanced((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showAdvanced ? "Hide planning assumptions" : "Adjust planning assumptions"}
          </button>
        </div>
      </div>
      <DistributionPanel
        title="Inventory brief"
        rows={[
          ...inventoryAuditRows,
          {
            label: "Execution call",
            value: inventoryExecutionPlan.decision,
            detail: `${inventoryExecutionPlan.owner} | ${inventoryExecutionPlan.cadence} | ${inventoryExecutionPlan.proofPriority}`,
          },
        ]}
      />
      <AuditNote lines={inventoryAuditLines} />
      <DistributionPanel title="This plan" rows={inventoryActionRows} />
      {showAdvanced ? (
        <div className="grid gap-3 md:grid-cols-2 xl:grid-cols-4">
          <Field label="Safety stock days">
            <NumberInput value={safetyStockDays} min="0" step="1" onChange={(e) => setSafetyStockDays(Number(e.target.value))} />
          </Field>
          <Field label="Seasonality multiplier">
            <NumberInput value={seasonalityMultiplier} min="0.5" step="0.05" onChange={(e) => setSeasonalityMultiplier(Number(e.target.value))} />
          </Field>
          <Field label="90-day sell-through rate">
            <NumberInput value={sellThroughRate} min="0" step="0.01" onChange={(e) => setSellThroughRate(Number(e.target.value))} />
          </Field>
          <Field label="Storage utilization ratio (weeks)">
            <NumberInput value={storageUtilizationWeeks} min="0" step="0.1" onChange={(e) => setStorageUtilizationWeeks(Number(e.target.value))} />
          </Field>
        </div>
      ) : null}
      <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-6">
        <Checkbox label="Professional seller plan" checked={professionalSeller} onChange={setProfessionalSeller} />
        <Checkbox label="Stranded inventory exists" checked={hasStrandedInventory} onChange={setHasStrandedInventory} />
        <Checkbox
          label="Within first 365 FBA days"
          checked={newSellerWithin365Days}
          onChange={setNewSellerWithin365Days}
        />
        <Checkbox label="AWD surcharge waiver likely" checked={awdWaiverEligible} onChange={setAwdWaiverEligible} />
      </div>
      <DistributionPanel title="Pressure ladder" rows={inventoryPressureRows} />
    </RuntimeShell>
  );
}

function ProfitAnalyzerRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("");
  const [category, setCategory] = useState("");
  const [sellingPrice, setSellingPrice] = useState(0);
  const [productCost, setProductCost] = useState(0);
  const [inboundShipping, setInboundShipping] = useState(0);
  const [fulfillmentFee, setFulfillmentFee] = useState(0);
  const [adCostPerOrder, setAdCostPerOrder] = useState(0);
  const [returnRate, setReturnRate] = useState(0);
  const [couponRate, setCouponRate] = useState(0);
  const [storageCostPerUnit, setStorageCostPerUnit] = useState(0);
  const [overheadPerUnit, setOverheadPerUnit] = useState(0);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [showOverrides, setShowOverrides] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const profitPlan = useMemo(
    () =>
      inferProfitCostPlan({
        snapshot,
        category,
        sellingPrice,
      }),
    [category, sellingPrice, snapshot],
  );

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }

      setSnapshot(payload);
      const livePrice = parseCurrencyAmount(payload.priceText);
      if (livePrice > 0) {
        setSellingPrice(livePrice);
      }
      const matchedCategory = inferCategoryOption(payload, calculatorCategoryOptionGroups);
      if (matchedCategory) {
        setCategory(matchedCategory);
      }
      if (!showOverrides) {
        const nextPlan = inferProfitCostPlan({
          snapshot: payload,
          category: matchedCategory ?? category,
          sellingPrice: livePrice > 0 ? livePrice : sellingPrice,
        });
        setProductCost(nextPlan.productCost);
        setInboundShipping(nextPlan.inboundShipping);
        setFulfillmentFee(nextPlan.fulfillmentFee);
        setAdCostPerOrder(nextPlan.adCostPerOrder);
        setReturnRate(nextPlan.returnRate);
        setCouponRate(nextPlan.couponRate);
        setStorageCostPerUnit(nextPlan.storageCostPerUnit);
        setOverheadPerUnit(nextPlan.overheadPerUnit);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  const profitDecisionRows = useMemo(
    () =>
      buildProfitDecisionRows({
        snapshot,
        category,
        sellingPrice,
        productCost,
        inboundShipping,
        fulfillmentFee,
        adCostPerOrder,
        returnRate,
        couponRate,
        storageCostPerUnit,
        overheadPerUnit,
      }),
    [
      adCostPerOrder,
      couponRate,
      fulfillmentFee,
      inboundShipping,
      overheadPerUnit,
      productCost,
      returnRate,
      sellingPrice,
      snapshot,
      storageCostPerUnit,
    ],
  );

  const profitExecutionPlan = useMemo(
    () =>
      inferProfitExecutionPlan({
        hasSnapshot: Boolean(snapshot),
        hasAsinInput: Boolean(asinOrUrl.trim()),
        sellingPrice,
        productCost,
        inboundShipping,
        fulfillmentFee,
        adCostPerOrder,
        returnRate,
        couponRate,
        storageCostPerUnit,
        overheadPerUnit,
      }),
    [
      adCostPerOrder,
      asinOrUrl,
      couponRate,
      fulfillmentFee,
      inboundShipping,
      overheadPerUnit,
      productCost,
      returnRate,
      sellingPrice,
      snapshot,
      storageCostPerUnit,
    ],
  );

  const result = useMemo(() => {
    if (sellingPrice <= 0) {
      return {
        headline: isAmazonBotProtectionError(error)
          ? "Amazon blocked the live profit baseline fetch"
          : "Profit check is waiting on a real sell-price baseline",
        summary:
          "Use this profit check only after the live sell price and cost stack are both real.",
        metrics: [
          {
            label: "Current result",
            value: "Sell price missing",
            detail: snapshot?.priceText
              ? "A live listing exists, but the visible sell price could not be read cleanly."
              : isAmazonBotProtectionError(error)
                ? "Amazon temporarily blocked the live sell-price read on this request."
              : "Load a live ASIN or set the sell price before trusting any margin read.",
          },
          {
            label: "Execution call",
            value: profitExecutionPlan.decision,
            detail: `${profitExecutionPlan.owner} | ${profitExecutionPlan.cadence} | ${profitExecutionPlan.proofPriority}`,
          },
          {
            label: "First move",
            value: snapshot
              ? "Confirm the live sell price"
              : isAmazonBotProtectionError(error)
                ? "Use manual economics inputs or retry later"
                : "Load a live listing or set the sell price",
            detail: "Margin math without a real selling-price anchor is still decorative.",
          },
          {
            label: "Execution owner",
            value: profitExecutionPlan.owner,
            detail: "Keep the first economics fix under one owner until price truth and cost truth are both locked.",
          },
        ],
        recommendations: [
          isAmazonBotProtectionError(error)
            ? "Use manual price, category, and cost inputs for this pass if the decision cannot wait."
            : "Start with a live ASIN when possible so price and category come from the actual PDP.",
          "Do not talk about contribution margin until sell price and COGS are both explicit.",
          "Do not approve this SKU yet.",
          "Do not build a margin story from placeholders.",
        ],
        status: {
          label: "Profit baseline is incomplete",
          tone: "warning",
        },
        missingItems: ["Sell price"],
        nextSteps: [
          snapshot
            ? "Confirm the live sell price manually."
            : isAmazonBotProtectionError(error)
              ? "Either retry the live fetch later or enter the real sell price and category manually."
              : "Load a live listing or set the sell price.",
          "Put one owner on the first economics blocker.",
          "Re-run the profit read once the price baseline is explicit.",
        ],
        actionStance: {
          label: "Do not trust a margin story without a price anchor",
          tone: "warning",
          detail: isAmazonBotProtectionError(error)
            ? "The right move here is not to fake confidence. The live Amazon read was blocked, so the tool should force either manual truth or a later retry. Do not approve this SKU yet. Do not build a margin story from placeholders."
            : "This SKU stays blocked until the price anchor and cost stack are both real. Do not approve it yet. Do not build a margin story from placeholders.",
        },
      } satisfies ToolEvaluation;
    }

    return evaluateProfitAnalyzer({
      marketplace,
      category,
      sellingPrice,
      productCost,
      inboundShipping,
      fulfillmentFee,
      adCostPerOrder,
      returnRate,
      couponRate,
      storageCostPerUnit,
      overheadPerUnit,
    });
  }, [
    adCostPerOrder,
    category,
    couponRate,
    fulfillmentFee,
    inboundShipping,
    marketplace,
    overheadPerUnit,
    productCost,
    returnRate,
    sellingPrice,
    storageCostPerUnit,
    snapshot,
    profitExecutionPlan,
    error,
  ]);

  const auditLines = useMemo(() => {
    const lines: string[] = [];
    if (snapshot) {
      lines.push("Live PDP loaded. Price and category are anchored to the current listing where Amazon exposed them.");
    } else {
      lines.push("Load the live PDP first so price and category are not guessed manually.");
    }
    lines.push("Use this pass to close the economics question before price, ads, or inventory work reopen it.");
    if (sellingPrice > 0 && productCost <= 0) {
      lines.push("COGS is still missing. Until that is real, margin output is only directional.");
    }
    if (snapshot && sellingPrice > 0) {
      lines.push(
        `Estimated draft from the live PDP: ${formatUsd(profitPlan.productCost)} COGS, ${formatUsd(profitPlan.fulfillmentFee)} fulfillment, ${formatUsd(profitPlan.adCostPerOrder)} ad cost, ${roundNumber(profitPlan.returnRate * 100, 1)}% returns.`,
      );
    }
    if (!snapshot) {
      lines.push("Manual price and category entry should be the exception, not the default operating mode.");
    }
    return lines;
  }, [productCost, profitPlan.adCostPerOrder, profitPlan.fulfillmentFee, profitPlan.productCost, profitPlan.returnRate, sellingPrice, snapshot]);

  const detectedCategoryLabel = useMemo(() => {
    for (const group of calculatorCategoryOptionGroups) {
      const option = group.options.find((item) => item.value === category);
      if (option) {
        return option.label;
      }
    }
    return "Not matched yet";
  }, [category]);

  const profitAuditRows = useMemo(
    () => [
      {
        label: "Detected category",
        value: category ? detectedCategoryLabel : "Missing",
        detail: snapshot?.breadcrumbs.length
          ? snapshot.breadcrumbs.join(" / ")
          : "Load a live listing or set the category manually",
      },
      {
        label: "Visible sell price",
        value: sellingPrice > 0 ? formatUsd(roundNumber(sellingPrice)) : "Missing",
        detail: snapshot?.priceText ?? "No live price loaded yet",
      },
      {
        label: "Cost basis",
        value: productCost > 0 ? "Loaded" : "Missing",
        detail:
          productCost > 0
            ? `${formatUsd(roundNumber(productCost))} COGS per unit${snapshot && !showOverrides ? " (estimated from the live PDP until you override it)" : ""}`
            : "Estimated draft will load after a live ASIN is available",
      },
      {
        label: "Fulfillment basis",
        value: fulfillmentFee > 0 ? "Loaded" : "Missing",
        detail:
          fulfillmentFee > 0
            ? `${formatUsd(roundNumber(fulfillmentFee))} per unit${snapshot && !showOverrides ? " (estimated from the live PDP until you override it)" : ""}`
            : "Estimated draft will load after a live ASIN is available",
      },
      {
        label: localeText(locale, "Execution call", "执行判断"),
        value: profitExecutionPlan.decision,
        detail: `${profitExecutionPlan.owner} | ${profitExecutionPlan.cadence} | ${profitExecutionPlan.proofPriority}`,
      },
    ],
    [category, detectedCategoryLabel, fulfillmentFee, productCost, profitExecutionPlan, sellingPrice, snapshot],
  );

  const profitActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: profitExecutionPlan.decision,
        detail: profitExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: profitExecutionPlan.owner,
        detail: `${profitExecutionPlan.proofPriority} is the proof to lock before trusting the margin story.`,
      },
      {
        label: "Do this now",
        value:
          profitDecisionRows.actionRows.find((row) => row.label === "Do this now")?.value ??
          (sellingPrice <= 0
            ? snapshot
              ? "Confirm the live sell price before discussing margin"
              : isAmazonBotProtectionError(error)
                ? "Use manual economics inputs or retry the live fetch later"
                : "Load the live ASIN or set the real sell price"
            : profitExecutionPlan.cadence),
        detail:
          profitDecisionRows.actionRows.find((row) => row.label === "Do this now")?.detail ??
          (sellingPrice <= 0
            ? "Until price is real, every downstream profit number is still decorative."
            : "If a margin only works before ads, returns, or promo drag, it is not a robust operating margin."),
      },
      {
        label: "Go / no-go line",
        value:
          profitDecisionRows.actionRows.find((row) => row.label === "Go / no-go line")?.value ??
          (sellingPrice <= 0 ? "Do not approve this SKU yet" : "Decision line pending"),
        detail:
          profitDecisionRows.actionRows.find((row) => row.label === "Go / no-go line")?.detail ??
          (sellingPrice <= 0
            ? "A unit with no real price anchor is not ready for a go or no-go call."
            : "Use this as the operating verdict, not just a pretty margin display."),
      },
      {
        label: "Do not cross",
        value:
          profitDecisionRows.actionRows.find((row) => row.label === "Do not cross")?.value ??
          (sellingPrice <= 0 ? "Do not build a margin story from placeholders" : "Spreadsheet profit illusion"),
        detail:
          profitDecisionRows.actionRows.find((row) => row.label === "Do not cross")?.detail ??
          (sellingPrice <= 0
            ? "The first commercial truth is price. Everything else should wait until that anchor is real."
            : profitExecutionPlan.watchout),
      },
      {
        label: "Then do",
        value: profitExecutionPlan.cadence,
        detail: "Re-run only after the first blocker changes. Do not reopen price, ads, promo, and inventory all at once.",
      },
      {
        label: "Watch",
        value: profitExecutionPlan.proofPriority,
        detail: profitExecutionPlan.watchout,
      },
    ],
    [error, profitDecisionRows.actionRows, profitExecutionPlan, sellingPrice, snapshot],
  );

  const profitFirstScreenRows = useMemo(() => {
    const missingCoreCost = productCost <= 0 || fulfillmentFee <= 0;
    const missingTrafficCost = adCostPerOrder <= 0;
    const netRow = profitDecisionRows.waterfallRows.find((row) => row.label === "True net");
    const acosRow = profitDecisionRows.pressureRows.find((row) => row.label === "Break-even ACoS");
    const biggestLeakRow = profitDecisionRows.pressureRows.find((row) => row.label === "Biggest leak");

    return [
      {
        label: "Current result",
        value:
          sellingPrice <= 0
            ? "Price blocked"
            : missingCoreCost
              ? "Economics baseline thin"
              : netRow?.value ?? "Net pending",
        detail:
          sellingPrice <= 0
            ? "Do not let the user invent a margin story before the live or manual selling price is explicit."
            : missingCoreCost
              ? "The tool has a live price anchor, but the real cost stack is still too thin for a trustworthy profit call."
              : netRow?.detail ?? "Net contribution is ready for a first commercial read.",
      },
      {
        label: "Biggest pressure",
        value:
          biggestLeakRow?.value ??
          (missingCoreCost
            ? "COGS or fulfillment missing"
            : missingTrafficCost
              ? "Traffic cost still missing"
              : "Leak review pending"),
        detail:
          biggestLeakRow?.detail ??
          (missingCoreCost
            ? "Load the core unit-cost lines before calling any downstream leak the biggest problem."
            : missingTrafficCost
              ? "Without ad cost per order, the tool can only judge pre-traffic economics."
              : "The first leak should stay attached to one owner until it is retested."),
      },
      {
        label: "Break-even room",
        value:
          acosRow?.value ??
          (sellingPrice <= 0
            ? "Blocked"
            : missingCoreCost
              ? "Incomplete"
              : "Pending"),
        detail:
          acosRow?.detail ??
          (sellingPrice <= 0
            ? "No break-even room exists until price is real."
            : missingCoreCost
              ? "Break-even ad room should stay closed until the core stack is loaded."
              : "Use this line to decide whether PPC can scale without breaking contribution."),
      },
      {
        label: "First-screen verdict",
        value:
          sellingPrice <= 0
            ? "Load price first"
            : missingCoreCost
              ? "Complete cost stack first"
              : profitExecutionPlan.decision,
        detail:
          sellingPrice <= 0
            ? "The first job is not optimization. It is locking the selling-price truth."
            : missingCoreCost
              ? "Do not widen the conversation into scale, promo, or ads before the unit-cost truth is loaded."
              : `${profitExecutionPlan.owner} owns the first economics blocker until the same SKU is re-read.`,
      },
    ];
  }, [
    adCostPerOrder,
    fulfillmentFee,
    productCost,
    profitDecisionRows.pressureRows,
    profitDecisionRows.waterfallRows,
    profitExecutionPlan.decision,
    profitExecutionPlan.owner,
    sellingPrice,
  ]);

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 md:grid-cols-[1.4fr_0.8fr_auto] xl:grid-cols-[1.6fr_0.8fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} placeholder="Optional: load a live ASIN first" />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote lines={auditLines} />
      <DistributionPanel title="Live profit inputs" rows={profitAuditRows} />
      <DistributionPanel title="First-screen operator call" rows={profitFirstScreenRows} />
      <DistributionPanel title="This profit call" rows={profitActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">{manualOverridesHeading(locale)}</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when the live PDP missed price or category, or when you want to pressure-test an alternate price scenario.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {manualOverridesToggle(locale, showOverrides)}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-2">
              <Field label="Product category">
                <SelectInput value={category} onChange={(e) => setCategory(e.target.value)}>
                  <option value="">Select category</option>
                  {renderOptionGroups(calculatorCategoryOptionGroups)}
                </SelectInput>
              </Field>
              <Field label="Selling price">
                <NumberInput value={sellingPrice} min="0" step="0.01" onChange={(e) => setSellingPrice(Number(e.target.value))} />
              </Field>
            </div>
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-4">
              <Field label="COGS per unit">
                <NumberInput value={productCost} min="0" step="0.01" onChange={(e) => setProductCost(Number(e.target.value))} />
              </Field>
              <Field label="Inbound shipping per unit">
                <NumberInput value={inboundShipping} min="0" step="0.01" onChange={(e) => setInboundShipping(Number(e.target.value))} />
              </Field>
              <Field label="Fulfillment fee per unit">
                <NumberInput value={fulfillmentFee} min="0" step="0.01" onChange={(e) => setFulfillmentFee(Number(e.target.value))} />
              </Field>
              <Field label="Ad cost per order">
                <NumberInput value={adCostPerOrder} min="0" step="0.01" onChange={(e) => setAdCostPerOrder(Number(e.target.value))} />
              </Field>
              <Field label="Return rate">
                <NumberInput value={returnRate} min="0" max="1" step="0.01" onChange={(e) => setReturnRate(Number(e.target.value))} />
              </Field>
              <Field label="Coupon or discount rate">
                <NumberInput value={couponRate} min="0" max="1" step="0.01" onChange={(e) => setCouponRate(Number(e.target.value))} />
              </Field>
              <Field label="Storage cost per unit">
                <NumberInput value={storageCostPerUnit} min="0" step="0.01" onChange={(e) => setStorageCostPerUnit(Number(e.target.value))} />
              </Field>
              <Field label="Other overhead per unit">
                <NumberInput value={overheadPerUnit} min="0" step="0.01" onChange={(e) => setOverheadPerUnit(Number(e.target.value))} />
              </Field>
            </div>
          </div>
        ) : null}
      </div>
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title="Profit waterfall" rows={profitDecisionRows.waterfallRows} />
        <DistributionPanel title="Margin pressure" rows={profitDecisionRows.pressureRows} />
        <DistributionPanel title="Decision order" rows={profitDecisionRows.actionRows} />
      </div>
    </RuntimeShell>
  );
}

function SalesEstimatorRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("");
  const [decisionUse, setDecisionUse] = useState("opportunity-screen");
  const [confidenceNeed, setConfidenceNeed] = useState("medium");
  const [category, setCategory] = useState("");
  const [bsr, setBsr] = useState(0);
  const [sellingPrice, setSellingPrice] = useState(0);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [showOverrides, setShowOverrides] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const salesScenarioPlan = useMemo(
    () =>
      inferSalesScenarioPlan({
        snapshot,
        marketplace,
        category,
        bsr,
        sellingPrice,
        decisionUse,
        confidenceNeed,
      }),
    [bsr, category, confidenceNeed, decisionUse, marketplace, sellingPrice, snapshot],
  );

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }

      setSnapshot(payload);
      const livePrice = parseCurrencyAmount(payload.priceText);
      if (livePrice > 0) {
        setSellingPrice(livePrice);
      }

      const liveRank =
        parseRankValue(payload.bestSellersRank) || parseRankValue(payload.subCategoryRank);
      if (liveRank > 0) {
        setBsr(liveRank);
      }

      const matchedCategory = inferCategoryOption(payload, calculatorCategoryOptionGroups);
      if (matchedCategory) {
        setCategory(matchedCategory);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  const salesDecisionRows = useMemo(
    () =>
      buildSalesDecisionRows({
        snapshot,
        marketplace,
        category,
        bsr,
        sellingPrice,
        source: snapshot ? "live" : "manual",
      }),
    [bsr, category, marketplace, sellingPrice, snapshot],
  );

  const salesAuditLines = useMemo(() => {
    const lines: string[] = [];
    if (snapshot) {
      lines.push("Live ASIN mode is active. Rank, price, and category were pulled from the product page where available.");
    } else {
      lines.push("Use live ASIN lookup first when possible. Manual BSR mode should stay in overrides for scenario testing only.");
    }
    lines.push(`System focus: ${salesScenarioPlan.primaryFocus}. ${salesScenarioPlan.cautionLevel} caution posture for this estimate.`);
    if (bsr <= 0) {
      lines.push("No BSR yet. Keep this estimate closed until you either load a live listing or enter rank manually.");
    } else if (bsr > 30000) {
      lines.push("This BSR sits in a noisier long-tail band. Treat the output as directional until you compare nearby ASINs.");
    }
    if (!snapshot) {
      lines.push("Use manual inputs only when Amazon does not expose the rank signal or when you want to test a different scenario deliberately.");
    }
    return lines;
  }, [bsr, confidenceNeed, decisionUse, salesScenarioPlan.primaryFocus, snapshot]);
  const salesExecutionPlan = useMemo(
    () =>
      inferSalesExecutionPlan({
        hasSnapshot: Boolean(snapshot),
        bsr,
        hasCategory: Boolean(category),
        sellingPrice,
        decisionUse,
      cautionLevel: salesScenarioPlan.cautionLevel,
    }),
    [bsr, category, decisionUse, salesScenarioPlan.cautionLevel, sellingPrice, snapshot],
  );

  const result = useMemo(() => {
    if (bsr <= 0) {
      return {
        headline: "Sales estimate is waiting on a rank baseline",
        summary:
          "Use this demand estimate only after a real rank baseline exists.",
        metrics: [
          {
            label: "Current result",
            value: "Rank signal missing",
            detail: snapshot
              ? "A live listing exists, but a usable BSR could not be read from the page."
              : "Load a live ASIN or enter a realistic BSR before trusting any demand estimate.",
          },
          {
            label: "Execution call",
            value: salesExecutionPlan.decision,
            detail: `${salesExecutionPlan.proofPriority} | ${salesExecutionPlan.cadence}`,
          },
          {
            label: "First move",
            value: snapshot ? "Confirm a usable BSR" : "Load a live listing or set the BSR",
            detail: "Demand math without a rank baseline is still just a narrative, not a decision tool.",
          },
          {
            label: "Execution owner",
            value: salesExecutionPlan.owner,
            detail: "Keep the first demand-proof blocker with one owner until the rank baseline is real.",
          },
        ],
        recommendations: [
          "Use live ASIN mode first when possible so rank, price, and category come from the actual PDP.",
          "Do not turn a price hunch into a demand estimate without a rank anchor.",
        ],
        status: {
          label: "Demand baseline is incomplete",
          tone: "warning",
        },
        missingItems: ["Rank signal"],
        nextSteps: [
          snapshot ? "Confirm the live BSR manually." : "Load a live listing or enter the BSR.",
          "Put one owner on the first estimate blocker.",
          "Re-run the estimate once the rank baseline is explicit.",
        ],
        actionStance: {
          label: "Do not trust a demand read without a rank anchor",
          tone: "warning",
          detail: "Stop the demand read here until rank is real. A price hunch without BSR proof should not become a volume story.",
        },
      } satisfies ToolEvaluation;
    }

    return evaluateSalesEstimator({
      marketplace,
      category,
      bsr,
      sellingPrice,
      source: snapshot ? "live" : "manual",
    });
  }, [bsr, category, marketplace, sellingPrice, snapshot, salesExecutionPlan]);

  const detectedCategoryLabel = useMemo(() => {
    for (const group of calculatorCategoryOptionGroups) {
      const option = group.options.find((item) => item.value === category);
      if (option) {
        return option.label;
      }
    }
    return "Not matched yet";
  }, [category]);

  const salesAuditRows = useMemo(
    () => [
      {
        label: "Detected category",
        value: category ? detectedCategoryLabel : "Missing",
        detail: snapshot?.breadcrumbs.length
          ? snapshot.breadcrumbs.join(" / ")
          : "Load a live listing or set the category manually",
      },
      {
        label: "Live rank signal",
        value: bsr > 0 ? `#${bsr.toLocaleString("en-US")}` : "Missing",
        detail:
          snapshot?.bestSellersRank || snapshot?.subCategoryRank
            ? snapshot.bestSellersRank ?? snapshot.subCategoryRank ?? ""
            : "No visible BSR on the live page yet",
      },
      {
        label: "Visible sell price",
        value: sellingPrice > 0 ? formatUsd(roundNumber(sellingPrice)) : "Missing",
        detail: snapshot?.priceText ?? "No live price loaded yet",
      },
      {
        label: "System focus",
        value: salesScenarioPlan.primaryFocus,
        detail: `${salesScenarioPlan.cautionLevel} caution posture for this estimate`,
      },
      {
        label: "Estimate mode",
        value: snapshot ? "Live-first" : "Manual",
        detail: snapshot ? "ASIN-backed estimate using live PDP signals" : "Directional estimate using manual rank and price inputs",
      },
      {
        label: localeText(locale, "Execution call", "执行判断"),
        value: salesExecutionPlan.decision,
        detail: `${salesExecutionPlan.proofPriority} | ${salesExecutionPlan.cadence}`,
      },
    ],
    [bsr, category, detectedCategoryLabel, salesExecutionPlan, salesScenarioPlan.cautionLevel, salesScenarioPlan.primaryFocus, sellingPrice, snapshot],
  );

  const salesActionRows = useMemo(() => {
    return [
      {
        label: "First move",
        value: salesExecutionPlan.decision,
        detail: salesExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: salesExecutionPlan.owner,
        detail: `${salesExecutionPlan.cadence}. ${salesExecutionPlan.watchout}`,
      },
      {
        label: "Do not cross",
        value:
          bsr <= 0
            ? "Do not trust a demand read without a rank anchor"
            : !snapshot
              ? "Do not let manual estimate mode become the default operating mode"
              : "Do not turn one rank estimate into a full commercial thesis",
        detail:
          bsr <= 0
            ? "Without BSR, the estimate is still a narrative, not a decision tool."
            : !snapshot
              ? "Manual mode is useful for scenario testing, but paid value comes from live evidence first."
              : "Demand still needs price, margin, and competitive context before it becomes a business decision.",
      },
      {
        label: "Then do",
        value:
          decisionUse === "reorder"
            ? "Translate units into cover and reorder timing"
            : "Compare volume against price and margin",
        detail:
          decisionUse === "reorder"
            ? "For replenishment decisions, the estimate needs to become cover math, not just a demand headline."
            : "Demand without price and profit context is still only half of the commercial picture.",
      },
      {
        label: "Watch",
        value: salesExecutionPlan.proofPriority,
        detail: "A nice-looking output can still be directionally weak if the category curve or rank freshness is poor.",
      },
    ];
  }, [decisionUse, salesExecutionPlan]);

  const salesFirstScreenRows = useMemo(() => {
    const longTail = bsr > 30000;
    const hasLiveBaseline = Boolean(snapshot) && bsr > 0 && sellingPrice > 0 && category;

    return [
      {
        label: "Demand anchor",
        value:
          bsr <= 0
            ? "Rank missing"
            : longTail
              ? "Long-tail estimate"
              : "Usable rank anchor",
        detail:
          bsr <= 0
            ? "Do not let the user infer demand from price or hope. This estimate needs a real BSR first."
            : longTail
              ? "This rank sits in a noisier band, so the estimate should stay directional until you compare nearby ASINs."
              : "The rank signal is strong enough to support the first demand conversation.",
      },
      {
        label: "Scenario posture",
        value: salesScenarioPlan.primaryFocus,
        detail: `${salesScenarioPlan.cautionLevel} caution posture | ${snapshot ? "live-first mode" : "manual mode still open"}`,
      },
      {
        label: "First-screen verdict",
        value:
          !hasLiveBaseline
            ? "Load live PDP or rank first"
            : decisionUse === "reorder"
              ? "Translate demand into cover math"
              : sellingPrice <= 0
                ? "Price baseline still thin"
                : "Compare demand against margin next",
        detail:
          !hasLiveBaseline
            ? "This page should not ask the user to believe a demand story before rank, category, and price are all visible."
            : decisionUse === "reorder"
              ? "The estimate is ready to become inventory timing, not just a units headline."
              : "The next commercial move is not more estimation. It is deciding whether the visible demand survives price and unit economics.",
      },
    ];
  }, [bsr, category, decisionUse, salesScenarioPlan.cautionLevel, salesScenarioPlan.primaryFocus, sellingPrice, snapshot]);

  const salesEscalationRows = useMemo(
    () =>
      buildSalesEscalationRows({
        snapshot,
        category,
        bsr,
        sellingPrice,
        source: snapshot ? "live" : "manual",
      }),
    [bsr, category, sellingPrice, snapshot],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1.3fr_0.7fr_auto_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} placeholder="Optional: use live ASIN lookup mode" />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide estimate settings" : "Adjust estimate settings"}
          </button>
        </div>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote lines={salesAuditLines} />
      <DistributionPanel title="Live estimate inputs" rows={salesAuditRows} />
      <DistributionPanel title="First-screen operator call" rows={salesFirstScreenRows} />
      <DistributionPanel title="This estimate call" rows={salesActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">{manualOverridesHeading(locale)}</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when the live page hides BSR, price, or category, or when you want to model a different rank scenario or decision posture.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {manualOverridesToggle(locale, showOverrides)}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-2">
              <Field label="Decision use">
                <SelectInput value={decisionUse} onChange={(e) => setDecisionUse(e.target.value)}>
                  <option value="opportunity-screen">Opportunity screen</option>
                  <option value="competitor-check">Competitor validation</option>
                  <option value="reorder">Reorder scenario</option>
                </SelectInput>
              </Field>
              <Field label="Confidence need">
                <SelectInput value={confidenceNeed} onChange={(e) => setConfidenceNeed(e.target.value)}>
                  <option value="medium">Medium</option>
                  <option value="high">High</option>
                </SelectInput>
              </Field>
            </div>
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-3">
              <Field label="Product category">
                <SelectInput value={category} onChange={(e) => setCategory(e.target.value)}>
                  <option value="">Select category</option>
                  {renderOptionGroups(calculatorCategoryOptionGroups)}
                </SelectInput>
              </Field>
              <Field label="Best Sellers Rank">
                <NumberInput value={bsr} min="0" step="1" onChange={(e) => setBsr(Number(e.target.value))} />
              </Field>
              <Field label="Selling price">
                <NumberInput value={sellingPrice} min="0" step="0.01" onChange={(e) => setSellingPrice(Number(e.target.value))} />
              </Field>
            </div>
          </div>
        ) : null}
      </div>
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title="Demand verdict" rows={salesDecisionRows.verdictRows} />
        <DistributionPanel title="Estimate pressure" rows={salesDecisionRows.pressureRows} />
        <DistributionPanel title="Decision order" rows={salesDecisionRows.actionRows} />
      </div>
      <DistributionPanel title="Commercial use of estimate" rows={salesEscalationRows} />
    </RuntimeShell>
  );
}

function NegativeKeywordsRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [cleanupMode, setCleanupMode] = useState("weekly-cleanup");
  const [aggressiveness, setAggressiveness] = useState("balanced");
  const [bandwidth, setBandwidth] = useState("standard");
  const [targetAcos, setTargetAcos] = useState(0.28);
  const [targetCpa, setTargetCpa] = useState(12);
  const [reportText, setReportText] = useState(
    "search term\tspend\tclicks\torders\tsales\nmirror full length\t31.40\t23\t0\t0\narched mirror gold\t12.90\t7\t2\t97.98\nfloor mirror bedroom\t8.25\t6\t1\t48.99\nbody mirror standing\t17.50\t11\t0\t0\nfull body mirror large\t10.10\t5\t0\t0",
  );
  const [showAdvanced, setShowAdvanced] = useState(false);
  const targetAcosPrefillRef = useRef(false);
  const targetCpaPrefillRef = useRef(false);

  const parsedRows = useMemo(() => parseSearchTermReport(reportText), [reportText]);
  const inferredPlan = useMemo(
    () =>
      inferNegativeKeywordPlan({
        rows: parsedRows,
        cleanupMode,
        aggressiveness,
        bandwidth,
      }),
    [aggressiveness, bandwidth, cleanupMode, parsedRows],
  );

  useEffect(() => {
    if (targetAcosPrefillRef.current || !inferredPlan.targetAcos) {
      return;
    }
    if (targetAcos === 0.28) {
      setTargetAcos(inferredPlan.targetAcos);
    }
    targetAcosPrefillRef.current = true;
  }, [inferredPlan.targetAcos, targetAcos]);

  useEffect(() => {
    if (targetCpaPrefillRef.current || !inferredPlan.targetCpa) {
      return;
    }
    if (targetCpa === 12) {
      setTargetCpa(inferredPlan.targetCpa);
    }
    targetCpaPrefillRef.current = true;
  }, [inferredPlan.targetCpa, targetCpa]);

  const decisions = useMemo(
    () => classifySearchTerms(parsedRows, targetAcos, targetCpa),
    [parsedRows, targetAcos, targetCpa],
  );
  const negativeExecutionPlan = useMemo(() => {
    const negateCount = decisions.filter((item) => item.bucket === "negate").length;
    const isolateCount = decisions.filter((item) => item.bucket === "isolate").length;
    const keepCount = decisions.filter((item) => item.bucket === "keep").length;
    const testCount = decisions.filter((item) => item.bucket === "test").length;
    const wastedSpend = decisions
      .filter((item) => item.bucket === "negate")
      .reduce((sum, item) => sum + item.spend, 0);

    return inferNegativeKeywordExecutionPlan({
      parsedRowCount: parsedRows.length,
      negateCount,
      isolateCount,
      testCount,
      keepCount,
      wastedSpend,
      cleanupMode,
      bandwidth,
    });
  }, [bandwidth, cleanupMode, decisions, parsedRows.length]);

  const result = useMemo(() => {
    const negateCount = decisions.filter((item) => item.bucket === "negate").length;
    const isolateCount = decisions.filter((item) => item.bucket === "isolate").length;
    const keepCount = decisions.filter((item) => item.bucket === "keep").length;
    const testCount = decisions.filter((item) => item.bucket === "test").length;
    const wastedSpend = decisions
      .filter((item) => item.bucket === "negate")
      .reduce((sum, item) => sum + item.spend, 0);

    return evaluateNegativeKeywords({
      termCount: decisions.length,
      negateCount,
      isolateCount,
      keepCount,
      testCount,
      wastedSpend,
      targetAcos,
      targetCpa,
    });
  }, [decisions, targetAcos, targetCpa]);

  const negativeAuditRows = useMemo(() => {
    const negate = decisions.filter((item) => item.bucket === "negate");
    const isolate = decisions.filter((item) => item.bucket === "isolate");
    const keep = decisions.filter((item) => item.bucket === "keep");
    const test = decisions.filter((item) => item.bucket === "test");
    const wastedSpend = negate.reduce((sum, item) => sum + item.spend, 0);
    const winnerSpend = isolate.reduce((sum, item) => sum + item.spend, 0);

    return [
      {
        label: "Rows parsed",
        value: `${parsedRows.length}`,
        detail: "Search-term rows successfully read from the pasted report",
      },
      {
        label: "Negate now",
        value: `${Math.min(negate.length, inferredPlan.maxNegateNow)}`,
        detail: `${formatUsd(roundNumber(wastedSpend, 2))} spend currently sits on obvious waste candidates`,
      },
      {
        label: "Isolate next",
        value: `${Math.min(isolate.length, inferredPlan.maxIsolateNow)}`,
        detail: `${formatUsd(roundNumber(winnerSpend, 2))} spend sits on proven terms worth splitting out`,
      },
      {
        label: "Watchlist load",
        value: `${test.length}`,
        detail: `${keep.length} keep terms remain healthy while ${test.length} still need evidence`,
      },
      {
        label: "System guardrails",
        value: `${roundNumber(targetAcos * 100, 1)}% / ${formatUsd(roundNumber(targetCpa, 2))}`,
        detail: `${cleanupMode.replace(/-/g, " ")} mode with ${aggressiveness} rules and ${bandwidth} bandwidth`,
      },
      {
        label: "Execution call",
        value: negativeExecutionPlan.decision,
        detail: `${negativeExecutionPlan.proofPriority} | ${negativeExecutionPlan.cadence}`,
      },
    ];
  }, [aggressiveness, bandwidth, cleanupMode, decisions, inferredPlan.maxIsolateNow, inferredPlan.maxNegateNow, negativeExecutionPlan, parsedRows.length, targetAcos, targetCpa]);

  const negativeActionRows = useMemo(() => {
    const negateCount = decisions.filter((item) => item.bucket === "negate").length;
    const isolateCount = decisions.filter((item) => item.bucket === "isolate").length;
    const testCount = decisions.filter((item) => item.bucket === "test").length;
    const keepCount = decisions.filter((item) => item.bucket === "keep").length;
    const negate = decisions
      .filter((item) => item.bucket === "negate")
      .sort((a, b) => b.spend - a.spend)
      .slice(0, inferredPlan.maxNegateNow)
      .map((item) => ({
        label: item.term,
        value: "Negate now",
        detail: `${formatUsd(roundNumber(item.spend, 2))} spend | ${item.clicks} clicks | ${item.orders} orders`,
      }));
    const isolate = decisions
      .filter((item) => item.bucket === "isolate")
      .sort((a, b) => b.sales - a.sales)
      .slice(0, inferredPlan.maxIsolateNow)
      .map((item) => ({
        label: item.term,
        value: "Isolate next",
        detail: `${formatUsd(roundNumber(item.sales, 2))} sales | ${item.orders} orders | ${(item.acos * 100).toFixed(1)}% ACoS`,
      }));
    const watch = decisions
      .filter((item) => item.bucket === "test")
      .sort((a, b) => b.spend - a.spend)
      .slice(0, 2)
      .map((item) => ({
        label: item.term,
        value: "Watch",
        detail: `${formatUsd(roundNumber(item.spend, 2))} spend is still gathering enough evidence`,
      }));

    const firstMove =
      negateCount > 0
        ? {
            label: "First move",
            value: "Cut the waste before scaling anything",
            detail: "The account is still bleeding on clearly bad terms, so expansion work is secondary until the leak is closed.",
          }
        : isolateCount > 0
          ? {
              label: "First move",
              value: "Split proven search terms into their own control lanes",
              detail: "Winner terms deserve cleaner bidding and budget control instead of staying mixed into discovery traffic.",
            }
          : testCount > keepCount
            ? {
                label: "First move",
                value: "Reduce the observation backlog",
                detail: "Too many uncertain terms are still consuming spend without a clear next decision.",
              }
            : {
                label: "First move",
                value: "Protect the healthy terms and keep the report clean",
                detail: "The current search-term mix is stable enough that the main job is disciplined maintenance rather than rescue.",
              };

    return [
      {
        label: "First move",
        value: negativeExecutionPlan.decision,
        detail: negativeExecutionPlan.nextMove,
      },
      {
        label: "Sprint brief",
        value: negativeExecutionPlan.proofPriority,
        detail: inferredPlan.cleanupFocus,
      },
      {
        label: "Execution owner",
        value: negativeExecutionPlan.owner,
        detail: `${negativeExecutionPlan.cadence}. ${negativeExecutionPlan.watchout}`,
      },
      {
        label: "Do not cross",
        value:
          negateCount > 0
            ? "Do not scale before cutting the obvious waste"
            : isolateCount > 0
              ? "Do not leave proven winners buried in discovery traffic"
              : "Do not keep a bloated observation backlog alive forever",
        detail:
          negateCount > 0
            ? "Expansion work is lower value while clearly bad terms are still leaking spend."
            : isolateCount > 0
              ? "Winner terms deserve their own control lane before more cleanup theory."
              : "Terms that never graduate into keep, isolate, or negate are just clutter with spend attached.",
      },
      {
        label: "Then do",
        value:
          negateCount > 0
            ? "Re-check waste after the first cleanup pass"
            : isolateCount > 0
              ? "Split the winners, then tighten negatives again"
              : "Refresh the report before making another threshold change",
        detail: "The sequence matters more than making every PPC cleanup move at once.",
      },
      ...negate,
      ...isolate,
      ...watch,
      {
        label: "Watch",
        value: negativeExecutionPlan.proofPriority,
        detail: negativeExecutionPlan.watchout,
      },
    ];
  }, [decisions, inferredPlan.cleanupFocus, inferredPlan.maxIsolateNow, inferredPlan.maxNegateNow, negativeExecutionPlan]);

  const auditLines = useMemo(() => {
    if (!parsedRows.length) {
      return ["Paste a recent search-term report first. Keep PPC cleanup closed until real search-term evidence is loaded."];
    }

    return [
      `Cleanup mode: ${cleanupMode.replace(/-/g, " ")}. ${inferredPlan.cleanupFocus}`,
      `System draft guardrails: ${roundNumber(inferredPlan.targetAcos * 100, 1)}% target ACoS and ${formatUsd(roundNumber(inferredPlan.targetCpa, 2))} target CPA.`,
      "Use manual guardrail overrides only when account truth differs from the report read. The default operating mode should be report-first, not threshold-first.",
    ];
  }, [cleanupMode, inferredPlan.cleanupFocus, inferredPlan.targetAcos, inferredPlan.targetCpa, parsedRows.length]);

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1.15fr_0.75fr_0.75fr_0.75fr_auto]">
        <Field label="Search term report paste">
          <TextAreaInput
            value={reportText}
            onChange={(e) => setReportText(e.target.value)}
            spellCheck={false}
          />
        </Field>
        <Field label="Cleanup mode">
          <SelectInput value={cleanupMode} onChange={(e) => setCleanupMode(e.target.value)}>
            <option value="weekly-cleanup">Weekly cleanup</option>
            <option value="stop-loss">Stop-loss</option>
            <option value="harvest-winners">Harvest winners</option>
          </SelectInput>
        </Field>
        <Field label="Aggressiveness">
          <SelectInput value={aggressiveness} onChange={(e) => setAggressiveness(e.target.value)}>
            <option value="strict">Strict</option>
            <option value="balanced">Balanced</option>
            <option value="lenient">Lenient</option>
          </SelectInput>
        </Field>
        <Field label="Team bandwidth">
          <SelectInput value={bandwidth} onChange={(e) => setBandwidth(e.target.value)}>
            <option value="tight">Tight</option>
            <option value="standard">Standard</option>
            <option value="full">Full sprint</option>
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowAdvanced((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showAdvanced ? "Hide guardrails" : "Adjust guardrails"}
          </button>
        </div>
      </div>
      {showAdvanced ? (
        <div className="grid gap-2.5 md:grid-cols-2">
          <Field label="Target ACoS">
            <NumberInput value={targetAcos} min="0" max="1" step="0.01" onChange={(e) => setTargetAcos(Number(e.target.value))} />
          </Field>
          <Field label="Target CPA">
            <NumberInput value={targetCpa} min="0" step="0.01" onChange={(e) => setTargetCpa(Number(e.target.value))} />
          </Field>
        </div>
      ) : null}
      <AuditNote lines={auditLines} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-3 text-sm text-slate-700">
        Parsed {parsedRows.length} rows. Paste TSV or CSV with columns for search term, spend, clicks, orders, and sales.
      </div>
      <DistributionPanel title="Cleanup brief" rows={negativeAuditRows} />
      <DistributionPanel title="This pass" rows={negativeActionRows} />
      <SearchTermDecisionPanel decisions={decisions} />
    </RuntimeShell>
  );
}

function CompetitorAnalysisRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [ownAsinOrUrl, setOwnAsinOrUrl] = useState("");
  const [competitorInputs, setCompetitorInputs] = useState("");
  const [ownSnapshot, setOwnSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [competitorSnapshots, setCompetitorSnapshots] = useState<AmazonListingSnapshot[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  async function loadComparison() {
    try {
      if (!ownAsinOrUrl.trim()) {
        setError("Load your own ASIN or Amazon URL first.");
        setOwnSnapshot(null);
        setCompetitorSnapshots([]);
        return;
      }

      const candidates = splitAsinCandidates(competitorInputs).slice(0, 3);
      if (candidates.length === 0) {
        setError("Add at least one competitor ASIN or Amazon URL.");
        setCompetitorSnapshots([]);
        return;
      }

      setLoading(true);
      setError("");
      const ownResponse = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(ownAsinOrUrl)}`,
      );
      const ownPayload = (await ownResponse.json()) as AmazonListingSnapshot | { error: string };
      if (!ownResponse.ok || "error" in ownPayload) {
        throw new Error("error" in ownPayload ? ownPayload.error : "Failed to load own listing.");
      }

      const loadedCompetitors: AmazonListingSnapshot[] = [];
      for (const candidate of candidates) {
        const response = await fetch(
          `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(candidate)}`,
        );
        const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
        if (response.ok && !("error" in payload)) {
          loadedCompetitors.push(payload);
        }
      }

      setOwnSnapshot(ownPayload);
      setCompetitorSnapshots(loadedCompetitors);
    } catch (fetchError) {
      setOwnSnapshot(null);
      setCompetitorSnapshots([]);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load comparison set.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(() => {
    if (!ownSnapshot || competitorSnapshots.length === 0) {
      const baselineDecision = !ownSnapshot ? "Load your PDP before judging the market" : "Lock the rival set before naming a gap";
      const baselineOwner = !ownSnapshot ? "PDP owner" : "Competitive intel lead";
      return {
        headline: "Competitive read is blocked until your home PDP is real",
        summary:
          "No gap call should leave this page until your own PDP and the rival set are both anchored.",
        metrics: [
          {
            label: "Own PDP",
            value: ownSnapshot?.asin || "Missing",
            detail: ownSnapshot?.priceText || "Load your live ASIN first.",
          },
          {
            label: "Competitor set",
            value: `${competitorSnapshots.length}`,
            detail: competitorSnapshots.length ? "Loaded competitor pages are waiting on your own PDP baseline." : "No live competitor set loaded yet.",
          },
          {
            label: "First move",
            value: baselineDecision,
            detail: !ownSnapshot
              ? "Anchor the comparison to the live home listing before calling any market gap real."
              : "Freeze one competitor set before naming any market gap the main problem.",
          },
          {
            label: "Execution owner",
            value: baselineOwner,
            detail: "The first competitive read should belong to one operator, not a vague team.",
          },
        ],
        recommendations: [
          "Do not call any market gap real until your own PDP baseline is loaded.",
          competitorSnapshots.length === 0
            ? "Load at least one direct competitor so this becomes a live commercial comparison."
            : "Freeze one competitor set and stop changing the benchmark mid-read.",
        ],
        status: {
          label: "Competitive baseline is incomplete",
          tone: "warning" as const,
        },
        missingItems: [
          !ownSnapshot ? "Own live PDP baseline" : "",
          competitorSnapshots.length === 0 ? "Competitor live PDP set" : "",
        ].filter(Boolean),
        nextSteps: [
          baselineDecision,
          "Lock one comparison set before naming any gap category the main problem.",
          "Re-run after your own PDP and competitor set are both live.",
        ],
        actionStance: {
          label: "Do not chase competitor gaps before your own baseline is real",
          tone: "warning" as const,
          detail:
            "Anchor your own PDP first. Until that baseline is real, every competitor gap risks sending the team after the wrong repair lane.",
        },
        riskItems: [
          !ownSnapshot
            ? "Without your own live PDP baseline, the team will overreact to competitor surfaces that may not be your real blocker."
            : "Without a frozen rival set, every comparison turns into opinion and the first repair lane stays blurry.",
        ],
      } satisfies ToolEvaluation;
    }
    if (!isCustomSnapshotDecisionGrade(ownSnapshot, ["title", "price", "reviewCount", "images"])) {
      return {
        headline: "Competitive read needs a stronger own-page baseline",
        summary:
          "The listing is loaded, but the current own-page evidence is still too thin to let the market comparison drive the next move.",
        metrics: [
          {
            label: "Current result",
            value: "Own PDP evidence is thin",
            detail: "Title, price, review proof, and image coverage need to be strong enough before market gaps become actionable.",
          },
          {
            label: "Execution call",
            value: competitorExecutionPlan.comparisonDecision,
            detail: `${competitorExecutionPlan.owner} | ${competitorExecutionPlan.executionCadence} | ${competitorExecutionPlan.proofPriority}`,
          },
          {
            label: "First move",
            value: "Repair the own PDP baseline first",
            detail: "Make the own listing read decision-grade before letting competitor deltas dictate where the team moves next.",
          },
          {
            label: "Execution owner",
            value: competitorExecutionPlan.owner,
            detail: "Tighten the own-page evidence under one owner before the comparison set starts steering decisions.",
          },
          {
            label: "Do not cross",
            value: "Do not compare the market from a weak own-page read",
            detail: "If your own baseline is blurry, every competitor delta looks more important than it really is.",
          },
        ],
        recommendations: [
          "Reload the own ASIN until title, price, review proof, and image coverage are all visible.",
          "Keep the competitor set frozen while you repair the home baseline.",
        ],
        status: {
          label: "Own competitive baseline needs review",
          tone: "warning" as const,
        },
        missingItems: ["Stronger own PDP evidence"],
        nextSteps: [
          "Reload the own PDP baseline.",
          "Confirm the first losing surface on your own page.",
          "Then re-run the competitor comparison against the same market set.",
        ],
        actionStance: {
          label: "Do not let blurry own evidence create fake market urgency",
          tone: "warning" as const,
          detail: "Blurry own-page evidence makes every rival delta look bigger than it is. Repair your baseline before the market set starts steering the team.",
        },
      } satisfies ToolEvaluation;
    }
    if (
      getMultiSnapshotEvidenceStatus(
        competitorSnapshots,
        ["title", "price", "reviewCount", "images"],
      ).level === "weak"
    ) {
      return {
        headline: "Competitive read needs a cleaner rival set",
        summary:
          "The rival pack is loaded, but too much of the visible market proof is missing. Keep this comparison open only until the benchmark set gets cleaner.",
        metrics: [
          {
            label: "Current result",
            value: `${competitorSnapshots.length} competitors loaded`,
            detail: "The market pack exists, but the loaded rivals do not yet carry enough visible price, review, and image proof.",
          },
          {
            label: "Execution call",
            value: competitorExecutionPlan.comparisonDecision,
            detail: `${competitorExecutionPlan.owner} | ${competitorExecutionPlan.executionCadence} | ${competitorExecutionPlan.proofPriority}`,
          },
          {
            label: "First move",
            value: "Replace weak competitor references",
            detail: "Use direct substitutes with cleaner price, review, and image evidence before naming one competitive gap the main blocker.",
          },
          {
            label: "Execution owner",
            value: competitorExecutionPlan.owner,
            detail: "Repair benchmark quality under one owner before the team starts copying market surfaces.",
          },
          {
            label: "Do not cross",
            value: "Do not name a market loser from a weak rival set",
            detail: "Noisy benchmarks can make normal assortment differences look like urgent commercial failures.",
          },
        ],
        recommendations: [
          "Swap in direct competitors with visible price, review count, and gallery depth.",
          "Keep the current gap map open only until the benchmark set is stronger.",
        ],
        status: {
          label: "Competitor evidence needs rebuild",
          tone: "warning" as const,
        },
        missingItems: ["Stronger competitor evidence"],
        nextSteps: [
          "Replace weak competitor ASINs.",
          "Re-run the competitive read.",
          "Only then choose one gap to attack first.",
        ],
        actionStance: {
          label: "Do not let a noisy benchmark trigger a broad rewrite",
          tone: "warning" as const,
          detail: "Benchmark quality decides whether this page saves time or wastes it. Keep the rival set clean before opening more work.",
        },
      } satisfies ToolEvaluation;
    }

    const ownPrice = parseCurrencyAmount(ownSnapshot.priceText);
    const ownReviews = parseReviewCountValue(ownSnapshot.reviewCountText);
    const ownImages = ownSnapshot.imageUrls.length;
    const ownRating = parseRatingValue(ownSnapshot.ratingText);
    const ownCurrentRank =
      parseRankValue(ownSnapshot.bestSellersRank) || parseRankValue(ownSnapshot.subCategoryRank);
    const competitorPrices = competitorSnapshots.map((item) => parseCurrencyAmount(item.priceText));
    const competitorReviews = competitorSnapshots.map((item) => parseReviewCountValue(item.reviewCountText));
    const competitorImages = competitorSnapshots.map((item) => item.imageUrls.length);
    const competitorRatings = competitorSnapshots.map((item) => parseRatingValue(item.ratingText));
    const competitorRanks = competitorSnapshots
      .map((item) => parseRankValue(item.bestSellersRank) || parseRankValue(item.subCategoryRank))
      .filter((value) => value > 0);

    return evaluateCompetitorAnalysis({
      ownPrice,
      ownReviewCount: ownReviews,
      ownImageCount: ownImages,
      ownHasAPlus: ownSnapshot.hasAPlus,
      ownRating,
      competitorCount: competitorSnapshots.length,
      averageCompetitorPrice:
        competitorPrices.reduce((sum, value) => sum + value, 0) / competitorPrices.length,
      averageCompetitorReviewCount:
        competitorReviews.reduce((sum, value) => sum + value, 0) / competitorReviews.length,
      averageCompetitorImageCount:
        competitorImages.reduce((sum, value) => sum + value, 0) / competitorImages.length,
      competitorsWithAPlus: competitorSnapshots.filter((item) => item.hasAPlus).length,
      cheaperCompetitors: competitorPrices.filter((value) => value > 0 && value < ownPrice).length,
      strongerReviewCompetitors: competitorReviews.filter((value) => value > ownReviews).length,
      richerImageCompetitors: competitorImages.filter((value) => value > ownImages).length,
      higherRatedCompetitors: competitorRatings.filter((value) => value > ownRating).length,
      ownCurrentRank,
      averageCompetitorRank: competitorRanks.length
        ? competitorRanks.reduce((sum, value) => sum + value, 0) / competitorRanks.length
        : 0,
      bestCompetitorRank: competitorRanks.length ? Math.min(...competitorRanks) : 0,
    });
  }, [competitorSnapshots, ownSnapshot]);

  const competitorDecisionRows = useMemo(
    () => buildCompetitorGapRows({ ownSnapshot, competitorSnapshots }),
    [competitorSnapshots, ownSnapshot],
  );
  const competitorExecutionPlan = useMemo(() => {
    const ownPrice = parseCurrencyAmount(ownSnapshot?.priceText);
    const ownReviews = parseReviewCountValue(ownSnapshot?.reviewCountText);
    const ownImages = ownSnapshot?.imageUrls.length ?? 0;
    const cheaperCompetitors = competitorSnapshots.filter((item) => {
      const price = parseCurrencyAmount(item.priceText);
      return price > 0 && ownPrice > 0 && price < ownPrice;
    }).length;
    const strongerProofCompetitors = competitorSnapshots.filter(
      (item) => parseReviewCountValue(item.reviewCountText) > ownReviews,
    ).length;
    const richerCreativeCompetitors = competitorSnapshots.filter(
      (item) => item.imageUrls.length > ownImages,
    ).length;

    return inferCompetitorExecutionPlan({
      hasOwnSnapshot: Boolean(ownSnapshot),
      competitorCount: competitorSnapshots.length,
      cheaperCompetitors,
      strongerProofCompetitors,
      richerCreativeCompetitors,
    });
  }, [competitorSnapshots, ownSnapshot]);

  const competitorAuditLines = useMemo(() => {
    const lines = [];
    if (ownSnapshot) {
      const ownEvidence = getCustomSnapshotEvidenceStatus(ownSnapshot, [
        "title",
        "price",
        "reviewCount",
        "images",
      ]);
      lines.push(`Own listing evidence: ${ownEvidence.label}. ${ownEvidence.detail}`);
    }
    if (competitorSnapshots.length) {
      const competitorEvidence = getMultiSnapshotEvidenceStatus(competitorSnapshots, [
        "title",
        "price",
        "reviewCount",
        "images",
      ]);
      lines.push(`Competitor set quality: ${competitorEvidence.label}. ${competitorEvidence.detail}`);
      if (competitorEvidence.level !== "complete") {
        lines.push("Keep this comparison open only until the rival set has stronger live coverage.");
      }
    } else {
      lines.push("Load your ASIN plus at least one competitor ASIN or URL to get a real comparison.");
    }
    lines.push("Price, review, image, rating, and A+ gaps should come from the loaded listings, not from manual guesswork.");
    return lines;
  }, [competitorSnapshots, ownSnapshot]);

  const competitorAuditRows = useMemo(
    () => [
      {
        label: "Own PDP",
        value: ownSnapshot?.asin || "Missing",
        detail: ownSnapshot?.priceText || "Load your live listing first",
      },
      {
        label: "Competitor set",
        value: `${competitorSnapshots.length}`,
        detail: competitorSnapshots.length ? "Loaded from live competitor PDPs" : "No live competitor set yet",
      },
      {
        label: "Price layer",
        value:
          competitorSnapshots.length > 0
            ? `${competitorSnapshots.filter((item) => parseCurrencyAmount(item.priceText) > 0).length}/${competitorSnapshots.length}`
            : "0/0",
        detail: "Competitors with visible price data in the current comparison set",
      },
      {
        label: "Proof layer",
        value:
          competitorSnapshots.length > 0
            ? `${competitorSnapshots.filter((item) => parseReviewCountValue(item.reviewCountText) > 0).length}/${competitorSnapshots.length}`
            : "0/0",
        detail: "Competitors with visible review-count evidence in the current comparison set",
      },
      {
        label: "Execution call",
        value: competitorExecutionPlan.comparisonDecision,
        detail: `${competitorExecutionPlan.proofPriority} | ${competitorExecutionPlan.executionCadence}`,
      },
    ],
    [competitorExecutionPlan, competitorSnapshots, ownSnapshot],
  );

  const competitorActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: competitorExecutionPlan.comparisonDecision,
        detail: `${competitorExecutionPlan.nextMove} Freeze every non-primary surface until this first competitive gap is either repaired or disproven.`,
      },
      {
        label: "Execution owner",
        value: competitorExecutionPlan.owner,
        detail: `Put ${competitorExecutionPlan.proofPriority.toLowerCase()} under one operator who closes the next gap before any other team reopens the rest of the PDP.`,
      },
      {
        label: "Do not cross",
        value: !ownSnapshot
          ? "Do not compare the market before anchoring your own PDP"
          : competitorSnapshots.length === 0
            ? "Do not name a competitive gap from an empty rival set"
            : "Do not reopen every surface at once",
        detail: !ownSnapshot
          ? "A competitor read without your own live offer baseline turns into people discussing everyone else instead of fixing your own commercial problem."
          : competitorSnapshots.length === 0
            ? "A single-sided comparison is not market intelligence. It is just anxiety with better formatting."
            : "Pick the first gap that actually moves the lane. Broad rewrites spread the effort and hide the real blocker.",
      },
      {
        label: "Then do",
        value: competitorExecutionPlan.executionCadence,
        detail: "Hold every non-primary surface steady until the first competitive repair either moves conversion or clearly fails.",
      },
      {
        label: "Watch",
        value: competitorExecutionPlan.proofPriority,
        detail: `${competitorExecutionPlan.watchout} Reopen the comparison only if the same rival set still proves the same gap after the first repair ships.`,
      },
    ],
    [competitorExecutionPlan, competitorSnapshots.length, ownSnapshot],
  );

  const competitorInputRows = useMemo(
    () => [
      ...competitorAuditRows,
      {
        label: "Decision owner",
        value: competitorActionRows[1]?.value ?? "Competitive intel lead pending",
        detail: competitorActionRows[1]?.value
          ? `${competitorActionRows[1].value} owns the first competitive gap until the same rival set is rechecked.`
          : "Assign one owner before the comparison turns into an unfocused gap list.",
      },
    ],
    [competitorActionRows, competitorAuditRows],
  );

  const competitorFocusRows = useMemo(
    () =>
      buildCompetitorFocusRows({
        ownSnapshot,
        competitorSnapshots,
      }),
    [competitorSnapshots, ownSnapshot],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_1fr_0.7fr_auto]">
        <Field label="Your ASIN or Amazon product URL">
          <TextInput
            value={ownAsinOrUrl}
            onChange={(e) => setOwnAsinOrUrl(e.target.value)}
            placeholder="Paste your ASIN or Amazon URL"
            spellCheck={false}
          />
        </Field>
        <Field label="Competitor ASINs or URLs">
          <TextAreaInput
            value={competitorInputs}
            onChange={(e) => setCompetitorInputs(e.target.value)}
            placeholder={"One competitor ASIN or URL per line"}
            className={undefined}
            spellCheck={false}
          />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadComparison} disabled={loading}>
            {runtimeActionButtonLabel(locale, loading, "Load comparison and generate result", "加载对比并生成结果")}
          </ActionButton>
        </div>
      </div>
      <AuditNote lines={competitorAuditLines} />
      <SnapshotPanel snapshot={ownSnapshot} error={error} loading={loading} />
      <div className="rounded-xl border border-teal-200 bg-teal-50 px-3 py-3 text-sm text-teal-950">
        {runtimeResultHint(locale)}
      </div>
      <DistributionPanel title={runtimeResultTitle(locale)} rows={competitorInputRows} />
      <DistributionPanel title={runtimeActionPlanTitle(locale)} rows={competitorActionRows} />
      <CompetitorBoard own={ownSnapshot} competitors={competitorSnapshots} />
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title={localeText(locale, "Result details", "结果细分")} rows={competitorDecisionRows.verdictRows} />
        <DistributionPanel title="Pressure map" rows={competitorDecisionRows.gapRows} />
        <DistributionPanel title="Execution steps" rows={competitorDecisionRows.actionRows} />
      </div>
      <DistributionPanel title="Hold / open / benchmark" rows={competitorFocusRows} />
    </RuntimeShell>
  );
}

function ReviewAnalyzerRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [reviewObjective, setReviewObjective] = useState("reduce-returns");
  const [executionLane, setExecutionLane] = useState("listing-fix");
  const [responseUrgency, setResponseUrgency] = useState("this-week");
  const [reviewText, setReviewText] = useState(
    "rating\treview\n5\tBeautiful mirror and very easy to set up. Looks modern in the bedroom.\n2\tArrived with a cracked corner and the packaging felt weak.\n4\tGreat value for the size, but the mounting instructions could be clearer.\n3\tThe color is nice but it feels a bit flimsy for the price.\n5\tSturdy, stylish, and perfect for our dressing room.",
  );
  const [confirmedAt, setConfirmedAt] = useState(0);

  const rows = useMemo(() => parseReviewRows(reviewText), [reviewText]);
  const analysis = useMemo(() => analyzeReviewThemes(rows), [rows]);
  const result = useMemo(
    () =>
      evaluateReviewAnalyzer({
        reviewCount: rows.length,
        averageRating: analysis.averageRating,
        negativeShare: analysis.negativeShare,
        complaintThemeCount: analysis.complaintThemes.length,
        praiseThemeCount: analysis.praiseThemes.length,
        featureOpportunityCount: analysis.opportunityThemes.length,
        topComplaintTheme: analysis.complaintThemes[0]?.label ?? "",
        topPraiseTheme: analysis.praiseThemes[0]?.label ?? "",
      }),
    [analysis, rows.length],
  );
  const reviewExecutionPlan = useMemo(
    () =>
      inferReviewExecutionDecisionPlan({
        reviewCount: rows.length,
        topComplaintLabel: analysis.complaintThemes[0]?.label ?? "",
        complaintCount: analysis.complaintThemes[0]?.count ?? 0,
        topPraiseLabel: analysis.praiseThemes[0]?.label ?? "",
        hasOpportunity: Boolean(analysis.opportunityThemes.length),
        reviewObjective,
        executionLane,
        responseUrgency,
      }),
    [analysis.complaintThemes, analysis.opportunityThemes.length, analysis.praiseThemes, executionLane, responseUrgency, reviewObjective, rows.length],
  );

  const reviewAuditRows = useMemo(
    () => [
      {
        label: "Reviews parsed",
        value: `${rows.length}`,
        detail: "Current sample size behind the theme read",
      },
      {
        label: "Average rating",
        value: analysis.averageRating > 0 ? roundNumber(analysis.averageRating, 2).toString() : "Missing",
        detail: `${roundNumber(analysis.negativeShare * 100, 1)}% negative-share in the current sample`,
      },
      {
        label: "Complaint focus",
        value: analysis.complaintThemes[0]?.label ?? "No dominant complaint yet",
        detail: analysis.complaintThemes[0]
          ? `${analysis.complaintThemes[0].count} mentions in the current sample`
          : "Do not launch a fix sprint until one complaint theme is clearly heavier than the rest.",
      },
      {
        label: "Praise anchor",
        value: analysis.praiseThemes[0]?.label ?? "No dominant praise yet",
        detail: analysis.praiseThemes[0] ? `${analysis.praiseThemes[0].count} mentions in the current sample` : "No clear praise anchor in this sample yet",
      },
      {
        label: "Execution brief",
        value: `${reviewObjective.replace(/-/g, " ")} / ${executionLane.replace(/-/g, " ")}`,
        detail: `${responseUrgency.replace(/-/g, " ")} response window for this pass`,
      },
      {
        label: "Execution call",
        value: reviewExecutionPlan.responseDecision,
        detail: `${reviewExecutionPlan.proofPriority} | ${reviewExecutionPlan.responseCadence}`,
      },
    ],
    [analysis, executionLane, responseUrgency, reviewExecutionPlan, reviewObjective, rows.length],
  );

  const reviewActionRows = useMemo(() => {
    const complaint = analysis.complaintThemes[0];
    const praise = analysis.praiseThemes[0];
    const opportunity = analysis.opportunityThemes[0];

    const firstMove =
      complaint
        ? {
            label: "First move",
            value: reviewExecutionPlan.responseDecision,
            detail: `${reviewExecutionPlan.nextMove} Current dominant complaint: ${complaint.label} (${complaint.count} mentions).`,
          }
        : {
            label: "First move",
            value: reviewExecutionPlan.responseDecision,
            detail: `${reviewExecutionPlan.nextMove} The sample is still too thin to justify broad repair work.`,
          };

    const preserveMove =
      praise
        ? {
            label: "Preserve",
            value: praise.label,
            detail: `Keep this praise theme visible in copy and creatives so the fix work does not erase what already converts. Mentions: ${praise.count}.`,
          }
        : {
            label: "Preserve",
            value: "No dominant praise theme",
            detail: "There is no clear customer-loved anchor yet in the current sample.",
          };

    const nextMove =
      opportunity
        ? {
            label: "Then do",
            value: opportunity.label,
            detail: `Turn this gap into listing, packaging, or product-improvement work after the main complaint is addressed. Mentions: ${opportunity.count}.`,
          }
        : {
            label: "Then do",
            value: "Tighten expectation match",
            detail: "If no opportunity theme dominates, use the next pass to reduce expectation mismatch in copy and assets.",
          };

    const objectiveBrief =
      reviewObjective === "reduce-returns"
        ? "Prioritize the complaint most likely to create refunds, replacements, or inbound damage."
        : reviewObjective === "protect-conversion"
          ? "Prioritize the complaint most likely to block clicks from converting on the PDP."
          : "Prioritize the complaint most likely to distort customer expectation before purchase.";

    const laneBrief =
      executionLane === "listing-fix"
        ? "Keep the response inside title, bullets, images, A+, and expectation-setting assets unless the sample clearly proves a product fault."
        : executionLane === "product-fix"
          ? "Treat this as a product or supply problem first; do not hide it behind copy edits."
          : "Use a mixed lane only when the complaint clearly spans both the product and the listing.";

    return [
      firstMove,
      {
        label: "Response brief",
        value: reviewExecutionPlan.proofPriority,
        detail: `${objectiveBrief} ${laneBrief}`,
      },
      {
        label: "Execution owner",
        value: reviewExecutionPlan.owner,
        detail: `${reviewExecutionPlan.responseCadence}. One owner carries the first complaint fix all the way to the next review read. ${reviewExecutionPlan.watchout}`,
      },
      {
        label: "Do not cross",
        value:
          executionLane === "product-fix"
            ? "Do not hide product faults behind copy edits"
            : executionLane === "listing-fix"
              ? "Do not reopen the whole PDP before the main complaint is isolated"
              : "Do not split ownership before the main complaint is isolated",
        detail:
          executionLane === "product-fix"
            ? "If the sample points to a real product or QA problem, cleaner merchandising will only bury the defect for a shorter time."
            : executionLane === "listing-fix"
              ? "One dominant complaint should drive one focused fix first, otherwise the team rewrites everything and learns nothing."
              : "Mixed-lane work should start only after one complaint cluster clearly proves that both product and listing are contributing.",
      },
      preserveMove,
      {
        label: "Then do",
        value: complaint ? "Protect the current strength while the fix lands" : reviewExecutionPlan.responseCadence,
        detail: complaint
          ? `${nextMove.detail} Keep every second fix lane closed until the first complaint either softens or proves stubborn.`
          : "Keep the same review sample in watch mode until one complaint cluster is clearly heavier than the rest.",
      },
      {
        label: "Watch",
        value: complaint ? `${complaint.label} complaint drift` : "Complaint concentration",
        detail: complaint
          ? `Re-run once the first fix is live and confirm whether ${complaint.label} is still the dominant complaint before opening a second fix lane.`
          : "If no complaint cluster dominates yet, extend the same review sample before expanding the fix scope.",
      },
    ];
  }, [analysis, reviewExecutionPlan, executionLane, reviewObjective]);

  const auditLines = useMemo(() => {
    if (!rows.length) {
      return ["Paste review rows first. Do not assign a customer problem until real review evidence is loaded."];
    }

    const topComplaint = analysis.complaintThemes[0];
    const topPraise = analysis.praiseThemes[0];

    return [
      `Review objective: ${reviewObjective.replace(/-/g, " ")} with ${responseUrgency.replace(/-/g, " ")} urgency.`,
      topComplaint
        ? `Primary complaint signal: ${topComplaint.label} (${topComplaint.count} mentions).`
        : "No stable complaint theme yet. Do not assign a fix owner or launch a broad rewrite from this sample.",
      topPraise
        ? `Protect this strength while fixing the complaint: ${topPraise.label} (${topPraise.count} mentions).`
        : "No strong praise anchor yet, so do not invent a new promise just to make the page sound cleaner.",
    ];
  }, [analysis.complaintThemes, analysis.praiseThemes, responseUrgency, reviewObjective, rows.length]);

  const customerVoiceRows = useMemo(() => {
    const rows: Array<{ label: string; value: string; detail: string }> = [];
    const topComplaint = analysis.complaintThemes[0];
    const topPraise = analysis.praiseThemes[0];
    const topOpportunity = analysis.opportunityThemes[0];

    if (topComplaint?.examples[0]) {
      rows.push({
        label: "Loudest complaint",
        value: topComplaint.label,
        detail: topComplaint.examples[0],
      });
    }
    if (topPraise?.examples[0]) {
      rows.push({
        label: "Keep this strength",
        value: topPraise.label,
        detail: topPraise.examples[0],
      });
    }
    if (topOpportunity?.examples[0]) {
      rows.push({
        label: "Hidden opportunity",
        value: topOpportunity.label,
        detail: topOpportunity.examples[0],
      });
    }

    return rows;
  }, [analysis]);

  const reviewResultRows = useMemo(() => {
    const topComplaint = analysis.complaintThemes[0];
    const complaintThemeCount = analysis.complaintThemes.length;
    const isThinSample = rows.length < 8;
    const currentResult =
      topComplaint && analysis.negativeShare >= 0.35
        ? localeText(locale, "Fix-first", "先修问题")
        : topComplaint
          ? localeText(locale, "Controlled repair", "受控修复")
          : localeText(locale, "Watch mode", "观察模式");
    const reviewStatus = topComplaint
      ? isThinSample
        ? localeText(locale, "Directional sample", "方向性样本")
        : localeText(locale, "Decision-grade complaint read", "可拍板投诉判断")
      : localeText(locale, "No stable complaint yet", "还没有稳定投诉主题");

    return [
      {
        label: "Current result",
        value: `${Math.max(0, Math.round(100 - analysis.negativeShare * 100 - Math.max(0, complaintThemeCount - analysis.praiseThemes.length) * 6))}/100`,
        detail: topComplaint
          ? `${currentResult} | ${complaintThemeCount} recurring complaint themes; 0 messaging gaps to address`
          : localeText(locale, "No dominant complaint theme is strong enough yet.", "当前还没有足够强的主投诉主题。"),
      },
      {
        label: "Review status",
        value: reviewStatus,
        detail: topComplaint
          ? `${topComplaint.label} is the complaint lane to isolate first.`
          : localeText(locale, "Extend the same review batch before opening more fix lanes.", "先扩大同一批评论样本，再决定是否开更多修复线。"),
      },
      {
        label: "Protected assist",
        value: localeText(locale, "Available after deterministic review", "确定性结果后可用"),
        detail: localeText(
          locale,
          "Only use the short assist after the first complaint owner and first move are already clear.",
          "只有在第一负责人和第一步动作已经明确后，才使用短增强。",
        ),
      },
    ];
  }, [analysis.complaintThemes, analysis.negativeShare, analysis.praiseThemes.length, locale, rows.length]);

  function confirmReviewAnalysis() {
    setConfirmedAt(Date.now());
    if (typeof window !== "undefined") {
      window.requestAnimationFrame(() => {
        document
          .getElementById("runtime-result-panel")
          ?.scrollIntoView({ behavior: "smooth", block: "start" });
      });
    }
  }

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1.15fr_0.7fr_0.7fr_0.7fr]">
        <Field label="Review text or TSV/CSV paste">
          <TextAreaInput value={reviewText} onChange={(e) => setReviewText(e.target.value)} spellCheck={false} />
        </Field>
        <Field label="Review objective">
          <SelectInput value={reviewObjective} onChange={(e) => setReviewObjective(e.target.value)}>
            <option value="reduce-returns">Reduce returns</option>
            <option value="protect-conversion">Protect conversion</option>
            <option value="fix-expectation">Fix expectation match</option>
          </SelectInput>
        </Field>
        <Field label="Execution lane">
          <SelectInput value={executionLane} onChange={(e) => setExecutionLane(e.target.value)}>
            <option value="listing-fix">Listing fix</option>
            <option value="product-fix">Product fix</option>
            <option value="mixed-fix">Mixed fix</option>
          </SelectInput>
        </Field>
        <Field label="Response urgency">
          <SelectInput value={responseUrgency} onChange={(e) => setResponseUrgency(e.target.value)}>
            <option value="this-week">This week</option>
            <option value="next-sprint">Next sprint</option>
            <option value="monitor">Monitor first</option>
          </SelectInput>
        </Field>
      </div>
      <div className="flex flex-wrap items-center gap-3">
        <ActionButton type="button" onClick={confirmReviewAnalysis} disabled={!reviewText.trim()}>
          {localeText(locale, "Analyze reviews and generate result", "分析评论并生成结果")}
        </ActionButton>
        <p className="text-sm text-slate-500">
          {localeText(locale, "Confirm once, then read the current result and next move below.", "确认后，先看下方的当前结果和下一步动作。")}
        </p>
      </div>
      <AuditNote lines={auditLines} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-3 text-sm text-slate-700">
        Parsed {rows.length} reviews. Pick one complaint to fix first. Everything else stays closed until that repair is live.
      </div>
      <DistributionPanel title={localeText(locale, "Current result", "当前结果")} rows={reviewResultRows} />
      <DistributionPanel title={localeText(locale, "Review brief", "评论简报")} rows={reviewAuditRows} />
      <DistributionPanel title={localeText(locale, "Action plan", "行动建议")} rows={reviewActionRows} />
      {confirmedAt ? (
        <div className="rounded-xl border border-teal-200 bg-teal-50 px-4 py-3 text-sm text-teal-950">
          {localeText(locale, "The review result below is based on the current pasted review set.", "下方评论结果已按当前粘贴的评论集重新生成。")}
        </div>
      ) : null}
      <DistributionPanel title="Customer voice evidence" rows={customerVoiceRows} />
      <div className="grid gap-3 xl:grid-cols-3">
        <ThemePanel title="Complaint themes" themes={analysis.complaintThemes} />
        <ThemePanel title="Praise themes" themes={analysis.praiseThemes} />
        <ThemePanel title="Opportunity themes" themes={analysis.opportunityThemes} />
      </div>
      <LowTokenAssistPanel
        toolSlug="amazon-review-analyzer"
        locale={locale}
        result={result}
        context={{
          parsedReviewCount: rows.length,
          averageRating: analysis.averageRating,
          complaintThemes: summarizeThemeTallies(analysis.complaintThemes),
          praiseThemes: summarizeThemeTallies(analysis.praiseThemes),
          opportunityThemes: summarizeThemeTallies(analysis.opportunityThemes),
        }}
      />
    </RuntimeShell>
  );
}

function KeywordResearchRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [seedKeyword, setSeedKeyword] = useState("arched full length mirror");
  const [competitorInputs, setCompetitorInputs] = useState("B0GYRT3FNL\nB0G6K4VXK7\nB0FX2PRMFR\nB0CLNLL9RZ");
  const [researchObjective, setResearchObjective] = useState("title-terms");
  const [intentTolerance, setIntentTolerance] = useState("balanced");
  const [deploymentSurface, setDeploymentSurface] = useState("listing-first");
  const [snapshots, setSnapshots] = useState<AmazonListingSnapshot[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  async function loadKeywords() {
    try {
      setLoading(true);
      setError("");
      const candidates = splitAsinCandidates(competitorInputs).slice(0, 4);
      const loaded: AmazonListingSnapshot[] = [];
      for (const candidate of candidates) {
        const response = await fetch(
          `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(candidate)}`,
        );
        const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
        if (response.ok && !("error" in payload)) {
          loaded.push(payload);
        }
      }
      setSnapshots(loaded);
      if (!loaded.length) {
        setError("No competitor listings could be loaded from the current ASIN set.");
      }
    } catch (fetchError) {
      setSnapshots([]);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load competitor keyword set.");
    } finally {
      setLoading(false);
    }
  }

  const extracted = useMemo(() => extractKeywordCandidates(seedKeyword, snapshots), [seedKeyword, snapshots]);
  const decisionRows = useMemo(
    () =>
      buildKeywordResearchDecisionRows({
        competitorCount: snapshots.length,
        candidates: extracted.candidates,
      }),
    [extracted.candidates, snapshots.length],
  );
  const keywordResearchExecutionPlan = useMemo(
    () =>
      inferKeywordResearchExecutionPlan({
        competitorCount: snapshots.length,
        priorityTermCount: decisionRows.priorityTermCount,
        broadSeedRisk: decisionRows.broadSeedRisk,
        researchObjective,
        deploymentSurface,
      }),
    [decisionRows.broadSeedRisk, decisionRows.priorityTermCount, deploymentSurface, researchObjective, snapshots.length],
  );
  const titleCoverageCount = useMemo(() => {
    const titleText = snapshots.map((item) => item.title.toLowerCase()).join(" ");
    return seedKeyword
      .toLowerCase()
      .split(/[^a-z0-9]+/)
      .filter(Boolean)
      .filter((word) => titleText.includes(word)).length;
  }, [seedKeyword, snapshots]);
  const result = useMemo(
    () => {
      if (
        getMultiSnapshotEvidenceStatus(snapshots, ["title", "breadcrumbs", "bullets"]).level ===
        "weak"
      ) {
        return null;
      }
      return evaluateKeywordResearch({
        competitorCount: snapshots.length,
        seedWordCount: extracted.seedWordCount,
        candidateCount: extracted.candidates.length,
        consensusCandidateCount: extracted.candidates.filter((item) => item.count >= Math.max(2, Math.ceil(snapshots.length / 2))).length,
        strongestTermRepeats: extracted.candidates[0]?.count ?? 0,
        titleCoverageCount,
        featureTermCount: extracted.featureTerms.length,
        categoryTermCount: extracted.categoryTerms.length,
        priorityTermCount: decisionRows.priorityTermCount,
        broadSeedRisk: decisionRows.broadSeedRisk,
      });
    },
    [decisionRows.broadSeedRisk, decisionRows.priorityTermCount, extracted, snapshots.length, titleCoverageCount],
  );

  const keywordResearchAuditLines = useMemo(() => {
    const lines = [];
    if (snapshots.length) {
      const evidenceStatus = getMultiSnapshotEvidenceStatus(snapshots, [
        "title",
        "breadcrumbs",
        "bullets",
      ]);
      lines.push(`Reference-set quality: ${evidenceStatus.label}. ${evidenceStatus.detail}`);
      if (evidenceStatus.level !== "complete") {
        lines.push("Treat this shortlist as watch-mode only until competitor titles, browse paths, and bullet support are stronger.");
      }
      lines.push(`Research brief: ${researchObjective.replace(/-/g, " ")} with ${intentTolerance} intent tolerance.`);
    } else {
      lines.push("Load competitor ASINs first so the shortlist comes from live market language.");
    }
    return lines;
  }, [intentTolerance, researchObjective, snapshots]);

  const keywordResearchAuditRows = useMemo(
    () => [
      {
        label: "Reference set",
        value: `${snapshots.length} competitors`,
        detail: snapshots.length ? "Live titles, browse paths, and bullets loaded from the current comparison set." : "No live competitor reference set loaded yet.",
      },
      {
        label: "Seed posture",
        value: seedKeyword.trim() || "Missing",
        detail: `${extracted.seedWordCount} seed words currently driving extraction`,
      },
      {
        label: "Consensus terms",
        value: `${decisionRows.priorityTermCount}`,
        detail: decisionRows.broadSeedRisk ? "Signal is still broad and fragmented." : "Signal is converging into a workable shortlist.",
      },
      {
        label: "Research brief",
        value: `${researchObjective.replace(/-/g, " ")} / ${intentTolerance}`,
        detail: `${deploymentSurface.replace(/-/g, " ")} deployment posture for this pass`,
      },
      {
        label: "Execution call",
        value: keywordResearchExecutionPlan.researchDecision,
        detail: `${keywordResearchExecutionPlan.proofPriority} | ${keywordResearchExecutionPlan.executionCadence}`,
      },
    ],
    [decisionRows.broadSeedRisk, decisionRows.priorityTermCount, deploymentSurface, extracted.seedWordCount, intentTolerance, keywordResearchExecutionPlan, researchObjective, seedKeyword, snapshots.length],
  );

  const keywordResearchActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: keywordResearchExecutionPlan.researchDecision,
        detail: keywordResearchExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: keywordResearchExecutionPlan.owner,
        detail: `${keywordResearchExecutionPlan.proofPriority} belongs to the operator who can actually turn the shortlist into a real test.`,
      },
      {
        label: "Do not cross",
        value:
          !snapshots.length
            ? "Do not deploy terms before loading live competitor language"
            : decisionRows.broadSeedRisk
              ? "Do not promote a broad mixed-intent seed into the listing"
              : deploymentSurface === "hold"
                ? "Do not let a ready shortlist die in a vague backlog"
                : "Do not stuff every repeated modifier into one surface",
        detail:
          !snapshots.length
            ? "Keep keyword deployment closed until the shortlist comes from real market language instead of operator intuition."
            : decisionRows.broadSeedRisk
              ? "A broad seed creates fake abundance and usually turns keyword work into clutter."
              : deploymentSurface === "hold"
                ? "A good shortlist still loses value if nobody owns the next deployment step."
                : "One clean deployment surface is easier to measure than spraying every term into title, bullets, and backend at once.",
      },
      {
        label: "Then do",
        value: keywordResearchExecutionPlan.executionCadence,
        detail: "Separate title terms from bullet-support and backend terms before deployment spreads wider.",
      },
      {
        label: "Watch",
        value: keywordResearchExecutionPlan.proofPriority,
        detail: keywordResearchExecutionPlan.watchout,
      },
    ],
    [keywordResearchExecutionPlan],
  );

  const keywordResearchFocusRows = useMemo(
    () =>
      buildKeywordResearchFocusRows({
        snapshots,
        seedKeyword,
        extracted,
        decisionRows,
      }),
    [decisionRows, extracted, seedKeyword, snapshots],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_1fr_0.7fr_0.8fr_0.8fr_0.8fr_auto]">
        <Field label="Seed keyword">
          <TextInput value={seedKeyword} onChange={(e) => setSeedKeyword(e.target.value)} />
        </Field>
        <Field label="Competitor ASINs or URLs">
          <TextAreaInput
            value={competitorInputs}
            onChange={(e) => setCompetitorInputs(e.target.value)}
            className="min-h-[7.5rem]"
            spellCheck={false}
          />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <Field label="Research objective">
          <SelectInput value={researchObjective} onChange={(e) => setResearchObjective(e.target.value)}>
            <option value="title-terms">Title terms</option>
            <option value="bullet-support">Bullet support</option>
            <option value="seed-validation">Seed validation</option>
          </SelectInput>
        </Field>
        <Field label="Intent tolerance">
          <SelectInput value={intentTolerance} onChange={(e) => setIntentTolerance(e.target.value)}>
            <option value="strict">Strict</option>
            <option value="balanced">Balanced</option>
            <option value="broad">Broad</option>
          </SelectInput>
        </Field>
        <Field label="Deployment surface">
          <SelectInput value={deploymentSurface} onChange={(e) => setDeploymentSurface(e.target.value)}>
            <option value="listing-first">Listing first</option>
            <option value="backend-first">Backend first</option>
            <option value="hold">Hold</option>
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadKeywords} disabled={loading || !seedKeyword.trim()}>
            {loading ? "Loading..." : "Load competitor keywords"}
          </ActionButton>
        </div>
      </div>
      {error ? (
        <div className="rounded-xl border border-rose-200 bg-rose-50 px-4 py-3 text-sm text-rose-950">
          {error}
        </div>
      ) : null}
      <AuditNote lines={keywordResearchAuditLines} />
      <DistributionPanel title="Keyword brief" rows={keywordResearchAuditRows} />
      <DistributionPanel title="This research pass" rows={keywordResearchActionRows} />
      <CompetitorBoard own={snapshots[0] ?? null} competitors={snapshots.slice(1)} primaryLabel="Seed competitor" />
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title="Priority shortlist" rows={decisionRows.shortlistRows} />
        <DistributionPanel title="Keyword signals" rows={decisionRows.signalRows} />
        <DistributionPanel title="Hold for later testing" rows={decisionRows.weakRows} />
      </div>
      <DistributionPanel title="Research call" rows={keywordResearchFocusRows} />
      <div className="grid gap-3 xl:grid-cols-3">
        <KeywordCandidatePanel title="Recurring modifiers" items={extracted.candidates} />
        <KeywordCandidatePanel title="Feature terms" items={extracted.featureTerms} />
        <KeywordCandidatePanel title="Category terms" items={extracted.categoryTerms} />
      </div>
    </RuntimeShell>
  );
}

function BackendKeywordsRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("B0GYRT3FNL");
  const [seedKeyword, setSeedKeyword] = useState("arched full length mirror standing gold bedroom");
  const [keywordPool, setKeywordPool] = useState(
    "arched, full length, standing, bedroom, wall mount, dressing room, aluminum frame, shatterproof, leaning, freestanding, home decor, oversized, nano glass, modern",
  );
  const [byteLimit, setByteLimit] = useState(249);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [showOverrides, setShowOverrides] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const backendPlan = useMemo(() => inferBackendKeywordPlan(snapshot), [snapshot]);

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }
      setSnapshot(payload);
      const nextPlan = inferBackendKeywordPlan(payload);
      setSeedKeyword(nextPlan.seedKeyword);
      setKeywordPool(nextPlan.keywordPool);
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  const packed = useMemo(
    () =>
      buildBackendKeywordPack({
        title: snapshot?.title ?? "",
        bullets: snapshot?.bulletPoints ?? [],
        seedKeyword,
        keywordPool,
        byteLimit,
      }),
    [byteLimit, keywordPool, seedKeyword, snapshot],
  );

  const result = useMemo(
    () => {
      if (snapshot && !isCustomSnapshotDecisionGrade(snapshot, ["title", "bullets"])) {
        return null;
      }
      return evaluateBackendKeywords({
        byteLimit,
        usedBytes: packed.usedBytes,
        includedCount: packed.kept.length,
        removedCount: packed.removedTerms.length,
        duplicateCount: packed.duplicateTerms.length,
        coveredSeedCount: packed.coveredSeedCount,
        totalSeedCount: packed.totalSeedCount,
      });
    },
    [byteLimit, packed],
  );
  const backendKeywordExecutionPlan = useMemo(() => {
    const coverageRate = packed.totalSeedCount > 0 ? packed.coveredSeedCount / packed.totalSeedCount : 0;
    const byteUtilization = byteLimit > 0 ? packed.usedBytes / byteLimit : 0;

    return inferBackendKeywordExecutionPlan({
      hasSnapshot: Boolean(snapshot),
      coverageRate,
      duplicateCount: packed.duplicateTerms.length,
      removedCount: packed.removedTerms.length,
      includedCount: packed.kept.length,
      byteUtilization,
    });
  }, [byteLimit, packed, snapshot]);

  const backendAuditRows = useMemo(
    () => [
      {
        label: "Seed draft",
        value: `${splitKeywordPhrases(seedKeyword).length} phrases`,
        detail: seedKeyword || "Load a live listing to draft the initial seed set",
      },
      {
        label: "Keyword pool",
        value: `${tokenizeKeywordPool(keywordPool).length} terms`,
        detail: snapshot ? "Built from title, bullets, brand, and browse path" : "Manual pool until a live listing is loaded",
      },
      {
        label: "Byte limit",
        value: `${byteLimit}`,
        detail: `${packed.usedBytes}/${byteLimit} bytes used in the current packed string`,
      },
      {
        label: "Mode",
        value: snapshot ? "Live-first" : "Manual",
        detail: snapshot ? "Listing-backed draft before manual cleanup" : "Manual keyword drafting mode",
      },
      {
        label: "Execution call",
        value: backendKeywordExecutionPlan.backendDecision,
        detail: `${backendKeywordExecutionPlan.proofPriority} | ${backendKeywordExecutionPlan.executionCadence}`,
      },
    ],
    [backendKeywordExecutionPlan, byteLimit, keywordPool, packed.usedBytes, seedKeyword, snapshot],
  );

  const backendActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: backendKeywordExecutionPlan.backendDecision,
        detail: `${backendKeywordExecutionPlan.nextMove} Keep visible copy frozen until duplicate filtering and seed coverage are checked against the same live baseline.`,
      },
      {
        label: "Execution owner",
        value: backendKeywordExecutionPlan.owner,
        detail: `Put ${backendKeywordExecutionPlan.proofPriority.toLowerCase()} under one operator who can clear the next backend-term blocker before anyone repacks the field again or reopens visible copy.`,
      },
      {
        label: "Do not cross",
        value:
          !snapshot
            ? "Do not pack backend terms before loading live visible copy"
            : packed.duplicateTerms.length >= 4
              ? "Do not waste backend bytes on title and bullet duplicates"
              : packed.totalSeedCount > 0 && packed.coveredSeedCount / packed.totalSeedCount < 0.6
                ? "Do not chase extra modifiers before core seed coverage is intact"
                : "Do not fill the field just because bytes remain",
        detail:
          !snapshot
            ? "The backend field should be incremental search coverage, not a blind keyword bucket built without the real PDP."
            : packed.duplicateTerms.length >= 4
              ? "Duplicate-heavy packs look busy but usually add almost no incremental indexing value."
              : packed.totalSeedCount > 0 && packed.coveredSeedCount / packed.totalSeedCount < 0.6
                ? "If the main intent is still weak, a byte-perfect pack still underperforms."
                : "Unused bytes are less dangerous than low-quality bytes that add clutter and overlap.",
      },
      {
        label: "Then do",
        value: backendKeywordExecutionPlan.executionCadence,
        detail: "Freeze visible copy while this pass ships, then validate whether the backend field is adding net-new indexing before reopening either layer or repacking the field again.",
      },
      {
        label: "Watch",
        value: backendKeywordExecutionPlan.proofPriority,
        detail: `${backendKeywordExecutionPlan.watchout} Reopen the field only after an indexing check or a visible-copy change materially changes the search gap.`,
      },
    ],
    [backendKeywordExecutionPlan],
  );

  const backendInputRows = useMemo(
    () => backendAuditRows,
    [backendAuditRows],
  );

  const backendFocusRows = useMemo(
    () =>
      buildBackendKeywordFocusRows({
        snapshot,
        packed,
        byteLimit,
      }),
    [byteLimit, packed, snapshot],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 md:grid-cols-[1.4fr_0.8fr_auto] xl:grid-cols-[1.6fr_0.8fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <DistributionPanel title="Live keyword inputs" rows={backendInputRows} />
      <DistributionPanel title="This backend-term call" rows={backendActionRows} />
      <AuditNote
        lines={
          snapshot
            ? (() => {
                const evidenceStatus = getCustomSnapshotEvidenceStatus(snapshot, [
                  "title",
                  "bullets",
                ]);
                const lines = [
                  `System draft: ${backendPlan.visibleCopyPressure}. Seed phrases ${splitKeywordPhrases(seedKeyword).length}, keyword pool ${tokenizeKeywordPool(keywordPool).length} terms.`,
                  `Evidence quality: ${evidenceStatus.label}. ${evidenceStatus.detail}`,
                ];
                if (evidenceStatus.level !== "complete") {
                  lines.push("Use the packed string as a draft only until title and bullet support are both present.");
                }
                return lines;
              })()
            : ["Load a live listing when possible so duplicate filtering starts from the actual title and bullet copy."]
        }
      />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">{manualOverridesHeading(locale)}</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when you want to replace the live seed draft, edit the keyword pool, or pressure-test a different byte limit.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {manualOverridesToggle(locale, showOverrides)}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 xl:grid-cols-[1fr_1fr_0.55fr]">
              <Field label="Seed keyword ideas">
                <TextAreaInput value={seedKeyword} onChange={(e) => setSeedKeyword(e.target.value)} spellCheck={false} />
              </Field>
              <Field label="Keyword pool">
                <TextAreaInput value={keywordPool} onChange={(e) => setKeywordPool(e.target.value)} spellCheck={false} />
              </Field>
              <Field label="Byte limit">
                <NumberInput value={byteLimit} min="50" step="1" onChange={(e) => setByteLimit(Number(e.target.value))} />
              </Field>
            </div>
          </div>
        ) : null}
      </div>
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Packed backend string</p>
        <p className="mt-2 text-sm leading-6 text-slate-900 break-words">{packed.packed || "No usable backend terms yet."}</p>
      </div>
      <DistributionPanel title="Pack posture" rows={backendFocusRows} />
      <div className="grid gap-3 xl:grid-cols-3">
        <KeywordCandidatePanel title="Included terms" items={packed.kept} />
        <KeywordCandidatePanel title="Visible-copy duplicates" items={packed.duplicateTerms} />
        <KeywordCandidatePanel title="Dropped on byte limit" items={packed.removedTerms} />
      </div>
    </RuntimeShell>
  );
}

function ReturnReductionRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [returnReasons, setReturnReasons] = useState(
    "reason\tcount\nArrived damaged\t7\nNot as described\t5\nToo difficult to assemble\t3\nScratched frame\t4\nWrong size for room\t2",
  );
  const [reviewText, setReviewText] = useState(
    "rating\treview\n2\tArrived with a cracked corner and weak packaging.\n3\tMirror looks good but the size felt smaller than expected.\n2\tAssembly instructions were confusing and the mount hardware felt cheap.\n4\tBeautiful design, but the frame had a small scratch.\n5\tLooks perfect in our bedroom and was easy to place.",
  );

  const reasonRows = useMemo(() => parseReturnReasonRows(returnReasons), [returnReasons]);
  const reasonGroups = useMemo(() => groupReturnReasonSignals(reasonRows), [reasonRows]);
  const reviewRows = useMemo(() => parseReviewRows(reviewText), [reviewText]);
  const reviewAnalysis = useMemo(() => analyzeReviewThemes(reviewRows), [reviewRows]);
  const totalReasons = reasonGroups.reduce((sum, item) => sum + item.count, 0);
  const topReasonShare = totalReasons > 0 && reasonGroups[0] ? reasonGroups[0].count / totalReasons : 0;

  const result = useMemo(
    () =>
      evaluateReturnReduction({
        reasonCount: reasonGroups.length,
        topReasonShare,
        complaintThemeCount: reviewAnalysis.complaintThemes.length,
        packagingIssueCount:
          (reasonGroups.find((item) => item.label === "packaging")?.count ?? 0) +
          (reviewAnalysis.complaintThemes.find((item) => item.label === "packaging")?.count ?? 0),
        clarityIssueCount:
          (reasonGroups.find((item) => item.label === "clarity")?.count ?? 0) +
          (reviewAnalysis.complaintThemes.find((item) => item.label === "size")?.count ?? 0) +
          (reviewAnalysis.complaintThemes.find((item) => item.label === "clarity")?.count ?? 0),
        qualityIssueCount:
          (reasonGroups.find((item) => item.label === "quality")?.count ?? 0) +
          (reviewAnalysis.complaintThemes.find((item) => item.label === "quality")?.count ?? 0),
      }),
    [reasonGroups, reviewAnalysis, topReasonShare],
  );
  const packagingCount =
    (reasonGroups.find((item) => item.label === "packaging")?.count ?? 0) +
    (reviewAnalysis.complaintThemes.find((item) => item.label === "packaging")?.count ?? 0);
  const clarityCount =
    (reasonGroups.find((item) => item.label === "clarity")?.count ?? 0) +
    (reviewAnalysis.complaintThemes.find((item) => item.label === "clarity")?.count ?? 0) +
    (reviewAnalysis.complaintThemes.find((item) => item.label === "size")?.count ?? 0);
  const setupCount =
    (reasonGroups.find((item) => item.label === "setup")?.count ?? 0) +
    (reviewAnalysis.complaintThemes.find((item) => item.label === "assembly")?.count ?? 0);
  const qualityCount =
    (reasonGroups.find((item) => item.label === "quality")?.count ?? 0) +
    (reviewAnalysis.complaintThemes.find((item) => item.label === "quality")?.count ?? 0);
  const returnExecutionPlan = useMemo(
    () =>
      inferReturnReductionDecisionPlan({
        reasonCount: reasonGroups.length,
        topReasonShare,
        packagingCount,
        clarityCount,
        setupCount,
        qualityCount,
      }),
    [clarityCount, packagingCount, qualityCount, reasonGroups.length, setupCount, topReasonShare],
  );

  const reasonThemes = reasonGroups.map((item) => ({
    label: item.label,
    count: item.count,
    examples: [],
  }));
  const returnPressureRows = useMemo(
    () => buildReturnPressureRows({ reasonGroups, reviewAnalysis }),
    [reasonGroups, reviewAnalysis],
  );

  const returnAuditRows = useMemo(
    () => [
      {
        label: "Parsed evidence",
        value: `${reasonRows.length} return rows / ${reviewRows.length} review rows`,
        detail: "The tool is reading structured return reasons and shopper-language complaints together.",
      },
      {
        label: "Top return pressure",
        value: reasonGroups[0] ? `${reasonGroups[0].label} (${reasonGroups[0].count})` : "No dominant reason yet",
        detail: `${Math.round(topReasonShare * 100)}% share of tagged return causes`,
      },
      {
        label: "Complaint load",
        value: `${reviewAnalysis.complaintThemes.length} complaint clusters`,
        detail: `${reviewAnalysis.opportunityThemes.length} opportunity themes | average rating ${roundNumber(reviewAnalysis.averageRating, 1) || 0}`,
      },
      {
        label: "Execution call",
        value: returnExecutionPlan.returnDecision,
        detail: `${returnExecutionPlan.proofPriority} | ${returnExecutionPlan.executionCadence}`,
      },
    ],
    [reasonGroups, reasonRows.length, returnExecutionPlan, reviewAnalysis.averageRating, reviewAnalysis.complaintThemes.length, reviewAnalysis.opportunityThemes.length, reviewRows.length, topReasonShare],
  );

  const returnActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: returnExecutionPlan.returnDecision,
        detail: returnExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: returnExecutionPlan.owner,
        detail: `${returnExecutionPlan.proofPriority} should map to the team that can actually remove the return cause.`,
      },
      {
        label: "Do not cross",
        value:
          packagingCount >= Math.max(clarityCount, setupCount, qualityCount)
            ? "Do not blame the PDP before transit damage is contained"
            : qualityCount >= Math.max(clarityCount, setupCount)
              ? "Do not hide defect returns behind copy cleanup"
              : setupCount > clarityCount
                ? "Do not redesign the product before fixing guidance friction"
                : "Do not spread the fix across every team at once",
        detail:
          packagingCount >= Math.max(clarityCount, setupCount, qualityCount)
            ? "Damage-led returns are operational first, and copy edits will not stop broken units from arriving broken."
            : qualityCount >= Math.max(clarityCount, setupCount)
              ? "If the strongest signal is product quality, merchandising work should not become a shield for supplier problems."
              : setupCount > clarityCount
                ? "Setup-heavy returns often fall faster with better instructions than with bigger structural changes."
                : "One dominant return cause should get one owner first, or the fix dissolves into generic cleanup.",
      },
      {
        label: "Then do",
        value: returnExecutionPlan.executionCadence,
        detail: "Keep packaging, listing clarity, setup support, and product quality as separate owners instead of turning the plan into a blended cleanup list.",
      },
      {
        label: "Watch",
        value: returnExecutionPlan.proofPriority,
        detail: returnExecutionPlan.watchout,
      },
    ],
    [clarityCount, packagingCount, qualityCount, returnExecutionPlan, setupCount],
  );

  const returnInputRows = useMemo(
    () => [
      ...returnAuditRows,
      {
        label: "Execution call",
        value: returnActionRows[0]?.value ?? "Return-reduction decision pending",
        detail: returnActionRows[1]?.value
          ? `${returnActionRows[1].value} owns the first return-cause fix until the same complaint sample is rechecked.`
          : "Name one owner before return causes dissolve into a blended cleanup list.",
      },
    ],
    [returnActionRows, returnAuditRows],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-2">
        <Field label="Return reason data">
          <TextAreaInput value={returnReasons} onChange={(e) => setReturnReasons(e.target.value)} spellCheck={false} />
        </Field>
        <Field label="Review complaint data">
          <TextAreaInput value={reviewText} onChange={(e) => setReviewText(e.target.value)} spellCheck={false} />
        </Field>
      </div>
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-3 text-sm text-slate-700">
        Parsed {reasonRows.length} return-reason rows and {reviewRows.length} review rows.
      </div>
      <DistributionPanel title="Live return inputs" rows={returnInputRows} />
      <DistributionPanel title="This return call" rows={returnActionRows} />
      <div className="grid gap-3 xl:grid-cols-[1fr_1fr]">
        <DistributionPanel title="Pressure by fix surface" rows={returnPressureRows} />
        <DistributionPanel title="Return-cause clusters" rows={returnPressureRows} />
      </div>
      <div className="grid gap-3 xl:grid-cols-3">
        <ThemePanel title="Return-cause clusters" themes={reasonThemes} />
        <ThemePanel title="Complaint themes" themes={reviewAnalysis.complaintThemes} />
        <ThemePanel title="Opportunity themes" themes={reviewAnalysis.opportunityThemes} />
      </div>
    </RuntimeShell>
  );
}

function SearchOptimizationRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [category, setCategory] = useState("");
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("");
  const [listingTitle, setListingTitle] = useState("");
  const [backendTerms, setBackendTerms] = useState("");
  const [targetKeywords, setTargetKeywords] = useState("");
  const [itemType, setItemType] = useState("");
  const [currentRank, setCurrentRank] = useState(0);
  const [reviewCount, setReviewCount] = useState(0);
  const [hasAPlus, setHasAPlus] = useState(false);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [showOverrides, setShowOverrides] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const searchPlan = useMemo(() => inferSearchOptimizationPlan(snapshot), [snapshot]);

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }

      setSnapshot(payload);
      setListingTitle(payload.title);
      const nextPlan = inferSearchOptimizationPlan(payload);
      setItemType(nextPlan.itemType);
      setBackendTerms(nextPlan.backendTerms);
      setCurrentRank(nextPlan.currentRank);
      setReviewCount(nextPlan.reviewCount);
      setHasAPlus(nextPlan.hasAPlus);
      if (!showOverrides && nextPlan.targetKeywords) {
        setTargetKeywords(nextPlan.targetKeywords);
      }

      const matchedCategory = inferCategoryOption(payload, calculatorCategoryOptionGroups);
      if (matchedCategory) {
        setCategory(matchedCategory);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  const detectedCategoryLabel = useMemo(() => {
    for (const group of calculatorCategoryOptionGroups) {
      const option = group.options.find((item) => item.value === category);
      if (option) {
        return option.label;
      }
    }
    return "Not matched yet";
  }, [category]);

  const keywordCount = useMemo(
    () => targetKeywords.split(",").map((item) => item.trim()).filter(Boolean).length,
    [targetKeywords],
  );
  const searchExecutionPlan = useMemo(
    () =>
      inferSearchOptimizationExecutionPlan({
        hasSnapshot: Boolean(snapshot),
        keywordCount,
        hasItemType: Boolean(itemType.trim()),
        currentRank,
        reviewCount,
        hasAPlus,
      }),
    [currentRank, hasAPlus, itemType, keywordCount, reviewCount, snapshot],
  );

  const result = useMemo(
    () => {
      if (!snapshot) {
        return {
          headline: "Load the live PDP before touching search surfaces",
          summary:
            "Keep search work closed until the live page provides the real title, browse path, proof depth, and rank context.",
          metrics: [
            {
              label: "First blocker",
              value: "Live PDP baseline",
              detail: "Load the current ASIN so keyword posture and browse wording come from the real page instead of manual guesses.",
            },
            {
              label: "Decision owner",
              value: searchExecutionPlan.owner,
              detail: "One owner clears the first search blocker.",
            },
            {
              label: "Execution call",
              value: searchExecutionPlan.decision,
              detail: `${searchExecutionPlan.owner} | ${searchExecutionPlan.cadence} | ${searchExecutionPlan.proofPriority}`,
            },
            {
              label: "Do not cross",
              value: "Do not optimize search surfaces before loading the live PDP",
              detail: "Do not start from placeholders.",
            },
          ],
          recommendations: [
            "Load the ASIN or Amazon URL before touching title, backend terms, or browse wording.",
            "Use manual overrides only for a deliberate what-if pass after the live read exists.",
          ],
          status: {
            label: "Live search baseline is missing",
            tone: "warning" as const,
          },
          missingItems: ["Live PDP baseline"],
          nextSteps: [
            "Load the live ASIN.",
            "Let the tool draft the first keyword and browse-fit read.",
            "Then decide whether the first blocker is relevance, browse fit, or conversion proof.",
          ],
          actionStance: {
            label: "Do not run search strategy from placeholders",
            tone: "warning" as const,
            detail: "Do not let offline guesses turn into search edits. Load the live PDP first so relevance, browse fit, and proof all come from the real page.",
          },
        } satisfies ToolEvaluation;
      }
      if (!isCustomSnapshotDecisionGrade(snapshot, ["title", "breadcrumbs", "reviewCount"])) {
        return {
          headline: "Repair the live read before making a search move",
          summary:
            "The page is loaded, but the evidence is still too thin to approve a real search-surface change.",
          metrics: [
            {
              label: "First blocker",
              value: "Live PDP evidence",
              detail: "The current read is still too thin to approve a search move.",
            },
            {
              label: "Decision owner",
              value: searchExecutionPlan.owner,
              detail: "One owner repairs the live read first.",
            },
            {
              label: "Execution call",
              value: searchExecutionPlan.decision,
              detail: `${searchExecutionPlan.owner} | ${searchExecutionPlan.cadence} | ${searchExecutionPlan.proofPriority}`,
            },
            {
              label: "Do not cross",
              value: "Do not chase rank before the live proof stack is clear",
              detail: "Do not turn a weak read into a keyword fix.",
            },
          ],
          recommendations: [
            "Reload the live page until title, browse path, and visible proof are stable.",
            "Keep any manual keyword pass open only until the PDP read is stronger.",
          ],
          status: {
            label: "Live search evidence needs review",
            tone: "warning" as const,
          },
          missingItems: ["Stronger live PDP evidence"],
          nextSteps: [
            "Repair the live listing read.",
            "Re-run the search posture.",
            "Then make one focused search-surface revision.",
          ],
          actionStance: {
            label: "Do not confuse weak evidence with a keyword problem",
            tone: "warning" as const,
            detail: "The wrong search diagnosis usually starts with a weak read of the current page.",
          },
        } satisfies ToolEvaluation;
      }
      return evaluateSearchOptimization({
        category,
        title: listingTitle,
        backendTerms,
        targetKeywords,
        itemType,
        currentRank,
        reviewCount,
        hasAPlus,
      });
    },
    [
      backendTerms,
      category,
      currentRank,
      hasAPlus,
      itemType,
      listingTitle,
      reviewCount,
      searchExecutionPlan,
      targetKeywords,
      snapshot,
    ],
  );

  const searchAuditRows = useMemo(
    () => [
      {
        label: "Detected category",
        value: detectedCategoryLabel,
        detail: snapshot?.breadcrumbs.length ? snapshot.breadcrumbs.join(" / ") : "Using current category mapping",
      },
      {
        label: "Browse wording",
        value: itemType || "Missing",
        detail: snapshot ? "Pulled from the live browse path" : "Load a listing to detect item-type wording",
      },
      {
        label: "Keyword set",
        value: snapshot ? `${keywordCount} targets` : "Waiting on live draft",
        detail: targetKeywords || "Load a live listing to draft the first target-keyword set",
      },
      {
        label: "Rank and proof",
        value: currentRank > 0 ? `#${currentRank.toLocaleString("en-US")}` : "Rank not loaded",
        detail: `${reviewCount.toLocaleString("en-US")} reviews | ${hasAPlus ? "A+ live" : "No A+"}`,
      },
      {
        label: "Execution call",
        value: searchExecutionPlan.decision,
        detail: `${searchExecutionPlan.proofPriority} | ${searchExecutionPlan.cadence}`,
      },
    ],
    [currentRank, detectedCategoryLabel, hasAPlus, itemType, keywordCount, reviewCount, searchExecutionPlan, snapshot, targetKeywords],
  );

  const searchAuditLines = useMemo(() => {
    const lines = [];
    if (snapshot) {
      const evidenceStatus = getCustomSnapshotEvidenceStatus(snapshot, [
        "title",
        "breadcrumbs",
        "reviewCount",
      ]);
      lines.push(`Live path: ${snapshot.breadcrumbs.length ? snapshot.breadcrumbs.join(" / ") : detectedCategoryLabel}.`);
      lines.push(
        `Current lane: ${keywordCount} target phrases, item type "${searchPlan.itemType || "missing"}", ${searchPlan.currentRank > 0 ? `rank #${searchPlan.currentRank.toLocaleString("en-US")}` : "no live rank"}, ${searchPlan.reviewCount.toLocaleString("en-US")} reviews.`,
      );
      lines.push(`Evidence: ${evidenceStatus.label}. ${evidenceStatus.detail}`);
      if (evidenceStatus.level !== "complete") {
        lines.push("Keep this read in triage.");
      }
    } else {
      lines.push("Load the live PDP first.");
      lines.push("Keep search edits closed until the baseline is real.");
    }
    lines.push("Open manual overrides only for one alternate path.");
    return lines;
  }, [detectedCategoryLabel, keywordCount, searchPlan.currentRank, searchPlan.itemType, searchPlan.reviewCount, snapshot]);

  const searchActionRows = useMemo(() => {
    const firstMove =
      !snapshot
        ? {
            label: "First move",
            value: "Load the live PDP",
            detail: "Search optimization is strongest when title, browse path, BSR, review depth, and A+ status come from the live page.",
          }
        : keywordCount < 3
          ? {
              label: "First move",
              value: "Tighten the target keyword set",
              detail: "A vague keyword plan makes every later title and backend edit feel precise while still aiming at a fuzzy target.",
            }
          : !itemType.trim()
            ? {
                label: "First move",
                value: "Fix browse wording first",
                detail: "Weak browse wording can suppress relevance before title polish has a chance to matter.",
              }
            : currentRank <= 0 && reviewCount < 20
              ? {
                  label: "First move",
                  value: "Strengthen proof before chasing more rank",
                  detail: "Low visible proof often means traffic gains will not hold even if keyword placement improves.",
                }
              : !hasAPlus && reviewCount >= 20
                ? {
                    label: "First move",
                    value: "Use richer content to support conversion",
                    detail: "The page has enough social proof that the next lift may come from better conversion support rather than more indexing edits.",
                  }
                : {
                    label: "First move",
                    value: "Run one focused title and backend revision",
                    detail: "The surface is strong enough now that the best next move is a controlled search-surface test, not broad rework.",
                  };

    return [
      {
        label: "First move",
        value: searchExecutionPlan.decision,
        detail: `${searchExecutionPlan.nextMove} Freeze everything else.`,
      },
      {
        label: "Execution owner",
        value: searchExecutionPlan.owner,
        detail: `${searchExecutionPlan.cadence}. One owner carries this pass.`,
      },
      {
        label: "Do not cross",
        value: !snapshot
          ? "Do not optimize search surfaces before loading the live PDP"
          : keywordCount < 3
            ? "Do not rewrite title and backend terms around a vague keyword set"
            : !itemType.trim()
              ? "Do not chase rank before browse wording is clear"
              : currentRank <= 0 && reviewCount < 20
                ? "Do not buy traffic before proof can hold it"
                : !hasAPlus && reviewCount >= 20
                  ? "Do not keep stacking keyword edits while conversion support is thin"
                  : "Do not turn one search test into a full PDP rewrite",
        detail: !snapshot
          ? "Load the real page first."
          : keywordCount < 3
            ? "Fix the target before the copy."
            : !itemType.trim()
              ? "Fix browse fit before rank work."
              : currentRank <= 0 && reviewCount < 20
                ? "Proof first, traffic second."
                : !hasAPlus && reviewCount >= 20
                  ? "Support conversion before more indexing edits."
                  : "Keep the test narrow.",
      },
      {
        label: "Then do",
        value: "Check title, backend, and browse fit together",
        detail: "Make sure all three point at the same demand path.",
      },
      {
        label: "Watch",
        value: searchExecutionPlan.proofPriority,
        detail: "Reopen only if the same blockage remains after the first pass.",
      },
    ];
  }, [currentRank, hasAPlus, itemType, keywordCount, reviewCount, searchExecutionPlan, snapshot]);

  const searchInputRows = useMemo(
    () =>
      !snapshot
        ? [
            {
              label: "Live PDP",
              value: "Not loaded",
              detail: "Load the current PDP so search work starts from real title, browse path, proof, and rank signals.",
            },
            {
              label: "First blocker",
              value: "Live search baseline",
              detail: "The tool still needs the real title, browse wording, review depth, and rank context.",
            },
            {
              label: "Decision owner",
              value: searchExecutionPlan.owner,
              detail: "One SEO owner carries the first blocked move until the same live PDP is rechecked.",
            },
            {
              label: "Execution call",
              value: searchActionRows[0]?.value ?? "Load the live PDP",
              detail: `${searchExecutionPlan.owner} | ${searchExecutionPlan.cadence} | ${searchExecutionPlan.proofPriority}`,
            },
          ]
        : [
            {
              label: "Live PDP",
              value: snapshot.asin ?? "Loaded",
              detail: snapshot.title || "The current title was pulled from the live listing.",
            },
            {
              label: "First blocker",
              value: keywordCount < 3
                ? "Keyword direction"
                : !itemType.trim()
                  ? "Browse wording"
                  : currentRank <= 0 && reviewCount < 20
                    ? "Proof depth"
                    : !hasAPlus && reviewCount >= 20
                      ? "Conversion support"
                      : "Search-surface revision",
              detail: keywordCount < 3
                ? "The keyword set is still too thin to support a clean search move."
                : !itemType.trim()
                  ? "Browse wording is still too weak to trust the relevance layer."
                  : currentRank <= 0 && reviewCount < 20
                    ? "The page needs stronger proof before more traffic work."
                    : !hasAPlus && reviewCount >= 20
                      ? "Conversion support is still behind the current demand signal."
                      : "The page is ready for one contained search-surface test.",
            },
            {
              label: "Decision owner",
              value: searchExecutionPlan.owner,
              detail: "Keep one SEO owner on the first blocked move until the same live PDP is re-read.",
            },
            {
              label: "Execution call",
              value: searchActionRows[0]?.value ?? "Search-optimization decision pending",
              detail: searchActionRows[1]?.value
                ? `${searchActionRows[1].value} owns the first search-surface fix until the same keyword pack is rechecked on the live PDP.`
                : "Put one optimization owner on the first blocked search move before more edits stack up.",
            },
          ],
    [searchActionRows, searchAuditRows, searchExecutionPlan, snapshot],
  );

  const searchFocusRows = useMemo(
    () =>
      buildSearchOptimizationFocusRows({
        snapshot,
        listingTitle,
        backendTerms,
        targetKeywords,
        itemType,
        currentRank,
        reviewCount,
        hasAPlus,
      }),
    [backendTerms, currentRank, hasAPlus, itemType, listingTitle, reviewCount, snapshot, targetKeywords],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 md:grid-cols-[1.4fr_0.8fr_auto] xl:grid-cols-[1.6fr_0.8fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput
            value={asinOrUrl}
            onChange={(e) => setAsinOrUrl(e.target.value)}
            placeholder="Paste your ASIN or Amazon URL"
            spellCheck={false}
          />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {runtimeActionButtonLabel(
              locale,
              loading,
              "Load listing and generate search result",
              "加载商品并生成搜索结果",
            )}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote lines={searchAuditLines} />
      <div className="rounded-xl border border-teal-200 bg-teal-50 px-3 py-3 text-sm text-teal-950">
        {runtimeResultHint(locale)}
      </div>
      <DistributionPanel title={runtimeResultTitle(locale)} rows={searchInputRows} />
      <DistributionPanel title={runtimeActionPlanTitle(locale)} rows={searchActionRows} />
      <DistributionPanel title={localeText(locale, "Search focus", "搜索重点")} rows={searchFocusRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">{manualOverridesHeading(locale)}</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only to test one alternate search path after the live read is stable.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {manualOverridesToggle(locale, showOverrides)}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-4">
              <Field label="Category or browse path">
                <SelectInput value={category} onChange={(e) => setCategory(e.target.value)}>
                  <option value="">Use detected category after live load</option>
                  {renderOptionGroups(calculatorCategoryOptionGroups)}
                </SelectInput>
              </Field>
              <Field label="Item type wording">
                <TextInput value={itemType} onChange={(e) => setItemType(e.target.value)} placeholder="Pulled from the live browse path" />
              </Field>
              <Field label="Target keywords">
                <TextInput
                  value={targetKeywords}
                  onChange={(e) => setTargetKeywords(e.target.value)}
                  placeholder="Leave empty until the live PDP drafts the first keyword pack"
                />
              </Field>
              <Field label="Current BSR">
                <NumberInput value={currentRank} min="0" step="1" onChange={(e) => setCurrentRank(Number(e.target.value))} />
              </Field>
            </div>
            <div className="grid gap-2.5 md:grid-cols-2">
              <Field label="Listing title">
                <TextInput value={listingTitle} onChange={(e) => setListingTitle(e.target.value)} placeholder="Pulled from the live PDP" />
              </Field>
              <Field label="Backend search terms">
                <TextInput
                  value={backendTerms}
                  onChange={(e) => setBackendTerms(e.target.value)}
                  placeholder="Pulled from the live PDP or your keyword system"
                />
              </Field>
            </div>
            <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-3">
              <Checkbox label="A+ content is live" checked={hasAPlus} onChange={setHasAPlus} />
              <Field label="Visible review count">
                <NumberInput value={reviewCount} min="0" step="1" onChange={(e) => setReviewCount(Number(e.target.value))} />
              </Field>
            </div>
          </div>
        ) : null}
      </div>
    </RuntimeShell>
  );
}

function VariationStrategyRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [category, setCategory] = useState("home__root-home-kitchen-tth");
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("B0GYRT3FNL");
  const [variationTheme, setVariationTheme] = useState("style");
  const [childCount, setChildCount] = useState(1);
  const [sameCoreProduct, setSameCoreProduct] = useState(true);
  const [sameBrand, setSameBrand] = useState(true);
  const [differsOnlyByTheme, setDiffersOnlyByTheme] = useState(true);
  const [mixedBundleLogic, setMixedBundleLogic] = useState(false);
  const [titlesAligned, setTitlesAligned] = useState(true);
  const [reviewBalanceHealthy, setReviewBalanceHealthy] = useState(true);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [showOverrides, setShowOverrides] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }

      setSnapshot(payload);
      const colorCount = payload.colorOptions.length;
      const sizeCount = payload.sizeOptions.length;
      const inferredTheme =
        colorCount >= 2
          ? "color"
          : sizeCount >= 2
            ? "size"
            : /pack|count|set/i.test(payload.title)
              ? "pack"
              : "style";
      setVariationTheme(inferredTheme);
      setChildCount(Math.max(colorCount, sizeCount, 1));
      setSameCoreProduct(true);
      setSameBrand(true);
      setDiffersOnlyByTheme(colorCount >= 2 || sizeCount >= 2);
      setTitlesAligned(true);
      setMixedBundleLogic(inferredTheme !== "pack" && /bundle|kit|set of|multi-pack/i.test(payload.title));
      setReviewBalanceHealthy(!/bundle|kit|set of|multi-pack/i.test(payload.title));

      const matchedCategory = inferCategoryOption(payload, complianceCategoryOptionGroups);
      if (matchedCategory) {
        setCategory(matchedCategory);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(
    () =>
      evaluateVariationStrategy({
        category,
        variationTheme,
        childCount,
        sameCoreProduct,
        sameBrand,
        differsOnlyByTheme,
        mixedBundleLogic,
        titlesAligned,
        reviewBalanceHealthy,
      }),
    [
      category,
      childCount,
      differsOnlyByTheme,
      mixedBundleLogic,
      reviewBalanceHealthy,
      sameBrand,
      sameCoreProduct,
      titlesAligned,
      variationTheme,
    ],
  );

  const detectedCategoryLabel = useMemo(() => {
    for (const group of complianceCategoryOptionGroups) {
      const option = group.options.find((item) => item.value === category);
      if (option) {
        return option.label;
      }
    }
    return "Not matched yet";
  }, [category]);

  const variationAuditRows = useMemo(
    () => [
      {
        label: "Detected category",
        value: detectedCategoryLabel,
        detail: snapshot?.breadcrumbs.length ? snapshot.breadcrumbs.join(" / ") : "Using current category mapping",
      },
      {
        label: "Detected theme",
        value: variationTheme,
        detail:
          snapshot && (snapshot.colorOptions.length > 1 || snapshot.sizeOptions.length > 1)
            ? "Inferred from visible selectors on the live page"
            : "Fallback inferred from copy and structure",
      },
      {
        label: "Visible child signal",
        value: `${childCount}`,
        detail:
          snapshot && (snapshot.colorOptions.length > 0 || snapshot.sizeOptions.length > 0)
            ? `Colors: ${snapshot.colorOptions.length}, Sizes: ${snapshot.sizeOptions.length}`
            : "No strong selector count was visible",
      },
      {
        label: "Merge risk",
        value: mixedBundleLogic || !differsOnlyByTheme ? "At risk" : "Usable",
        detail: mixedBundleLogic
          ? "Bundle or multi-pack logic is mixed into the family."
          : differsOnlyByTheme
            ? "Children look close enough to one true variation theme."
            : "Children appear to differ by more than one theme.",
      },
    ],
    [childCount, detectedCategoryLabel, differsOnlyByTheme, mixedBundleLogic, snapshot, variationTheme],
  );

  const variationAuditLines = useMemo(() => {
    const lines = [];
    if (snapshot) {
      lines.push(`Detected category path: ${snapshot.breadcrumbs.length ? snapshot.breadcrumbs.join(" / ") : detectedCategoryLabel}.`);
      lines.push("Theme, child-count signal, and merge risk were pulled from the live listing.");
    }
    lines.push("Only use manual overrides when the live page hides the true family structure or you are planning a merge or split.");
    return lines;
  }, [detectedCategoryLabel, snapshot]);

  const variationActionRows = useMemo(() => {
    const firstMove =
      !snapshot
        ? {
            label: "First move",
            value: "Load the live family first",
            detail: "Variation decisions are too easy to get wrong when the selector structure and visible children are still unknown.",
          }
        : mixedBundleLogic
          ? {
              label: "First move",
              value: "Split bundles and packs out of the family",
              detail: "Mixed bundle logic is one of the fastest ways to turn a usable family into a variation-policy problem.",
            }
          : !differsOnlyByTheme
            ? {
                label: "First move",
                value: "Reduce the family to one true variation axis",
                detail: "If children differ by more than one core dimension, the parent starts behaving like a category bucket instead of a variation family.",
              }
            : !titlesAligned
              ? {
                  label: "First move",
                  value: "Normalize child-title structure",
                  detail: "Misaligned child titles confuse the family logic and make the listing feel stitched together.",
                }
              : !reviewBalanceHealthy
                ? {
                    label: "First move",
                    value: "Audit review spillover risk",
                    detail: "An unhealthy review mix can poison the family even when the structural theme is technically valid.",
                  }
                : childCount < 2
                  ? {
                      label: "First move",
                      value: "Add or expose real child selection",
                      detail: "A single-child parent does not need family complexity unless another child is genuinely on deck.",
                    }
                  : {
                      label: "First move",
                      value: `Keep the family on ${variationTheme}`,
                      detail: "The structure is coherent enough that the next job is clean execution rather than more abstract family debate.",
                    };

    return [
      firstMove,
      !snapshot
        ? {
            label: "Execution owner",
            value: "Variation owner",
            detail: "Variation work should start with the operator who can inspect the real live family before touching structure decisions.",
          }
        : mixedBundleLogic
          ? {
              label: "Execution owner",
              value: "Catalog structure owner",
              detail: "Bundle contamination in a family should be fixed by the person who owns parent-child structure, not by copy cleanup.",
            }
          : !differsOnlyByTheme
            ? {
                label: "Execution owner",
                value: "Variation governance owner",
                detail: "If children vary on too many axes, one owner has to narrow the family before policy risk spreads.",
              }
            : !titlesAligned
              ? {
                  label: "Execution owner",
                  value: "Listing ops owner",
                  detail: "Misaligned child titles belong to the team controlling child-level merchandising consistency.",
                }
              : !reviewBalanceHealthy
                ? {
                    label: "Execution owner",
                    value: "Reputation owner",
                    detail: "Review spillover risk should be owned by the team protecting family-level trust and child cleanliness.",
                  }
                : childCount < 2
                  ? {
                      label: "Execution owner",
                      value: "Assortment owner",
                      detail: "A one-child family needs a real child strategy from the person deciding whether the parent should exist at all.",
                    }
                  : {
                      label: "Execution owner",
                      value: "Variation launch owner",
                      detail: "Once the family is coherent, one owner should keep the live child experience clean across selectors and buyability.",
                    },
      {
        label: "Do not cross",
        value:
          !snapshot
            ? "Do not restructure the family before loading the live variation page"
            : mixedBundleLogic
              ? "Do not mix bundles and true child variants in one family"
              : !differsOnlyByTheme
                ? "Do not let one parent carry multiple variation axes"
                : "Do not keep a parent alive just because it exists already",
        detail:
          !snapshot
            ? "Variation work gets expensive fast when the selector structure is guessed instead of inspected."
            : mixedBundleLogic
              ? "Bundle contamination is one of the fastest ways to turn a usable family into a policy-risk family."
              : !differsOnlyByTheme
                ? "When children differ by more than one core dimension, the parent stops behaving like a real variation family."
                : "A weak or unnecessary parent should be simplified, not defended out of habit.",
      },
      {
        label: "Then do",
        value: "Check titles, swatches, and child buyability together",
        detail: "Variation quality breaks at the shopper surface first, not only in the backend family relationship.",
      },
      {
        label: "Watch",
        value: "Selector-to-offer mismatch",
        detail: "Families often look valid in theory while hiding broken child UX, weak titles, or mixed-offer logic on the page.",
      },
    ];
  }, [childCount, differsOnlyByTheme, mixedBundleLogic, reviewBalanceHealthy, snapshot, titlesAligned, variationTheme]);

  const variationInputRows = useMemo(
    () => [
      ...variationAuditRows,
      {
        label: "Execution call",
        value: variationActionRows[0]?.value ?? "Variation decision pending",
        detail: variationActionRows[1]?.value
          ? `${variationActionRows[1].value} owns the first family-structure fix until the same family baseline is rechecked.`
          : "Assign one variation owner before the family keeps drifting.",
      },
    ],
    [variationActionRows, variationAuditRows],
  );

  const variationFocusRows = useMemo(
    () =>
      buildVariationFocusRows({
        snapshot,
        variationTheme,
        childCount,
        mixedBundleLogic,
        differsOnlyByTheme,
        titlesAligned,
        reviewBalanceHealthy,
      }),
    [childCount, differsOnlyByTheme, mixedBundleLogic, reviewBalanceHealthy, snapshot, titlesAligned, variationTheme],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 md:grid-cols-[1.4fr_0.8fr_auto] xl:grid-cols-[1.6fr_0.8fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      {snapshot ? (
        <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4 text-sm text-slate-700">
          <p className="font-semibold text-slate-950">Visible family signals from the live page</p>
          <div className="mt-2 grid gap-2 md:grid-cols-2 xl:grid-cols-4">
            <div>Color options: {snapshot.colorOptions.length ? snapshot.colorOptions.join(", ") : "None visible"}</div>
            <div>Size options: {snapshot.sizeOptions.length ? snapshot.sizeOptions.join(", ") : "None visible"}</div>
            <div>Selected color: {snapshot.selectedColor ?? "Not shown"}</div>
            <div>Selected size: {snapshot.selectedSize ?? "Not shown"}</div>
          </div>
        </div>
      ) : null}
      <AuditNote lines={variationAuditLines} />
      <DistributionPanel title="Live variation-strategy analysis" rows={variationInputRows} />
      <DistributionPanel title="This variation call" rows={variationActionRows} />
      <DistributionPanel title="Family posture" rows={variationFocusRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">{manualOverridesHeading(locale)}</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Use this only when you know the family structure is different from what the live page exposes.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {manualOverridesToggle(locale, showOverrides)}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-4">
              <Field label="Product category">
                <SelectInput value={category} onChange={(e) => setCategory(e.target.value)}>
                  {renderOptionGroups(complianceCategoryOptionGroups)}
                </SelectInput>
              </Field>
              <Field label="Variation theme">
                <SelectInput value={variationTheme} onChange={(e) => setVariationTheme(e.target.value)}>
                  {renderOptions(variationThemeOptions)}
                </SelectInput>
              </Field>
              <Field label="Child ASIN count">
                <NumberInput value={childCount} min="1" step="1" onChange={(e) => setChildCount(Number(e.target.value))} />
              </Field>
            </div>
            <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-3 2xl:grid-cols-6">
              <Checkbox label="All children are the same core product" checked={sameCoreProduct} onChange={setSameCoreProduct} />
              <Checkbox label="All children are under the same brand" checked={sameBrand} onChange={setSameBrand} />
              <Checkbox label="Children differ only by the chosen variation theme" checked={differsOnlyByTheme} onChange={setDiffersOnlyByTheme} />
              <Checkbox label="Bundles or mixed pack logic are included" checked={mixedBundleLogic} onChange={setMixedBundleLogic} />
              <Checkbox label="Child titles stay structurally aligned" checked={titlesAligned} onChange={setTitlesAligned} />
              <Checkbox label="Review balance across children looks healthy" checked={reviewBalanceHealthy} onChange={setReviewBalanceHealthy} />
            </div>
          </div>
        ) : null}
      </div>
    </RuntimeShell>
  );
}

function PriceTrackerRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [ownAsinOrUrl, setOwnAsinOrUrl] = useState("");
  const [competitorInputs, setCompetitorInputs] = useState("");
  const [responseObjective, setResponseObjective] = useState("balanced-watch");
  const [marketPosture, setMarketPosture] = useState("match-pack");
  const [decisionUrgency, setDecisionUrgency] = useState("this-week");
  const [alertDelta, setAlertDelta] = useState(5);
  const [showOverrides, setShowOverrides] = useState(false);
  const [showMarginGuardrail, setShowMarginGuardrail] = useState(false);
  const [currentNetMarginRate, setCurrentNetMarginRate] = useState(0);
  const [minimumMarginRate, setMinimumMarginRate] = useState(0);
  const [ownSnapshot, setOwnSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [competitorSnapshots, setCompetitorSnapshots] = useState<AmazonListingSnapshot[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const pricePlan = useMemo(
    () => inferPriceTrackerPlan(ownSnapshot, competitorSnapshots),
    [competitorSnapshots, ownSnapshot],
  );
  const responsePlan = useMemo(
    () =>
      inferPriceResponsePlan({
        ownSnapshot,
        competitorSnapshots,
        responseObjective,
        marketPosture,
        decisionUrgency,
      }),
    [competitorSnapshots, decisionUrgency, marketPosture, ownSnapshot, responseObjective],
  );

  useEffect(() => {
    if (showMarginGuardrail) {
      return;
    }
    setAlertDelta(responsePlan.suggestedDelta);
  }, [responsePlan.suggestedDelta, showMarginGuardrail]);

  async function loadComparison() {
    try {
      setLoading(true);
      setError("");
      const ownResponse = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(ownAsinOrUrl)}`,
      );
      const ownPayload = (await ownResponse.json()) as AmazonListingSnapshot | { error: string };
      if (!ownResponse.ok || "error" in ownPayload) {
        throw new Error("error" in ownPayload ? ownPayload.error : "Failed to load own listing.");
      }

      const candidates = splitAsinCandidates(competitorInputs).slice(0, 4);
      const loadedCompetitors: AmazonListingSnapshot[] = [];
      for (const candidate of candidates) {
        const response = await fetch(
          `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(candidate)}`,
        );
        const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
        if (response.ok && !("error" in payload)) {
          loadedCompetitors.push(payload);
        }
      }

      setOwnSnapshot(ownPayload);
      setCompetitorSnapshots(loadedCompetitors);
    } catch (fetchError) {
      setOwnSnapshot(null);
      setCompetitorSnapshots([]);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load price comparison set.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(() => {
    const executionOwner =
      !ownSnapshot
        ? "Price-watch owner"
        : !competitorSnapshots.length
          ? "Competitive watch owner"
          : showMarginGuardrail && (currentNetMarginRate <= 0 || minimumMarginRate <= 0)
            ? "Pricing / finance owner"
            : "Response owner";
    const executionCall =
      !ownSnapshot
        ? "Load your live PDP first"
        : !competitorSnapshots.length
          ? "Build a real competitor watch set"
          : showMarginGuardrail && (currentNetMarginRate <= 0 || minimumMarginRate <= 0)
            ? "Set the real profit guardrail"
            : "Decide whether the next move is price, proof, or patience";

    if (!ownSnapshot || !isSnapshotDecisionGrade(ownSnapshot)) {
      return {
        headline: !ownSnapshot
          ? "Price tracker is waiting on your live offer baseline"
          : "Price tracker needs a stronger own-offer read first",
        summary:
          "Use this watch to decide whether pricing work stays closed until the live offer baseline is real, whether the competitor set needs rebuilding, or whether the team is finally ready for a controlled response rule.",
        metrics: [
          {
            label: "Current result",
            value: !ownSnapshot ? "Own offer baseline missing" : "Own offer evidence is still thin",
            detail: !ownSnapshot
              ? "Load your ASIN or product URL so price, review, and offer context come from the live PDP."
              : "The own listing needs a stronger live evidence read before any alert should shape action.",
          },
          {
            label: "Execution call",
            value: executionCall,
            detail: `${executionOwner} owns the first watch blocker until the own-offer baseline is decision-grade.`,
          },
          {
            label: "First move",
            value: executionCall,
            detail: !ownSnapshot
              ? "Do not set reaction rules before your own live offer is visible."
              : "Fix the evidence blocker before treating alerts as operating instructions.",
          },
          {
            label: "Execution owner",
            value: executionOwner,
            detail: "One owner clears the first pricing blocker before alerts turn into noise or spread into policy.",
          },
        ],
        recommendations: [
          "Start with your own live offer before building competitor alerts.",
          "Do not automate a response when the own-offer baseline is still uncertain.",
        ],
        status: {
          label: !ownSnapshot ? "Price-watch baseline is incomplete" : "Own-offer evidence needs review",
          tone: "warning",
        },
        missingItems: [
          !ownSnapshot ? "Live offer baseline" : "Stronger own-offer evidence",
          competitorSnapshots.length ? "" : "Competitor watch set",
        ].filter(Boolean),
        nextSteps: [
          !ownSnapshot ? "Load your own ASIN or Amazon URL." : "Reload the own PDP and verify live offer evidence.",
          "Keep one owner on the first watch blocker until the same offer baseline is rechecked.",
          "Only then decide whether the alert warrants a price move at all.",
        ],
        actionStance: {
          label: !ownSnapshot ? "Do not watch price without your own offer baseline" : "Do not react from weak own-offer evidence",
          tone: "warning",
          detail: !ownSnapshot
            ? "Clear the blind spot first. Alerts are not allowed to stand in for a missing own-offer baseline."
            : "If the own-offer read is weak, the next move is evidence repair, not pricing reflex.",
        },
      } satisfies ToolEvaluation;
    }
    if (competitorSnapshots.length === 0) {
      return {
        headline: "Price tracker needs a real competitor watch set",
        summary:
          "Without live competitor references, an alert delta is only a preference. Build the market surface first, then decide whether any price move deserves action.",
        metrics: [
          {
            label: "Current result",
            value: "Competitor watch set missing",
            detail: "No live competitor PDPs are loaded yet.",
          },
          {
            label: "Execution call",
            value: executionCall,
            detail: `${executionOwner} owns the first market-watch blocker until the competitor pack is stable enough to guide reactions.`,
          },
          {
            label: "First move",
            value: "Build a real competitor watch set",
            detail: "Use direct substitutes buyers would actually compare against before turning deltas into response rules.",
          },
          {
            label: "Execution owner",
            value: executionOwner,
          detail: "One owner assembles the market pack before alerts start driving policy.",
          },
        ],
        recommendations: [
          "Track direct substitutes, not aspirational leaders and random neighbors in one list.",
          "Do not set alert logic until the market pack is real enough to explain the move.",
        ],
        status: {
          label: "Competitor watch set is incomplete",
          tone: "warning",
        },
        missingItems: ["Competitor watch set"],
        nextSteps: [
          "Load direct competitor ASINs.",
          "Keep one owner on watch-set quality.",
          "Re-run the watch after the market pack is real.",
        ],
        actionStance: {
          label: "Do not turn alert deltas into strategy without competitors",
          tone: "warning",
          detail: "A price alert with no market context creates fake urgency and usually sends the team to the wrong lever first.",
        },
      } satisfies ToolEvaluation;
    }

    const ownPrice = parseCurrencyAmount(ownSnapshot?.priceText);
    const ownRating = parseRatingValue(ownSnapshot?.ratingText);
    const competitorPrices = competitorSnapshots
      .map((item) => parseCurrencyAmount(item.priceText))
      .filter((value) => value > 0);
    const competitorRatings = competitorSnapshots
      .map((item) => parseRatingValue(item.ratingText))
      .filter((value) => value > 0);

    return evaluatePriceTracker({
      ownPrice,
      competitorCount: competitorPrices.length,
      averageCompetitorPrice: competitorPrices.length
        ? competitorPrices.reduce((sum, value) => sum + value, 0) / competitorPrices.length
        : 0,
      lowestCompetitorPrice: competitorPrices.length ? Math.min(...competitorPrices) : 0,
      highestCompetitorPrice: competitorPrices.length ? Math.max(...competitorPrices) : 0,
      alertDelta,
      ownRating,
      averageCompetitorRating: competitorRatings.length
        ? competitorRatings.reduce((sum, value) => sum + value, 0) / competitorRatings.length
        : 0,
      ownReviewCount: parseReviewCountValue(ownSnapshot?.reviewCountText),
      averageCompetitorReviewCount: competitorSnapshots.length
        ? competitorSnapshots.reduce((sum, item) => sum + parseReviewCountValue(item.reviewCountText), 0) / competitorSnapshots.length
        : 0,
      ownHasAPlus: ownSnapshot?.hasAPlus ?? false,
      aPlusCompetitorCount: competitorSnapshots.filter((item) => item.hasAPlus).length,
    });
  }, [alertDelta, competitorSnapshots, ownSnapshot]);

  const priceDecisionRows = useMemo(
    () =>
      buildPriceDecisionRows({
        ownSnapshot,
        competitorSnapshots,
        alertDelta,
        currentNetMarginRate,
        minimumMarginRate,
      }),
    [alertDelta, competitorSnapshots, currentNetMarginRate, minimumMarginRate, ownSnapshot],
  );

  const auditLines = useMemo(() => {
    const lines: string[] = [];
    if (ownSnapshot) {
      const evidenceStatus = getSnapshotEvidenceStatus(ownSnapshot);
      lines.push("Live price-watch mode loaded the current PDP so price, review, and A+ context come from the live page.");
      lines.push(`Evidence quality: ${evidenceStatus.label}. ${evidenceStatus.detail}`);
      if (evidenceStatus.level !== "complete") {
        lines.push("Keep the watch in evidence-gathering mode until the own listing snapshot is decision-grade.");
      }
    } else {
      lines.push("Load your ASIN first so the watch starts from live PDP evidence, not memory.");
    }
    if (!competitorSnapshots.length) {
      lines.push("Competitor watch entries are still missing. Alert rules stay thin until the live comparison set is loaded.");
    } else {
      lines.push("Decide whether the next move is price, proof, or patience. Do not let price alerts operate in isolation.");
    }
    if (ownSnapshot && competitorSnapshots.length) {
      lines.push(`Response brief: ${responsePlan.responseBrief}`);
      lines.push(`System draft: ${formatUsd(responsePlan.suggestedDelta)} price-watch band for a ${responseObjective.replace(/-/g, " ")} posture.`);
    }
    return lines;
  }, [competitorSnapshots.length, ownSnapshot, responseObjective, responsePlan.responseBrief, responsePlan.suggestedDelta]);

  const priceAuditRows = useMemo(
    () => [
      {
        label: "Own PDP",
        value: ownSnapshot?.asin || "Missing",
        detail: ownSnapshot?.priceText || "Load your live listing first",
      },
      {
        label: "Competitor set",
        value: `${competitorSnapshots.length}`,
        detail: competitorSnapshots.length ? "Loaded from live competitor PDPs" : "No live competitor set yet",
      },
      {
        label: "System alert band",
        value: formatUsd(roundNumber(alertDelta)),
        detail: showOverrides
          ? "Manual override for what price move should trigger attention."
          : "System draft for when price movement deserves a review.",
      },
      {
        label: "Guardrail mode",
        value: showMarginGuardrail ? "Open" : "Closed",
        detail: showMarginGuardrail ? "Private margin thresholds are active for this read" : "Pure PDP comparison mode",
      },
    ],
    [alertDelta, competitorSnapshots.length, ownSnapshot, showMarginGuardrail, showOverrides],
  );

  const priceActionQueueRows = useMemo(() => {
    const firstMove =
      !ownSnapshot
        ? {
            label: "First move",
            value: "Load your live PDP first",
            detail: "No watch rule is valid while your own offer evidence is still missing.",
          }
        : !competitorSnapshots.length
          ? {
              label: "First move",
              value: "Build a real competitor watch set",
              detail: "Without market context, an alert delta is still preference, not policy.",
            }
          : showMarginGuardrail && (currentNetMarginRate <= 0 || minimumMarginRate <= 0)
            ? {
                label: "First move",
                value: "Set the real profit guardrail",
                detail: "A price alert becomes dangerous when the team can react faster than it can protect contribution margin.",
              }
            : {
                label: "First move",
                value: "Decide whether the next move is price, proof, or patience",
                detail: "The baseline is finally strong enough to choose the right response instead of gathering more basic evidence.",
              };
    const doNotCrossRow =
      priceDecisionRows.watchRows.find((row) => row.label === "Do not cross") ??
      (!ownSnapshot
        ? {
            label: "Do not cross",
            value: "Do not react to price before loading your own offer baseline",
            detail: "Without your live offer, a price alert can push the team into false urgency.",
          }
        : !competitorSnapshots.length
          ? {
              label: "Do not cross",
              value: "Do not set alert policy without a real market set",
              detail: "One product and no substitutes is not a watchlist. It is just guesswork.",
            }
          : showMarginGuardrail && (currentNetMarginRate <= 0 || minimumMarginRate <= 0)
            ? {
                label: "Do not cross",
                value: "Do not let price alerts outrun your margin floor",
                detail: "A fast reaction rule without a profit stop line trains the team to chase movement instead of protect contribution.",
              }
            : {
                label: "Do not cross",
                value: "Do not let the lowest visible price become the only rule",
                detail: "Some alerts should send you to proof, offer quality, or patience before they send you to a price cut.",
              });

    return [
      firstMove,
      {
        label: "Response brief",
        value: responsePlan.responseBrief,
        detail: `${responsePlan.postureBrief} ${responsePlan.urgencyBrief}`,
      },
      !ownSnapshot
        ? {
            label: "Execution owner",
            value: "Price-watch owner",
            detail: "Price monitoring should begin with the operator who owns the live offer baseline, not with spreadsheet memory.",
          }
        : !competitorSnapshots.length
          ? {
              label: "Execution owner",
              value: "Competitive watch owner",
              detail: "Without a live competitor set, someone has to own building the watch surface before alerts are meaningful.",
            }
          : showMarginGuardrail && (currentNetMarginRate <= 0 || minimumMarginRate <= 0)
            ? {
                label: "Execution owner",
                value: "Pricing / finance owner",
                detail: "If margin guardrails are open but blank, pricing and finance should set them before any reaction rule goes live.",
              }
            : {
                label: "Execution owner",
              value: "Response owner",
              detail: "One operator owns the response ladder so each alert resolves into price, proof, or patience instead of a multi-team scramble.",
            },
      !ownSnapshot
        ? {
            label: "Do this now",
            value: "Load your live offer before discussing alerts",
            detail: "A price watch without your own live offer baseline is still just opinion dressed up as monitoring.",
          }
        : !competitorSnapshots.length
          ? {
              label: "Do this now",
              value: "Load 3 to 4 direct substitutes buyers would actually compare",
              detail: "Do not mix aspirational leaders and weak neighbors into the same watch set.",
            }
          : showMarginGuardrail && (currentNetMarginRate <= 0 || minimumMarginRate <= 0)
            ? {
                label: "Do this now",
                value: "Set the minimum margin floor before any response rule goes live",
                detail: "A fast alert without a margin stop line trains the team to react instead of decide.",
              }
            : {
                label: "Do this now",
                value: priceDecisionRows.watchRows.find((row) => row.label === "Do this now")?.value ?? "Check whether price is really the first lever",
                detail: priceDecisionRows.watchRows.find((row) => row.label === "Do this now")?.detail ?? "Some alerts should send you to proof or offer quality before they send you to price.",
              },
      doNotCrossRow,
      {
        label: "Then do",
        value: "Check if the alert warrants a price move at all",
        detail: "Route the alert through reviews, A+, and offer quality before you give pricing permission to move the visible offer.",
      },
      {
        label: "Watch",
        value: "Reaction speed over decision quality",
        detail: "The failure mode is winning the reaction-speed contest while losing contribution margin or offer quality in the same hour.",
      },
    ];
  }, [competitorSnapshots.length, currentNetMarginRate, minimumMarginRate, ownSnapshot, priceDecisionRows.watchRows, responsePlan.postureBrief, responsePlan.responseBrief, responsePlan.urgencyBrief, showMarginGuardrail]);

  const priceEscalationRows = useMemo(
    () =>
      buildPriceEscalationRows({
        ownSnapshot,
        competitorSnapshots,
        alertDelta,
        currentNetMarginRate,
        minimumMarginRate,
      }),
    [alertDelta, competitorSnapshots, currentNetMarginRate, minimumMarginRate, ownSnapshot],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_1fr_0.8fr_auto]">
        <Field label="Your ASIN or Amazon product URL">
          <TextInput
            value={ownAsinOrUrl}
            onChange={(e) => setOwnAsinOrUrl(e.target.value)}
            placeholder="Paste your ASIN or Amazon URL"
            spellCheck={false}
          />
        </Field>
        <Field label="Competitor ASINs or URLs">
          <TextAreaInput
            value={competitorInputs}
            onChange={(e) => setCompetitorInputs(e.target.value)}
            placeholder={"One competitor ASIN or URL per line"}
            spellCheck={false}
          />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadComparison} disabled={loading || !ownAsinOrUrl.trim()}>
            {runtimeActionButtonLabel(locale, loading, "Load comparison and generate result", "加载对比并生成结果")}
          </ActionButton>
        </div>
      </div>
      <AuditNote lines={auditLines} />
      <div className="rounded-xl border border-teal-200 bg-teal-50 px-3 py-3 text-sm text-teal-950">
        {runtimeResultHint(locale)}
      </div>
      <DistributionPanel title={runtimeResultTitle(locale)} rows={priceAuditRows} />
      <DistributionPanel title={runtimeActionPlanTitle(locale)} rows={priceActionQueueRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">{manualOverridesHeading(locale)}</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Use this only when you want to override the system draft watch posture, response urgency, or alert band.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {manualOverridesToggle(locale, showOverrides)}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-4">
              <Field label="Response objective">
                <SelectInput value={responseObjective} onChange={(e) => setResponseObjective(e.target.value)}>
                  <option value="balanced-watch">Balanced watch</option>
                  <option value="margin-defense">Margin defense</option>
                  <option value="conversion-defense">Conversion defense</option>
                </SelectInput>
              </Field>
              <Field label="Market posture">
                <SelectInput value={marketPosture} onChange={(e) => setMarketPosture(e.target.value)}>
                  <option value="match-pack">Match pack</option>
                  <option value="premium">Premium</option>
                  <option value="value">Value</option>
                </SelectInput>
              </Field>
              <Field label="Decision urgency">
                <SelectInput value={decisionUrgency} onChange={(e) => setDecisionUrgency(e.target.value)}>
                  <option value="same-day">Same day</option>
                  <option value="this-week">This week</option>
                  <option value="monitor">Monitor</option>
                </SelectInput>
              </Field>
              <Field label="Alert delta">
                <NumberInput value={alertDelta} min="0" step="0.5" onChange={(e) => setAlertDelta(Number(e.target.value))} />
              </Field>
            </div>
          </div>
        ) : null}
      </div>
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Optional profit guardrail</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when you want to test whether reacting to a price alert would cut below your target contribution margin.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowMarginGuardrail((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showMarginGuardrail ? "Hide margin guardrail" : "Test profit impact"}
          </button>
        </div>
        {showMarginGuardrail ? (
          <div className="mt-4 grid gap-2.5 md:grid-cols-2 xl:grid-cols-2">
            <Field label="Current net margin %">
              <NumberInput value={currentNetMarginRate} min="0" step="0.1" onChange={(e) => setCurrentNetMarginRate(Number(e.target.value))} />
            </Field>
            <Field label="Minimum acceptable margin %">
              <NumberInput value={minimumMarginRate} min="0" step="0.1" onChange={(e) => setMinimumMarginRate(Number(e.target.value))} />
            </Field>
          </div>
        ) : null}
      </div>
      <SnapshotPanel snapshot={ownSnapshot} error={error} loading={loading} />
      <CompetitorBoard own={ownSnapshot} competitors={competitorSnapshots} />
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title="Price verdict" rows={priceDecisionRows.verdictRows} />
        <DistributionPanel title={localeText(locale, "Response rules", "响应规则")} rows={priceDecisionRows.watchRows} />
        <DistributionPanel title="Proof context" rows={priceDecisionRows.proofRows} />
      </div>
      <DistributionPanel title="Escalation logic" rows={priceEscalationRows} />
    </RuntimeShell>
  );
}

function RankTrackerRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [ownAsinOrUrl, setOwnAsinOrUrl] = useState("B0GYRT3FNL");
  const [competitorInputs, setCompetitorInputs] = useState("B0G6K4VXK7\nB0FX2PRMFR\nB0CLNLL9RZ");
  const [rankObjective, setRankObjective] = useState("defend-band");
  const [responseLane, setResponseLane] = useState("mixed-diagnosis");
  const [decisionUrgency, setDecisionUrgency] = useState("this-week");
  const [targetKeywords, setTargetKeywords] = useState(
    "arched full length mirror, standing mirror, gold mirror, bedroom floor mirror",
  );
  const [alertThreshold, setAlertThreshold] = useState(5000);
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [ownSnapshot, setOwnSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [competitorSnapshots, setCompetitorSnapshots] = useState<AmazonListingSnapshot[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const rankPlan = useMemo(
    () => inferKeywordTrackerPlan(ownSnapshot, competitorSnapshots),
    [competitorSnapshots, ownSnapshot],
  );

  async function loadComparison() {
    try {
      setLoading(true);
      setError("");
      const ownResponse = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(ownAsinOrUrl)}`,
      );
      const ownPayload = (await ownResponse.json()) as AmazonListingSnapshot | { error: string };
      if (!ownResponse.ok || "error" in ownPayload) {
        throw new Error("error" in ownPayload ? ownPayload.error : "Failed to load own listing.");
      }

      const candidates = splitAsinCandidates(competitorInputs).slice(0, 4);
      const loadedCompetitors: AmazonListingSnapshot[] = [];
      for (const candidate of candidates) {
        const response = await fetch(
          `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(candidate)}`,
        );
        const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
        if (response.ok && !("error" in payload)) {
          loadedCompetitors.push(payload);
        }
      }

      setOwnSnapshot(ownPayload);
      setCompetitorSnapshots(loadedCompetitors);
      const nextResponsePlan = inferRankResponsePlan(ownPayload, loadedCompetitors, targetKeywords);
      if (!showAdvanced) {
        const nextPlan = inferKeywordTrackerPlan(ownPayload, loadedCompetitors);
        if (nextPlan.targetKeywords) {
          setTargetKeywords(nextPlan.targetKeywords);
        }
        setAlertThreshold(nextPlan.alertThreshold);
        setRankObjective(nextResponsePlan.rankObjective);
        setResponseLane(nextResponsePlan.responseLane);
        setDecisionUrgency(nextResponsePlan.decisionUrgency);
      } else if (!targetKeywords.trim()) {
        const nextPlan = inferKeywordTrackerPlan(ownPayload, loadedCompetitors);
        if (nextPlan.targetKeywords) {
          setTargetKeywords(nextPlan.targetKeywords);
        }
      }
    } catch (fetchError) {
      setOwnSnapshot(null);
      setCompetitorSnapshots([]);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load rank comparison set.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(() => {
    const trackedKeywordCount = targetKeywords.split(/[\n,]+/).map((item) => item.trim()).filter(Boolean).length;
    const fallbackPlan = inferRankExecutionPlan({
      hasOwnSnapshot: Boolean(ownSnapshot),
      competitorCount: competitorSnapshots.length,
      trackedKeywordCount,
      responseLane,
      decisionUrgency,
    });
    const competitorEvidence = getMultiSnapshotEvidenceStatus(
      competitorSnapshots,
      ["title", "breadcrumbs", "reviewCount"],
    );

    if (!ownSnapshot || !isCustomSnapshotDecisionGrade(ownSnapshot, ["title", "breadcrumbs", "reviewCount"])) {
      return {
        headline: !ownSnapshot
          ? "Rank tracker is waiting on your live PDP baseline"
          : "Rank tracker needs a stronger own-listing read first",
        summary:
          "Use this rank watch to decide whether the team should defend rank now, repair the live baseline first, or ignore noise until the listing read is decision-grade.",
        metrics: [
          {
            label: "Current result",
            value: !ownSnapshot ? "Own PDP missing" : "Own PDP evidence is thin",
            detail: !ownSnapshot
              ? "Load your ASIN or product URL so rank pressure is anchored to a real listing."
              : "The own PDP needs stronger title, breadcrumb, and review coverage before you trust the rank read.",
          },
          {
            label: "Execution call",
            value: fallbackPlan.decision,
            detail: `${fallbackPlan.proofPriority} | ${fallbackPlan.cadence}`,
          },
          {
            label: "First move",
            value: !ownSnapshot ? "Load your own ASIN first" : "Reload a stronger own PDP sample",
            detail: !ownSnapshot
              ? "Do not benchmark competitors until the tool has your live rank, proof, and browse path."
              : "Fix the own-listing evidence gap before escalating rank drops into a commercial response.",
          },
          {
            label: "Execution owner",
            value: fallbackPlan.owner,
            detail: `${fallbackPlan.watchout} Keep one owner on the first watchlist repair until the same live baseline is rechecked.`,
          },
        ],
        recommendations: [
          "Start with the listing you actually own before comparing against competitors.",
          "Keep the first pass narrow: one PDP, one competitor set, one watchlist.",
        ],
        status: {
          label: !ownSnapshot ? "Own listing baseline is missing" : "Own listing evidence needs review",
          tone: "warning",
        },
        missingItems: [
          !ownSnapshot ? "Own PDP snapshot" : "Stronger own-listing evidence",
          trackedKeywordCount ? "" : "Keyword watchlist",
        ].filter(Boolean),
        nextSteps: [
          !ownSnapshot ? "Load your own ASIN or Amazon URL." : "Reload the own PDP and verify live evidence fields.",
          "Keep one owner on the first rank-response decision.",
          "Only compare against competitors after your own baseline is decision-grade.",
        ],
        actionStance: {
          label: !ownSnapshot ? "Do not watch rank without your own baseline" : "Do not overreact to weak own-listing evidence",
          tone: "warning",
          detail: !ownSnapshot
            ? "Keep rank reactions closed until the tool can tell you when to act instead of dressing missing data up like a dashboard."
            : "If the own PDP read is thin, the next move is evidence repair, not commercial thrash.",
        },
      } satisfies ToolEvaluation;
    }
    if (competitorSnapshots.length > 0 && competitorEvidence.level === "weak") {
      return {
        headline: "Rank tracker needs a stronger competitor pack",
        summary:
          "Use this rank watch to decide whether the competitor pack is strong enough to explain pressure or whether the whole response should pause until the market sample is rebuilt.",
        metrics: [
          {
            label: "Current result",
            value: `${competitorSnapshots.length} competitors loaded`,
            detail: competitorEvidence.detail,
          },
          {
            label: "Execution call",
            value: fallbackPlan.decision,
            detail: `${fallbackPlan.proofPriority} | ${fallbackPlan.cadence}`,
          },
          {
            label: "First move",
            value: "Tighten the competitor sample",
            detail: "Replace weak or irrelevant ASINs before treating rank pressure as a price, proof, or keyword problem.",
          },
          {
            label: "Execution owner",
            value: fallbackPlan.owner,
            detail: `${fallbackPlan.watchout} Keep one owner on the competitor-pack repair until the same benchmark set is rechecked.`,
          },
        ],
        recommendations: [
          "Use direct substitutes buyers would compare against in the same search path.",
          "Do not mix aspirational leaders with weak substitutes in the same rank read.",
        ],
        status: {
          label: "Competitor evidence needs rebuild",
          tone: "warning",
        },
        missingItems: ["Stronger competitor evidence"],
        nextSteps: [
          "Replace weak competitor ASINs.",
          "Re-run the same keyword watchlist against a cleaner market pack.",
          "Only then decide whether rank pressure is commercial or catalog-driven.",
        ],
        actionStance: {
          label: "Treat this rank read as directional",
          tone: "warning",
          detail: "A thin competitor set makes every rank move look more dramatic and more explainable than it really is.",
        },
      } satisfies ToolEvaluation;
    }

    const currentRank =
      parseRankValue(ownSnapshot.bestSellersRank) || parseRankValue(ownSnapshot.subCategoryRank);
    const competitorRanks = competitorSnapshots
      .map((item) => parseRankValue(item.bestSellersRank) || parseRankValue(item.subCategoryRank))
      .filter((value) => value > 0);
    const ownPrice = parseCurrencyAmount(ownSnapshot.priceText);
    const competitorPrices = competitorSnapshots
      .map((item) => parseCurrencyAmount(item.priceText))
      .filter((value) => value > 0);
    const ownReviewCount = parseReviewCountValue(ownSnapshot.reviewCountText);
    const competitorReviewCounts = competitorSnapshots
      .map((item) => parseReviewCountValue(item.reviewCountText))
      .filter((value) => value > 0);
    const titleText = ownSnapshot.title.toLowerCase();
    const targetWords = tokenizeInputWords(targetKeywords);
    const titleCoverageCount = targetWords.filter((word) => titleText.includes(word)).length;

    return evaluateRankTracker({
      currentRank,
      competitorCount: competitorRanks.length,
      averageCompetitorRank: competitorRanks.length
        ? competitorRanks.reduce((sum, value) => sum + value, 0) / competitorRanks.length
        : 0,
      bestCompetitorRank: competitorRanks.length ? Math.min(...competitorRanks) : 0,
      targetKeywordCount: targetWords.length,
      titleCoverageCount,
      alertThreshold,
      cheaperCompetitorCount: competitorPrices.filter((price) => ownPrice > 0 && price < ownPrice).length,
      strongerReviewCompetitorCount: competitorReviewCounts.filter((count) => count > ownReviewCount).length,
      aPlusCompetitorCount: competitorSnapshots.filter((item) => item.hasAPlus).length,
      ownHasAPlus: ownSnapshot.hasAPlus,
      ownReviewCount,
      averageCompetitorReviewCount: competitorReviewCounts.length
        ? competitorReviewCounts.reduce((sum, value) => sum + value, 0) / competitorReviewCounts.length
        : 0,
      ownPrice,
      averageCompetitorPrice: competitorPrices.length
        ? competitorPrices.reduce((sum, value) => sum + value, 0) / competitorPrices.length
        : 0,
    });
  }, [alertThreshold, competitorSnapshots, ownSnapshot, targetKeywords]);

  const rankRows = useMemo(() => {
    const currentRank =
      parseRankValue(ownSnapshot?.bestSellersRank) || parseRankValue(ownSnapshot?.subCategoryRank);
    const competitorRanks = competitorSnapshots
      .map((item) => parseRankValue(item.bestSellersRank) || parseRankValue(item.subCategoryRank))
      .filter((value) => value > 0);
    const ownPrice = parseCurrencyAmount(ownSnapshot?.priceText);
    const competitorPrices = competitorSnapshots
      .map((item) => parseCurrencyAmount(item.priceText))
      .filter((value) => value > 0);
    const ownReviewCount = parseReviewCountValue(ownSnapshot?.reviewCountText);
    const competitorReviewCounts = competitorSnapshots
      .map((item) => parseReviewCountValue(item.reviewCountText))
      .filter((value) => value > 0);
    const titleText = ownSnapshot?.title.toLowerCase() ?? "";
    const targetWords = tokenizeInputWords(targetKeywords);
    const titleCoverageCount = targetWords.filter((word) => titleText.includes(word)).length;

    return buildRankDecisionRows({
      currentRank,
      averageCompetitorRank: competitorRanks.length
        ? competitorRanks.reduce((sum, value) => sum + value, 0) / competitorRanks.length
        : 0,
      bestCompetitorRank: competitorRanks.length ? Math.min(...competitorRanks) : 0,
      coverageCount: titleCoverageCount,
      targetKeywordCount: targetWords.length,
      ownPrice,
      averageCompetitorPrice: competitorPrices.length
        ? competitorPrices.reduce((sum, value) => sum + value, 0) / competitorPrices.length
        : 0,
      cheaperCompetitorCount: competitorPrices.filter((price) => ownPrice > 0 && price < ownPrice).length,
      strongerReviewCompetitorCount: competitorReviewCounts.filter((count) => count > ownReviewCount).length,
      aPlusCompetitorCount: competitorSnapshots.filter((item) => item.hasAPlus).length,
      competitorCount: competitorRanks.length,
    });
  }, [competitorSnapshots, ownSnapshot, targetKeywords]);

  const rankTrackerAuditLines = useMemo(() => {
    const lines = [];
    if (ownSnapshot) {
      const ownEvidence = getCustomSnapshotEvidenceStatus(ownSnapshot, [
        "title",
        "breadcrumbs",
        "reviewCount",
      ]);
      lines.push(`Own listing evidence: ${ownEvidence.label}. ${ownEvidence.detail}`);
    }
    if (competitorSnapshots.length) {
      const competitorEvidence = getMultiSnapshotEvidenceStatus(competitorSnapshots, [
        "title",
        "breadcrumbs",
        "reviewCount",
      ]);
      lines.push(`Competitor set quality: ${competitorEvidence.label}. ${competitorEvidence.detail}`);
      if (competitorEvidence.level !== "complete") {
        lines.push("Treat rank pressure and keyword-defend calls as directional until the competitor set has stronger live coverage.");
      }
    } else {
      lines.push("Load competitor ASINs so rank pressure is anchored to a real market baseline.");
    }
    if (ownSnapshot) {
      lines.push(
        `System draft: ${targetKeywords.split(/[\n,]+/).map((item) => item.trim()).filter(Boolean).length} tracked phrases with a ${rankPlan.alertThreshold.toLocaleString("en-US")} rank alert threshold.`,
      );
    }
    return lines;
  }, [competitorSnapshots, ownSnapshot, rankPlan.alertThreshold, targetKeywords]);
  const rankExecutionPlan = useMemo(
    () =>
      inferRankExecutionPlan({
        hasOwnSnapshot: Boolean(ownSnapshot),
        competitorCount: competitorSnapshots.length,
        trackedKeywordCount: targetKeywords.split(/[\n,]+/).map((item) => item.trim()).filter(Boolean).length,
        responseLane,
        decisionUrgency,
      }),
    [competitorSnapshots.length, decisionUrgency, ownSnapshot, responseLane, targetKeywords],
  );

  const rankAuditRows = useMemo(
    () => {
      const currentRank =
        parseRankValue(ownSnapshot?.bestSellersRank) || parseRankValue(ownSnapshot?.subCategoryRank);
      return [
        {
          label: "Own PDP",
          value: ownSnapshot?.asin || "Missing",
          detail: currentRank > 0 ? `Live rank #${currentRank.toLocaleString("en-US")}` : "No live rank parsed yet",
        },
        {
          label: "Competitor set",
          value: `${competitorSnapshots.length}`,
          detail: competitorSnapshots.length ? "Loaded from live competitor PDPs" : "No live competitor set yet",
        },
        {
          label: "Keyword watchlist",
          value: `${targetKeywords.split(/[\n,]+/).map((item) => item.trim()).filter(Boolean).length}`,
          detail: showAdvanced
            ? "Editable phrase watchlist for this run."
            : "System-drafted phrase watchlist from the live PDP and competitor set.",
        },
        {
          label: "Rank brief",
          value: `${rankObjective.replace(/-/g, " ")} / ${responseLane.replace(/-/g, " ")}`,
          detail: `${decisionUrgency.replace(/-/g, " ")} urgency for the current rank pass`,
        },
        {
          label: "Alert threshold",
          value: `${alertThreshold.toLocaleString("en-US")} ranks`,
          detail: showAdvanced
            ? "Manual override for when a rank gap should escalate into action."
            : "System-drafted gap size that should escalate into action.",
        },
        {
          label: "Execution call",
          value: rankExecutionPlan.decision,
          detail: `${rankExecutionPlan.proofPriority} | ${rankExecutionPlan.cadence}`,
        },
      ];
    },
    [alertThreshold, competitorSnapshots.length, decisionUrgency, ownSnapshot, rankExecutionPlan, rankObjective, responseLane, showAdvanced, targetKeywords],
  );

  const rankActionRows = useMemo(() => {
    return [
      {
        label: "First move",
        value: rankExecutionPlan.decision,
        detail: `${rankExecutionPlan.nextMove} Keep every non-primary diagnosis closed until this first rank explanation survives the next live read.`,
      },
      {
        label: "Execution owner",
        value: rankExecutionPlan.owner,
        detail: `${rankExecutionPlan.cadence}. One owner carries this diagnosis from alert to recheck. ${rankExecutionPlan.watchout}`,
      },
      {
        label: "Do not cross",
        value:
          !ownSnapshot
            ? "Do not treat rank drift as actionable before loading the live PDP"
            : responseLane === "content-coverage"
              ? "Do not blame price or proof before coverage gaps are checked"
              : responseLane === "proof-offer"
                ? "Do not keep rewriting keywords if proof or offer is the blocker"
                : "Do not stack multiple explanations into one rank move",
        detail:
          !ownSnapshot
            ? "Anchor the current listing first instead of narrating rank drift from memory."
            : responseLane === "content-coverage"
              ? "If relevance coverage is still weak, broader commercial moves will hide the root cause."
              : responseLane === "proof-offer"
                ? "Traffic gains rarely hold when the real problem is offer strength or trust proof."
                : "One clean diagnosis teaches more than a bundle of simultaneous hypotheses.",
      },
      {
        label: "Then do",
        value:
          decisionUrgency === "now"
            ? "Re-run after the first commercial fix"
            : decisionUrgency === "this-week"
              ? "Freeze the baseline and review once this cycle"
              : "Keep the same competitor set and monitor drift",
        detail:
          decisionUrgency === "now"
            ? "Do not stack multiple explanations at once. Make one commercial fix, then re-check whether rank moves before opening a second theory."
            : decisionUrgency === "this-week"
              ? "The next read should compare the same market pack rather than introduce a new benchmark or a new excuse."
              : "A stable baseline is more useful than hyperactive rank watching when the gap is still inside the band and no first fix has landed.",
      },
      {
        label: "Watch",
        value: rankExecutionPlan.proofPriority,
        detail: "Reopen the rank call only if the same keyword watchlist and the same competitor pack still show drift after the first fix lands, not because the team wants a fresh theory.",
      },
    ];
  }, [decisionUrgency, rankExecutionPlan]);

  const rankInputRows = useMemo(
    () => [
      ...rankAuditRows,
      {
        label: "Execution call",
        value: rankActionRows[0]?.value ?? "Rank decision pending",
        detail: rankActionRows[1]?.value
          ? `${rankActionRows[1].value} owns the first rank-response move until the same watchlist is rechecked.`
          : "Assign one rank owner before the watchlist turns into passive monitoring.",
      },
    ],
    [rankActionRows, rankAuditRows],
  );

  const rankEscalationRows = useMemo(
    () =>
      buildRankEscalationRows({
        ownSnapshot,
        competitorSnapshots,
        targetKeywords,
        alertThreshold,
      }),
    [alertThreshold, competitorSnapshots, ownSnapshot, targetKeywords],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_1fr_auto_auto]">
        <Field label="Your ASIN or Amazon product URL">
          <TextInput value={ownAsinOrUrl} onChange={(e) => setOwnAsinOrUrl(e.target.value)} />
        </Field>
        <Field label="Competitor ASINs or URLs">
          <TextAreaInput value={competitorInputs} onChange={(e) => setCompetitorInputs(e.target.value)} spellCheck={false} />
        </Field>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowAdvanced((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showAdvanced
              ? localeText(locale, "Hide advanced settings", "隐藏高级设置")
              : localeText(locale, "Adjust advanced settings", "调整高级设置")}
          </button>
        </div>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadComparison} disabled={loading || !ownAsinOrUrl.trim()}>
            {runtimeActionButtonLabel(locale, loading, "Load rank data and generate result", "加载排名并生成结果")}
          </ActionButton>
        </div>
      </div>
      <div className="grid gap-2.5 md:grid-cols-[0.95fr_0.95fr_0.95fr]">
        <Field label="Rank objective">
          <SelectInput value={rankObjective} onChange={(e) => setRankObjective(e.target.value)}>
            <option value="recover-rank">Recover rank</option>
            <option value="defend-band">Defend band</option>
            <option value="hold-lead">Hold lead</option>
          </SelectInput>
        </Field>
        <Field label="Response lane">
          <SelectInput value={responseLane} onChange={(e) => setResponseLane(e.target.value)}>
            <option value="content-coverage">Content coverage</option>
            <option value="proof-offer">Proof / offer</option>
            <option value="price-posture">Price posture</option>
            <option value="mixed-diagnosis">Mixed diagnosis</option>
          </SelectInput>
        </Field>
        <Field label="Decision urgency">
          <SelectInput value={decisionUrgency} onChange={(e) => setDecisionUrgency(e.target.value)}>
            <option value="now">Now</option>
            <option value="this-week">This week</option>
            <option value="monitor">Monitor</option>
          </SelectInput>
        </Field>
      </div>
      {showAdvanced ? (
        <div className="grid gap-2.5 md:grid-cols-[0.8fr_1.6fr_0.8fr]">
          <Field label="Marketplace">
            <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
              {renderOptions(amazonMarketplaces)}
            </SelectInput>
          </Field>
          <Field label="Target keywords">
            <TextAreaInput value={targetKeywords} onChange={(e) => setTargetKeywords(e.target.value)} spellCheck={false} />
          </Field>
          <Field label="Alert threshold">
            <NumberInput value={alertThreshold} min="100" step="100" onChange={(e) => setAlertThreshold(Number(e.target.value))} />
          </Field>
        </div>
      ) : null}
      <SnapshotPanel snapshot={ownSnapshot} error={error} loading={loading} />
      <AuditNote lines={rankTrackerAuditLines} />
      <div className="rounded-xl border border-teal-200 bg-teal-50 px-3 py-3 text-sm text-teal-950">
        {runtimeResultHint(locale)}
      </div>
      <DistributionPanel title={runtimeResultTitle(locale)} rows={rankInputRows} />
      <DistributionPanel title={runtimeActionPlanTitle(locale)} rows={rankActionRows} />
      <CompetitorBoard own={ownSnapshot} competitors={competitorSnapshots} />
      {ownSnapshot ? (
        <div className="grid gap-3 xl:grid-cols-2">
          <DistributionPanel title="Rank verdict" rows={rankRows.verdictRows} />
          <DistributionPanel title="Pressure map" rows={rankRows.pressureRows} />
        </div>
      ) : null}
      <DistributionPanel title="Escalation logic" rows={rankEscalationRows} />
    </RuntimeShell>
  );
}

function CompetitorMonitoringRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [competitorInputs, setCompetitorInputs] = useState("B0GYRT3FNL\nB0G6K4VXK7\nB0FX2PRMFR\nB0CLNLL9RZ");
  const [watchObjective, setWatchObjective] = useState("balanced-watch");
  const [disruptionFocus, setDisruptionFocus] = useState("balanced");
  const [responseCadence, setResponseCadence] = useState("normal");
  const [interruptionRule, setInterruptionRule] = useState("monitor-only");
  const [businessLens, setBusinessLens] = useState("balanced-defense");
  const [interruptionCadence, setInterruptionCadence] = useState("next-review");
  const [alertDelta, setAlertDelta] = useState(5);
  const [reviewAlertThreshold, setReviewAlertThreshold] = useState(75);
  const [cadenceDays, setCadenceDays] = useState(3);
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [snapshots, setSnapshots] = useState<AmazonListingSnapshot[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const monitoringPlan = useMemo(() => inferCompetitorMonitoringPlan(snapshots), [snapshots]);
  const watchPlan = useMemo(
    () =>
      inferCompetitorWatchPlan({
        snapshots,
        watchObjective,
        disruptionFocus,
        responseCadence,
      }),
    [disruptionFocus, responseCadence, snapshots, watchObjective],
  );
  const interruptionPlan = useMemo(
    () =>
      inferCompetitorInterruptionPlan({
        snapshots,
        watchObjective,
        disruptionFocus,
        responseCadence,
      }),
    [disruptionFocus, responseCadence, snapshots, watchObjective],
  );

  useEffect(() => {
    if (showAdvanced) {
      return;
    }
    setAlertDelta(watchPlan.alertDelta);
    setReviewAlertThreshold(watchPlan.reviewAlertThreshold);
    setCadenceDays(watchPlan.cadenceDays);
    setInterruptionRule(interruptionPlan.interruptionRule);
    setBusinessLens(interruptionPlan.businessLens);
    setInterruptionCadence(interruptionPlan.interruptionCadence);
  }, [
    interruptionPlan.businessLens,
    interruptionPlan.interruptionCadence,
    interruptionPlan.interruptionRule,
    showAdvanced,
    watchPlan.alertDelta,
    watchPlan.cadenceDays,
    watchPlan.reviewAlertThreshold,
  ]);

  async function loadWatchlist() {
    try {
      setLoading(true);
      setError("");
      const candidates = splitAsinCandidates(competitorInputs).slice(0, 5);
      const loaded: AmazonListingSnapshot[] = [];
      for (const candidate of candidates) {
        const response = await fetch(
          `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(candidate)}`,
        );
        const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
        if (response.ok && !("error" in payload)) {
          loaded.push(payload);
        }
      }
      setSnapshots(loaded);
      if (!loaded.length) {
        setError("No competitor listings could be loaded from the current ASIN set.");
      }
    } catch (fetchError) {
      setSnapshots([]);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load competitor watchlist.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(() => {
    const evidenceStatus = getMultiSnapshotEvidenceStatus(snapshots, [
      "title",
      "price",
      "reviewCount",
    ]);
    if (!snapshots.length || evidenceStatus.level === "weak") {
      const fallbackDecision = !snapshots.length
        ? "Load the first live watchlist"
        : "Replace weak PDPs before escalating alerts";
      const fallbackOwner =
        interruptionRule === "interrupt-on-price"
          ? "Pricing / marketplace owner"
          : interruptionRule === "interrupt-on-authority"
            ? "Brand / content owner"
            : interruptionRule === "interrupt-on-new-entrants"
              ? "Competitive intelligence owner"
              : "Marketplace ops owner";
      return {
        headline: !snapshots.length
          ? "Competitor watchlist is waiting on a real live set"
          : "Competitor watchlist needs stronger live evidence",
        summary:
          "Use this watchlist read to decide what still needs loading, who owns the next move, and which signal deserves the first interruption.",
        metrics: [
          {
            label: "Watchlist coverage",
            value: snapshots.length ? `${snapshots.length} loaded` : "Missing",
            detail: snapshots.length
              ? evidenceStatus.detail
              : "Load direct competitor ASINs before building an alert ladder.",
          },
          {
            label: "First move",
            value: fallbackDecision,
            detail: !snapshots.length
              ? "Build the watch set from real PDPs before the alert ladder starts steering work."
              : "Resolve the weakest evidence gap before escalating noise as disruption.",
          },
          {
            label: "Execution owner",
            value: fallbackOwner,
            detail: "Keep one owner on the first interruption rule before the watchlist turns into shared noise.",
          },
          {
            label: "Alert posture",
            value: watchPlan.watchBrief,
            detail: `${interruptionRule.replace(/-/g, " ")} / ${businessLens.replace(/-/g, " ")}`,
          },
        ],
        recommendations: [
          !snapshots.length
            ? "Load the same competitor set you would actually watch every week."
            : "Freeze one stable watchlist before interpreting scattered PDP gaps as market movement.",
          "Keep one owner on the first interruption rule so the watchlist does not become ambient noise.",
        ],
        status: {
          label: !snapshots.length ? "Watchlist baseline is incomplete" : "Watchlist evidence is still weak",
          tone: "warning" as const,
        },
        missingItems: [
          !snapshots.length ? "Live competitor watchlist" : "",
          evidenceStatus.level === "weak" ? "Stronger PDP evidence" : "",
        ].filter(Boolean),
        nextSteps: [
          !snapshots.length ? "Load the first live competitor set." : "Replace weak PDPs with stronger competitor pages.",
          "Assign one watch owner to the first interruption rule.",
          "Re-run once the baseline set is stable.",
        ],
        actionStance: {
          label: !snapshots.length ? "Do not monitor from theory" : "Do not escalate weak evidence",
          tone: "warning" as const,
          detail: !snapshots.length
            ? "Begin monitoring from a real watchlist, not a hypothetical alert scheme."
            : "Weak PDP coverage turns monitoring into story-telling instead of interruption discipline.",
        },
      } satisfies ToolEvaluation;
    }

    const prices = snapshots.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const reviewCounts = snapshots.map((item) => parseReviewCountValue(item.reviewCountText));
    const ranks = snapshots
      .map((item) => parseRankValue(item.bestSellersRank) || parseRankValue(item.subCategoryRank))
      .filter((value) => value > 0);
    const averagePrice = prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0;

    return evaluateCompetitorMonitoring({
      competitorCount: snapshots.length,
      averagePrice,
      lowestPrice: prices.length ? Math.min(...prices) : 0,
      highestPrice: prices.length ? Math.max(...prices) : 0,
      volatilePriceCount: prices.filter((value) => averagePrice > 0 && Math.abs(value - averagePrice) > alertDelta).length,
      averageReviewCount: reviewCounts.length ? reviewCounts.reduce((sum, value) => sum + value, 0) / reviewCounts.length : 0,
      reviewSpread: reviewCounts.length ? Math.max(...reviewCounts) - Math.min(...reviewCounts) : 0,
      lowReviewCount: reviewCounts.filter((value) => value > 0 && value <= reviewAlertThreshold).length,
      averageRank: ranks.length ? ranks.reduce((sum, value) => sum + value, 0) / ranks.length : 0,
      bestRank: ranks.length ? Math.min(...ranks) : 0,
      worstRank: ranks.length ? Math.max(...ranks) : 0,
      rankSpread: ranks.length ? Math.max(...ranks) - Math.min(...ranks) : 0,
      aPlusCount: snapshots.filter((item) => item.hasAPlus).length,
      badgeCarrierCount: snapshots.filter((item) => item.badges.length > 0).length,
      missingPriceCount: snapshots.filter((item) => !parseCurrencyAmount(item.priceText)).length,
      missingRankCount: snapshots.filter(
        (item) => !(parseRankValue(item.bestSellersRank) || parseRankValue(item.subCategoryRank)),
      ).length,
      alertDelta,
      reviewAlertThreshold,
      cadenceDays,
    });
  }, [alertDelta, businessLens, cadenceDays, interruptionRule, reviewAlertThreshold, snapshots, watchPlan.watchBrief]);

  const competitorMonitoringAuditLines = useMemo(() => {
    const evidenceStatus = getMultiSnapshotEvidenceStatus(snapshots, [
      "title",
      "price",
      "reviewCount",
    ]);
    const lines = [`Watchlist evidence: ${evidenceStatus.label}. ${evidenceStatus.detail}`];
    if (!snapshots.length) {
      lines.push("Load competitor ASINs to build a real watchlist before using the alert ladder.");
    } else if (evidenceStatus.level !== "complete") {
      lines.push("Treat price and review alerts as directional until more of the watchlist resolves to full live data.");
    }
    if (snapshots.length) {
      lines.push(
        localeText(locale, `Result summary: ${watchPlan.watchBrief}`, `结果摘要：${watchPlan.watchBrief}`),
      );
      lines.push(
        `System draft: ${formatUsd(watchPlan.alertDelta)} price alert band, ${watchPlan.reviewAlertThreshold} review launch cap, ${watchPlan.cadenceDays}-day watch cadence.`,
      );
    }
    return lines;
  }, [snapshots, watchPlan.alertDelta, watchPlan.cadenceDays, watchPlan.reviewAlertThreshold, watchPlan.watchBrief]);

  const monitoringRows = useMemo(() => {
    const prices = snapshots.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    return buildMonitoringDecisionRows({
      snapshots,
      averagePrice: prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0,
      alertDelta,
      reviewAlertThreshold,
      cadenceDays,
    });
  }, [alertDelta, cadenceDays, reviewAlertThreshold, snapshots]);
  const monitoringExecutionPlan = useMemo(() => {
    const prices = snapshots.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const averagePrice = prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0;
    const priceOutlierCount = snapshots.filter((item) => {
      const price = parseCurrencyAmount(item.priceText);
      return price > 0 && averagePrice > 0 && Math.abs(price - averagePrice) > alertDelta;
    }).length;
    const lowReviewEntrantCount = snapshots.filter((item) => {
      const reviews = parseReviewCountValue(item.reviewCountText);
      return reviews > 0 && reviews <= reviewAlertThreshold;
    }).length;

    return inferCompetitorMonitoringExecutionPlan({
      snapshotCount: snapshots.length,
      interruptionRule,
      businessLens,
      cadenceDays,
      priceOutlierCount,
      lowReviewEntrantCount,
    });
  }, [alertDelta, businessLens, cadenceDays, interruptionRule, reviewAlertThreshold, snapshots]);

  const watchAuditRows = useMemo(
    () => [
      {
        label: "Watchlist coverage",
        value: `${snapshots.length} loaded`,
        detail: snapshots.length
          ? `${splitAsinCandidates(competitorInputs).slice(0, 5).length} requested from the current ASIN set`
          : "Load competitor ASINs to create the live watch baseline",
      },
      {
        label: "Marketplace",
        value: marketplace,
        detail: "Every alert is computed from the current marketplace PDP sample",
      },
      {
        label: "System alert band",
        value: formatUsd(alertDelta),
        detail: showAdvanced
          ? "Manual override for what price move should trigger attention."
          : "System-drafted disruption threshold for the current live watch set.",
      },
      {
        label: "Launch review cap",
        value: `${reviewAlertThreshold}`,
        detail: showAdvanced
          ? "Manual override for when a competitor still looks like a fresh entrant."
          : "System-drafted cap for when a competitor still looks like a fresh entrant.",
      },
      {
        label: "Cadence",
        value: `${cadenceDays} day${cadenceDays === 1 ? "" : "s"}`,
        detail: showAdvanced
          ? "Manual override for how often to rerun the same watch set."
          : `${responseCadence} response posture for this watch set.`,
      },
      {
        label: "Interruption posture",
        value: monitoringExecutionPlan.proofPriority,
        detail: `${interruptionCadence.replace(/-/g, " ")} escalation posture for this watch set`,
      },
      {
        label: "Execution call",
        value: monitoringExecutionPlan.decision,
        detail: `${monitoringExecutionPlan.proofPriority} | ${monitoringExecutionPlan.cadence}`,
      },
    ],
    [alertDelta, cadenceDays, competitorInputs, interruptionCadence, marketplace, monitoringExecutionPlan, responseCadence, reviewAlertThreshold, showAdvanced, snapshots.length],
  );

  const watchActionRows = useMemo(() => {
    const priceOutliers = snapshots.filter((item) => {
      const price = parseCurrencyAmount(item.priceText);
      const prices = snapshots.map((snapshot) => parseCurrencyAmount(snapshot.priceText)).filter((value) => value > 0);
      const averagePrice = prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0;
      return price > 0 && averagePrice > 0 && Math.abs(price - averagePrice) > alertDelta;
    }).length;
    const lowReviewEntrants = snapshots.filter((item) => {
      const reviews = parseReviewCountValue(item.reviewCountText);
      return reviews > 0 && reviews <= reviewAlertThreshold;
    }).length;

    return [
      {
        label: "First move",
        value: monitoringExecutionPlan.decision,
        detail: monitoringExecutionPlan.nextMove,
      },
      {
        label: localeText(locale, "Result summary", "结果摘要"),
        value: watchPlan.watchBrief,
        detail: `${watchPlan.focusBrief} ${watchPlan.cadenceBrief}`,
      },
      {
        label: "Execution owner",
        value: monitoringExecutionPlan.owner,
        detail: `${monitoringExecutionPlan.cadence}. ${monitoringExecutionPlan.watchout}`,
      },
      {
        label: "Do not cross",
        value:
          !snapshots.length
            ? "Do not monitor from theory"
            : interruptionCadence === "same-day"
              ? "Do not let same-day alerts become constant noise"
              : disruptionFocus === "new-entrants"
                ? "Do not keep swapping the entrant set every run"
                : "Do not confuse list churn with market change",
        detail:
          !snapshots.length
            ? "A paid monitoring page starts from a real watchlist, not an imagined alert ladder."
            : interruptionCadence === "same-day"
              ? "Only the highest-consequence move should interrupt the day."
              : disruptionFocus === "new-entrants"
                ? "A stable entrant set teaches more than constantly changing the benchmark pool."
                : "Monitoring loses value when the watched set changes more than the market does.",
      },
      {
        label: "Then do",
        value:
          interruptionCadence === "same-day"
            ? "Escalate only the strongest change today"
            : interruptionCadence === "weekly-batch"
              ? "Batch weak signals, isolate the real disruptor"
          : disruptionFocus === "promo-shocks"
            ? "Escalate badge pickup faster than slow review drift"
            : disruptionFocus === "new-entrants"
              ? "Freeze the entrant set and recheck proof growth"
              : "Freeze the set and compare change, not list churn",
        detail:
          interruptionCadence === "same-day"
            ? "Do not let same-day alerting turn into constant noise. Pick the move with the highest commercial consequence."
            : interruptionCadence === "weekly-batch"
              ? "A weekly review only works when weak noise is filtered before it reaches the queue."
          : disruptionFocus === "promo-shocks"
            ? "Promo and authority badges can move click share faster than small proof changes."
            : disruptionFocus === "new-entrants"
              ? "A stable entrant set is more useful than constantly swapping in new ASINs."
              : "Monitoring gets noisy when the ASIN list changes more than the market does.",
      },
      {
        label: "Watch",
        value: monitoringExecutionPlan.proofPriority,
        detail: `${priceOutliers}/${lowReviewEntrants} current price outliers / low-review entrants in the live watch set.`,
      },
    ];
  }, [alertDelta, disruptionFocus, interruptionCadence, monitoringExecutionPlan, reviewAlertThreshold, snapshots, watchPlan.cadenceBrief, watchPlan.focusBrief, watchPlan.watchBrief]);

  const monitoringEscalationRows = useMemo(
    () => {
      const prices = snapshots.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
      return buildMonitoringEscalationRows({
        snapshots,
        averagePrice: prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0,
        alertDelta,
        reviewAlertThreshold,
        cadenceDays,
      });
    },
    [alertDelta, cadenceDays, reviewAlertThreshold, snapshots],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1.4fr_0.8fr_auto_auto]">
        <Field label="Competitor ASINs or URLs">
          <TextAreaInput value={competitorInputs} onChange={(e) => setCompetitorInputs(e.target.value)} spellCheck={false} />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowAdvanced((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showAdvanced
              ? localeText(locale, "Hide advanced settings", "隐藏高级设置")
              : localeText(locale, "Adjust advanced settings", "调整高级设置")}
          </button>
        </div>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadWatchlist} disabled={loading || !competitorInputs.trim()}>
            {runtimeActionButtonLabel(locale, loading, "Load competitors and generate result", "加载竞品并生成结果")}
          </ActionButton>
        </div>
      </div>
      {showAdvanced ? (
        <div className="grid gap-4">
          <div className="grid gap-2.5 xl:grid-cols-[1fr_1fr_1fr]">
            <Field label="Watch objective">
              <SelectInput value={watchObjective} onChange={(e) => setWatchObjective(e.target.value)}>
                <option value="balanced-watch">Balanced watch</option>
                <option value="price-defense">Price defense</option>
                <option value="launch-watch">Launch watch</option>
              </SelectInput>
            </Field>
            <Field label="Disruption focus">
              <SelectInput value={disruptionFocus} onChange={(e) => setDisruptionFocus(e.target.value)}>
                <option value="balanced">Balanced</option>
                <option value="new-entrants">New entrants</option>
                <option value="promo-shocks">Promo shocks</option>
              </SelectInput>
            </Field>
            <Field label="Response cadence">
              <SelectInput value={responseCadence} onChange={(e) => setResponseCadence(e.target.value)}>
                <option value="normal">Normal</option>
                <option value="daily">Daily</option>
                <option value="weekly">Weekly</option>
              </SelectInput>
            </Field>
          </div>
          <div className="grid gap-2.5 md:grid-cols-[0.95fr_0.95fr_0.95fr]">
            <Field label="Interruption rule">
              <SelectInput value={interruptionRule} onChange={(e) => setInterruptionRule(e.target.value)}>
                <option value="monitor-only">Monitor only</option>
                <option value="interrupt-on-price">Interrupt on price</option>
                <option value="interrupt-on-new-entrants">Interrupt on new entrants</option>
                <option value="interrupt-on-authority">Interrupt on authority</option>
              </SelectInput>
            </Field>
            <Field label="Business lens">
              <SelectInput value={businessLens} onChange={(e) => setBusinessLens(e.target.value)}>
                <option value="balanced-defense">Balanced defense</option>
                <option value="margin-defense">Margin defense</option>
                <option value="entry-defense">Entry defense</option>
                <option value="click-share-defense">Click-share defense</option>
              </SelectInput>
            </Field>
            <Field label="Interruption cadence">
              <SelectInput value={interruptionCadence} onChange={(e) => setInterruptionCadence(e.target.value)}>
                <option value="same-day">Same day</option>
                <option value="next-review">Next review</option>
                <option value="weekly-batch">Weekly batch</option>
              </SelectInput>
            </Field>
          </div>
          <div className="grid gap-2.5 md:grid-cols-[0.7fr_0.7fr_0.7fr]">
            <Field label="Price alert delta">
              <NumberInput value={alertDelta} min="0" step="0.5" onChange={(e) => setAlertDelta(Number(e.target.value))} />
            </Field>
            <Field label="Launch review cap">
              <NumberInput
                value={reviewAlertThreshold}
                min="1"
                step="1"
                onChange={(e) => setReviewAlertThreshold(Number(e.target.value))}
              />
            </Field>
            <Field label="Cadence (days)">
              <NumberInput value={cadenceDays} min="1" step="1" onChange={(e) => setCadenceDays(Number(e.target.value))} />
            </Field>
          </div>
        </div>
      ) : null}
      {error ? (
        <div className="rounded-xl border border-rose-200 bg-rose-50 px-4 py-3 text-sm text-rose-950">
          {error}
        </div>
      ) : null}
      <div className="rounded-xl border border-teal-200 bg-teal-50 px-3 py-3 text-sm text-teal-950">
        {runtimeResultHint(locale)}
      </div>
      <DistributionPanel title={runtimeResultTitle(locale)} rows={watchAuditRows} />
      <AuditNote lines={competitorMonitoringAuditLines} />
      <CompetitorBoard
        own={snapshots[0] ?? null}
        competitors={snapshots.slice(1)}
        primaryLabel={localeText(locale, "Baseline item", "基准商品")}
      />
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title={runtimeActionPlanTitle(locale)} rows={watchActionRows} />
        <DistributionPanel title="Alert priorities" rows={monitoringRows.alertRows} />
        <DistributionPanel title={localeText(locale, "Focus targets", "重点对象")} rows={monitoringRows.targetRows} />
        <DistributionPanel title="Review cadence" rows={monitoringRows.cadenceRows} />
      </div>
      <DistributionPanel title="Escalation logic" rows={monitoringEscalationRows} />
    </RuntimeShell>
  );
}

function ProductResearchRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [seedKeyword, setSeedKeyword] = useState("arched full length mirror");
  const [referenceInputs, setReferenceInputs] = useState("B0GYRT3FNL\nB0G6K4VXK7\nB0FX2PRMFR\nB0CLNLL9RZ");
  const [entryObjective, setEntryObjective] = useState("balanced-entry");
  const [capitalPosture, setCapitalPosture] = useState("normal");
  const [moatTolerance, setMoatTolerance] = useState("medium");
  const [category, setCategory] = useState("home__root-home-kitchen-tth");
  const [targetMargin, setTargetMargin] = useState(0.2);
  const [landedCost, setLandedCost] = useState(55);
  const [fulfillmentCost, setFulfillmentCost] = useState(18);
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [snapshots, setSnapshots] = useState<AmazonListingSnapshot[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const researchPlan = useMemo(() => inferProductResearchPlan(snapshots, category), [category, snapshots]);
  const entryScenarioPlan = useMemo(
    () =>
      inferEntryScenarioPlan({
        snapshots,
        category,
        entryObjective,
        capitalPosture,
        moatTolerance,
      }),
    [capitalPosture, category, entryObjective, moatTolerance, snapshots],
  );

  useEffect(() => {
    if (showAdvanced) {
      return;
    }
    setTargetMargin(entryScenarioPlan.targetMargin);
    setLandedCost(entryScenarioPlan.landedCost);
    setFulfillmentCost(entryScenarioPlan.fulfillmentCost);
  }, [
    entryScenarioPlan.fulfillmentCost,
    entryScenarioPlan.landedCost,
    entryScenarioPlan.targetMargin,
    showAdvanced,
  ]);

  async function loadResearchSet() {
    try {
      setLoading(true);
      setError("");
      const candidates = splitAsinCandidates(referenceInputs).slice(0, 5);
      const loaded: AmazonListingSnapshot[] = [];
      for (const candidate of candidates) {
        const response = await fetch(
          `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(candidate)}`,
        );
        const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
        if (response.ok && !("error" in payload)) {
          loaded.push(payload);
        }
      }

      setSnapshots(loaded);
      let nextCategory = category;
      if (loaded[0]) {
        const matchedCategory = inferCategoryOption(loaded[0], calculatorCategoryOptionGroups);
        if (matchedCategory) {
          setCategory(matchedCategory);
          nextCategory = matchedCategory;
        }
      }
      if (!showAdvanced && loaded.length) {
        const nextPlan = inferEntryScenarioPlan({
          snapshots: loaded,
          category: nextCategory,
          entryObjective,
          capitalPosture,
          moatTolerance,
        });
        setTargetMargin(nextPlan.targetMargin);
        setLandedCost(nextPlan.landedCost);
        setFulfillmentCost(nextPlan.fulfillmentCost);
      }
      if (!loaded.length) {
        setError("No reference ASINs could be loaded from the current set.");
      }
    } catch (fetchError) {
      setSnapshots([]);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load product research set.");
    } finally {
      setLoading(false);
    }
  }

  const researchRows = useMemo(() => {
    if (!snapshots.length) {
      return {
        opportunityRows: [] as Array<{ label: string; value: string; detail?: string }>,
        competitionRows: [] as Array<{ label: string; value: string; detail?: string }>,
        differentiationRows: [] as Array<{ label: string; value: string; detail?: string }>,
        moatPressure: 0,
        differentiationPressure: 0,
        viableEntryCount: 0,
      };
    }

    const prices = snapshots.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const ranks = snapshots
      .map((item) => parseRankValue(item.bestSellersRank) || parseRankValue(item.subCategoryRank))
      .filter((value) => value > 0);
    const estimatedMonthlyUnits = estimateMonthlyUnitsFromBsr(
      category,
      ranks.length ? ranks.reduce((sum, value) => sum + value, 0) / ranks.length : 0,
    );
    const averagePrice = prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0;
    const reviewCounts = snapshots.map((item) => parseReviewCountValue(item.reviewCountText)).filter((value) => value > 0);
    const averageReviewCount =
      reviewCounts.length ? reviewCounts.reduce((sum, value) => sum + value, 0) / reviewCounts.length : 0;
    const referralRate = getResearchReferralRate(category);
    const estimatedNetMargin =
      averagePrice > 0 ? (averagePrice - averagePrice * referralRate - landedCost - fulfillmentCost) / averagePrice : 0;

    return buildProductResearchDecisionRows({
      snapshots,
      averagePrice,
      averageReviewCount,
      estimatedMonthlyUnits,
      estimatedNetMargin,
      targetMargin,
    });
  }, [category, fulfillmentCost, landedCost, snapshots, targetMargin]);
  const researchExecutionPlan = useMemo(() => {
    const viableShare = snapshots.length ? researchRows.viableEntryCount / snapshots.length : 0;
    return inferProductResearchExecutionPlan({
      snapshotCount: snapshots.length,
      viableShare,
      moatPressure: researchRows.moatPressure,
      entryObjective,
      capitalPosture,
      targetMargin,
      estimatedNetMargin: researchPlan.estimatedNetMargin,
    });
  }, [capitalPosture, entryObjective, researchPlan.estimatedNetMargin, researchRows.moatPressure, researchRows.viableEntryCount, snapshots.length, targetMargin]);

  const result = useMemo(() => {
    const evidenceStatus = getMultiSnapshotEvidenceStatus(snapshots, [
      "title",
      "reviewCount",
      "breadcrumbs",
    ]);
    if (!snapshots.length || evidenceStatus.level === "weak") {
      const isBootstrappingLiveSet = loading && !snapshots.length && !error && !!referenceInputs.trim();
      const seededReferenceCount = splitAsinCandidates(referenceInputs).slice(0, 5).length;
      const fallbackDecision = !snapshots.length
        ? isBootstrappingLiveSet
          ? "Reading the live research set"
          : "Stage the reference set and load the live research read"
        : "Strengthen the research set before making an entry call";
      const fallbackOwner =
        capitalPosture === "tight"
          ? "Finance / sourcing owner"
          : entryObjective === "fast-follower"
            ? "Category manager"
            : "Category research lead";
      const fallbackCommercialCall = !snapshots.length
        ? isBootstrappingLiveSet
          ? "Hold until the live references finish loading"
          : "Do not approve sourcing from setup alone"
        : researchPlan.estimatedNetMargin < targetMargin
          ? "Hold - economics fail before wedge work"
          : "Narrow the entry wedge before more spend";
      return {
        headline: !snapshots.length
          ? isBootstrappingLiveSet
            ? "Reading the live reference set before making an entry call"
            : "The product lane is waiting on live proof before sourcing"
          : "Do not approve this lane yet - the live reference set is still too weak",
        summary:
          "This lane stays blocked until the live reference set proves one believable entry wedge.",
        metrics: [
          {
            label: "Commercial call",
            value: fallbackCommercialCall,
            detail: !snapshots.length
              ? "The current setup is only a starting pack for validation. It is not approval for inventory or sourcing."
              : researchPlan.estimatedNetMargin < targetMargin
                ? `Current draft economics are below the ${roundNumber(targetMargin * 100, 1)}% hurdle, so more market storytelling is the wrong next step.`
                : "Do not call this lane open until the reference set proves one wedge instead of a vague market story.",
          },
          {
            label: "Reference set",
            value: snapshots.length ? `${snapshots.length} loaded` : `${seededReferenceCount} references ready`,
            detail: snapshots.length
              ? evidenceStatus.detail
              : isBootstrappingLiveSet
                ? "Live substitute PDPs are loading now from the current reference set."
                : "The reference pack is ready. Pull those live substitutes before trusting any entry verdict.",
          },
          {
            label: "Approval hurdle",
            value: `${roundNumber(targetMargin * 100, 1)}% margin target`,
            detail: `${formatUsd(landedCost)} landed | ${formatUsd(fulfillmentCost)} fulfillment cost assumption`,
          },
          {
            label: "Open lane",
            value: fallbackDecision,
            detail: !snapshots.length
              ? "Sourcing stays closed until those references resolve into live leaders."
              : "Replace weak references before calling the lane viable, crowded, or worth capital.",
          },
          {
            label: "Decision owner",
            value: fallbackOwner,
            detail: "Keep the first research blocker with one owner until the lane is either provable or dead.",
          },
        ],
        recommendations: [
          !snapshots.length
            ? isBootstrappingLiveSet
              ? "Let the current live references finish loading before replacing the set or judging the lane."
              : "Use the current ASIN pack as the first proof set and load the live read before opening any sourcing discussion."
            : "Replace weak references before judging the lane as viable or crowded.",
          "Forbidden move: confusing a target margin model with proof that the market can actually support your entry.",
          !snapshots.length
            ? isBootstrappingLiveSet
              ? "Do not approve sourcing or launch prep while the live reference read is still in flight."
              : "Do not spend on sourcing, creatives, or launch prep while the live reference read is still missing."
            : researchPlan.estimatedNetMargin < targetMargin
              ? "Do not keep researching this lane as if the problem were only competitive. Fix the economic stack first or drop the idea."
              : "Only continue if the next pass can prove one believable entry wedge instead of a general market curiosity.",
        ],
        status: {
          label: !snapshots.length ? "Reference lane is waiting on live proof" : "Reference quality is still weak",
          tone: "warning" as const,
        },
        riskItems: [
          !snapshots.length
            ? isBootstrappingLiveSet
              ? "The live pull is still in flight, so the lane is not ready for a sourcing or budgeting call yet."
              : "The lane still has no live reference proof; sourcing, launch prep, and capital approval should stay closed."
            : researchPlan.estimatedNetMargin < targetMargin
              ? `Draft economics are still below the ${roundNumber(targetMargin * 100, 1)}% hurdle, so the current lane can fail before differentiation work even starts.`
              : "Weak live reference coverage can make the lane look softer or more open than the real category actually is.",
        ],
        missingItems: [
          !snapshots.length ? "Live substitute proof" : "",
          evidenceStatus.level === "weak" ? "Stronger niche evidence" : "",
        ].filter(Boolean),
        nextSteps: [
          !snapshots.length
            ? isBootstrappingLiveSet
              ? "Wait for the current reference set to finish loading."
              : "Load the current reference set as a live read."
            : researchPlan.estimatedNetMargin < targetMargin
              ? "Pause sourcing work and repair the margin stack before the next pass."
              : "Tighten the research set with stronger references.",
          "Keep one owner on budget-fit and entry-truth.",
          "Approve the next move only after one believable wedge survives this pass.",
        ],
        actionStance: {
          label: !snapshots.length
            ? isBootstrappingLiveSet
              ? "Wait for the live research read to finish"
              : "Do not approve sourcing before the live proof lands"
            : "Do not trust a thin research sample",
          tone: "warning" as const,
          detail: !snapshots.length
            ? isBootstrappingLiveSet
              ? "The tool is already pulling live substitutes. Let that read finish before you accept or reject the product lane."
              : "Until the live reference set lands, sourcing, launch prep, and capital discussion stay closed."
            : "Weak reference coverage makes the lane look cleaner or softer than it really is.",
        },
      } satisfies ToolEvaluation;
    }

    const prices = snapshots.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const ranks = snapshots
      .map((item) => parseRankValue(item.bestSellersRank) || parseRankValue(item.subCategoryRank))
      .filter((value) => value > 0);
    const reviewCounts = snapshots.map((item) => parseReviewCountValue(item.reviewCountText)).filter((value) => value > 0);
    const ratings = snapshots.map((item) => parseRatingValue(item.ratingText)).filter((value) => value > 0);
    const seedWords = tokenizeInputWords(seedKeyword);
    const titleCoverage =
      seedWords.length > 0
        ? Math.round(
            (seedWords.filter((word) =>
              snapshots.some((item) => item.title.toLowerCase().includes(word))).length /
              seedWords.length) *
              100,
          )
        : 100;

    if (!prices.length) {
      const averageRank = ranks.length ? ranks.reduce((sum, value) => sum + value, 0) / ranks.length : 0;
      const averageReviewCount =
        reviewCounts.length ? reviewCounts.reduce((sum, value) => sum + value, 0) / reviewCounts.length : 0;
      const estimatedMonthlyUnits =
        averageRank > 0 ? estimateMonthlyUnitsFromBsr(category, averageRank) : 0;
      const aPlusCoverage = snapshots.length
        ? Math.round((snapshots.filter((item) => item.hasAPlus).length / snapshots.length) * 100)
        : 0;
      const competitionPressure =
        averageReviewCount >= 300 || aPlusCoverage >= 60
          ? "High"
          : averageReviewCount >= 120 || aPlusCoverage >= 35
            ? "Medium"
            : "Moderate";

      return {
        headline:
          estimatedMonthlyUnits >= 180
            ? `Keep this lane alive, but do not approve sourcing until pricing is confirmed`
            : "Directional demand exists, but this lane is still too incomplete to approve",
        summary:
          "This lane is still blocked. Demand and moat can be screened here, but sourcing stays closed until visible pricing is real.",
        metrics: [
          {
            label: "Commercial call",
            value: estimatedMonthlyUnits >= 180 ? "Keep screening the lane" : "Hold this lane for now",
            detail: "Use the live cluster for demand and moat screening only. Do not convert this into a sourcing decision yet.",
          },
          {
            label: "Demand screen",
            value: estimatedMonthlyUnits > 0 ? `${estimatedMonthlyUnits.toLocaleString("en-US")} units/mo` : "Partial rank baseline",
            detail:
              averageRank > 0
                ? `Average BSR #${Math.round(averageRank).toLocaleString("en-US")} from the current live cluster`
                : "Not enough rank evidence to size the lane cleanly",
          },
          {
            label: "Competition proof",
            value: `${Math.round(averageReviewCount)} reviews`,
            detail: `${snapshots.filter((item) => item.hasAPlus).length}/${snapshots.length} references already show A+`,
          },
          {
            label: "Pressure level",
            value: competitionPressure,
            detail: `${researchRows.viableEntryCount}/${snapshots.length} references still look like softer entry templates`,
          },
          {
            label: "Economics gate",
            value: "Price capture missing",
            detail: "Do not approve margin math, sourcing, or launch budgeting until at least one visible sell-price baseline is recovered.",
          },
          {
            label: "Decision owner",
            value: "Category research lead",
            detail: "One owner confirms the missing price layer before anyone turns this into a product approval.",
          },
        ],
        recommendations: [
          estimatedMonthlyUnits >= 180
            ? "Demand is strong enough to keep this lane on the board, but only as a screened candidate."
            : "Do not let a partial live read graduate into sourcing just because the cluster looks interesting.",
          "Forbidden move: approving a product lane from rank and review signals alone when visible sell-price proof is still missing.",
          "Freeze this same live reference set and re-run the economics layer once at least one clean price baseline is recovered.",
          competitionPressure === "High"
            ? "Assume the lane already needs a sharper proof wedge, not a parity offer."
            : "The cluster is not automatically closed, but the opening lane still needs a tighter economic read.",
        ],
        alerts: [
          "Visible pricing is missing across the current live reference set.",
          "Economic approval is blocked until at least one price baseline is recovered.",
        ],
        status: {
          label: "Directional research read only",
          tone: "warning" as const,
        },
        actionStance: {
          label: "Screen the lane, but do not fund it yet",
          tone: "warning" as const,
          detail:
            "This is enough evidence to narrow the lane, not enough to approve sourcing, inventory, or contribution-margin work.",
        },
        missingItems: ["Visible competitor price data"],
        riskItems: [
          "Without price, margin and entry math remain unapproved.",
        ],
        nextSteps: [
          "Keep only the strongest reference cluster and recover visible pricing from the same set.",
          "Do not open sourcing or launch prep until price and margin baselines are real.",
          "Re-run the lane once economics can be judged on live evidence instead of assumptions.",
        ],
      } satisfies ToolEvaluation;
    }

    return evaluateProductResearch({
      marketplace,
      category,
      competitorCount: snapshots.length,
      averagePrice: prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0,
      lowestPrice: prices.length ? Math.min(...prices) : 0,
      highestPrice: prices.length ? Math.max(...prices) : 0,
      averageRank: ranks.length ? ranks.reduce((sum, value) => sum + value, 0) / ranks.length : 0,
      bestRank: ranks.length ? Math.min(...ranks) : 0,
      averageReviewCount: reviewCounts.length ? reviewCounts.reduce((sum, value) => sum + value, 0) / reviewCounts.length : 0,
      strongReviewCompetitors: reviewCounts.filter((value) => value >= 300).length,
      averageRating: ratings.length ? ratings.reduce((sum, value) => sum + value, 0) / ratings.length : 0,
      aPlusCount: snapshots.filter((item) => item.hasAPlus).length,
      titleSeedCoverage: titleCoverage,
      targetMargin,
      landedCost,
      fulfillmentCost,
      viableEntryCount: researchRows.viableEntryCount,
      moatPressure: researchRows.moatPressure,
      differentiationPressure: researchRows.differentiationPressure,
    });
  }, [capitalPosture, category, entryObjective, fulfillmentCost, landedCost, marketplace, researchRows.differentiationPressure, researchRows.moatPressure, researchRows.viableEntryCount, seedKeyword, snapshots, targetMargin]);

  const productResearchAuditLines = useMemo(() => {
    const evidenceStatus = getMultiSnapshotEvidenceStatus(snapshots, [
      "title",
      "reviewCount",
      "breadcrumbs",
    ]);
    const seededReferenceCount = splitAsinCandidates(referenceInputs).slice(0, 5).length;
    const isBootstrappingLiveSet = loading && !snapshots.length && !error && seededReferenceCount > 0;
    const lines = [`Reference set quality: ${evidenceStatus.label}. ${evidenceStatus.detail}`];
    if (!snapshots.length) {
      lines.push(
        isBootstrappingLiveSet
          ? "The reference lane is loading now. Hold the entry call until the live read finishes."
          : seededReferenceCount > 0
            ? "The reference lane is ready. Pull the same ASIN set live before approving sourcing or margin work."
            : "Load reference ASINs so the opportunity read is anchored to real category listings.",
      );
    } else if (evidenceStatus.level !== "complete") {
      lines.push("Keep margin and moat calls in watch mode until the reference set has fuller live coverage.");
    }
    if (snapshots.length) {
      lines.push(`Entry brief: ${entryScenarioPlan.entryBrief}`);
      lines.push(
        `System draft: ${roundNumber(entryScenarioPlan.targetMargin * 100, 1)}% target margin, ${formatUsd(entryScenarioPlan.landedCost)} landed, ${formatUsd(entryScenarioPlan.fulfillmentCost)} fulfillment.`,
      );
    }
    return lines;
  }, [entryScenarioPlan.entryBrief, entryScenarioPlan.fulfillmentCost, entryScenarioPlan.landedCost, entryScenarioPlan.targetMargin, error, loading, referenceInputs, snapshots]);

  const researchAuditRows = useMemo(() => {
    const seededReferenceCount = splitAsinCandidates(referenceInputs).slice(0, 5).length;
    const isBootstrappingLiveSet = loading && !snapshots.length && !error && seededReferenceCount > 0;
    return [
      {
        label: "Reference coverage",
        value: snapshots.length ? `${snapshots.length} loaded` : seededReferenceCount ? `${seededReferenceCount} references ready` : "0 loaded",
        detail: snapshots.length
          ? `${splitAsinCandidates(referenceInputs).slice(0, 5).length} requested from the current set`
          : isBootstrappingLiveSet
            ? "Pulling the current substitute set into live PDP reads now"
            : seededReferenceCount
              ? "The substitute set is ready. Run the live pull before trusting the opportunity read."
              : "Load direct substitutes to anchor the opportunity read to live PDPs",
      },
      {
        label: "Detected category",
        value: getCategoryLabel(category),
        detail: snapshots[0]?.breadcrumbs.length ? snapshots[0].breadcrumbs.join(" / ") : "Updated from the first live reference when available",
      },
      {
        label: "Live keyword frame",
        value: seedKeyword || "Not set",
        detail: "Used to test title coverage against the current reference cluster",
      },
      {
        label: "Target margin",
        value: `${roundNumber(targetMargin * 100, 1)}%`,
        detail: showAdvanced
          ? "Manual override for your internal hurdle."
          : `${entryObjective.replace(/-/g, " ")} with ${moatTolerance} moat tolerance.`,
      },
      {
        label: "Unit cost stack",
        value: formatUsd(landedCost + fulfillmentCost),
        detail: showAdvanced
          ? `${formatUsd(landedCost)} landed + ${formatUsd(fulfillmentCost)} fulfillment`
          : `${capitalPosture} capital posture driving the current entry assumptions`,
      },
      {
        label: "Execution call",
        value: researchExecutionPlan.decision,
        detail: `${researchExecutionPlan.proofPriority} | ${researchExecutionPlan.cadence}`,
      },
    ];
  }, [capitalPosture, category, entryObjective, error, fulfillmentCost, landedCost, loading, moatTolerance, referenceInputs, researchExecutionPlan, seedKeyword, showAdvanced, snapshots, targetMargin]);

  const researchEntryRows = useMemo(() => {
    const seededReferenceCount = splitAsinCandidates(referenceInputs).slice(0, 5).length;
    const isBootstrappingLiveSet = loading && !snapshots.length && !error && seededReferenceCount > 0;
    const hardestReference = snapshots
      .map((snapshot) => ({
        snapshot,
        reviews: parseReviewCountValue(snapshot.reviewCountText),
        rank: parseRankValue(snapshot.bestSellersRank) || parseRankValue(snapshot.subCategoryRank),
      }))
      .sort((a, b) => b.reviews - a.reviews || a.rank - b.rank)[0];
    const wedgeReference = snapshots
      .map((snapshot) => ({
        snapshot,
        reviews: parseReviewCountValue(snapshot.reviewCountText),
        price: parseCurrencyAmount(snapshot.priceText),
      }))
      .sort((a, b) => a.reviews - b.reviews || a.price - b.price)[0];

    return [
      {
        label: "First move",
        value: snapshots.length
          ? researchExecutionPlan.decision
          : isBootstrappingLiveSet
            ? "Wait for the live research read"
          : seededReferenceCount
              ? "Load the current research set live"
              : "Load the live research set",
        detail: snapshots.length
          ? researchExecutionPlan.nextMove
          : isBootstrappingLiveSet
            ? "The current substitute lane is already being read live. Let it finish before changing the product call."
            : seededReferenceCount
              ? "The product lane is still unproven, so it cannot become a sourcing decision before the live pull."
              : "A product-entry tool should start from real substitute ASINs before it pretends an opening exists.",
      },
      {
        label: "Execution owner",
        value: researchExecutionPlan.owner,
        detail: `${researchExecutionPlan.cadence}. ${researchExecutionPlan.watchout}`,
      },
      {
        label: "Do not cross",
        value:
          !snapshots.length
            ? seededReferenceCount
              ? "Do not approve this lane from a draft setup"
              : "Do not choose a product from narrative alone"
            : capitalPosture === "tight"
              ? "Do not fund a lane before margin and opening wedge both clear"
              : "Do not confuse a soft incumbent with a real opening",
        detail:
          !snapshots.length
            ? seededReferenceCount
              ? "This lane matters only if the same references survive the live pass and still justify entry."
              : "Narrow false positives instead of helping the team invent them."
            : capitalPosture === "tight"
              ? "With tight capital, being directionally right is still not enough if the opening lane cannot survive the first buy."
              : "One weak-looking incumbent does not matter if the cluster is structurally hard to enter.",
      },
      {
        label: "Then do",
        value: wedgeReference?.snapshot.asin ? `Reverse-engineer ${wedgeReference.snapshot.asin}` : "Freeze 3-5 direct substitutes",
        detail: wedgeReference
          ? `${wedgeReference.snapshot.priceText || "No price"} | ${wedgeReference.snapshot.reviewCountText || "No review proof"} | Start by mapping why this listing still survives.`
          : "Use a fixed substitute set before you let the idea turn into sourcing work.",
      },
      {
        label: "Watch",
        value: hardestReference?.snapshot.asin ?? "Leader to lock next",
        detail: hardestReference
          ? `${hardestReference.snapshot.reviewCountText || "No review proof"} | ${hardestReference.snapshot.bestSellersRank || hardestReference.snapshot.subCategoryRank || "No rank"} | This is the reference to beat only after the wedge is proven.`
          : seededReferenceCount
            ? "Run the current references first, then lock the strongest incumbent as the leader benchmark."
            : "Load the strongest visible incumbent first so the niche gets stress-tested against a real market leader.",
      },
    ];
  }, [capitalPosture, error, loading, referenceInputs, researchExecutionPlan, snapshots]);

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_1.15fr_0.8fr_0.8fr_0.8fr_auto_auto]">
        <Field label="Product idea or seed keyword">
          <TextInput value={seedKeyword} onChange={(e) => setSeedKeyword(e.target.value)} />
        </Field>
        <Field label="Reference ASINs or URLs">
          <TextAreaInput
            value={referenceInputs}
            onChange={(e) => setReferenceInputs(e.target.value)}
            className="min-h-[7.5rem]"
            spellCheck={false}
          />
        </Field>
        <Field label="Entry objective">
          <SelectInput value={entryObjective} onChange={(e) => setEntryObjective(e.target.value)}>
            <option value="balanced-entry">Balanced entry</option>
            <option value="low-risk-validation">Low-risk validation</option>
            <option value="aggressive-entry">Aggressive entry</option>
          </SelectInput>
        </Field>
        <Field label="Capital posture">
          <SelectInput value={capitalPosture} onChange={(e) => setCapitalPosture(e.target.value)}>
            <option value="normal">Normal</option>
            <option value="tight">Tight</option>
            <option value="deep">Deep</option>
          </SelectInput>
        </Field>
        <Field label="Moat tolerance">
          <SelectInput value={moatTolerance} onChange={(e) => setMoatTolerance(e.target.value)}>
            <option value="low">Low</option>
            <option value="medium">Medium</option>
            <option value="high">High</option>
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowAdvanced((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showAdvanced ? "Hide advanced settings" : "Adjust assumptions"}
          </button>
        </div>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadResearchSet} disabled={loading || !referenceInputs.trim()}>
            {loading ? "Loading..." : "Load live research set"}
          </ActionButton>
        </div>
      </div>
      {showAdvanced ? (
        <div className="grid gap-2.5 md:grid-cols-[0.75fr_1fr_0.7fr_0.7fr_0.7fr]">
          <Field label="Marketplace">
            <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
              {renderOptions(amazonMarketplaces)}
            </SelectInput>
          </Field>
          <Field label="Category">
            <SelectInput value={category} onChange={(e) => setCategory(e.target.value)}>
              {renderOptionGroups(calculatorCategoryOptionGroups)}
            </SelectInput>
          </Field>
          <Field label="Target margin">
            <NumberInput value={targetMargin} min="0" max="0.8" step="0.01" onChange={(e) => setTargetMargin(Number(e.target.value))} />
          </Field>
          <Field label="Landed cost">
            <NumberInput value={landedCost} min="0" step="0.01" onChange={(e) => setLandedCost(Number(e.target.value))} />
          </Field>
          <Field label="Fulfillment cost">
            <NumberInput value={fulfillmentCost} min="0" step="0.01" onChange={(e) => setFulfillmentCost(Number(e.target.value))} />
          </Field>
        </div>
      ) : null}
      {error ? (
        <div className="rounded-xl border border-rose-200 bg-rose-50 px-4 py-3 text-sm text-rose-950">
          {error}
        </div>
      ) : null}
      <DistributionPanel title="Decision brief" rows={researchAuditRows} />
      <AuditNote lines={productResearchAuditLines} />
      <CompetitorBoard own={snapshots[0] ?? null} competitors={snapshots.slice(1)} primaryLabel="Reference ASIN 1" />
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title="Approval board" rows={researchRows.opportunityRows} />
        <DistributionPanel title="Pressure map" rows={researchRows.competitionRows} />
        <DistributionPanel title="Entry wedge" rows={researchRows.differentiationRows} />
      </div>
      <DistributionPanel title="Decision board" rows={researchEntryRows} />
    </RuntimeShell>
  );
}

function KeywordTrackerRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [ownAsinOrUrl, setOwnAsinOrUrl] = useState("B0GYRT3FNL");
  const [competitorInputs, setCompetitorInputs] = useState("B0G6K4VXK7\nB0FX2PRMFR\nB0CLNLL9RZ");
  const [watchObjective, setWatchObjective] = useState("gap-closure");
  const [responseMode, setResponseMode] = useState("balanced");
  const [executionWindow, setExecutionWindow] = useState("this-week");
  const [targetKeywords, setTargetKeywords] = useState(
    "arched full length mirror, standing mirror, gold mirror, bedroom floor mirror",
  );
  const [alertThreshold, setAlertThreshold] = useState(5000);
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [ownSnapshot, setOwnSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [competitorSnapshots, setCompetitorSnapshots] = useState<AmazonListingSnapshot[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const keywordPlan = useMemo(
    () => inferKeywordTrackerPlan(ownSnapshot, competitorSnapshots),
    [competitorSnapshots, ownSnapshot],
  );
  const keywordWatchPlan = useMemo(
    () =>
      inferKeywordWatchPlan({
        ownSnapshot,
        competitorSnapshots,
        watchObjective,
        responseMode,
        executionWindow,
      }),
    [competitorSnapshots, executionWindow, ownSnapshot, responseMode, watchObjective],
  );

  useEffect(() => {
    if (showAdvanced) {
      return;
    }
    if (keywordWatchPlan.targetKeywords) {
      setTargetKeywords(keywordWatchPlan.targetKeywords);
    }
    setAlertThreshold(keywordWatchPlan.alertThreshold);
  }, [keywordWatchPlan.alertThreshold, keywordWatchPlan.targetKeywords, showAdvanced]);

  async function loadKeywordBaseline() {
    try {
      setLoading(true);
      setError("");
      const ownResponse = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(ownAsinOrUrl)}`,
      );
      const ownPayload = (await ownResponse.json()) as AmazonListingSnapshot | { error: string };
      if (!ownResponse.ok || "error" in ownPayload) {
        throw new Error("error" in ownPayload ? ownPayload.error : "Failed to load own listing.");
      }

      const candidates = splitAsinCandidates(competitorInputs).slice(0, 4);
      const loadedCompetitors: AmazonListingSnapshot[] = [];
      for (const candidate of candidates) {
        const response = await fetch(
          `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(candidate)}`,
        );
        const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
        if (response.ok && !("error" in payload)) {
          loadedCompetitors.push(payload);
        }
      }

      setOwnSnapshot(ownPayload);
      setCompetitorSnapshots(loadedCompetitors);
      if (showAdvanced && !targetKeywords.trim()) {
        const nextPlan = inferKeywordTrackerPlan(ownPayload, loadedCompetitors);
        if (nextPlan.targetKeywords) {
          setTargetKeywords(nextPlan.targetKeywords);
        }
      }
    } catch (fetchError) {
      setOwnSnapshot(null);
      setCompetitorSnapshots([]);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load keyword tracking baseline.");
    } finally {
      setLoading(false);
    }
  }

  const trackedRows = useMemo(() => {
    if (!ownSnapshot) {
      return [] as Array<{
        phrase: string;
        ownVisible: boolean;
        competitorMatches: number;
        priority: "gap" | "defend" | "observe";
      }>;
    }

    const phrases = splitKeywordPhrases(targetKeywords).slice(0, 12);
    const ownText = `${ownSnapshot.title} ${ownSnapshot.bulletPoints.join(" ")} ${ownSnapshot.breadcrumbs.join(" ")}`
      .toLowerCase();
    const competitorTexts = competitorSnapshots.map((item) =>
      `${item.title} ${item.bulletPoints.join(" ")} ${item.breadcrumbs.join(" ")}`.toLowerCase(),
    );
    const majorityThreshold = Math.max(1, Math.ceil(competitorSnapshots.length / 2));

    return phrases.map((phrase) => {
      const ownVisible = textHasPhraseCoverage(ownText, phrase);
      const competitorMatches = competitorTexts.filter((text) => textHasPhraseCoverage(text, phrase)).length;
      const priority: "gap" | "defend" | "observe" =
        competitorMatches >= majorityThreshold && !ownVisible
          ? "gap"
          : ownVisible && competitorMatches >= majorityThreshold
            ? "defend"
            : "observe";

      return {
        phrase,
        ownVisible,
        competitorMatches,
        priority,
      };
    });
  }, [competitorSnapshots, ownSnapshot, targetKeywords]);

  const result = useMemo(() => {
    const trackedKeywordCount = splitKeywordPhrases(targetKeywords).length;
    const gapCount = trackedRows.filter((row) => row.priority === "gap").length;
    const defendCount = trackedRows.filter((row) => row.priority === "defend").length;
    const observeCount = trackedRows.filter((row) => row.priority === "observe").length;
    const fallbackPlan = inferKeywordTrackerExecutionPlan({
      hasOwnSnapshot: Boolean(ownSnapshot),
      competitorCount: competitorSnapshots.length,
      trackedKeywordCount,
      gapCount,
      defendCount,
      observeCount,
      watchObjective,
      executionWindow,
    });
    const competitorEvidence = getMultiSnapshotEvidenceStatus(
      competitorSnapshots,
      ["title", "breadcrumbs", "reviewCount"],
    );

    if (!ownSnapshot || !isCustomSnapshotDecisionGrade(ownSnapshot, ["title", "breadcrumbs", "reviewCount"])) {
      return {
        headline: !ownSnapshot
          ? "Keyword tracker is waiting on your live listing baseline"
          : "Keyword tracker needs a stronger own-listing read first",
        summary:
          "Use this keyword watch to decide whether the tool should draft the first watchlist from the live PDP, defend proven terms now, or keep strategy closed until the baseline is real.",
        metrics: [
          {
            label: "Current result",
            value: !ownSnapshot ? "Own PDP missing" : "Own PDP evidence is thin",
            detail: !ownSnapshot
              ? "Load your ASIN or Amazon URL so the watchlist comes from a real page."
              : "The own PDP needs stronger title, breadcrumb, and review coverage before term gaps should steer action.",
          },
          {
            label: "Execution call",
            value: fallbackPlan.decision,
            detail: `${fallbackPlan.proofPriority} | ${fallbackPlan.cadence}`,
          },
          {
            label: "First move",
            value: !ownSnapshot ? "Load your own listing first" : "Repair the own PDP baseline",
            detail: !ownSnapshot
              ? "Draft the initial phrase pool from your live PDP instead of guessing it from scratch."
              : "Do not escalate missing-term alerts until the own-listing evidence is decision-grade.",
          },
          {
            label: "Execution owner",
            value: fallbackPlan.owner,
            detail: `${fallbackPlan.watchout} Keep one owner on the first watchlist repair until the same live baseline is rechecked.`,
          },
        ],
        recommendations: [
          "Let the tool derive the first phrase pool from the live PDP and competitor set.",
          "Only use manual phrase edits after the baseline already reflects the real page.",
        ],
        status: {
          label: !ownSnapshot ? "Own listing baseline is missing" : "Own listing evidence needs review",
          tone: "warning",
        },
        missingItems: [
          !ownSnapshot ? "Own PDP snapshot" : "Stronger own-listing evidence",
          trackedKeywordCount ? "" : "Keyword watchlist",
        ].filter(Boolean),
        nextSteps: [
          !ownSnapshot ? "Load your ASIN or Amazon URL." : "Reload the own PDP and verify live evidence fields.",
          "Draft the first watchlist from the real PDP.",
          "Then decide whether the job is gap closure, defense, or simple monitoring.",
        ],
        actionStance: {
          label: !ownSnapshot ? "Do not track keywords from memory" : "Do not trust term gaps from weak own-listing evidence",
          tone: "warning",
          detail: !ownSnapshot
            ? "Keep keyword tracking closed until the watch starts from the live page instead of an invented keyword set."
            : "If the own PDP baseline is weak, the next job is evidence repair, not phrase churn.",
        },
      } satisfies ToolEvaluation;
    }
    if (competitorEvidence.level === "weak") {
      return {
        headline: "Keyword tracker needs a stronger competitor benchmark",
        summary:
          "A weak competitor pack creates fake keyword gaps. The first job is deciding whether the benchmark set is strong enough to shape the watchlist at all.",
        metrics: [
          {
            label: "Current result",
            value: `${competitorSnapshots.length} competitors loaded`,
            detail: competitorEvidence.detail,
          },
          {
            label: "Execution call",
            value: fallbackPlan.decision,
            detail: `${fallbackPlan.proofPriority} | ${fallbackPlan.cadence}`,
          },
          {
            label: "First move",
            value: "Replace weak competitor references",
            detail: "Use direct substitutes buyers would actually compare against before turning gaps into rewrite work.",
          },
          {
            label: "Execution owner",
            value: fallbackPlan.owner,
            detail: `${fallbackPlan.watchout} Keep one owner on the competitor-pack repair until the same benchmark set is rechecked.`,
          },
        ],
        recommendations: [
          "Keep only real substitutes in the competitor pack.",
          "Do not use a thin reference set to expand the watchlist.",
        ],
        status: {
          label: "Competitor evidence needs rebuild",
          tone: "warning",
        },
        missingItems: ["Stronger competitor evidence"],
        nextSteps: [
          "Replace weak competitor ASINs.",
          "Re-run the watchlist against a cleaner pack.",
          "Then decide which phrases deserve defense versus rewrite work.",
        ],
        actionStance: {
          label: "Rebuild this watchlist before acting",
          tone: "warning",
          detail: "Weak competitor references make keyword pressure look broader and cleaner than the real market does.",
        },
      } satisfies ToolEvaluation;
    }

    const majorityThreshold = Math.max(1, Math.ceil(competitorSnapshots.length / 2));
    const currentRank =
      parseRankValue(ownSnapshot.bestSellersRank) || parseRankValue(ownSnapshot.subCategoryRank);
    const bestCompetitorRank = competitorSnapshots
      .map((item) => parseRankValue(item.bestSellersRank) || parseRankValue(item.subCategoryRank))
      .filter((value) => value > 0)
      .sort((a, b) => a - b)[0] ?? 0;

    return evaluateKeywordTracker({
      trackedKeywordCount: trackedRows.length,
      ownCoverageCount: trackedRows.filter((row) => row.ownVisible).length,
      competitorCount: competitorSnapshots.length,
      majorityCompetitorCount: trackedRows.filter((row) => row.competitorMatches >= majorityThreshold).length,
      gapCount: trackedRows.filter((row) => row.priority === "gap").length,
      defendCount: trackedRows.filter((row) => row.priority === "defend").length,
      observeCount: trackedRows.filter((row) => row.priority === "observe").length,
      currentRank,
      bestCompetitorRank,
      alertThreshold,
      cheaperCompetitorCount: competitorSnapshots.filter((item) => {
        const ownPrice = parseCurrencyAmount(ownSnapshot.priceText);
        const competitorPrice = parseCurrencyAmount(item.priceText);
        return ownPrice > 0 && competitorPrice > 0 && competitorPrice < ownPrice;
      }).length,
      strongerReviewCompetitorCount: competitorSnapshots.filter(
        (item) => parseReviewCountValue(item.reviewCountText) > parseReviewCountValue(ownSnapshot.reviewCountText),
      ).length,
      aPlusCompetitorCount: competitorSnapshots.filter((item) => item.hasAPlus).length,
      ownHasAPlus: ownSnapshot.hasAPlus,
    });
  }, [alertThreshold, competitorSnapshots, ownSnapshot, trackedRows]);

  const keywordDecisionRows = useMemo(
    () =>
      buildKeywordTrackerDecisionRows({
        rows: trackedRows,
        competitorCount: competitorSnapshots.length,
      }),
    [competitorSnapshots.length, trackedRows],
  );
  const keywordExecutionPlan = useMemo(
    () =>
      inferKeywordTrackerExecutionPlan({
        hasOwnSnapshot: Boolean(ownSnapshot),
        competitorCount: competitorSnapshots.length,
        trackedKeywordCount: splitKeywordPhrases(targetKeywords).length,
        gapCount: trackedRows.filter((row) => row.priority === "gap").length,
        defendCount: trackedRows.filter((row) => row.priority === "defend").length,
        observeCount: trackedRows.filter((row) => row.priority === "observe").length,
        watchObjective,
        executionWindow,
      }),
    [competitorSnapshots.length, executionWindow, ownSnapshot, targetKeywords, trackedRows, watchObjective],
  );

  const keywordTrackerAuditLines = useMemo(() => {
    const lines = [];
    if (ownSnapshot) {
      const ownEvidence = getCustomSnapshotEvidenceStatus(ownSnapshot, [
        "title",
        "breadcrumbs",
        "reviewCount",
      ]);
      lines.push(`Own listing evidence: ${ownEvidence.label}. ${ownEvidence.detail}`);
    }
    if (competitorSnapshots.length) {
      const competitorEvidence = getMultiSnapshotEvidenceStatus(competitorSnapshots, [
        "title",
        "breadcrumbs",
        "reviewCount",
      ]);
      lines.push(`Competitor set quality: ${competitorEvidence.label}. ${competitorEvidence.detail}`);
      if (competitorEvidence.level !== "complete") {
        lines.push("Treat missing-term alerts as directional until the competitor set has stronger live coverage.");
      }
    } else {
      lines.push("Load competitor ASINs so keyword gaps are anchored to real market pages.");
    }
    if (ownSnapshot) {
      lines.push(
        localeText(locale, `Result summary: ${keywordWatchPlan.watchBrief}`, `结果摘要：${keywordWatchPlan.watchBrief}`),
      );
      lines.push(
        `System draft: ${splitKeywordPhrases(keywordWatchPlan.targetKeywords).length} tracked phrases with a rank alert threshold of ${keywordWatchPlan.alertThreshold.toLocaleString("en-US")}.`,
      );
    }
    return lines;
  }, [competitorSnapshots, keywordWatchPlan.alertThreshold, keywordWatchPlan.targetKeywords, keywordWatchPlan.watchBrief, ownSnapshot]);

  const keywordAuditRows = useMemo(
    () => [
      {
        label: "Own listing",
        value: ownSnapshot?.asin ?? "Not loaded",
        detail: ownSnapshot?.title ? ownSnapshot.title : "Load your PDP to let the tracker generate the live baseline first",
      },
      {
        label: "Competitor set",
        value: `${competitorSnapshots.length} loaded`,
        detail: competitorSnapshots.length
          ? `${splitAsinCandidates(competitorInputs).slice(0, 4).length} requested from the current watch set`
          : "Add direct competitors so gap terms come from the real battlefield",
      },
      {
        label: "Tracked phrases",
        value: `${splitKeywordPhrases(targetKeywords).length}`,
        detail: targetKeywords.trim()
          ? showAdvanced
            ? "Editable watchlist generated from your PDP and competitor set."
            : "System-drafted watchlist generated from your PDP and competitor set."
          : "Leave this blank and the tool will draft a first-pass phrase pool from the live listing",
      },
      {
        label: "System focus",
        value: keywordWatchPlan.watchBrief,
        detail: `${keywordWatchPlan.responseBrief} ${keywordWatchPlan.executionBrief}`,
      },
      {
        label: "Marketplace",
        value: marketplace,
        detail: "Copy coverage and rank pressure are measured from this marketplace sample",
      },
      {
        label: "Rank alert threshold",
        value: alertThreshold.toLocaleString("en-US"),
        detail: showAdvanced
          ? "Manual override for what rank gap should trigger escalation."
          : "System-drafted threshold for what rank gap should trigger escalation.",
      },
      {
        label: "Execution call",
        value: keywordExecutionPlan.decision,
        detail: `${keywordExecutionPlan.proofPriority} | ${keywordExecutionPlan.cadence}`,
      },
    ],
    [alertThreshold, competitorInputs, competitorSnapshots.length, keywordExecutionPlan, keywordWatchPlan.executionBrief, keywordWatchPlan.responseBrief, keywordWatchPlan.watchBrief, marketplace, ownSnapshot, showAdvanced, targetKeywords],
  );

  const keywordActionRows = useMemo(() => {
    const gapCount = trackedRows.filter((row) => row.priority === "gap").length;
    const defendCount = trackedRows.filter((row) => row.priority === "defend").length;
    const observeCount = trackedRows.filter((row) => row.priority === "observe").length;

    return [
      {
        label: "First move",
        value: keywordExecutionPlan.decision,
        detail: keywordExecutionPlan.nextMove,
      },
      {
        label: "Response brief",
        value: keywordWatchPlan.watchBrief,
        detail: `${keywordWatchPlan.responseBrief} ${keywordWatchPlan.executionBrief}`,
      },
      {
        label: "Execution owner",
        value: keywordExecutionPlan.owner,
        detail: `${keywordExecutionPlan.cadence}. ${keywordExecutionPlan.watchout}`,
      },
      {
        label: "Do not cross",
        value:
          !ownSnapshot
            ? "Do not track keywords before loading the live PDP"
            : watchObjective === "gap-closure"
              ? "Do not keep adding phrases while current gaps are still unresolved"
              : watchObjective === "rank-defense"
                ? "Do not blame phrase drift before checking proof and price pressure"
                : "Do not bloat the watchlist beyond what someone will actually review",
        detail:
          !ownSnapshot
            ? "A paid tracker should draft the initial watch set from the real listing before it asks for operator judgment."
            : watchObjective === "gap-closure"
              ? "Gap closure only works when the team proves the repaired set first instead of continuously widening the list."
              : watchObjective === "rank-defense"
                ? "Rank pressure can come from proof or offer weakness, so phrase edits should not become the default scapegoat."
                : "A monitor set that no one can actually review on schedule is clutter, not operating leverage.",
      },
      {
        label: "Then do",
        value:
          watchObjective === "gap-closure"
            ? "Freeze the repaired set and re-check drift"
            : watchObjective === "rank-defense"
              ? "Check whether proof or price is weakening the defended set"
              : "Re-run only when the competitor set or listing changes",
        detail:
          watchObjective === "gap-closure"
            ? "Do not keep adding phrases while you are still validating the repairs on the current commercial gaps."
            : watchObjective === "rank-defense"
              ? "Tracked phrases will not defend themselves if the real problem becomes proof or price pressure."
              : "A lean monitor set is more useful than a bloated list no one actually reviews.",
      },
      {
        label: "Watch",
        value: keywordExecutionPlan.proofPriority,
        detail: `${gapCount}/${defendCount}/${observeCount} gap / defend / observe phrase mix in the current watch set.`,
      },
    ];
  }, [keywordExecutionPlan, keywordWatchPlan.executionBrief, keywordWatchPlan.responseBrief, keywordWatchPlan.watchBrief, trackedRows]);

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_1fr_0.8fr_auto_auto]">
        <Field label="Your ASIN or Amazon product URL">
          <TextInput value={ownAsinOrUrl} onChange={(e) => setOwnAsinOrUrl(e.target.value)} />
        </Field>
        <Field label="Competitor ASINs or URLs">
          <TextAreaInput
            value={competitorInputs}
            onChange={(e) => setCompetitorInputs(e.target.value)}
            className="min-h-[7.5rem]"
            spellCheck={false}
          />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowAdvanced((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showAdvanced
              ? localeText(locale, "Hide advanced settings", "隐藏高级设置")
              : localeText(locale, "Adjust advanced settings", "调整高级设置")}
          </button>
        </div>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadKeywordBaseline} disabled={loading || !ownAsinOrUrl.trim()}>
            {runtimeActionButtonLabel(locale, loading, "Load keywords and generate result", "加载关键词并生成结果")}
          </ActionButton>
        </div>
      </div>
      {showAdvanced ? (
        <div className="grid gap-4">
          <div className="grid gap-2.5 md:grid-cols-3">
            <Field label="Watch objective">
              <SelectInput value={watchObjective} onChange={(e) => setWatchObjective(e.target.value)}>
                <option value="gap-closure">Gap closure</option>
                <option value="rank-defense">Rank defense</option>
                <option value="monitor-only">Monitor only</option>
              </SelectInput>
            </Field>
            <Field label="Response mode">
              <SelectInput value={responseMode} onChange={(e) => setResponseMode(e.target.value)}>
                <option value="balanced">Balanced</option>
                <option value="aggressive">Aggressive</option>
                <option value="conservative">Conservative</option>
              </SelectInput>
            </Field>
            <Field label="Execution window">
              <SelectInput value={executionWindow} onChange={(e) => setExecutionWindow(e.target.value)}>
                <option value="now">Now</option>
                <option value="this-week">This week</option>
                <option value="monitor">Monitor</option>
              </SelectInput>
            </Field>
          </div>
          <div className="grid gap-2.5 md:grid-cols-[0.8fr_1.6fr]">
            <Field label="Rank alert threshold">
              <NumberInput value={alertThreshold} min="100" step="100" onChange={(e) => setAlertThreshold(Number(e.target.value))} />
            </Field>
            <Field label="Tracked keywords">
              <TextAreaInput value={targetKeywords} onChange={(e) => setTargetKeywords(e.target.value)} spellCheck={false} />
            </Field>
          </div>
        </div>
      ) : null}
      <SnapshotPanel snapshot={ownSnapshot} error={error} loading={loading} />
      <div className="rounded-xl border border-teal-200 bg-teal-50 px-3 py-3 text-sm text-teal-950">
        {runtimeResultHint(locale)}
      </div>
      <DistributionPanel title={runtimeResultTitle(locale)} rows={keywordAuditRows} />
      <AuditNote lines={keywordTrackerAuditLines} />
      <CompetitorBoard own={ownSnapshot} competitors={competitorSnapshots} />
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title={runtimeActionPlanTitle(locale)} rows={keywordActionRows} />
        <DistributionPanel title="Priority keyword actions" rows={keywordDecisionRows.actionRows} />
        <DistributionPanel title="Defend terms" rows={keywordDecisionRows.defendRows} />
        <DistributionPanel title="Hold for later" rows={keywordDecisionRows.backlogRows} />
      </div>
      <KeywordWatchPanel rows={trackedRows} />
    </RuntimeShell>
  );
}

function NicheFinderRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [category, setCategory] = useState("home__root-home-kitchen-tth");
  const [referenceInputs, setReferenceInputs] = useState("B0GYRT3FNL\nB0G6K4VXK7\nB0FX2PRMFR\nB0CLNLL9RZ");
  const [targetMinPrice, setTargetMinPrice] = useState(120);
  const [targetMaxPrice, setTargetMaxPrice] = useState(220);
  const [launchBudget, setLaunchBudget] = useState(6000);
  const [landedCost, setLandedCost] = useState(55);
  const [riskTolerance, setRiskTolerance] = useState("medium");
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [snapshots, setSnapshots] = useState<AmazonListingSnapshot[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const nichePlan = useMemo(() => inferNichePlan(snapshots), [snapshots]);

  async function loadNicheSet() {
    try {
      setLoading(true);
      setError("");
      const candidates = splitAsinCandidates(referenceInputs).slice(0, 5);
      const loaded: AmazonListingSnapshot[] = [];
      for (const candidate of candidates) {
        const response = await fetch(
          `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(candidate)}`,
        );
        const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
        if (response.ok && !("error" in payload)) {
          loaded.push(payload);
        }
      }

      setSnapshots(loaded);
      if (loaded[0]) {
        const matchedCategory = inferCategoryOption(loaded[0], calculatorCategoryOptionGroups);
        if (matchedCategory) {
          setCategory(matchedCategory);
        }
      }
      if (!showAdvanced && loaded.length) {
        const nextPlan = inferNichePlan(loaded);
        setTargetMinPrice(nextPlan.targetMinPrice);
        setTargetMaxPrice(nextPlan.targetMaxPrice);
        setLaunchBudget(nextPlan.launchBudget);
        setLandedCost(nextPlan.landedCost);
        setRiskTolerance(nextPlan.riskTolerance);
      }
      if (!loaded.length) {
        setError("No reference ASINs could be loaded from the current niche set.");
      }
    } catch (fetchError) {
      setSnapshots([]);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load niche references.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(() => {
    const evidenceStatus = getMultiSnapshotEvidenceStatus(snapshots, [
      "title",
      "price",
      "reviewCount",
      "breadcrumbs",
    ]);
    if (!snapshots.length || evidenceStatus.level === "weak") {
      const fallbackDecision = !snapshots.length
        ? "Load direct reference ASINs"
        : "Tighten the niche sample with stronger references";
      const fallbackOwner =
        riskTolerance === "high"
          ? "Founder / GM"
          : riskTolerance === "low"
          ? "Finance / sourcing owner"
          : "Category research owner";
      const fallbackCommercialCall = !snapshots.length
        ? "Do not fund this lane yet"
        : launchBudget / Math.max(landedCost, 1) < 60
          ? "Hold - budget cannot support the lane"
          : "Narrow to one smaller wedge";
      return {
        headline: !snapshots.length
          ? "Niche screen is waiting on a real reference set"
          : "Niche screen needs stronger live references",
        summary:
          "Use this niche read to decide whether the lane deserves one more pass, whether the sample must be tightened first, or whether the idea should be dropped before launch work starts.",
        metrics: [
          {
            label: "Commercial call",
            value: fallbackCommercialCall,
            detail: !snapshots.length
              ? "A niche is not a product until live comparables prove the lane is real."
              : launchBudget / Math.max(landedCost, 1) < 60
                ? "The current budget buys too little opening inventory to treat this lane as a serious launch candidate."
                : "The broad cluster is still too noisy; only a smaller wedge deserves one more pass.",
          },
          {
            label: "Reference set",
            value: snapshots.length ? `${snapshots.length} loaded` : "Missing",
            detail: snapshots.length
              ? evidenceStatus.detail
              : "Load direct substitutes before trusting any niche verdict.",
          },
          {
            label: "Target lane",
            value: `${formatUsd(targetMinPrice)} - ${formatUsd(targetMaxPrice)}`,
            detail: `${formatUsd(launchBudget)} budget | ${formatUsd(landedCost)} landed cost assumption`,
          },
          {
            label: "First move",
            value: fallbackDecision,
            detail: !snapshots.length
              ? "The tool cannot judge whether the niche is real until the comparison set comes from live leaders."
              : "Replace weak references before calling the lane affordable or launchable.",
          },
          {
            label: "Execution owner",
            value: fallbackOwner,
            detail: "Keep the first research blocker with one owner until the lane is narrowed or rejected.",
          },
        ],
        recommendations: [
          !snapshots.length
            ? "Start with the 3-5 ASINs buyers would actually compare against you."
            : "Replace weak references before judging the lane as affordable or crowded.",
          "Do not confuse a desired price band with proof that the niche can support your opening inventory.",
          !snapshots.length
            ? "Do not advance this lane into sourcing or supplier work while the comparable set is still blank."
            : launchBudget / Math.max(landedCost, 1) < 60
              ? "Do not keep polishing the niche story when the budget cannot credibly support entry."
              : "Only continue if the next pass can shrink the lane to one narrower opening with lighter proof pressure.",
        ],
        status: {
          label: !snapshots.length ? "Reference baseline is incomplete" : "Reference quality is still weak",
          tone: "warning" as const,
        },
        missingItems: [
          !snapshots.length ? "Live reference set" : "",
          evidenceStatus.level === "weak" ? "Stronger niche evidence" : "",
        ].filter(Boolean),
        nextSteps: [
          !snapshots.length
            ? "Load direct substitute ASINs."
            : launchBudget / Math.max(landedCost, 1) < 60
              ? "Pause launch planning until budget or landed cost changes materially."
              : "Tighten the niche sample with stronger references.",
          "Keep one owner on budget-fit and entry-lane truth.",
          "Re-run the niche screen before debating launch timing.",
        ],
        actionStance: {
          label: !snapshots.length ? "Do not choose a niche from vibes" : "Do not trust a thin niche sample",
          tone: "warning" as const,
          detail: !snapshots.length
            ? "Keep niche approval closed until the tool is preventing false starts instead of letting the team imagine a market from scratch."
            : "Weak reference coverage makes the lane look cleaner or softer than it really is.",
        },
      } satisfies ToolEvaluation;
    }

    const prices = snapshots.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const ranks = snapshots
      .map((item) => parseRankValue(item.bestSellersRank) || parseRankValue(item.subCategoryRank))
      .filter((value) => value > 0);
    const reviewCounts = snapshots.map((item) => parseReviewCountValue(item.reviewCountText)).filter((value) => value > 0);
    const averageRank = ranks.length ? ranks.reduce((sum, value) => sum + value, 0) / ranks.length : 0;
    const estimatedMonthlyUnits = averageRank > 0 ? estimateMonthlyUnitsFromBsr(category, averageRank) : 0;
    const affordableUnits = landedCost > 0 ? launchBudget / landedCost : 0;
    const monthsOfCover = estimatedMonthlyUnits > 0 ? affordableUnits / estimatedMonthlyUnits : 0;

    return evaluateNicheFinder({
      category,
      referenceCount: snapshots.length,
      averagePrice: prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0,
      lowestPrice: prices.length ? Math.min(...prices) : 0,
      highestPrice: prices.length ? Math.max(...prices) : 0,
      targetMinPrice,
      targetMaxPrice,
      averageRank,
      averageReviewCount: reviewCounts.length ? reviewCounts.reduce((sum, value) => sum + value, 0) / reviewCounts.length : 0,
      strongReviewCount: reviewCounts.filter((value) => value >= 300).length,
      aPlusCount: snapshots.filter((item) => item.hasAPlus).length,
      launchBudget,
      landedCost,
      affordableUnits,
      monthsOfCover,
      riskTolerance: riskTolerance as "low" | "medium" | "high",
    });
  }, [category, landedCost, launchBudget, riskTolerance, snapshots, targetMaxPrice, targetMinPrice]);

  const nicheFinderAuditLines = useMemo(() => {
    const evidenceStatus = getMultiSnapshotEvidenceStatus(snapshots, [
      "title",
      "price",
      "reviewCount",
      "breadcrumbs",
    ]);
    const lines = [`Reference set quality: ${evidenceStatus.label}. ${evidenceStatus.detail}`];
    if (!snapshots.length) {
      lines.push("Load reference ASINs so niche viability is based on real listings instead of assumptions.");
    } else if (evidenceStatus.level !== "complete") {
      lines.push("Treat entry posture and budget-fit calls as directional until the live niche set has fuller coverage.");
    }
    if (snapshots.length) {
      lines.push(`System draft: ${formatUsd(targetMinPrice)}-${formatUsd(targetMaxPrice)} entry lane with ${formatUsd(launchBudget)} launch budget.`);
    }
    return lines;
  }, [launchBudget, snapshots, targetMaxPrice, targetMinPrice]);

  const nicheRows = useMemo(() => {
    if (!snapshots.length) {
      return {
        viabilityRows: [] as Array<{ label: string; value: string; detail?: string }>,
        pressureRows: [] as Array<{ label: string; value: string; detail?: string }>,
        entryRows: [] as Array<{ label: string; value: string; detail?: string }>,
        affordableCount: 0,
        compressedCount: 0,
      };
    }

    const prices = snapshots.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const ranks = snapshots
      .map((item) => parseRankValue(item.bestSellersRank) || parseRankValue(item.subCategoryRank))
      .filter((value) => value > 0);
    const averageRank = ranks.length ? ranks.reduce((sum, value) => sum + value, 0) / ranks.length : 0;
    const estimatedMonthlyUnits = averageRank > 0 ? estimateMonthlyUnitsFromBsr(category, averageRank) : 0;
    const affordableUnits = landedCost > 0 ? launchBudget / landedCost : 0;
    const monthsOfCover = estimatedMonthlyUnits > 0 ? affordableUnits / estimatedMonthlyUnits : 0;

    return buildNicheDecisionRows({
      snapshots,
      averagePrice: prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0,
      estimatedMonthlyUnits,
      targetMinPrice,
      targetMaxPrice,
      monthsOfCover,
      launchBudget,
      landedCost,
    });
  }, [category, landedCost, launchBudget, snapshots, targetMaxPrice, targetMinPrice]);
  const nicheExecutionPlan = useMemo(() => {
    const affordableShare = snapshots.length ? nicheRows.affordableCount / snapshots.length : 0;
    const compressedShare = snapshots.length ? nicheRows.compressedCount / snapshots.length : 0;
    const lowReviewEntryCount = snapshots
      .map((snapshot) => parseReviewCountValue(snapshot.reviewCountText))
      .filter((value) => value > 0 && value <= 120).length;

    return inferNicheExecutionPlan({
      snapshotCount: snapshots.length,
      affordableShare,
      compressedShare,
      lowReviewEntryCount,
      riskTolerance,
    });
  }, [nicheRows.affordableCount, nicheRows.compressedCount, riskTolerance, snapshots]);

  const nicheAuditRows = useMemo(
    () => [
      {
        label: "Reference coverage",
        value: `${snapshots.length} loaded`,
        detail: snapshots.length
          ? `${splitAsinCandidates(referenceInputs).slice(0, 5).length} requested from the niche sample`
          : "Load direct substitutes before using the niche verdict",
      },
      {
        label: "Detected category",
        value: getCategoryLabel(category),
        detail: snapshots[0]?.breadcrumbs.length ? snapshots[0].breadcrumbs.join(" / ") : "Updated from the first live reference when available",
      },
      {
        label: "Target price band",
        value: `${formatUsd(targetMinPrice)} - ${formatUsd(targetMaxPrice)}`,
        detail: "This is your desired sell-price lane, not a live marketplace fact",
      },
      {
        label: "Launch budget",
        value: formatUsd(launchBudget),
        detail: `${formatUsd(landedCost)} assumed landed cost per unit`,
      },
      {
        label: "Risk posture",
        value: riskTolerance,
        detail: "Used to judge whether the same niche looks acceptable for a cautious or aggressive launch",
      },
      {
        label: "Execution call",
        value: nicheExecutionPlan.decision,
        detail: `${nicheExecutionPlan.proofPriority} | ${nicheExecutionPlan.cadence}`,
      },
    ],
    [category, landedCost, launchBudget, nicheExecutionPlan, referenceInputs, riskTolerance, snapshots, targetMaxPrice, targetMinPrice],
  );

  const nicheDecisionRows = useMemo(() => {
    const openingReference = snapshots
      .map((snapshot) => ({
        snapshot,
        reviews: parseReviewCountValue(snapshot.reviewCountText),
        price: parseCurrencyAmount(snapshot.priceText),
      }))
      .filter((item) => item.price >= targetMinPrice && item.price <= targetMaxPrice)
      .sort((a, b) => a.reviews - b.reviews || a.price - b.price)[0];

    return [
      {
        label: "First move",
        value: snapshots.length ? nicheExecutionPlan.decision : "Load direct reference ASINs",
        detail: snapshots.length
          ? nicheExecutionPlan.nextMove
          : "A niche screen only becomes useful when it starts from the real products buyers already compare.",
      },
      {
        label: "Execution owner",
        value: nicheExecutionPlan.owner,
        detail: `${nicheExecutionPlan.cadence}. One owner carries budget truth, entry truth, and wedge truth through the same pass. ${nicheExecutionPlan.watchout}`,
      },
      {
        label: "Do not cross",
        value:
          !snapshots.length
            ? "Do not choose a niche from a price band alone"
            : nicheRows.affordableCount <= 0
              ? "Do not force-fit budget into a lane it cannot fund"
              : "Do not mistake lower reviews for a free opening",
        detail:
          !snapshots.length
            ? "Your target band and budget are constraints, not proof that the market lane is good."
            : nicheRows.affordableCount <= 0
              ? "If opening inventory math already breaks, more optimism does not rescue the lane."
              : "Softer review proof still needs to be checked against demand quality, price pressure, and catalog strength.",
      },
      {
        label: "Then do",
        value: openingReference?.snapshot.asin ?? "Tighten the niche sample",
        detail: openingReference
          ? `${openingReference.snapshot.priceText || "No price"} | ${openingReference.snapshot.reviewCountText || "No reviews"} | Reverse-engineer the smallest viable opening from this one reference before the team widens the lane again.`
          : "No reference currently sits inside the target lane with obviously softer proof.",
      },
      {
        label: "Watch",
        value: nicheRows.affordableCount ? `${nicheRows.affordableCount} reachable references` : "Budget mismatch",
        detail: `Current budget and landed-cost assumptions buy roughly ${Math.floor(launchBudget / Math.max(landedCost, 1)).toLocaleString("en-US")} units of opening inventory. Do not widen the lane again until that opening math still holds on the next pass with the same reference pack.`,
      },
    ];
  }, [launchBudget, landedCost, nicheExecutionPlan, nicheRows.affordableCount, nicheRows.compressedCount, snapshots, targetMaxPrice, targetMinPrice]);

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1.2fr_1.2fr_auto_auto]">
        <Field label="Reference ASINs or URLs">
          <TextAreaInput
            value={referenceInputs}
            onChange={(e) => setReferenceInputs(e.target.value)}
            className="min-h-[7.5rem]"
            spellCheck={false}
          />
        </Field>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowAdvanced((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showAdvanced ? "Hide advanced settings" : "Adjust entry assumptions"}
          </button>
        </div>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadNicheSet} disabled={loading || !referenceInputs.trim()}>
            {loading ? "Loading..." : "Load live niche set"}
          </ActionButton>
        </div>
      </div>
      {showAdvanced ? (
        <div className="grid gap-2.5 md:grid-cols-[1fr_0.7fr_0.7fr_0.8fr_0.8fr_0.8fr_0.8fr]">
          <Field label="Broad category">
            <SelectInput value={category} onChange={(e) => setCategory(e.target.value)}>
              {renderOptionGroups(calculatorCategoryOptionGroups)}
            </SelectInput>
          </Field>
          <Field label="Marketplace">
            <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
              {renderOptions(amazonMarketplaces)}
            </SelectInput>
          </Field>
          <Field label="Min price">
            <NumberInput value={targetMinPrice} min="0" step="1" onChange={(e) => setTargetMinPrice(Number(e.target.value))} />
          </Field>
          <Field label="Max price">
            <NumberInput value={targetMaxPrice} min="0" step="1" onChange={(e) => setTargetMaxPrice(Number(e.target.value))} />
          </Field>
          <Field label="Launch budget">
            <NumberInput value={launchBudget} min="0" step="100" onChange={(e) => setLaunchBudget(Number(e.target.value))} />
          </Field>
          <Field label="Risk tolerance">
            <SelectInput value={riskTolerance} onChange={(e) => setRiskTolerance(e.target.value)}>
              <option value="low">Low</option>
              <option value="medium">Medium</option>
              <option value="high">High</option>
            </SelectInput>
          </Field>
          <Field label="Assumed landed cost per unit">
            <NumberInput value={landedCost} min="0" step="0.01" onChange={(e) => setLandedCost(Number(e.target.value))} />
          </Field>
        </div>
      ) : null}
      {error ? (
        <div className="rounded-xl border border-rose-200 bg-rose-50 px-4 py-3 text-sm text-rose-950">
          {error}
        </div>
      ) : null}
      <DistributionPanel title="Live niche inputs" rows={nicheAuditRows} />
      <AuditNote lines={nicheFinderAuditLines} />
      <CompetitorBoard own={snapshots[0] ?? null} competitors={snapshots.slice(1)} primaryLabel="Reference ASIN 1" />
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title="Niche viability" rows={nicheRows.viabilityRows} />
        <DistributionPanel title="Pressure points" rows={nicheRows.pressureRows} />
        <DistributionPanel title="Entry posture" rows={nicheRows.entryRows} />
      </div>
      <DistributionPanel title="Entry decision" rows={nicheDecisionRows} />
    </RuntimeShell>
  );
}

function TrendingProductsRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [category, setCategory] = useState("home__root-home-kitchen-tth");
  const [seedKeyword, setSeedKeyword] = useState("arched full length mirror");
  const [referenceInputs, setReferenceInputs] = useState("B0GYRT3FNL\nB0G6K4VXK7\nB0FX2PRMFR\nB0CLNLL9RZ");
  const [trendObjective, setTrendObjective] = useState("launch-window");
  const [entryPosture, setEntryPosture] = useState("balanced");
  const [decisionCadence, setDecisionCadence] = useState("this-week");
  const [timeHorizonDays, setTimeHorizonDays] = useState(90);
  const [launchBudget, setLaunchBudget] = useState(6000);
  const [landedCost, setLandedCost] = useState(55);
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [snapshots, setSnapshots] = useState<AmazonListingSnapshot[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const trendPlan = useMemo(() => inferTrendingPlan(snapshots, category), [category, snapshots]);

  async function loadTrendSet() {
    try {
      setLoading(true);
      setError("");
      const candidates = splitAsinCandidates(referenceInputs).slice(0, 5);
      const loaded: AmazonListingSnapshot[] = [];
      for (const candidate of candidates) {
        const response = await fetch(
          `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(candidate)}`,
        );
        const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
        if (response.ok && !("error" in payload)) {
          loaded.push(payload);
        }
      }

      const nextTrendPlan = inferTrendingPlan(loaded, category);
      const nextExecutionPlan = inferTrendExecutionPlan(loaded, category);
      setSnapshots(loaded);
      if (loaded[0]) {
        const matchedCategory = inferCategoryOption(loaded[0], calculatorCategoryOptionGroups);
        if (matchedCategory) {
          setCategory(matchedCategory);
        }
      }
      if (!showAdvanced && loaded.length) {
        if (nextTrendPlan.seedKeyword) {
          setSeedKeyword(nextTrendPlan.seedKeyword);
        }
        setTrendObjective(nextExecutionPlan.trendObjective);
        setEntryPosture(nextExecutionPlan.entryPosture);
        setDecisionCadence(nextExecutionPlan.decisionCadence);
        setTimeHorizonDays(nextTrendPlan.timeHorizonDays);
        setLaunchBudget(nextTrendPlan.launchBudget);
        setLandedCost(nextTrendPlan.landedCost);
      }
      if (!loaded.length) {
        setError("No reference ASINs could be loaded from the current trend set.");
      }
    } catch (fetchError) {
      setSnapshots([]);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load trend references.");
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    if (snapshots.length || loading || error || !referenceInputs.trim()) {
      return;
    }
    void loadTrendSet();
  }, []);

  const trendRows = useMemo(() => {
    return buildTrendDecisionRows({
      snapshots,
      timeHorizonDays,
      seasonalityFactor: getRuntimeSeasonalityFactor(category, new Date().getMonth() + 1),
    });
  }, [category, snapshots, timeHorizonDays]);
  const trendDecisionPlan = useMemo(
    () =>
      inferTrendDecisionPlan({
        snapshotCount: snapshots.length,
        earlySignalCount: trendRows.earlySignalCount,
        matureSignalCount: trendRows.matureSignalCount,
        trendObjective,
        decisionCadence,
        seasonalityFactor: getRuntimeSeasonalityFactor(category, new Date().getMonth() + 1),
      }),
    [category, decisionCadence, snapshots.length, trendObjective, trendRows.earlySignalCount, trendRows.matureSignalCount],
  );

  const result = useMemo(() => {
    const evidenceStatus = getMultiSnapshotEvidenceStatus(snapshots, [
      "title",
      "price",
      "reviewCount",
      "breadcrumbs",
    ]);
    if (!snapshots.length || evidenceStatus.level === "weak") {
      const isBootstrappingLiveSet = loading && !snapshots.length && !error && !!referenceInputs.trim();
      const seededReferenceCount = splitAsinCandidates(referenceInputs).slice(0, 5).length;
      const fallbackDecision = !snapshots.length
        ? isBootstrappingLiveSet
          ? "Reading the live trend set first"
          : "Stage the trend cluster and load the live read"
        : "Strengthen the trend set before calling the window real";
      const fallbackOwner =
        decisionCadence === "now"
          ? "Category / launch owner"
          : decisionCadence === "monitor"
          ? "Trend watch lead"
          : "Trend watch lead";
      const fallbackCommercialCall = !snapshots.length
        ? isBootstrappingLiveSet
          ? "Hold until the live trend references finish loading"
          : "Do not open launch work from setup alone"
        : launchBudget / Math.max(landedCost, 1) < 60
          ? "Hold - timing signal is underfunded"
          : "Watch once more before acting";
      return {
        headline: !snapshots.length
          ? isBootstrappingLiveSet
            ? "Reading the live trend cluster before making a timing call"
            : "The trend cluster is waiting on live proof before launch work"
          : "Do not call this window real yet - the live trend cluster is still too weak",
        summary:
          "This timing call stays blocked until the same live cluster proves a tradable window twice.",
        metrics: [
          {
            label: "Commercial call",
            value: fallbackCommercialCall,
            detail: !snapshots.length
              ? "The current cluster can frame the watchlist, but it cannot approve launch work by itself."
              : launchBudget / Math.max(landedCost, 1) < 60
                ? "Even a real timing signal is not actionable if the current budget cannot support the opening move."
                : "The cluster may be interesting, but one more pass should prove persistence before anyone acts on it.",
          },
          {
            label: "Reference cluster",
            value: snapshots.length ? `${snapshots.length} loaded` : `${seededReferenceCount} references ready`,
            detail: snapshots.length
              ? evidenceStatus.detail
              : isBootstrappingLiveSet
                ? "Live leader PDPs are loading now from the current trend cluster."
                : "The trend cluster is ready; run the live read before trusting the timing call.",
          },
          {
            label: "Approval brief",
            value: `${trendObjective.replace(/-/g, " ")} / ${entryPosture}`,
            detail: `${timeHorizonDays} day horizon with ${formatUsd(launchBudget)} budget`,
          },
          {
            label: "Open window",
            value: fallbackDecision,
            detail: !snapshots.length
              ? "Launch work stays closed until those references resolve into live leaders."
              : "Replace weak references before naming the cluster early, mature, or late.",
          },
          {
            label: "Decision owner",
            value: fallbackOwner,
            detail: "Keep the timing call under one owner until the cluster is either tradable or dismissed.",
          },
        ],
        recommendations: [
          !snapshots.length
            ? isBootstrappingLiveSet
              ? "Let the current live trend references finish loading before you replace the cluster or call the window."
              : "Use the current ASIN pack as the first watch cluster, then load the live read before naming the window."
            : "Replace weak references before calling the window early enough to launch.",
          "Forbidden move: confusing a catchy keyword idea with proof that the timing window is commercially open.",
          !snapshots.length
            ? isBootstrappingLiveSet
              ? "Do not assign launch work while the live trend read is still in flight."
              : "Do not assign launch work yet while the cluster still has no live timing proof."
            : launchBudget / Math.max(landedCost, 1) < 60
              ? "Do not chase timing while capital reality is still below the opening requirement."
              : "Only continue if the next pass can prove the same cluster is still moving, not just noisy once.",
        ],
        status: {
          label: !snapshots.length ? "Trend cluster is waiting on live proof" : "Trend evidence is still weak",
          tone: "warning" as const,
        },
        riskItems: [
          !snapshots.length
            ? isBootstrappingLiveSet
              ? "The live trend pull is still running, so timing, budget, and launch work are still blocked."
              : "The cluster still has no live proof; assigning launch work now would turn a watchlist into false urgency."
            : launchBudget / Math.max(landedCost, 1) < 60
              ? "The current budget cannot support a credible opening move even if the timing signal turns out to be real."
              : "A thin live cluster can make random momentum look like a tradable launch window when it is only noise.",
        ],
        missingItems: [
          !snapshots.length ? "Live timing proof" : "",
          evidenceStatus.level === "weak" ? "Stronger trend evidence" : "",
        ].filter(Boolean),
        nextSteps: [
          !snapshots.length
            ? isBootstrappingLiveSet
              ? "Wait for the current trend cluster to finish loading."
              : "Load the current trend cluster as a live read."
            : launchBudget / Math.max(landedCost, 1) < 60
              ? "Pause launch planning until the opening budget can support the lane."
              : "Strengthen the trend cluster with clearer PDPs.",
          "Put one owner on the timing decision.",
          "Re-open this window only after the same cluster survives one stronger pass.",
        ],
        actionStance: {
          label: !snapshots.length
            ? isBootstrappingLiveSet
              ? "Wait for the live trend read to finish"
              : "Do not approve launch timing before the live references land"
            : "Do not overread thin trend evidence",
          tone: "warning" as const,
          detail: !snapshots.length
            ? isBootstrappingLiveSet
              ? "The tool is already pulling live leader PDPs. Let that read finish before you accept or reject the timing window."
              : "This cluster is still only a watchlist. Do not release launch work until the same live window proves itself twice."
            : "Weak cluster coverage makes the window look cleaner or earlier than the live market may really be.",
        },
      } satisfies ToolEvaluation;
    }

    const prices = snapshots.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const ranks = snapshots
      .map((item) => parseRankValue(item.bestSellersRank) || parseRankValue(item.subCategoryRank))
      .filter((value) => value > 0);
    const reviewCounts = snapshots.map((item) => parseReviewCountValue(item.reviewCountText)).filter((value) => value > 0);

    if (!prices.length) {
      const averageRank = ranks.length ? ranks.reduce((sum, value) => sum + value, 0) / ranks.length : 0;
      const estimatedMonthlyUnits =
        averageRank > 0 ? estimateMonthlyUnitsFromBsr(category, averageRank) : 0;
      const earlySignalShare = snapshots.length ? trendRows.earlySignalCount / snapshots.length : 0;
      const maturityPressure = trendRows.matureSignalCount > trendRows.earlySignalCount;

      return {
        headline:
          earlySignalShare >= 0.5 && estimatedMonthlyUnits >= 150
            ? "The window may be opening, but pricing still blocks launch approval"
            : "Do not call this launch window real yet",
        summary:
          "This is still watch mode. Momentum may be forming, but launch timing stays closed until price evidence is real.",
        metrics: [
          {
            label: "Commercial call",
            value:
              earlySignalShare >= 0.5 && estimatedMonthlyUnits >= 150
                ? "Keep this on the timing watchlist"
                : "Hold the timing call",
            detail: "Use this pass to judge signal persistence, not to approve launch work.",
          },
          {
            label: "Early signal share",
            value: `${trendRows.earlySignalCount}/${snapshots.length}`,
            detail: `${trendRows.matureSignalCount}/${snapshots.length} references already look mature or merchandised`,
          },
          {
            label: "Demand band",
            value: estimatedMonthlyUnits > 0 ? `${estimatedMonthlyUnits.toLocaleString("en-US")} units/mo` : "Partial rank baseline",
            detail:
              averageRank > 0
                ? `Average BSR #${Math.round(averageRank).toLocaleString("en-US")} from the current live cluster`
                : "Not enough rank evidence to size the timing window cleanly",
          },
          {
            label: "Momentum pressure",
            value: maturityPressure ? "Late / crowded" : "Still watchable",
            detail: "Review age, badge density, and merchandising maturity are driving this timing read.",
          },
          {
            label: "Economics gate",
            value: "Price capture missing",
            detail: "Do not approve opening inventory, launch timing, or budget coverage until at least one visible price baseline is recovered.",
          },
          {
            label: "Decision owner",
            value: "Trend watch lead",
            detail: "The same owner should re-check this cluster once price is recovered so timing and economics stay tied together.",
          },
        ],
        recommendations: [
          earlySignalShare >= 0.5
            ? "The cluster is interesting enough to watch closely, but not to fund yet."
            : "Do not let a partial trend read turn into launch urgency.",
          "Forbidden move: treating review, rank, and badge signals as a complete launch approval while visible sell-price proof is still missing.",
          maturityPressure
            ? "Assume the cluster may already be maturing. Re-open only if the same references still look early after the economics layer is recovered."
            : "Freeze the same reference cluster and re-run once price baselines are available.",
          "Do not assign sourcing or launch work until price, budget cover, and timing survive the same pass together.",
        ],
        alerts: [
          "Visible pricing is missing across the current live trend cluster.",
          "Launch timing cannot be approved without a real economics layer.",
        ],
        status: {
          label: "Directional trend read only",
          tone: "warning" as const,
        },
        actionStance: {
          label: "Watch the window, but do not launch into it yet",
          tone: "warning" as const,
          detail:
            "This is enough evidence to maintain or kill a watchlist candidate, not enough to approve budgeted launch work.",
        },
        missingItems: ["Visible competitor price data"],
        riskItems: [
          "Without price, timing and budget coverage remain unapproved.",
        ],
        nextSteps: [
          "Freeze the current cluster and recover visible pricing from the same references.",
          "Do not open launch work until timing and economics survive in the same read.",
          "Re-run the window only after price and budget coverage can be judged on live evidence.",
        ],
      } satisfies ToolEvaluation;
    }

    return evaluateTrendingProducts({
      category,
      keyword: seedKeyword,
      referenceCount: snapshots.length,
      timeHorizonDays,
      currentMonth: new Date().getMonth() + 1,
      averagePrice: prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0,
      averageRank: ranks.length ? ranks.reduce((sum, value) => sum + value, 0) / ranks.length : 0,
      lowReviewCount: reviewCounts.filter((value) => value > 0 && value <= 120).length,
      badgeCarrierCount: snapshots.filter((item) => item.badges.length > 0).length,
      strongDemandCount: ranks.filter((value) => value > 0 && value <= 5000).length,
      aPlusCount: snapshots.filter((item) => item.hasAPlus).length,
      launchBudget,
      landedCost,
      earlySignalCount: trendRows.earlySignalCount,
      matureSignalCount: trendRows.matureSignalCount,
    });
  }, [category, decisionCadence, entryPosture, landedCost, launchBudget, seedKeyword, snapshots, timeHorizonDays, trendObjective, trendRows.earlySignalCount, trendRows.matureSignalCount]);

  const trendingProductsAuditLines = useMemo(() => {
    const evidenceStatus = getMultiSnapshotEvidenceStatus(snapshots, [
      "title",
      "price",
      "reviewCount",
      "breadcrumbs",
    ]);
    const seededReferenceCount = splitAsinCandidates(referenceInputs).slice(0, 5).length;
    const isBootstrappingLiveSet = loading && !snapshots.length && !error && seededReferenceCount > 0;
    const lines = [`Trend set quality: ${evidenceStatus.label}. ${evidenceStatus.detail}`];
    if (!snapshots.length) {
      lines.push(
        isBootstrappingLiveSet
          ? "The trend cluster is loading now. Hold the timing call until the live read finishes."
          : seededReferenceCount > 0
            ? "The trend cluster is ready. Pull the same ASIN set live before assigning launch work."
            : "Load reference ASINs so the timing verdict is grounded in real category leaders.",
      );
    } else if (evidenceStatus.level !== "complete") {
      lines.push("Keep early-signal timing calls in watch mode until the trend set has fuller live coverage.");
    }
    if (snapshots.length) {
      lines.push(`System draft: ${timeHorizonDays}-day horizon with ${formatUsd(launchBudget)} launch budget and ${formatUsd(landedCost)} landed cost.`);
    }
    return lines;
  }, [error, landedCost, launchBudget, loading, referenceInputs, snapshots, timeHorizonDays]);

  const momentumRows = useMemo(
    () =>
      snapshots.map((snapshot) => {
        const rank = parseRankValue(snapshot.bestSellersRank) || parseRankValue(snapshot.subCategoryRank);
        const reviews = parseReviewCountValue(snapshot.reviewCountText);
        const price = parseCurrencyAmount(snapshot.priceText);
        const momentum =
          (rank > 0 && rank <= 5000 ? 1 : 0) +
          (reviews > 0 && reviews <= 120 ? 1 : 0) +
          (snapshot.badges.length > 0 ? 1 : 0) +
          (snapshot.hasAPlus ? 1 : 0);

        return {
          label: snapshot.asin,
          value: `${momentum}/4`,
          detail: `${price ? `$${Math.round(price)}` : "No price"} | ${rank ? `#${rank.toLocaleString("en-US")}` : "No rank"} | ${reviews ? `${reviews} reviews` : "No reviews"}`,
        };
      }),
    [snapshots],
  );

  const trendAuditRows = useMemo(() => {
    const seededReferenceCount = splitAsinCandidates(referenceInputs).slice(0, 5).length;
    const isBootstrappingLiveSet = loading && !snapshots.length && !error && seededReferenceCount > 0;
    return [
      {
        label: "Reference coverage",
        value: snapshots.length ? `${snapshots.length} loaded` : seededReferenceCount ? `${seededReferenceCount} references ready` : "0 loaded",
        detail: snapshots.length
          ? `${splitAsinCandidates(referenceInputs).slice(0, 5).length} requested from the trend cluster`
          : isBootstrappingLiveSet
            ? "Pulling the current trend cluster into live PDP reads now"
            : seededReferenceCount
              ? "The cluster is ready. Run the live pull before trusting the timing call."
              : "Load live reference ASINs before trusting timing calls",
      },
      {
        label: "Detected category",
        value: getCategoryLabel(category),
        detail: snapshots[0]?.breadcrumbs.length ? snapshots[0].breadcrumbs.join(" / ") : "Updated from the first live reference when available",
      },
      {
        label: "Trend frame",
        value: seedKeyword || "Not set",
        detail: "Keyword or idea used to name the cluster you are evaluating",
      },
      {
        label: "Approval brief",
        value: `${trendObjective.replace(/-/g, " ")} / ${entryPosture}`,
        detail: `${decisionCadence.replace(/-/g, " ")} cadence for this trend pass`,
      },
      {
        label: "Horizon",
        value: `${timeHorizonDays} days`,
        detail: `${formatUsd(launchBudget)} budget with ${formatUsd(landedCost)} landed cost assumption`,
      },
      {
        label: "Marketplace",
        value: marketplace,
        detail: "Seasonality and demand cues are read against this marketplace's PDP sample",
      },
      {
        label: "Execution call",
        value: trendDecisionPlan.decision,
        detail: `${trendDecisionPlan.proofPriority} | ${trendDecisionPlan.cadence}`,
      },
    ];
  }, [category, decisionCadence, entryPosture, error, landedCost, launchBudget, loading, marketplace, referenceInputs, seedKeyword, snapshots, timeHorizonDays, trendDecisionPlan, trendObjective]);

  const trendPostureRows = useMemo(() => {
    const seededReferenceCount = splitAsinCandidates(referenceInputs).slice(0, 5).length;
    const isBootstrappingLiveSet = loading && !snapshots.length && !error && seededReferenceCount > 0;
    const launchCapacity = landedCost > 0 ? launchBudget / landedCost : 0;
    const bestWindow = snapshots
      .map((snapshot) => {
        const rank = parseRankValue(snapshot.bestSellersRank) || parseRankValue(snapshot.subCategoryRank);
        const reviews = parseReviewCountValue(snapshot.reviewCountText);
        const price = parseCurrencyAmount(snapshot.priceText);
        const score = (rank > 0 && rank <= 5000 ? 2 : rank > 0 && rank <= 15000 ? 1 : 0) + (reviews > 0 && reviews <= 120 ? 2 : reviews > 0 && reviews <= 300 ? 1 : 0);
        return { snapshot, score, rank, reviews, price };
      })
      .sort((a, b) => b.score - a.score || a.reviews - b.reviews)[0];

    return [
      {
        label: "Approval call",
        value: snapshots.length
          ? trendDecisionPlan.decision
          : isBootstrappingLiveSet
            ? "Wait for the live trend read"
            : seededReferenceCount
              ? "Load the current trend cluster live"
              : trendDecisionPlan.decision,
        detail: snapshots.length
          ? trendDecisionPlan.nextMove
          : isBootstrappingLiveSet
            ? "The current cluster is already being read live. Let that finish before naming the launch window."
            : seededReferenceCount
              ? "The timing lane is still unproven, so it cannot become launch work before the live pull."
              : trendDecisionPlan.nextMove,
      },
      {
        label: "Benchmark first",
        value: bestWindow?.snapshot.asin ?? "Lead signal to lock next",
        detail: bestWindow
          ? `${bestWindow.snapshot.priceText || "No price"} | ${bestWindow.snapshot.reviewCountText || "No reviews"} | Use this ASIN as the timing benchmark for whether the window is still early.`
          : "Load the cluster leader first so the next timing pass is anchored to one real benchmark.",
      },
      {
        label: "Decision owner",
        value: trendDecisionPlan.owner,
        detail: `${trendDecisionPlan.cadence}. ${trendDecisionPlan.watchout}`,
      },
      {
        label: "Do not cross",
        value:
          !snapshots.length
            ? seededReferenceCount
              ? "Do not approve this timing lane from a draft setup"
              : "Do not time a launch from a keyword story alone"
            : decisionCadence === "now"
              ? "Do not broaden the cluster before testing the best timing signal"
              : "Do not confuse noisy momentum with a real launch window",
        detail:
          !snapshots.length
            ? seededReferenceCount
              ? "This cluster matters only if the same references survive the live pass and still justify launch timing."
              : "A real trend call starts from live PDPs, not from a catchy category phrase."
            : decisionCadence === "now"
              ? "When the team is acting now, the next job is to validate the strongest signal, not add more speculative references."
              : "Thin or mixed clusters often look trendier than the underlying demand really is.",
      },
      {
        label: "Budget gate",
        value: `${Math.floor(launchCapacity).toLocaleString("en-US")} units`,
        detail: "This is the approximate opening inventory your current budget supports at the assumed landed cost.",
      },
      {
        label: "Re-open only if",
        value:
          decisionCadence === "now"
            ? "Run product economics on the best signal"
            : decisionCadence === "this-week"
              ? "Re-check the same ASIN set once"
              : "Move this into niche screening later",
        detail:
          decisionCadence === "now"
            ? "Do not broaden the cluster before you test whether the likely entry SKU still works after cost and compliance."
            : decisionCadence === "this-week"
              ? "The next pass should answer persistence versus noise, not open a new research rabbit hole."
              : "If the timing window is weak now, preserve the references and revisit only when demand or seasonality changes.",
      },
      {
        label: "Hold this benchmark",
        value: bestWindow?.snapshot.asin ?? "Lead signal to lock next",
        detail:
          bestWindow
            ? `${bestWindow.rank ? `#${bestWindow.rank.toLocaleString("en-US")}` : "No rank"} | ${bestWindow.reviews ? `${bestWindow.reviews} reviews` : "No reviews"} | This is the benchmark to re-check for persistence versus noise.`
            : seededReferenceCount
              ? "Run the current references first, then lock the strongest benchmark so the next timing pass tests persistence instead of noise."
              : "Without one fixed timing benchmark, the trend story is still too soft for a real launch decision.",
      },
    ];
  }, [decisionCadence, error, landedCost, launchBudget, loading, referenceInputs, snapshots, trendDecisionPlan]);

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_1.1fr_auto_auto]">
        <Field label="Category or keyword">
          <TextInput value={seedKeyword} onChange={(e) => setSeedKeyword(e.target.value)} />
        </Field>
        <Field label="Reference ASINs or URLs">
          <TextAreaInput
            value={referenceInputs}
            onChange={(e) => setReferenceInputs(e.target.value)}
            className="min-h-[7.5rem]"
            spellCheck={false}
          />
        </Field>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowAdvanced((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showAdvanced ? "Hide advanced settings" : "Adjust timing assumptions"}
          </button>
        </div>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadTrendSet} disabled={loading || !referenceInputs.trim()}>
            {loading ? "Loading..." : "Load live trend set"}
          </ActionButton>
        </div>
      </div>
      <div className="grid gap-2.5 md:grid-cols-[0.95fr_0.95fr_0.95fr]">
        <Field label="Trend objective">
          <SelectInput value={trendObjective} onChange={(e) => setTrendObjective(e.target.value)}>
            <option value="launch-window">Launch window</option>
            <option value="watchlist">Watchlist</option>
            <option value="late-cluster-check">Late cluster check</option>
          </SelectInput>
        </Field>
        <Field label="Entry posture">
          <SelectInput value={entryPosture} onChange={(e) => setEntryPosture(e.target.value)}>
            <option value="balanced">Balanced</option>
            <option value="aggressive">Aggressive</option>
            <option value="conservative">Conservative</option>
          </SelectInput>
        </Field>
        <Field label="Decision cadence">
          <SelectInput value={decisionCadence} onChange={(e) => setDecisionCadence(e.target.value)}>
            <option value="now">Now</option>
            <option value="this-week">This week</option>
            <option value="monitor">Monitor</option>
          </SelectInput>
        </Field>
      </div>
      {showAdvanced ? (
        <div className="grid gap-2.5 md:grid-cols-[1fr_0.7fr_0.7fr_0.8fr_0.8fr_0.8fr]">
          <Field label="Broad category">
            <SelectInput value={category} onChange={(e) => setCategory(e.target.value)}>
              {renderOptionGroups(calculatorCategoryOptionGroups)}
            </SelectInput>
          </Field>
          <Field label="Marketplace">
            <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
              {renderOptions(amazonMarketplaces)}
            </SelectInput>
          </Field>
          <Field label="Horizon (days)">
            <NumberInput value={timeHorizonDays} min="30" step="30" onChange={(e) => setTimeHorizonDays(Number(e.target.value))} />
          </Field>
          <Field label="Budget">
            <NumberInput value={launchBudget} min="0" step="100" onChange={(e) => setLaunchBudget(Number(e.target.value))} />
          </Field>
          <Field label="Assumed landed cost per unit">
            <NumberInput value={landedCost} min="0" step="0.01" onChange={(e) => setLandedCost(Number(e.target.value))} />
          </Field>
        </div>
      ) : null}
      {error ? (
        <div className="rounded-xl border border-rose-200 bg-rose-50 px-4 py-3 text-sm text-rose-950">{error}</div>
      ) : null}
      <DistributionPanel title="Window brief" rows={trendAuditRows} />
      <AuditNote lines={trendingProductsAuditLines} />
      <CompetitorBoard own={snapshots[0] ?? null} competitors={snapshots.slice(1)} primaryLabel="Trend reference 1" />
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title="Approval board" rows={trendRows.timingRows} />
        <DistributionPanel title="Lead signals" rows={trendRows.leaderRows} />
        <DistributionPanel title="Window blockers" rows={trendRows.windowRows} />
      </div>
      <DistributionPanel title="Decision board" rows={trendPostureRows} />
      <DistributionPanel title="Signal map" rows={momentumRows} />
    </RuntimeShell>
  );
}

function SellerAnalyticsRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [portfolioInputs, setPortfolioInputs] = useState("B0GYRT3FNL\nB0G6K4VXK7\nB0FX2PRMFR\nB0CLNLL9RZ");
  const [portfolioObjective, setPortfolioObjective] = useState("copy-playbook");
  const [portfolioPosture, setPortfolioPosture] = useState("specialist-check");
  const [executionLens, setExecutionLens] = useState("assortment");
  const [benchmarkFocus, setBenchmarkFocus] = useState("assortment");
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [snapshots, setSnapshots] = useState<AmazonListingSnapshot[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  async function loadPortfolio() {
    try {
      setLoading(true);
      setError("");
      const candidates = splitAsinCandidates(portfolioInputs).slice(0, 8);
      const loaded: AmazonListingSnapshot[] = [];
      for (const candidate of candidates) {
        const response = await fetch(
          `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(candidate)}`,
        );
        const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
        if (response.ok && !("error" in payload)) {
          loaded.push(payload);
        }
      }

      setSnapshots(loaded);
      if (!showAdvanced && loaded.length) {
        setBenchmarkFocus(inferSellerBenchmarkFocus(loaded));
        const nextPortfolioPlan = inferSellerPortfolioPlan(loaded);
        setPortfolioObjective(nextPortfolioPlan.portfolioObjective);
        setPortfolioPosture(nextPortfolioPlan.portfolioPosture);
        setExecutionLens(nextPortfolioPlan.executionLens);
      }
      if (!loaded.length) {
        setError("No storefront or portfolio ASINs could be loaded from the current set.");
      }
    } catch (fetchError) {
      setSnapshots([]);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load seller portfolio.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(() => {
    const evidenceStatus = getMultiSnapshotEvidenceStatus(snapshots, [
      "title",
      "price",
      "reviewCount",
      "breadcrumbs",
    ]);
    if (!snapshots.length || evidenceStatus.level === "weak") {
      const fallbackDecision = !snapshots.length
        ? "Load a real storefront sample"
        : "Strengthen the portfolio sample before benchmarking";
      const fallbackOwner =
        executionLens === "price-ladder"
          ? "Pricing strategist"
          : executionLens === "proof-depth"
            ? "Brand / content owner"
            : portfolioObjective === "margin-playbook"
              ? "Category manager"
              : "Portfolio research owner";
      return {
        headline: !snapshots.length
          ? "Seller portfolio read is waiting on a live storefront sample"
          : "Seller portfolio read needs stronger live coverage",
        summary:
          "Use this storefront read to decide whether deeper benchmarking is still worth doing, which proof matters first, and who owns the next benchmark pass.",
        metrics: [
          {
            label: "Portfolio sample",
            value: snapshots.length ? `${snapshots.length} loaded` : "Missing",
            detail: snapshots.length
              ? evidenceStatus.detail
              : "Load the storefront ASINs you actually consider competitive.",
          },
          {
            label: "Read objective",
            value: `${portfolioObjective.replace(/-/g, " ")} / ${executionLens.replace(/-/g, " ")}`,
            detail: `${portfolioPosture.replace(/-/g, " ")} posture for this seller pass`,
          },
          {
            label: "First move",
            value: fallbackDecision,
            detail: !snapshots.length
              ? "The seller story should start from visible assortment truth, not guesswork."
              : "Replace weak portfolio pages before inferring assortment depth, pricing ladder, or moat shape.",
          },
          {
            label: "Execution owner",
            value: fallbackOwner,
            detail: "Keep one owner on the benchmark lens so the storefront read does not drift into anecdotes.",
          },
        ],
        recommendations: [
          !snapshots.length
            ? "Sample the seller's actual hero SKUs before you generalize the whole storefront."
            : "Replace weak portfolio pages before inferring assortment depth or monetization pattern.",
          "Do not benchmark a storefront from one anecdotal SKU when the real question is portfolio structure.",
        ],
        status: {
          label: !snapshots.length ? "Portfolio baseline is incomplete" : "Portfolio evidence is still weak",
          tone: "warning" as const,
        },
        missingItems: [
          !snapshots.length ? "Live portfolio sample" : "",
          evidenceStatus.level === "weak" ? "Stronger storefront evidence" : "",
        ].filter(Boolean),
        nextSteps: [
          !snapshots.length ? "Load the first storefront sample." : "Strengthen the portfolio sample with clearer PDPs.",
          "Keep one owner on the benchmark lens until the same portfolio sample is rechecked.",
          "Re-run before calling the seller a moat or a copy target.",
        ],
        actionStance: {
          label: !snapshots.length ? "Do not benchmark from anecdotes" : "Do not overread thin storefront evidence",
          tone: "warning" as const,
          detail: !snapshots.length
            ? "Keep catalog benchmarking closed until the tool is reading a real storefront sample instead of remembered assortment lore."
            : "Weak assortment coverage makes the seller look more coherent than the live portfolio may actually be.",
        },
      } satisfies ToolEvaluation;
    }

    const prices = snapshots.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const reviewCounts = snapshots.map((item) => parseReviewCountValue(item.reviewCountText)).filter((value) => value > 0);
    const categoryCounts = new Map<string, number>();
    for (const snapshot of snapshots) {
      const category = snapshot.breadcrumbs[0] || "Unknown";
      categoryCounts.set(category, (categoryCounts.get(category) ?? 0) + 1);
    }
    const sortedCategories = Array.from(categoryCounts.entries()).sort((a, b) => b[1] - a[1]);
    const heroCategory = sortedCategories[0]?.[0] ?? "Unknown";
    const heroCategoryShare = snapshots.length ? (sortedCategories[0]?.[1] ?? 0) / snapshots.length : 0;
    const averagePrice = prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0;

    return evaluateSellerAnalytics({
      referenceCount: snapshots.length,
      categoryCount: categoryCounts.size,
      heroCategory: benchmarkFocus === "assortment" ? heroCategory : `${heroCategory} (${benchmarkFocus})`,
      heroCategoryShare,
      averagePrice,
      lowestPrice: prices.length ? Math.min(...prices) : 0,
      highestPrice: prices.length ? Math.max(...prices) : 0,
      premiumShare: snapshots.length ? prices.filter((value) => value >= averagePrice * 1.15).length / snapshots.length : 0,
      valueShare: snapshots.length ? prices.filter((value) => value > 0 && value <= averagePrice * 0.85).length / snapshots.length : 0,
      averageReviewCount: reviewCounts.length ? reviewCounts.reduce((sum, value) => sum + value, 0) / reviewCounts.length : 0,
      aPlusCount: snapshots.filter((item) => item.hasAPlus).length,
      badgeCarrierCount: snapshots.filter((item) => item.badges.length > 0).length,
    });
  }, [benchmarkFocus, executionLens, portfolioObjective, portfolioPosture, snapshots]);

  const sellerAnalyticsAuditLines = useMemo(() => {
    const evidenceStatus = getMultiSnapshotEvidenceStatus(snapshots, [
      "title",
      "price",
      "reviewCount",
      "breadcrumbs",
    ]);
    const lines = [`Portfolio evidence: ${evidenceStatus.label}. ${evidenceStatus.detail}`];
    if (!snapshots.length) {
      lines.push("Load portfolio ASINs so category mix and monetization signals come from real storefront pages.");
    } else if (evidenceStatus.level !== "complete") {
      lines.push("Treat assortment and monetization calls as directional until the portfolio set has fuller live coverage.");
    }
    if (snapshots.length) {
      lines.push(`System draft: default benchmark focus is ${benchmarkFocus}.`);
    }
    return lines;
  }, [benchmarkFocus, snapshots]);

  const categoryRows = useMemo(() => {
    const counts = new Map<string, number>();
    for (const snapshot of snapshots) {
      const category = snapshot.breadcrumbs[0] || "Unknown";
      counts.set(category, (counts.get(category) ?? 0) + 1);
    }

    return Array.from(counts.entries())
      .sort((a, b) => b[1] - a[1])
      .map(([label, count]) => ({
        label,
        value: `${count}`,
      }));
  }, [snapshots]);

  const sellerRows = useMemo(
    () =>
      buildSellerDecisionRows({
        snapshots,
        benchmarkFocus,
      }),
    [benchmarkFocus, snapshots],
  );

  const sellerExecutionPlan = useMemo(() => {
    const prices = snapshots.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const reviewCounts = snapshots.map((item) => parseReviewCountValue(item.reviewCountText)).filter((value) => value > 0);
    const categoryCounts = new Map<string, number>();
    for (const snapshot of snapshots) {
      const category = snapshot.breadcrumbs[0] || "Unknown";
      categoryCounts.set(category, (categoryCounts.get(category) ?? 0) + 1);
    }
    const sortedCategories = Array.from(categoryCounts.entries()).sort((a, b) => b[1] - a[1]);
    const heroShare = snapshots.length ? (sortedCategories[0]?.[1] ?? 0) / snapshots.length : 0;
    const averagePrice = prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0;
    const premiumShare = snapshots.length
      ? prices.filter((value) => value >= averagePrice * 1.15).length / snapshots.length
      : 0;
    const averageReviewCount = reviewCounts.length
      ? reviewCounts.reduce((sum, value) => sum + value, 0) / reviewCounts.length
      : 0;

    return inferSellerExecutionPlan({
      snapshotCount: snapshots.length,
      portfolioObjective,
      benchmarkFocus,
      executionLens,
      heroShare,
      premiumShare,
      averageReviewCount,
    });
  }, [benchmarkFocus, executionLens, portfolioObjective, snapshots]);

  const sellerAuditRows = useMemo(() => {
    const prices = snapshots.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const reviewCounts = snapshots.map((item) => parseReviewCountValue(item.reviewCountText)).filter((value) => value > 0);
    const categoryCounts = new Map<string, number>();
    for (const snapshot of snapshots) {
      const category = snapshot.breadcrumbs[0] || "Unknown";
      categoryCounts.set(category, (categoryCounts.get(category) ?? 0) + 1);
    }
    const sortedCategories = Array.from(categoryCounts.entries()).sort((a, b) => b[1] - a[1]);
    const heroCategory = sortedCategories[0]?.[0] ?? "Unknown";
    const heroCategoryShare = snapshots.length ? ((sortedCategories[0]?.[1] ?? 0) / snapshots.length) * 100 : 0;
    const averagePrice = prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0;

    return [
      {
        label: "Portfolio coverage",
        value: `${snapshots.length} loaded`,
        detail: snapshots.length
          ? `${splitAsinCandidates(portfolioInputs).slice(0, 8).length} requested from the current set`
          : "Load a storefront sample before trusting the assortment pattern",
      },
      {
        label: "Hero category",
        value: heroCategory,
        detail: snapshots.length ? `${roundNumber(heroCategoryShare, 0)}% of loaded ASINs sit here` : "No live category cluster yet",
      },
      {
        label: "Visible price ladder",
        value: prices.length ? formatUsd(roundNumber(averagePrice)) : "Missing",
        detail:
          prices.length > 1
            ? `${formatUsd(Math.min(...prices))} - ${formatUsd(Math.max(...prices))} across the visible set`
            : "Need more visible prices to read the price ladder",
      },
      {
        label: "Proof baseline",
        value: reviewCounts.length ? `${Math.round(reviewCounts.reduce((sum, value) => sum + value, 0) / reviewCounts.length)}` : "Missing",
        detail: `${snapshots.filter((item) => item.hasAPlus).length}/${snapshots.length || 0} listings show A+`,
      },
      {
        label: "Benchmark mode",
        value: benchmarkFocus,
        detail: "Use this to tilt the same live portfolio toward assortment, pricing, or proof depth",
      },
      {
        label: "Portfolio brief",
        value: `${portfolioObjective.replace(/-/g, " ")} / ${portfolioPosture.replace(/-/g, " ")}`,
        detail: `${executionLens.replace(/-/g, " ")} is the current lens for this portfolio read`,
      },
      {
        label: "Execution call",
        value: sellerExecutionPlan.decision,
        detail: `${sellerExecutionPlan.owner} | ${sellerExecutionPlan.cadence} | ${sellerExecutionPlan.proofPriority}`,
      },
    ];
  }, [benchmarkFocus, executionLens, portfolioInputs, portfolioObjective, portfolioPosture, sellerExecutionPlan, snapshots]);

  const sellerActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: sellerExecutionPlan.decision,
        detail: sellerExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: sellerExecutionPlan.owner,
        detail: `${sellerExecutionPlan.proofPriority} is the proof to validate before the team overreads the catalog.`,
      },
      {
        label: "Do not cross",
        value:
          !snapshots.length
            ? "Do not benchmark a seller from anecdotes"
            : portfolioPosture === "portfolio-cleanup"
              ? "Do not treat every SKU as equally strategic"
              : portfolioPosture === "expand-adjacent"
                ? "Do not infer the next wedge before the current moat is clear"
                : "Do not copy the whole storefront before dissecting the hero SKUs",
        detail:
          !snapshots.length
            ? "Do not benchmark a seller until the read starts from a real catalog."
            : portfolioPosture === "portfolio-cleanup"
              ? "Most of the seller signal usually sits in a smaller subset than the full portfolio suggests."
              : portfolioPosture === "expand-adjacent"
                ? "Adjacent expansion only matters after you understand how the current portfolio actually wins."
                : "Storefront averages hide where the real commercial authority sits.",
      },
      {
        label: "Then do",
        value:
          portfolioPosture === "portfolio-cleanup"
            ? "Separate core SKUs from filler SKUs"
            : portfolioPosture === "expand-adjacent"
              ? "Map the nearest adjacent wedge"
              : "Separate hero SKUs from filler SKUs",
        detail:
          portfolioPosture === "portfolio-cleanup"
            ? "Do not benchmark the whole seller evenly if most of the real signal sits in a small subset of listings."
            : portfolioPosture === "expand-adjacent"
              ? "Map the adjacent lane only after you can see which current wedge actually carries authority."
              : "Separate which ASINs carry category authority, which ones ladder price, and which ones are only coverage.",
      },
      {
        label: "Watch",
        value: sellerExecutionPlan.cadence,
        detail: sellerExecutionPlan.watchout,
      },
    ],
    [portfolioPosture, sellerExecutionPlan],
  );

  const portfolioLeaderRows = useMemo(
    () =>
      snapshots.slice(0, 6).map((snapshot) => ({
        label: snapshot.asin,
        value: snapshot.breadcrumbs[0] || "Unknown",
        detail: `${snapshot.priceText || "No price"} | ${snapshot.reviewCountText || "No reviews"} | ${snapshot.hasAPlus ? "A+" : "No A+"}`,
      })),
    [snapshots],
  );

  const sellerPlaybookRows = useMemo(() => {
    if (!snapshots.length) {
      return [] as Array<{ label: string; value: string; detail?: string }>;
    }

    const prices = snapshots.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const reviewCounts = snapshots.map((item) => parseReviewCountValue(item.reviewCountText)).filter((value) => value > 0);
    const averagePrice = prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : 0;
    const premiumShare = snapshots.length ? prices.filter((value) => value >= averagePrice * 1.15).length / snapshots.length : 0;
    const topPerformer = snapshots
      .map((snapshot) => ({
        snapshot,
        reviews: parseReviewCountValue(snapshot.reviewCountText),
        rank: parseRankValue(snapshot.bestSellersRank) || parseRankValue(snapshot.subCategoryRank),
      }))
      .sort((a, b) => a.rank - b.rank || b.reviews - a.reviews)[0];
    const breakoutRisk =
      reviewCounts.length > 0
        ? Math.max(...reviewCounts) / reviewCounts.reduce((sum, value) => sum + value, 0)
        : 0;

    return [
      {
        label: "Portfolio truth",
        value: sellerRows.assortmentRows[1]?.value ?? "Unknown",
        detail:
          premiumShare >= 0.3
            ? "This seller appears to use a premium ladder, not just broad SKU coverage."
            : "This seller looks more breadth-led than premium-led across the visible set.",
      },
      {
        label: "Breakout dependency",
        value: breakoutRisk >= 0.4 ? "High concentration risk" : "Spread across multiple SKUs",
        detail:
          breakoutRisk >= 0.4
            ? "A large share of visible review proof sits on one SKU, so the seller may be weaker than portfolio averages suggest."
            : "Visible proof looks distributed enough that the moat is not obviously riding on one SKU alone.",
      },
      {
        label: "Copy first",
        value: topPerformer?.snapshot.asin ?? "No clear leader",
        detail: topPerformer
          ? `${topPerformer.snapshot.priceText || "No price"} | ${topPerformer.snapshot.reviewCountText || "No reviews"} | Start by dissecting the seller's strongest visible SKU before copying the whole assortment.`
          : "Use the strongest live SKU as the actual benchmark, not the average of the whole storefront.",
      },
    ];
  }, [sellerRows.assortmentRows, snapshots]);

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1.3fr_auto_auto]">
        <Field label="Storefront or portfolio ASINs / URLs">
          <TextAreaInput
            value={portfolioInputs}
            onChange={(e) => setPortfolioInputs(e.target.value)}
            className="min-h-[7.5rem]"
            spellCheck={false}
          />
        </Field>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowAdvanced((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showAdvanced ? "Hide advanced settings" : "Adjust benchmark focus"}
          </button>
        </div>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadPortfolio} disabled={loading || !portfolioInputs.trim()}>
            {loading ? "Loading..." : "Load live portfolio"}
          </ActionButton>
        </div>
      </div>
      <div className="grid gap-2.5 md:grid-cols-[0.95fr_0.95fr_0.95fr]">
        <Field label="Portfolio objective">
          <SelectInput value={portfolioObjective} onChange={(e) => setPortfolioObjective(e.target.value)}>
            <option value="copy-playbook">Copy playbook</option>
            <option value="margin-playbook">Margin playbook</option>
            <option value="rationalize-threat">Rationalize threat</option>
          </SelectInput>
        </Field>
        <Field label="Portfolio posture">
          <SelectInput value={portfolioPosture} onChange={(e) => setPortfolioPosture(e.target.value)}>
            <option value="specialist-check">Specialist check</option>
            <option value="expand-adjacent">Expand adjacent</option>
            <option value="portfolio-cleanup">Portfolio cleanup</option>
          </SelectInput>
        </Field>
        <Field label="Execution lens">
          <SelectInput value={executionLens} onChange={(e) => setExecutionLens(e.target.value)}>
            <option value="assortment">Assortment</option>
            <option value="price-ladder">Price ladder</option>
            <option value="proof-depth">Proof depth</option>
          </SelectInput>
        </Field>
      </div>
      {showAdvanced ? (
        <div className="grid gap-2.5 md:grid-cols-[0.8fr_0.9fr]">
          <Field label="Marketplace">
            <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
              {renderOptions(amazonMarketplaces)}
            </SelectInput>
          </Field>
          <Field label="Benchmark focus">
            <SelectInput value={benchmarkFocus} onChange={(e) => setBenchmarkFocus(e.target.value)}>
              <option value="assortment">Assortment</option>
              <option value="pricing">Pricing</option>
              <option value="review-depth">Review depth</option>
            </SelectInput>
          </Field>
        </div>
      ) : null}
      {error ? (
        <div className="rounded-xl border border-rose-200 bg-rose-50 px-4 py-3 text-sm text-rose-950">{error}</div>
      ) : null}
      <DistributionPanel title="Live portfolio inputs" rows={sellerAuditRows} />
      <DistributionPanel title="This portfolio call" rows={sellerActionRows} />
      <AuditNote lines={sellerAnalyticsAuditLines} />
      <CompetitorBoard own={snapshots[0] ?? null} competitors={snapshots.slice(1)} primaryLabel="Portfolio item 1" />
      {snapshots.length ? (
        <div className="grid gap-3 xl:grid-cols-3">
          <DistributionPanel title="Assortment read" rows={sellerRows.assortmentRows} />
          <DistributionPanel title="Monetization pattern" rows={sellerRows.monetizationRows} />
          <DistributionPanel title="Moat signals" rows={sellerRows.moatRows} />
        </div>
      ) : null}
      <DistributionPanel title="Seller playbook summary" rows={sellerPlaybookRows} />
      <div className="grid gap-3 xl:grid-cols-2">
        <DistributionPanel title="Category mix" rows={categoryRows} />
        <DistributionPanel title="Portfolio leaders" rows={portfolioLeaderRows} />
      </div>
    </RuntimeShell>
  );
}

function ListingOptimizationRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("");
  const [competitorInputs, setCompetitorInputs] = useState("");
  const [targetKeywords, setTargetKeywords] = useState("");
  const [category, setCategory] = useState("");
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [competitors, setCompetitors] = useState<AmazonListingSnapshot[]>([]);
  const [showOverrides, setShowOverrides] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const optimizationPlan = useMemo(
    () => inferListingOptimizationPlan(snapshot, competitors),
    [competitors, snapshot],
  );

  async function loadComparison() {
    try {
      setLoading(true);
      setError("");
      const ownResponse = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const ownPayload = (await ownResponse.json()) as AmazonListingSnapshot | { error: string };
      if (!ownResponse.ok || "error" in ownPayload) {
        throw new Error("error" in ownPayload ? ownPayload.error : "Failed to load live listing.");
      }

      const loadedCompetitors: AmazonListingSnapshot[] = [];
      for (const candidate of splitAsinCandidates(competitorInputs).slice(0, 4)) {
        const response = await fetch(
          `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(candidate)}`,
        );
        const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
        if (response.ok && !("error" in payload)) {
          loadedCompetitors.push(payload);
        }
      }

      setSnapshot(ownPayload);
      setCompetitors(loadedCompetitors);
      const nextPlan = inferListingOptimizationPlan(ownPayload, loadedCompetitors);
      setTargetKeywords((current) => (current.trim() ? current : nextPlan.targetKeywords));
      const matchedCategory = inferCategoryOption(ownPayload, calculatorCategoryOptionGroups);
      if (matchedCategory) {
        setCategory(matchedCategory);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setCompetitors([]);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load listing comparison.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(() => {
    const targetPhrases = splitKeywordPhrases(targetKeywords);
    const fallbackPlan = inferListingExecutionPlan({
      hasSnapshot: Boolean(snapshot) && isCustomSnapshotDecisionGrade(snapshot, ["title", "breadcrumbs", "bullets", "images"]),
      targetCount: targetPhrases.length,
      coveredCount: 0,
      competitorCount: competitors.length,
      cheaperCount: 0,
      richerImageCount: 0,
      strongerReviewCount: 0,
    });
    const competitorEvidence = getMultiSnapshotEvidenceStatus(
      competitors,
      ["title", "reviewCount", "images"],
    );

    if (!snapshot || !isCustomSnapshotDecisionGrade(snapshot, ["title", "breadcrumbs", "bullets", "images"])) {
      return {
        headline: !snapshot
          ? isAmazonBotProtectionError(error)
            ? "Live Amazon read blocked: do not fake the PDP decision"
            : "Load the live PDP before reopening the listing"
          : "Repair the own-page read before rewriting the PDP",
        summary:
          "Keep the PDP frozen until the live page makes the first blocker explicit enough to assign and fix.",
        metrics: [
          {
            label: "First blocker",
            value: !snapshot ? "Live PDP baseline" : "Own-page evidence",
            detail: !snapshot
              ? isAmazonBotProtectionError(error)
                ? "Amazon temporarily blocked the live PDP fetch on this request."
                : "Load your ASIN or Amazon URL so the tool can inspect the real title, bullets, images, and category path."
              : "The own PDP needs stronger title, bullet, breadcrumb, and image coverage before optimization calls should move work.",
          },
          {
            label: "Decision owner",
            value: fallbackPlan.owner,
            detail: "One owner clears the first PDP blocker.",
          },
          {
            label: "Execution call",
            value: fallbackPlan.decision,
            detail: `${fallbackPlan.owner} | ${fallbackPlan.cadence}`,
          },
          {
            label: "Do not cross",
            value: !snapshot
              ? isAmazonBotProtectionError(error)
                ? "Do not pretend a blocked live read is a finished audit"
                : "Do not rewrite the PDP before loading the live listing"
              : "Do not rewrite from weak own-page evidence",
            detail: !snapshot
              ? isAmazonBotProtectionError(error)
                ? "Manual fallback is temporary only."
                : "Do not start from memory."
              : "Repair the read before the rewrite.",
          },
        ],
        recommendations: [
          isAmazonBotProtectionError(error)
            ? "Use manual keyword and category overrides only as a temporary bridge, then retry the live PDP later."
            : "Let the live listing draft category and keyword coverage before anyone rewrites the page.",
          "Only touch manual overrides after the live PDP and benchmark field have already been read.",
        ],
        status: {
          label: !snapshot ? "Live listing baseline is missing" : "Live listing evidence needs review",
          tone: "warning",
        },
        missingItems: [
          !snapshot ? "Live PDP baseline" : "Stronger own-listing evidence",
          targetPhrases.length ? "" : "Target phrase pool",
        ].filter(Boolean),
        nextSteps: [
          !snapshot
            ? isAmazonBotProtectionError(error)
              ? "Retry the live fetch later or enter the PDP context manually as a temporary bridge."
              : "Load your ASIN or Amazon URL."
            : "Reload the own PDP and verify title, bullet, image, and category evidence.",
          "Let the tool draft the first optimization brief from the live page.",
          "Then decide whether the first job is copy repair, asset repair, or proof repair.",
        ],
        actionStance: {
          label: !snapshot ? "Do not optimize a listing you have not loaded" : "Do not rewrite from weak own-page evidence",
          tone: "warning",
          detail: !snapshot
            ? isAmazonBotProtectionError(error)
              ? "Say plainly when Amazon blocked the live pull. A temporary manual pass is acceptable; fake certainty is not."
              : "If the live page has not been loaded, the team is still guessing. Do not turn that guesswork into a rewrite sprint."
            : "Weak own-page evidence makes the team rewrite the page before it has proved which surface is actually losing the sale.",
        },
      } satisfies ToolEvaluation;
    }
    if (competitors.length > 0 && competitorEvidence.level === "weak") {
      return {
        headline: "Rebuild the competitor set before changing the PDP",
        summary:
          "Do not let a weak benchmark pack drive a live rewrite. Tighten the field first, then choose the repair.",
        metrics: [
          {
            label: "First blocker",
            value: "Weak competitor set",
            detail: competitorEvidence.detail,
          },
          {
            label: "Decision owner",
            value: fallbackPlan.owner,
            detail: "One owner rebuilds the benchmark field.",
          },
          {
            label: "Execution call",
            value: fallbackPlan.decision,
            detail: `${fallbackPlan.owner} | ${fallbackPlan.cadence}`,
          },
          {
            label: "Do not cross",
            value: "Do not rewrite the PDP from a weak benchmark set",
            detail: "Fix the field before fixing the page.",
          },
        ],
        recommendations: [
          "Use competitors buyers really compare against in the same browse path.",
          "Do not let a noisy benchmark set dictate a full PDP rewrite.",
        ],
        status: {
          label: "Competitor evidence needs rebuild",
          tone: "warning",
        },
        missingItems: ["Stronger competitor evidence"],
        nextSteps: [
          "Replace weak competitor ASINs.",
          "Re-run the optimization audit against a cleaner market set.",
          "Only then choose between copy, asset, and proof fixes.",
        ],
        actionStance: {
          label: "Rebuild this optimization read before acting",
          tone: "warning",
          detail: "Weak competitor references make ordinary listing differences look like urgent defects and send the team after the wrong repair.",
        },
      } satisfies ToolEvaluation;
    }

    const visibleText = [snapshot.title, ...snapshot.bulletPoints, ...snapshot.breadcrumbs].join(" ").toLowerCase();
    const coveredKeywordCount = targetPhrases.filter((phrase) => textHasPhraseCoverage(visibleText, phrase)).length;
    const ownPrice = parseCurrencyAmount(snapshot.priceText);
    const ownReviews = parseReviewCountValue(snapshot.reviewCountText);
    const ownImages = getEffectiveListingImageCount(snapshot);

    return evaluateListingOptimization({
      category,
      titleLength: snapshot.title.length,
      bulletCount: snapshot.bulletPoints.length,
      imageCount: ownImages,
      reviewCount: ownReviews,
      hasAPlus: snapshot.hasAPlus,
      targetKeywordCount: targetPhrases.length,
      coveredKeywordCount,
      competitorCount: competitors.length,
      cheaperCompetitors: competitors.filter((item) => {
        const price = parseCurrencyAmount(item.priceText);
        return price > 0 && ownPrice > 0 && price < ownPrice;
      }).length,
      richerImageCompetitors: competitors.filter(
        (item) => getEffectiveListingImageCount(item) > ownImages,
      ).length,
      strongerReviewCompetitors: competitors.filter((item) => parseReviewCountValue(item.reviewCountText) > ownReviews).length,
      competitorAPlusCount: competitors.filter((item) => item.hasAPlus).length,
    });
  }, [category, competitors, snapshot, targetKeywords, error]);

  const keywordRows = useMemo(() => {
    if (!snapshot) {
      return [] as Array<{ label: string; value: string; detail?: string }>;
    }
    const visibleText = [snapshot.title, ...snapshot.bulletPoints, ...snapshot.breadcrumbs].join(" ").toLowerCase();
    return splitKeywordPhrases(targetKeywords).map((phrase) => ({
      label: phrase,
      value: textHasPhraseCoverage(visibleText, phrase) ? "Covered" : "Missing",
      detail: textHasPhraseCoverage(visibleText, phrase)
        ? "Visible in title, bullets, or browse path"
        : "Not clearly represented in visible copy",
    }));
  }, [snapshot, targetKeywords]);

  const competitorRows = useMemo(
    () =>
      competitors.map((item) => ({
        label: item.asin,
        value: `${getEffectiveListingImageCount(item)} effective images`,
        detail: `${item.priceText ?? "No price"} | ${item.reviewCountText ?? "No reviews"} | ${item.hasAPlus ? "A+" : "No A+"}`,
      })),
    [competitors],
  );

  const detectedCategoryLabel = useMemo(() => {
    for (const group of calculatorCategoryOptionGroups) {
      const option = group.options.find((item) => item.value === category);
      if (option) {
        return option.label;
      }
    }
    return "Not matched yet";
  }, [category]);

  const listingAuditRows = useMemo(
    () => [
      {
        label: "Detected category",
        value: detectedCategoryLabel,
        detail: snapshot?.breadcrumbs.length ? snapshot.breadcrumbs.join(" / ") : "Using current category mapping",
      },
      {
        label: "Target keyword coverage",
        value: snapshot ? `${keywordRows.filter((item) => item.value === "Covered").length}/${keywordRows.length || 0}` : "Waiting on live draft",
        detail: keywordRows.length ? "Coverage across title, bullets, and browse path" : "Load the live PDP first so the tool can draft the target phrase pool",
      },
      {
        label: "Competitor baseline",
        value: `${competitors.length} loaded`,
        detail: competitors.length ? "Used for image, review, price, and A+ gap checks" : "Load competitor ASINs to benchmark against the category leaders",
      },
      {
        label: "Content depth",
        value: snapshot ? `${snapshot.bulletPoints.length} bullets | ${getEffectiveListingImageCount(snapshot)} effective images` : "Not loaded",
        detail: snapshot ? `${snapshot.hasAPlus ? "A+ live" : "No A+"} | ${snapshot.reviewCountText || "No reviews"}` : "Load a listing to inspect the current asset stack",
      },
    ],
    [competitors.length, detectedCategoryLabel, keywordRows, snapshot],
  );

  const listingExecutionPlan = useMemo(() => {
    if (!snapshot) {
      return inferListingExecutionPlan({
        hasSnapshot: false,
        targetCount: splitKeywordPhrases(targetKeywords).length,
        coveredCount: 0,
        competitorCount: competitors.length,
        cheaperCount: 0,
        richerImageCount: 0,
        strongerReviewCount: 0,
      });
    }

    const coveredCount = keywordRows.filter((item) => item.value === "Covered").length;
    const targetCount = keywordRows.length;
    const missingPhraseSamples = keywordRows
      .filter((item) => item.value === "Missing")
      .slice(0, 3)
      .map((item) => item.label);
    const ownPrice = parseCurrencyAmount(snapshot.priceText);
    const cheaperCount = competitors.filter((item) => {
      const competitorPrice = parseCurrencyAmount(item.priceText);
      return ownPrice > 0 && competitorPrice > 0 && competitorPrice < ownPrice;
    }).length;
    const ownImageCount = getEffectiveListingImageCount(snapshot);
    const richerImageCount = competitors.filter(
      (item) => getEffectiveListingImageCount(item) > ownImageCount,
    ).length;
    const strongerReviewCount = competitors.filter(
      (item) => parseReviewCountValue(item.reviewCountText) > parseReviewCountValue(snapshot.reviewCountText),
    ).length;

    return inferListingExecutionPlan({
      hasSnapshot: true,
      targetCount,
      coveredCount,
      competitorCount: competitors.length,
      cheaperCount,
      richerImageCount,
      strongerReviewCount,
    });
  }, [competitors, keywordRows, snapshot, targetKeywords]);

  const listingActionRows = useMemo(() => {
    if (!snapshot) {
      return [
        {
          label: "First move",
          value: listingExecutionPlan.decision,
          detail: listingExecutionPlan.nextMove,
        },
        {
          label: "Execution owner",
          value: listingExecutionPlan.owner,
          detail: `${listingExecutionPlan.proofPriority} is the proof to gather before changing the PDP.`,
        },
        {
          label: "Do not cross",
          value: "Do not rewrite the PDP before loading the live listing",
          detail: "Without your own live title, images, and category path, the team is just rewriting in the dark.",
        },
        {
          label: "Then do",
          value: listingExecutionPlan.cadence,
          detail: "Load your own PDP first, then keep the same benchmark set fixed long enough to expose the real optimization job.",
        },
        {
          label: "Watch",
          value: listingExecutionPlan.proofPriority,
          detail: listingExecutionPlan.watchout,
        },
      ] as Array<{ label: string; value: string; detail?: string }>;
    }

    const coveredCount = keywordRows.filter((item) => item.value === "Covered").length;
    const targetCount = keywordRows.length;
    const missingPhraseSamples = keywordRows
      .filter((item) => item.value === "Missing")
      .slice(0, 3)
      .map((item) => item.label);
    const ownPrice = parseCurrencyAmount(snapshot.priceText);
    const cheaperCount = competitors.filter((item) => {
      const competitorPrice = parseCurrencyAmount(item.priceText);
      return ownPrice > 0 && competitorPrice > 0 && competitorPrice < ownPrice;
    }).length;
    const ownImageCount = getEffectiveListingImageCount(snapshot);
    const richerImageCount = competitors.filter(
      (item) => getEffectiveListingImageCount(item) > ownImageCount,
    ).length;
    const strongerReviewCount = competitors.filter(
      (item) => parseReviewCountValue(item.reviewCountText) > parseReviewCountValue(snapshot.reviewCountText),
    ).length;
    const missingKeywordCount = Math.max(0, targetCount - coveredCount);
    const coverageRatio = targetCount > 0 ? coveredCount / targetCount : 1;
    const leadCompetitor =
      competitors
        .map((item) => ({
          asin: item.asin,
          price: parseCurrencyAmount(item.priceText),
          reviews: parseReviewCountValue(item.reviewCountText),
          images: getEffectiveListingImageCount(item),
          hasAPlus: item.hasAPlus,
        }))
        .sort((left, right) => {
          const leftPressure =
            (left.images > ownImageCount ? 2 : 0) +
            (left.reviews > parseReviewCountValue(snapshot.reviewCountText) ? 2 : 0) +
            (left.hasAPlus && !snapshot.hasAPlus ? 1 : 0) +
            (ownPrice > 0 && left.price > 0 && left.price < ownPrice ? 1 : 0);
          const rightPressure =
            (right.images > ownImageCount ? 2 : 0) +
            (right.reviews > parseReviewCountValue(snapshot.reviewCountText) ? 2 : 0) +
            (right.hasAPlus && !snapshot.hasAPlus ? 1 : 0) +
            (ownPrice > 0 && right.price > 0 && right.price < ownPrice ? 1 : 0);
          return rightPressure - leftPressure;
        })[0];
    const firstEditSurface =
      listingExecutionPlan.decision === "Fix relevance coverage"
        ? "Title, bullets, and browse wording"
        : listingExecutionPlan.decision === "Upgrade image stack"
          ? "Hero image, benefit frames, and scale proof"
          : listingExecutionPlan.decision === "Strengthen proof before polishing copy"
            ? "Review proof, objection handling, and trust density"
        : listingExecutionPlan.decision === "Recheck price posture"
          ? "Offer, price, and value equation"
          : "Mid-page conversion layer";
    const firstTaskLine =
      listingExecutionPlan.decision === "Fix relevance coverage"
        ? missingPhraseSamples.length
          ? `Update the title and first two bullets with: ${missingPhraseSamples.join(", ")}.`
          : "Update the title and first two bullets with the missing tracked phrases."
        : listingExecutionPlan.decision === "Upgrade image stack"
          ? "Replace the hero image first, then add benefit and scale-proof frames."
          : listingExecutionPlan.decision === "Strengthen proof before polishing copy"
            ? "Add stronger proof near the top of the page before rewriting secondary copy."
            : listingExecutionPlan.decision === "Recheck price posture"
              ? "Check whether the current price still matches the visible proof and competitor field."
              : "Tighten objection handling and trust density in the middle of the PDP.";
    const secondTaskLine =
      listingExecutionPlan.decision === "Fix relevance coverage"
        ? coverageRatio < 0.5
          ? "Do not branch into image or price work until the core search terms are present."
          : "Re-run the audit after the title and bullet update before taking a second pass."
        : listingExecutionPlan.decision === "Upgrade image stack"
          ? `Prioritize the gaps against ${leadCompetitor?.asin ?? "the strongest competitor"} before producing a full new gallery.`
          : listingExecutionPlan.decision === "Strengthen proof before polishing copy"
            ? "Feed the biggest customer objections back into review harvesting, support scripts, or PDP proof blocks."
            : listingExecutionPlan.decision === "Recheck price posture"
              ? "Only lower price if the proof stack cannot justify the current offer."
              : "Use the next revision to improve clarity, not to rewrite every surface again.";
    const doNotCrossLine =
      listingExecutionPlan.decision === "Fix relevance coverage"
        ? "Do not rewrite images or price before core term coverage is fixed"
        : listingExecutionPlan.decision === "Upgrade image stack"
          ? "Do not judge copy before the hero and proof frames catch up"
          : listingExecutionPlan.decision === "Strengthen proof before polishing copy"
            ? "Do not buy conversion with copy while trust proof is still weak"
            : listingExecutionPlan.decision === "Recheck price posture"
              ? "Do not cut price before checking whether proof can justify the offer"
              : "Do not reopen every PDP surface once the big gaps are already closed";
    const doNotCrossDetail =
      listingExecutionPlan.decision === "Fix relevance coverage"
        ? "Search visibility is still the first blocker, so broad PDP polishing will hide the real problem."
        : listingExecutionPlan.decision === "Upgrade image stack"
          ? "If the gallery is lagging, copy edits will not explain away weak visual proof."
          : listingExecutionPlan.decision === "Strengthen proof before polishing copy"
            ? "When trust is thin, more copy usually adds friction faster than it adds conviction."
            : listingExecutionPlan.decision === "Recheck price posture"
              ? "Lowering price before testing the value equation can give away margin without fixing conversion."
              : "The structural issues are mostly closed, so another full rewrite is more likely to create churn than lift.";

    return [
      {
        label: "First move",
        value: listingExecutionPlan.decision,
        detail: `${listingExecutionPlan.nextMove} Freeze everything else.`,
      },
      {
        label: "Execution owner",
        value: listingExecutionPlan.owner,
        detail: `One owner clears this blocker first.`,
      },
      {
        label: "Do this now",
        value: firstTaskLine,
        detail: secondTaskLine,
      },
      {
        label: "Do not cross",
        value: doNotCrossLine,
        detail:
          listingExecutionPlan.decision === "Fix relevance coverage"
            ? "Fix relevance before broader PDP work."
            : listingExecutionPlan.decision === "Upgrade image stack"
              ? "Fix visuals before judging copy."
              : listingExecutionPlan.decision === "Strengthen proof before polishing copy"
                ? "Fix trust before adding more copy."
                : listingExecutionPlan.decision === "Recheck price posture"
                  ? "Check value before cutting price."
                  : "Do not reopen the full PDP.",
      },
      {
        label: "Edit this surface first",
        value: firstEditSurface,
        detail:
          listingExecutionPlan.decision === "Fix relevance coverage"
            ? missingPhraseSamples.length
              ? `Start with: ${missingPhraseSamples.join(", ")}.`
              : `${missingKeywordCount} phrases are still missing.`
            : listingExecutionPlan.decision === "Upgrade image stack"
              ? `${richerImageCount} competitors are ahead on images.`
              : listingExecutionPlan.decision === "Strengthen proof before polishing copy"
                ? `${strongerReviewCount} competitors are ahead on proof.`
                : listingExecutionPlan.decision === "Recheck price posture"
                  ? `${cheaperCount} competitors are priced lower.`
                  : "Most structural gaps are already closed.",
      },
      {
        label: "Primary benchmark ASIN",
        value: leadCompetitor?.asin ?? "No competitor loaded",
        detail:
          leadCompetitor
            ? `${leadCompetitor.images} images | ${leadCompetitor.reviews.toLocaleString("en-US")} reviews${leadCompetitor.hasAPlus ? " | A+" : ""}${leadCompetitor.price > 0 ? ` | ${formatUsd(roundNumber(leadCompetitor.price))}` : ""}`
            : "Add one direct competitor so the optimizer can point to the clearest benchmark pressure.",
      },
    ];
  }, [competitors, keywordRows, listingExecutionPlan, snapshot]);

  const listingAuditLines = useMemo(() => {
    const lines = [];
    if (snapshot) {
      const ownEvidence = getCustomSnapshotEvidenceStatus(snapshot, [
        "title",
        "breadcrumbs",
        "bullets",
        "images",
      ]);
      lines.push(`Live path: ${snapshot.breadcrumbs.length ? snapshot.breadcrumbs.join(" / ") : detectedCategoryLabel}.`);
      lines.push(`Current lane: ${optimizationPlan.benchmarkPosture}. ${optimizationPlan.proofPressure}.`);
      lines.push(`Own evidence: ${ownEvidence.label}. ${ownEvidence.detail}`);
      if (competitors.length) {
        const competitorEvidence = getMultiSnapshotEvidenceStatus(competitors, [
          "title",
          "reviewCount",
          "images",
        ]);
        lines.push(`Benchmark set: ${competitorEvidence.label}. ${competitorEvidence.detail}`);
        if (competitorEvidence.level !== "complete") {
          lines.push("Keep this in watch mode.");
        }
      }
    } else {
      lines.push("Load your own PDP first.");
      lines.push("Keep benchmarking closed until the first losing surface is real.");
    }
    lines.push("Open manual overrides only for one alternate benchmark path.");
    return lines;
  }, [competitors, detectedCategoryLabel, optimizationPlan.benchmarkPosture, optimizationPlan.proofPressure, snapshot]);

  const listingInputRows = useMemo(
    () =>
      !snapshot
        ? [
            {
              label: "Own PDP",
              value: "Not loaded",
              detail: "Load a live listing to let the optimizer build the first real decision pass",
            },
            {
              label: "Competitor set",
              value: `${competitors.length} loaded`,
              detail: competitors.length
                ? `${splitAsinCandidates(competitorInputs).slice(0, 4).length} requested from the current benchmark set`
                : "Add direct competitors only after your own PDP is loaded",
            },
            {
              label: "First blocker",
              value: "Own live PDP evidence",
              detail: "Title, bullets, category path, and image stack have to come from the real page before any rewrite gets approved.",
            },
            {
              label: "Decision owner",
              value: "PDP owner",
              detail: "One owner loads the page and confirms the first losing surface before copy, creative, and pricing reopen the whole listing.",
            },
            {
              label: localeText(locale, "Execution call", "执行判断"),
              value: "Load the live listing first",
              detail: "PDP owner | Before any rewrite | Own PDP evidence",
            },
          ]
        : [
            {
              label: "Own PDP",
              value: snapshot.asin ?? "Not loaded",
              detail: snapshot.title || "Load a live listing to let the optimizer build the first-pass audit",
            },
            {
              label: "Competitor set",
              value: `${competitors.length} loaded`,
              detail: competitors.length
                ? `${splitAsinCandidates(competitorInputs).slice(0, 4).length} requested from the current benchmark set`
                : "Add direct competitors so pressure is measured from the real battlefield",
            },
            {
              label: "First blocker",
              value:
                listingExecutionPlan.decision === "Fix relevance coverage"
                  ? "Relevance coverage"
                  : listingExecutionPlan.decision === "Upgrade image stack"
                    ? "Image stack"
                    : listingExecutionPlan.decision === "Strengthen proof before polishing copy"
                      ? "Trust proof"
                      : listingExecutionPlan.decision === "Recheck price posture"
                        ? "Price posture"
                        : "Mid-page conversion clarity",
              detail:
                listingExecutionPlan.decision === "Fix relevance coverage"
                  ? "Tracked phrases are still missing from the visible PDP."
                  : listingExecutionPlan.decision === "Upgrade image stack"
                    ? "The gallery is still behind the benchmark field."
                    : listingExecutionPlan.decision === "Strengthen proof before polishing copy"
                      ? "Visible trust support is still thinner than the lane requires."
                      : listingExecutionPlan.decision === "Recheck price posture"
                        ? "Offer pressure is stronger than the current page proof."
                        : "The next lift comes from conversion clarity, not another broad rewrite.",
            },
            {
              label: "Decision owner",
              value: listingExecutionPlan.owner,
              detail: `${listingExecutionPlan.proofPriority} stays under one owner until the same PDP and benchmark set are re-read.`,
            },
            {
              label: localeText(locale, "Execution call", "执行判断"),
              value: listingExecutionPlan.decision,
              detail: `${listingExecutionPlan.owner} | ${listingExecutionPlan.cadence} | ${listingExecutionPlan.proofPriority}`,
            },
          ],
    [competitorInputs, competitors.length, detectedCategoryLabel, listingExecutionPlan, snapshot, targetKeywords],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_1fr_0.7fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput
            value={asinOrUrl}
            onChange={(e) => setAsinOrUrl(e.target.value)}
            placeholder="Paste your ASIN or Amazon URL"
            spellCheck={false}
          />
        </Field>
        <Field label="Competitor ASINs or URLs (optional)">
          <TextAreaInput
            value={competitorInputs}
            onChange={(e) => setCompetitorInputs(e.target.value)}
            className="min-h-[7.5rem]"
            placeholder="Optional: add direct competitors, one per line"
            spellCheck={false}
          />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadComparison} disabled={loading || !asinOrUrl.trim()}>
            {runtimeActionButtonLabel(locale, loading, "Load listing and generate result", "加载商品并生成结果")}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote lines={listingAuditLines} />
      <div className="rounded-xl border border-teal-200 bg-teal-50 px-3 py-3 text-sm text-teal-950">
        {runtimeResultHint(locale)}
      </div>
      <DistributionPanel title={runtimeResultTitle(locale)} rows={listingInputRows} />
      <DistributionPanel title="Market pressure" rows={listingAuditRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">{manualOverridesHeading(locale)}</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only to test one alternate benchmark or keyword path after the live PDP is stable.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {manualOverridesToggle(locale, showOverrides)}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-[0.8fr_1.2fr]">
              <Field label="Category">
                <SelectInput value={category} onChange={(e) => setCategory(e.target.value)}>
                  <option value="">Use detected category after live load</option>
                  {renderOptionGroups(calculatorCategoryOptionGroups)}
                </SelectInput>
              </Field>
              <Field label="Target keywords">
                <TextInput
                  value={targetKeywords}
                  onChange={(e) => setTargetKeywords(e.target.value)}
                  placeholder="Leave empty until the live PDP drafts the keyword pool"
                />
              </Field>
            </div>
            <div className="rounded-xl border border-emerald-200 bg-emerald-50 px-3 py-3 text-xs leading-5 text-emerald-950">
              {targetKeywords.trim()
                ? `System draft keyword pool: ${targetKeywords}.`
                : "Load the live PDP first so the tool can draft the initial keyword pool from the listing and benchmark set."}
            </div>
          </div>
        ) : null}
      </div>
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title={runtimeActionPlanTitle(locale)} rows={listingActionRows} />
        <DistributionPanel title="Keyword gaps" rows={keywordRows} />
        <DistributionPanel title="Benchmark pressure" rows={competitorRows} />
      </div>
      <CompetitorBoard own={snapshot} competitors={competitors} />
      <LowTokenAssistPanel
        toolSlug="amazon-listing-optimization"
        locale={locale}
        result={result}
        context={{
          targetKeywords,
          ownTitle: snapshot?.title ?? "",
          ownBullets: snapshot?.bulletPoints.slice(0, 5) ?? [],
          competitorAsins: competitors.map((item) => item.asin),
        }}
      />
    </RuntimeShell>
  );
}

function APlusContentRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("B0GYRT3FNL");
  const [benefits, setBenefits] = useState("arched silhouette, shatter-resistant glass, floor-standing stability, bedroom decor lift");
  const [objections, setObjections] = useState("Will it tip easily?\nIs the reflection clear?\nDoes it fit a bedroom corner?");
  const [brandStory, setBrandStory] = useState("Design-led home mirror line focused on easy placement and premium finish.");
  const [comparisonRows, setComparisonRows] = useState(3);
  const [assets, setAssets] = useState<string[]>(["hero", "close-up", "lifestyle", "dimensions"]);
  const [professionalSeller, setProfessionalSeller] = useState(true);
  const [brandRepresentative, setBrandRepresentative] = useState(true);
  const [premiumRequested, setPremiumRequested] = useState(title.toLowerCase().includes("premium"));
  const [premiumEligibilityReady, setPremiumEligibilityReady] = useState(false);
  const [imageSpecReady, setImageSpecReady] = useState(true);
  const [altTextReady, setAltTextReady] = useState(true);
  const [plainTextMigrated, setPlainTextMigrated] = useState(true);
  const [retailContributionConflict, setRetailContributionConflict] = useState(false);
  const [genericAsin, setGenericAsin] = useState(false);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [showAdvanced, setShowAdvanced] = useState(false);
  const aPlusPlan = useMemo(() => inferAPlusPlan(snapshot, title), [snapshot, title]);

  const inferredGenericAsin = !snapshot?.brand?.trim();
  const inferredBrandRepresentative = Boolean(snapshot?.brandStoreLink || snapshot?.brand?.trim());
  const inferredPremiumEligibilityReady =
    Boolean(snapshot?.hasAPlus) && Boolean(snapshot?.brandStoreLink || snapshot?.brand?.trim());
  const inferredComparisonRows = snapshot?.hasAPlus ? 4 : 3;
  const inferredAssets = useMemo(() => {
    if (!snapshot) {
      return [] as string[];
    }

    const next = new Set<string>();
    if (snapshot.imageUrls.length > 0) next.add("hero");
    if (snapshot.imageUrls.length >= 2) next.add("close-up");
    if (snapshot.imageUrls.length >= 4) next.add("lifestyle");
    if (snapshot.productDimensionsText || snapshot.itemWeightText) next.add("dimensions");
    if (snapshot.hasAPlus) next.add("comparison");
    if (parseReviewCountValue(snapshot.reviewCountText) >= 50) next.add("ugc");
    return Array.from(next);
  }, [snapshot]);

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }
      setSnapshot(payload);
      if (!showAdvanced) {
        const nextPlan = inferAPlusPlan(payload, title);
        setBenefits(nextPlan.benefits);
        setObjections(nextPlan.objections);
        setBrandStory(nextPlan.brandStory);
        setComparisonRows(nextPlan.comparisonRows);
        setAssets(nextPlan.assets);
        setPremiumRequested(nextPlan.premiumRequested);
        setProfessionalSeller(nextPlan.professionalSeller);
        setBrandRepresentative(nextPlan.brandRepresentative);
        setPremiumEligibilityReady(nextPlan.premiumEligibilityReady);
        setImageSpecReady(nextPlan.imageSpecReady);
        setAltTextReady(nextPlan.altTextReady);
        setPlainTextMigrated(nextPlan.plainTextMigrated);
        setRetailContributionConflict(nextPlan.retailContributionConflict);
        setGenericAsin(nextPlan.genericAsin);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  const benefitList = splitKeywordPhrases(benefits);
  const objectionList = objections.split(/\r?\n|,/).map((item) => item.trim()).filter(Boolean);
  const plannedModules = useMemo(() => {
    const modules = [
      benefitList[0] ? { label: "Hero benefit module", value: benefitList[0], detail: "Lead with the strongest commercial promise" } : null,
      benefitList[1] ? { label: "Feature education module", value: benefitList[1], detail: "Show why the product works better" } : null,
      objectionList[0] ? { label: "Objection handling module", value: objectionList[0], detail: "Resolve buyer hesitation visually" } : null,
      comparisonRows > 0 ? { label: "Comparison table", value: `${comparisonRows} rows`, detail: "Clarify family or competitor differences" } : null,
      brandStory.trim() ? { label: "Brand story strip", value: "Ready", detail: "Use only real proof, not generic mission copy" } : null,
    ].filter(Boolean);
    return modules as Array<{ label: string; value: string; detail?: string }>;
  }, [benefitList, brandStory, comparisonRows, objectionList]);

  const result = evaluateAPlusContent({
    hasAPlus: Boolean(snapshot?.hasAPlus),
    benefitCount: benefitList.length,
    objectionCount: objectionList.length,
    assetCount: assets.length + (snapshot?.imageUrls.length ?? 0),
    moduleCount: plannedModules.length,
    comparisonRows,
    brandStoryReady: brandStory.trim().length >= 24,
    professionalSeller,
    brandRepresentative,
    premiumRequested,
    premiumEligibilityReady,
    imageSpecReady,
    altTextReady,
    plainTextMigrated,
    retailContributionConflict,
    genericAsin: genericAsin || inferredGenericAsin,
  });

  const liveAssetCount = (snapshot?.imageUrls.length ?? 0) + assets.length;

  const aPlusAuditRows = useMemo(
    () => [
      {
        label: "Live listing base",
        value: snapshot ? `${snapshot.marketplace} / ${snapshot.asin}` : "No live listing loaded",
        detail: snapshot ? `${snapshot.imageUrls.length} live images | ${snapshot.hasAPlus ? "A+ already live" : "No A+ detected"}` : "Load the listing first so the tool can anchor the plan to the real PDP.",
      },
      {
        label: "Commercial story inputs",
        value: `${benefitList.length} benefits / ${objectionList.length} objections`,
        detail: brandStory.trim()
          ? "Story input exists, so the next job is proof hierarchy rather than blank-page ideation."
          : "Brand story is still thin, so visual proof must do more of the conversion work.",
      },
      {
        label: "Asset stack",
        value: `${liveAssetCount} total assets`,
        detail: `${assets.length} planned modules supported by selected art types`,
      },
      {
        label: "Eligibility posture",
        value: `${premiumRequested ? "Premium requested" : "Standard A+"} / ${brandRepresentative ? "Brand rep ready" : "Brand rep gap"}`,
        detail: `${professionalSeller ? "Professional seller" : "Seller plan gap"} | ${inferredGenericAsin || genericAsin ? "Generic-brand risk" : "Branded ASIN"}`,
      },
      {
        label: "System inference",
        value: inferredBrandRepresentative ? "Brand surface found" : "Thin brand surface",
        detail: snapshot
          ? `${inferredAssets.length} asset roles inferred | ${inferredPremiumEligibilityReady ? "premium path may be viable" : "premium path still needs proof"}`
          : "Load a live listing so the page can infer asset roles and brand-control posture first.",
      },
    ],
    [assets.length, benefitList.length, brandRepresentative, brandStory, genericAsin, inferredAssets.length, inferredBrandRepresentative, inferredGenericAsin, inferredPremiumEligibilityReady, liveAssetCount, objectionList.length, premiumRequested, professionalSeller, snapshot],
  );

  const aPlusExecutionPlan = useMemo(
    () =>
      inferAPlusExecutionPlan({
        hasSnapshot: Boolean(snapshot),
        brandRepresentative,
        professionalSeller,
        benefitCount: benefitList.length,
        objectionCount: objectionList.length,
        premiumRequested,
        premiumEligibilityReady,
        imageSpecReady,
        altTextReady,
        plainTextMigrated,
        retailContributionConflict,
      }),
    [
      altTextReady,
      benefitList.length,
      brandRepresentative,
      imageSpecReady,
      objectionList.length,
      plainTextMigrated,
      premiumEligibilityReady,
      premiumRequested,
      professionalSeller,
      retailContributionConflict,
      snapshot,
    ],
  );

  const aPlusActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: aPlusExecutionPlan.decision,
        detail: aPlusExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: aPlusExecutionPlan.owner,
        detail: `${aPlusExecutionPlan.proofPriority} is the proof to lock before the team expands the module plan.`,
      },
      {
        label: "Do not cross",
        value:
          !snapshot
            ? "Do not plan A+ from a blank page"
            : premiumRequested
              ? "Do not open Premium A+ before brand-control proof is real"
              : "Do not turn A+ into decorative repetition",
        detail:
          !snapshot
            ? "Start A+ from the live PDP so modules solve real proof gaps instead of inventing generic content."
            : premiumRequested
              ? "Premium modules are wasted effort if brand-surface control and eligibility are still soft."
              : "A+ should add proof, objection handling, and comparison logic rather than restating bullets in larger boxes.",
      },
      {
        label: "Then do",
        value: aPlusExecutionPlan.cadence,
        detail: "Every A+ block should earn its place with a distinct conversion job rather than rephrasing the same feature.",
      },
      {
        label: "Watch",
        value: "Decorative module drift",
        detail: aPlusExecutionPlan.watchout,
      },
    ],
    [aPlusExecutionPlan],
  );

  const aPlusInputRows = useMemo(
    () => [
      ...aPlusAuditRows,
      {
        label: localeText(locale, "Execution call", "执行判断"),
        value: aPlusExecutionPlan.decision,
        detail: `${aPlusExecutionPlan.owner} | ${aPlusExecutionPlan.cadence} | ${aPlusExecutionPlan.proofPriority}`,
      },
    ],
    [aPlusAuditRows, aPlusExecutionPlan],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_0.7fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote
        lines={[
          snapshot
            ? "Live PDP loaded. The tool prefilled benefits, objection prompts, asset roles, and brand-surface signals from the current listing."
            : "Load a live ASIN first so A+ planning starts from the real PDP instead of blank-page ideation.",
          snapshot
            ? `System draft: ${benefitList.length} benefit angles, ${objectionList.length} objection prompts, ${assets.length} planned asset roles, ${comparisonRows} comparison rows.`
            : "The page will draft module inputs from bullets, images, dimensions, and brand signals after loading a listing.",
          "Only open publishing assumptions when you need to override account-level facts the live PDP cannot expose.",
        ]}
      />
      <DistributionPanel title="Live A+ inputs" rows={aPlusInputRows} />
      <DistributionPanel title="This A+ call" rows={aPlusActionRows} />
      <DistributionPanel title="Planned A+ modules" rows={plannedModules} />
      <div className="flex justify-end">
        <button
          type="button"
          onClick={() => setShowAdvanced((current) => !current)}
          className="text-sm font-medium text-teal-700 transition hover:text-teal-800"
        >
          {showAdvanced ? "Hide publishing assumptions" : "Adjust publishing assumptions"}
        </button>
      </div>
      {showAdvanced ? (
        <>
          <div className="grid gap-4">
            <div className="grid gap-2.5 xl:grid-cols-[1.2fr_1fr]">
              <Field label="Benefit angles">
                <TextAreaInput value={benefits} onChange={(e) => setBenefits(e.target.value)} className="min-h-[7rem]" spellCheck={false} />
              </Field>
              <Field label="Buyer objections">
                <TextAreaInput value={objections} onChange={(e) => setObjections(e.target.value)} className="min-h-[7rem]" spellCheck={false} />
              </Field>
            </div>
            <div className="grid gap-2.5 xl:grid-cols-[1.4fr_0.5fr]">
              <Field label="Brand story input">
                <TextAreaInput value={brandStory} onChange={(e) => setBrandStory(e.target.value)} className="min-h-[6rem]" spellCheck={false} />
              </Field>
              <Field label="Comparison rows">
                <NumberInput value={comparisonRows} min="0" step="1" onChange={(e) => setComparisonRows(Number(e.target.value))} />
              </Field>
            </div>
            <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-4">
              {[
                { value: "hero", label: "Hero visual" },
                { value: "close-up", label: "Detail close-up" },
                { value: "lifestyle", label: "Lifestyle scene" },
                { value: "dimensions", label: "Dimensions / infographic" },
                { value: "comparison", label: "Comparison art" },
                { value: "ugc", label: "UGC / social proof" },
              ].map((asset) => (
                <Checkbox
                  key={asset.value}
                  label={asset.label}
                  checked={assets.includes(asset.value)}
                  onChange={(checked) =>
                    setAssets((current) =>
                      checked ? Array.from(new Set([...current, asset.value])) : current.filter((item) => item !== asset.value),
                    )
                  }
                />
              ))}
            </div>
          </div>
          <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-5">
            <Checkbox label="Professional seller" checked={professionalSeller} onChange={setProfessionalSeller} />
            <Checkbox label="Brand Representative or reseller" checked={brandRepresentative} onChange={setBrandRepresentative} />
            <Checkbox label="Premium A+ plan" checked={premiumRequested} onChange={setPremiumRequested} />
            <Checkbox label="Premium eligibility ready" checked={premiumEligibilityReady} onChange={setPremiumEligibilityReady} />
            <Checkbox label="Generic ASIN" checked={genericAsin} onChange={setGenericAsin} />
          </div>
          <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-5">
            <Checkbox label="Image specs compliant" checked={imageSpecReady} onChange={setImageSpecReady} />
            <Checkbox label="Alt-text ready" checked={altTextReady} onChange={setAltTextReady} />
            <Checkbox label="Plain-text details migrated" checked={plainTextMigrated} onChange={setPlainTextMigrated} />
            <Checkbox label="Retail contribution conflict" checked={retailContributionConflict} onChange={setRetailContributionConflict} />
          </div>
        </>
      ) : null}
      <LowTokenAssistPanel
        toolSlug={premiumRequested ? "amazon-enhanced-brand-content" : "amazon-a-plus-content"}
        locale={locale}
        result={result}
        context={{
          benefitAngles: benefitList,
          buyerObjections: objectionList,
          brandStory,
          plannedModules: plannedModules.slice(0, 4).map((item) => item.label),
          assetChecklist: assets,
          liveTitle: snapshot?.title ?? "",
        }}
      />
    </RuntimeShell>
  );
}

function PpcCampaignRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [campaignText, setCampaignText] = useState(
    "Campaign\tCampaign Type\tSpend\tSales\tOrders\tClicks\tImpressions\tBudget\nSP Exact - Hero ASIN\tSponsored Products\t120\t820\t18\t210\t42000\t45\nSP Auto - Harvest\tSponsored Products\t140\t360\t7\t250\t68000\t40\nSB Video - Brand\tSponsored Brands\t80\t500\t9\t95\t22000\t30",
  );
  const [accountStage, setAccountStage] = useState("steady");
  const [marginPressure, setMarginPressure] = useState("normal");
  const [targetAcos, setTargetAcos] = useState(0.28);
  const [campaignMode, setCampaignMode] = useState("audit");
  const [showOverrides, setShowOverrides] = useState(false);
  const targetAcosPrefillRef = useRef(false);

  const rows = useMemo(() => parseCampaignPerformanceRows(campaignText), [campaignText]);
  const inferredTargetAcos = useMemo(() => inferTargetAcosFromCampaignRows(rows), [rows]);
  const ppcPlan = useMemo(
    () =>
      inferPpcAccountPlan({
        rows,
        accountStage,
        marginPressure,
      }),
    [accountStage, marginPressure, rows],
  );

  useEffect(() => {
    if (showOverrides || targetAcosPrefillRef.current) {
      return;
    }
    setTargetAcos(inferredTargetAcos || ppcPlan.targetAcos);
    setCampaignMode(ppcPlan.campaignMode);
    targetAcosPrefillRef.current = true;
  }, [inferredTargetAcos, ppcPlan, showOverrides]);

  const result = useMemo(() => {
    const spend = rows.reduce((sum, row) => sum + row.spend, 0);
    const sales = rows.reduce((sum, row) => sum + row.sales, 0);
    const orders = rows.reduce((sum, row) => sum + row.orders, 0);
    const clicks = rows.reduce((sum, row) => sum + row.clicks, 0);
    const impressions = rows.reduce((sum, row) => sum + row.impressions, 0);
    const acos = sales > 0 ? spend / sales : 0;
    const ctr = impressions > 0 ? clicks / impressions : 0;
    const cvr = clicks > 0 ? orders / clicks : 0;
    const winnerCount = rows.filter((row) => row.sales > 0 && row.spend / row.sales <= targetAcos).length;
    const wasteCount = rows.filter((row) => row.sales <= 0 || row.spend / Math.max(row.sales, 1) > targetAcos * 1.25).length;
    const typeCount = new Set(rows.map((row) => row.campaignType || "Unknown")).size;
    const winnerCampaign = rows
      .filter((row) => row.sales > 0 && row.spend / row.sales <= targetAcos)
      .sort((a, b) => b.sales - a.sales)[0];
    const wasteCampaign = rows
      .filter((row) => row.sales <= 0 || row.spend / Math.max(row.sales, 1) > targetAcos * 1.25)
      .sort((a, b) => b.spend - a.spend)[0];

    return evaluatePpcCampaign({
      rowCount: rows.length,
      campaignTypeCount: typeCount,
      spend,
      sales,
      orders,
      acos,
      ctr,
      cvr,
      winnerCount,
      wasteCount,
      targetAcos,
      topWinnerCampaign: winnerCampaign?.campaign ?? "",
      topWasteCampaign: wasteCampaign?.campaign ?? "",
    });
  }, [rows, targetAcos]);

  const campaignRows = useMemo(
    () =>
      rows.map((row) => {
        const acos = row.sales > 0 ? row.spend / row.sales : 999;
        return {
          label: row.campaign,
          value: row.sales > 0 ? `${Math.round(acos * 100)}% ACoS` : "No sales",
          detail: `${row.campaignType || "Unknown"} | ${row.orders} orders | ${row.clicks} clicks | ${row.spend.toFixed(2)} spend`,
        };
      }),
    [rows],
  );

  const ppcAuditRows = useMemo(() => {
    const spend = rows.reduce((sum, row) => sum + row.spend, 0);
    const sales = rows.reduce((sum, row) => sum + row.sales, 0);
    const orders = rows.reduce((sum, row) => sum + row.orders, 0);
    const clicks = rows.reduce((sum, row) => sum + row.clicks, 0);
    const impressions = rows.reduce((sum, row) => sum + row.impressions, 0);
    const acos = sales > 0 ? spend / sales : 0;
    const ctr = impressions > 0 ? clicks / impressions : 0;
    const cvr = clicks > 0 ? orders / clicks : 0;
    const winnerCount = rows.filter((row) => row.sales > 0 && row.spend / row.sales <= targetAcos).length;
    const wasteCount = rows.filter((row) => row.sales <= 0 || row.spend / Math.max(row.sales, 1) > targetAcos * 1.25).length;

    return [
      {
        label: "Rows parsed",
        value: `${rows.length}`,
        detail: `${campaignMode} mode | ${accountStage} account posture`,
      },
      {
        label: "Spend / sales",
        value: `${formatUsd(roundNumber(spend, 2))} / ${formatUsd(roundNumber(sales, 2))}`,
        detail: `${orders} tracked orders behind the current read`,
      },
      {
        label: "Observed ACoS",
        value: `${roundNumber(acos * 100, 1)}%`,
        detail: `${roundNumber(targetAcos * 100, 1)}% target guardrail | ${marginPressure} margin pressure${inferredTargetAcos ? ` | ${roundNumber(inferredTargetAcos * 100, 1)}% export read` : ""}`,
      },
      {
        label: "CTR / CVR",
        value: `${roundNumber(ctr * 100, 2)}% / ${roundNumber(cvr * 100, 1)}%`,
        detail: `${winnerCount} winner campaigns | ${wasteCount} waste campaigns`,
      },
    ];
  }, [accountStage, campaignMode, inferredTargetAcos, marginPressure, rows, targetAcos]);

  const ppcExecutionPlan = useMemo(() => {
    const spend = rows.reduce((sum, row) => sum + row.spend, 0);
    const sales = rows.reduce((sum, row) => sum + row.sales, 0);
    const clicks = rows.reduce((sum, row) => sum + row.clicks, 0);
    const impressions = rows.reduce((sum, row) => sum + row.impressions, 0);
    const orders = rows.reduce((sum, row) => sum + row.orders, 0);
    const acos = sales > 0 ? spend / sales : 0;
    const ctr = impressions > 0 ? clicks / impressions : 0;
    const cvr = clicks > 0 ? orders / clicks : 0;
    const winnerCampaign = rows
      .filter((row) => row.sales > 0 && row.spend / row.sales <= targetAcos)
      .sort((a, b) => b.sales - a.sales)[0];
    const wasteCampaign = rows
      .filter((row) => row.sales <= 0 || row.spend / Math.max(row.sales, 1) > targetAcos * 1.25)
      .sort((a, b) => b.spend - a.spend)[0];

    return inferPpcExecutionPlan({
      rowCount: rows.length,
      acos,
      targetAcos,
      ctr,
      cvr,
      hasWinnerCampaign: Boolean(winnerCampaign),
      hasWasteCampaign: Boolean(wasteCampaign),
    });
  }, [rows, targetAcos]);

  const ppcActionRows = useMemo(() => {
    const spend = rows.reduce((sum, row) => sum + row.spend, 0);
    const sales = rows.reduce((sum, row) => sum + row.sales, 0);
    const clicks = rows.reduce((sum, row) => sum + row.clicks, 0);
    const impressions = rows.reduce((sum, row) => sum + row.impressions, 0);
    const orders = rows.reduce((sum, row) => sum + row.orders, 0);
    const acos = sales > 0 ? spend / sales : 0;
    const ctr = impressions > 0 ? clicks / impressions : 0;
    const cvr = clicks > 0 ? orders / clicks : 0;
    const winnerCampaign = rows
      .filter((row) => row.sales > 0 && row.spend / row.sales <= targetAcos)
      .sort((a, b) => b.sales - a.sales)[0];
    const wasteCampaign = rows
      .filter((row) => row.sales <= 0 || row.spend / Math.max(row.sales, 1) > targetAcos * 1.25)
      .sort((a, b) => b.spend - a.spend)[0];

    return [
      {
        label: "First move",
        value: ppcExecutionPlan.decision,
        detail: ppcExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: ppcExecutionPlan.owner,
        detail: `${ppcExecutionPlan.proofPriority} is the proof to lock before opening more spend.`,
      },
      {
        label: "Then do",
        value: "Freeze one winner and one waste example",
        detail: "Use a controlled contrast so the next edit teaches the account instead of blurring multiple variables.",
      },
      {
        label: "Watch",
        value: ppcExecutionPlan.cadence,
        detail: ppcExecutionPlan.watchout,
      },
    ];
  }, [ppcExecutionPlan, rows, targetAcos]);

  const ppcInputRows = useMemo(
    () => [
      ...ppcAuditRows,
      {
        label: "Execution call",
        value: ppcExecutionPlan.decision,
        detail: `${ppcExecutionPlan.owner} | ${ppcExecutionPlan.cadence} | ${ppcExecutionPlan.proofPriority}`,
      },
    ],
    [ppcAuditRows, ppcExecutionPlan],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1.5fr_0.45fr_0.55fr]">
        <Field label="Campaign export">
          <TextAreaInput value={campaignText} onChange={(e) => setCampaignText(e.target.value)} className="min-h-[10rem]" spellCheck={false} />
        </Field>
        <Field label="Account stage">
          <SelectInput value={accountStage} onChange={(e) => setAccountStage(e.target.value)}>
            <option value="launch">Launch</option>
            <option value="steady">Steady-state</option>
            <option value="recovery">Recovery / cleanup</option>
          </SelectInput>
        </Field>
        <Field label="Margin pressure">
          <SelectInput value={marginPressure} onChange={(e) => setMarginPressure(e.target.value)}>
            <option value="normal">Normal</option>
            <option value="tight">Tight</option>
            <option value="aggressive">Can spend to grow</option>
          </SelectInput>
        </Field>
      </div>
      <AuditNote
        lines={[
          `Parsed ${rows.length} campaign rows with ${accountStage} account posture and ${marginPressure} margin pressure.`,
          `System draft: ${roundNumber(targetAcos * 100, 1)}% target ACoS and ${campaignMode} operating mode.`,
          "Accepted fields include campaign name, campaign type, spend, sales, orders, clicks, impressions, and budget.",
        ]}
      />
      <DistributionPanel title="Live PPC inputs" rows={ppcInputRows} />
      <DistributionPanel title="This PPC call" rows={ppcActionRows} />
      <DistributionPanel title="Campaign efficiency map" rows={campaignRows} />
      <div className="flex justify-end">
        <button
          type="button"
          onClick={() => setShowOverrides((current) => !current)}
          className="text-sm font-medium text-teal-700 transition hover:text-teal-800"
        >
          {showOverrides ? "Hide PPC overrides" : "Adjust PPC guardrails"}
        </button>
      </div>
      {showOverrides ? (
        <div className="grid gap-2.5 xl:grid-cols-[0.45fr_0.55fr]">
          <Field label="Target ACoS">
            <NumberInput value={targetAcos} min="0" step="0.01" onChange={(e) => setTargetAcos(Number(e.target.value))} />
          </Field>
          <Field label="Mode">
            <SelectInput value={campaignMode} onChange={(e) => setCampaignMode(e.target.value)}>
              <option value="audit">Audit current campaigns</option>
              <option value="launch">Launch structure planning</option>
              <option value="scale">Scale winners</option>
            </SelectInput>
          </Field>
        </div>
      ) : null}
      <LowTokenAssistPanel
        toolSlug="amazon-ppc-campaign"
        locale={locale}
        result={result}
        context={{
          campaignMode,
          targetAcos,
          parsedCampaignRows: rows.length,
          campaignEfficiencyMap: summarizeDistributionRows(campaignRows),
        }}
      />
    </RuntimeShell>
  );
}

function AdvertisingStrategyRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [campaignText, setCampaignText] = useState(
    "Campaign\tCampaign Type\tSpend\tSales\tOrders\tClicks\tImpressions\tBudget\nSP Exact - Hero ASIN\tSponsored Products\t120\t820\t18\t210\t42000\t45\nSP Auto - Harvest\tSponsored Products\t140\t360\t7\t250\t68000\t40\nSB Video - Brand\tSponsored Brands\t80\t500\t9\t95\t22000\t30\nSD Views Remarketing\tSponsored Display\t55\t190\t4\t60\t12000\t20",
  );
  const [accountPriority, setAccountPriority] = useState("stabilize");
  const [executionBandwidth, setExecutionBandwidth] = useState("medium");
  const [monthlyBudget, setMonthlyBudget] = useState(2500);
  const [heroAsinCount, setHeroAsinCount] = useState(2);
  const [goal, setGoal] = useState("profit");
  const [actionMode, setActionMode] = useState("repair");
  const [brandRegistered, setBrandRegistered] = useState(true);
  const [storefrontReady, setStorefrontReady] = useState(true);
  const [newSellerCreditWindow, setNewSellerCreditWindow] = useState(false);
  const [showOverrides, setShowOverrides] = useState(false);

  const rows = useMemo(() => parseCampaignPerformanceRows(campaignText), [campaignText]);
  const inferredPlan = useMemo(() => inferAdvertisingStrategyPlan(rows), [rows]);
  const operatingPlan = useMemo(
    () =>
      inferAdvertisingOperatingPlan({
        rows,
        accountPriority,
        executionBandwidth,
      }),
    [accountPriority, executionBandwidth, rows],
  );

  useEffect(() => {
    if (showOverrides) {
      return;
    }
    setGoal(operatingPlan.goal || inferredPlan.goal);
    setActionMode(operatingPlan.actionMode);
    setMonthlyBudget(inferredPlan.monthlyBudget);
    setHeroAsinCount(inferredPlan.heroAsinCount);
    setBrandRegistered(inferredPlan.brandRegistered);
    setStorefrontReady(inferredPlan.storefrontReady);
    setNewSellerCreditWindow(inferredPlan.newSellerCreditWindow);
  }, [inferredPlan, operatingPlan, showOverrides]);

  const result = useMemo(() => {
    const spend = rows.reduce((sum, row) => sum + row.spend, 0);
    const typeCounts = {
      sp: rows.filter((row) => {
        const type = row.campaignType.trim().toLowerCase();
        return type === "sponsored products" || type === "sp";
      }).length,
      sb: rows.filter((row) => {
        const type = row.campaignType.trim().toLowerCase();
        return type === "sponsored brands" || type === "sb";
      }).length,
      sd: rows.filter((row) => {
        const type = row.campaignType.trim().toLowerCase();
        return type === "sponsored display" || type === "sd";
      }).length,
    };
    const weakCampaignCount = rows.filter((row) => row.sales <= 0 || row.spend / Math.max(row.sales, 1) > 0.35).length;
    const sortedSpend = [...rows].sort((a, b) => b.spend - a.spend);
    const topSpend = sortedSpend.slice(0, Math.min(2, sortedSpend.length)).reduce((sum, row) => sum + row.spend, 0);

    return evaluateAdvertisingStrategy({
      rowCount: rows.length,
      campaignTypeCount: new Set(rows.map((row) => row.campaignType || "Unknown")).size,
      monthlyBudget,
      heroAsinCount,
      topCampaignShare: spend > 0 ? topSpend / spend : 0,
      weakCampaignCount,
      sponsoredProductsCount: typeCounts.sp,
      sponsoredBrandsCount: typeCounts.sb,
      sponsoredDisplayCount: typeCounts.sd,
      brandRegistered,
      storefrontReady,
      newSellerCreditWindow,
    });
  }, [brandRegistered, heroAsinCount, monthlyBudget, newSellerCreditWindow, rows, storefrontReady]);

  const allocationRows = useMemo(() => {
    const base =
      goal === "launch"
        ? [
            { label: "Sponsored Products", value: "55%", detail: "Harvest and defend hero ASIN demand first" },
            { label: "Sponsored Brands", value: "30%", detail: "Layer in branded and collection traffic after SP baseline" },
            { label: "Sponsored Display", value: "15%", detail: "Use for simple retargeting, not broad expansion" },
          ]
        : [
            { label: "Sponsored Products", value: "60%", detail: "Protect efficient search capture first" },
            { label: "Sponsored Brands", value: "25%", detail: "Push branded and cross-sell traffic where profitable" },
            { label: "Sponsored Display", value: "15%", detail: "Keep retargeting tight and measurable" },
          ];
    return base;
  }, [goal]);

  const advertisingAuditRows = useMemo(() => {
    const spend = rows.reduce((sum, row) => sum + row.spend, 0);
    const typeCounts = {
      sp: rows.filter((row) => {
        const type = row.campaignType.trim().toLowerCase();
        return type === "sponsored products" || type === "sp";
      }).length,
      sb: rows.filter((row) => {
        const type = row.campaignType.trim().toLowerCase();
        return type === "sponsored brands" || type === "sb";
      }).length,
      sd: rows.filter((row) => {
        const type = row.campaignType.trim().toLowerCase();
        return type === "sponsored display" || type === "sd";
      }).length,
    };
    const weakCampaignCount = rows.filter((row) => row.sales <= 0 || row.spend / Math.max(row.sales, 1) > 0.35).length;
    const sortedSpend = [...rows].sort((a, b) => b.spend - a.spend);
    const topSpend = sortedSpend.slice(0, Math.min(2, sortedSpend.length)).reduce((sum, row) => sum + row.spend, 0);

    return [
      {
        label: "Rows parsed",
        value: `${rows.length}`,
        detail: `${goal} strategy read | ${actionMode} action mode`,
      },
      {
        label: "Channel mix",
        value: `${typeCounts.sp}/${typeCounts.sb}/${typeCounts.sd}`,
        detail: "Sponsored Products / Sponsored Brands / Sponsored Display counts",
      },
      {
        label: "Budget / hero ASINs",
        value: `${formatUsd(roundNumber(monthlyBudget))} / ${heroAsinCount}`,
        detail: heroAsinCount > 0
          ? `${formatUsd(roundNumber(monthlyBudget / heroAsinCount))} budget per hero ASIN | system read ${formatUsd(roundNumber(inferredPlan.monthlyBudget))}`
          : "No hero ASIN focus yet",
      },
      {
        label: "Spend concentration",
        value: `${spend > 0 ? Math.round((topSpend / spend) * 100) : 0}%`,
        detail: `${weakCampaignCount} weak campaigns in the current account sample`,
      },
      {
        label: "Operating brief",
        value: `${accountPriority} / ${executionBandwidth}`,
        detail: `${operatingPlan.goal} goal inferred with ${operatingPlan.actionMode} motion`,
      },
      {
        label: "Brand stack",
        value: `${brandRegistered ? "Registered" : "Missing"} / ${storefrontReady ? "Store ready" : "Store gap"}`,
        detail: newSellerCreditWindow ? "New-seller ad-credit window is active" : "No special credit window in play",
      },
      {
        label: "System read",
        value: inferredPlan.goal,
        detail: `${inferredPlan.heroAsinCount} hero-ASIN candidate${inferredPlan.heroAsinCount > 1 ? "s" : ""} inferred from winner and naming patterns`,
      },
    ];
  }, [accountPriority, actionMode, brandRegistered, executionBandwidth, goal, heroAsinCount, inferredPlan, monthlyBudget, newSellerCreditWindow, operatingPlan.actionMode, operatingPlan.goal, rows, storefrontReady]);

  const advertisingExecutionPlan = useMemo(() => {
    const spend = rows.reduce((sum, row) => sum + row.spend, 0);
    const weakCampaignCount = rows.filter((row) => row.sales <= 0 || row.spend / Math.max(row.sales, 1) > 0.35).length;
    const sortedSpend = [...rows].sort((a, b) => b.spend - a.spend);
    const topSpend = sortedSpend.slice(0, Math.min(2, sortedSpend.length)).reduce((sum, row) => sum + row.spend, 0);
    const topShare = spend > 0 ? topSpend / spend : 0;
    const typeCount = new Set(rows.map((row) => row.campaignType || "Unknown")).size;
    const rowThreshold = Math.max(2, Math.ceil(rows.length * 0.35));
    const hasSponsoredBrands = rows.some((row) => row.campaignType.toLowerCase().includes("brands"));

    return inferAdvertisingExecutionPlan({
      rowCount: rows.length,
      actionMode,
      typeCount,
      topShare,
      weakCampaignCount,
      rowThreshold,
      storefrontReady,
      hasSponsoredBrands,
      monthlyBudget,
    });
  }, [actionMode, monthlyBudget, rows, storefrontReady]);

  const advertisingActionRows = useMemo(() => {
    return [
      {
        label: "First move",
        value: advertisingExecutionPlan.decision,
        detail: advertisingExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: advertisingExecutionPlan.owner,
        detail: `${advertisingExecutionPlan.proofPriority} is the proof to lock before broadening the channel plan.`,
      },
      {
        label: "Then do",
        value: "Keep one owner on budget concentration",
        detail: "Keep budget-shaping separate from channel-role design so the next edits are easier to attribute.",
      },
      {
        label: "Watch",
        value: advertisingExecutionPlan.cadence,
        detail: advertisingExecutionPlan.watchout,
      },
    ];
  }, [advertisingExecutionPlan]);

  const advertisingInputRows = useMemo(
    () => [
      ...advertisingAuditRows,
      {
        label: "Execution call",
        value: advertisingExecutionPlan.decision,
        detail: `${advertisingExecutionPlan.owner} | ${advertisingExecutionPlan.cadence} | ${advertisingExecutionPlan.proofPriority}`,
      },
    ],
    [advertisingAuditRows, advertisingExecutionPlan],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1.5fr_0.55fr_0.55fr_0.55fr_0.55fr]">
        <Field label="Campaign export">
          <TextAreaInput value={campaignText} onChange={(e) => setCampaignText(e.target.value)} className="min-h-[10rem]" spellCheck={false} />
        </Field>
        <Field label="Account priority">
          <SelectInput value={accountPriority} onChange={(e) => setAccountPriority(e.target.value)}>
            <option value="stabilize">Stabilize efficiency</option>
            <option value="launch">Support launch</option>
            <option value="defend">Defend brand position</option>
          </SelectInput>
        </Field>
        <Field label="Execution bandwidth">
          <SelectInput value={executionBandwidth} onChange={(e) => setExecutionBandwidth(e.target.value)}>
            <option value="tight">Tight</option>
            <option value="medium">Medium</option>
            <option value="broad">Broad</option>
          </SelectInput>
        </Field>
        <Field label="Monthly budget">
          <NumberInput value={monthlyBudget} min="0" step="100" onChange={(e) => setMonthlyBudget(Number(e.target.value))} />
        </Field>
        <Field label="Hero ASINs">
          <NumberInput value={heroAsinCount} min="0" step="1" onChange={(e) => setHeroAsinCount(Number(e.target.value))} />
        </Field>
      </div>
      <div className="grid gap-2 md:grid-cols-3 xl:grid-cols-6">
        <Checkbox label="Brand registered" checked={brandRegistered} onChange={setBrandRegistered} />
        <Checkbox label="Storefront ready" checked={storefrontReady} onChange={setStorefrontReady} />
        <Checkbox
          label="New seller ad-credit window"
          checked={newSellerCreditWindow}
          onChange={setNewSellerCreditWindow}
        />
      </div>
      <AuditNote
        lines={[
          `Parsed ${rows.length} campaign rows and drafted a ${goal} strategy read from the current account shape.`,
          `Operating brief: ${accountPriority} priority with ${executionBandwidth} bandwidth. System action mode: ${actionMode}.`,
          "The page now infers the likely operating goal, budget posture, and hero-ASIN focus before asking for manual strategy choices.",
          `System inference: ${inferredPlan.goal} goal, ${formatUsd(roundNumber(inferredPlan.monthlyBudget))} budget posture, ${inferredPlan.heroAsinCount} hero ASINs.`,
        ]}
      />
      <DistributionPanel title="Live ad-strategy inputs" rows={advertisingInputRows} />
      <DistributionPanel title="This ad-strategy call" rows={advertisingActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Advanced strategy overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Only open this if the system-read goal, budget posture, or brand stack is not the real operating situation.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide strategy overrides" : "Adjust strategy assumptions"}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 xl:grid-cols-[0.45fr_0.45fr_0.6fr]">
              <Field label="Monthly budget">
                <NumberInput value={monthlyBudget} min="0" step="100" onChange={(e) => setMonthlyBudget(Number(e.target.value))} />
              </Field>
              <Field label="Hero ASINs">
                <NumberInput value={heroAsinCount} min="0" step="1" onChange={(e) => setHeroAsinCount(Number(e.target.value))} />
              </Field>
              <Field label="Primary goal">
                <SelectInput value={goal} onChange={(e) => setGoal(e.target.value)}>
                  <option value="profit">Profit efficiency</option>
                  <option value="launch">New launch support</option>
                  <option value="defense">Brand defense</option>
                </SelectInput>
              </Field>
            </div>
            <div className="grid gap-2.5 xl:grid-cols-[0.6fr]">
              <Field label="Action mode">
                <SelectInput value={actionMode} onChange={(e) => setActionMode(e.target.value)}>
                  <option value="stabilize">Stabilize</option>
                  <option value="repair">Repair weak spots</option>
                  <option value="expand">Expand layered funnel</option>
                </SelectInput>
              </Field>
            </div>
            <div className="grid gap-2 md:grid-cols-3 xl:grid-cols-6">
              <Checkbox label="Brand registered" checked={brandRegistered} onChange={setBrandRegistered} />
              <Checkbox label="Storefront ready" checked={storefrontReady} onChange={setStorefrontReady} />
              <Checkbox label="New seller ad-credit window" checked={newSellerCreditWindow} onChange={setNewSellerCreditWindow} />
            </div>
          </div>
        ) : null}
      </div>
      <DistributionPanel title="Suggested channel allocation" rows={allocationRows} />
      <LowTokenAssistPanel
        toolSlug="amazon-advertising-strategy"
        locale={locale}
        result={result}
        context={{
          goal,
          monthlyBudget,
          heroAsinCount,
          parsedCampaignRows: rows.length,
          allocationRows: summarizeDistributionRows(allocationRows),
        }}
      />
    </RuntimeShell>
  );
}

function RepricingStrategyRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [ownAsinOrUrl, setOwnAsinOrUrl] = useState("");
  const [competitorInputs, setCompetitorInputs] = useState("");
  const [goal, setGoal] = useState("buy-box");
  const [automationMode, setAutomationMode] = useState("manual-only");
  const [pricePriority, setPricePriority] = useState("protect-margin");
  const [approvalPace, setApprovalPace] = useState("this-cycle");
  const [fulfillmentMode, setFulfillmentMode] = useState<"FBA" | "FBM">("FBA");
  const [netMarginRate, setNetMarginRate] = useState(0);
  const [minimumMarginRate, setMinimumMarginRate] = useState(0);
  const [breakEvenAcos, setBreakEvenAcos] = useState(0);
  const [expectedAcos, setExpectedAcos] = useState(0);
  const [showMarginGuardrail, setShowMarginGuardrail] = useState(false);
  const [ownSnapshot, setOwnSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [competitors, setCompetitors] = useState<AmazonListingSnapshot[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const repricingPlan = useMemo(
    () => inferRepricingPlan(ownSnapshot, competitors, goal),
    [competitors, goal, ownSnapshot],
  );

  async function loadComparison() {
    try {
      setLoading(true);
      setError("");
      const ownResponse = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(ownAsinOrUrl)}`,
      );
      const ownPayload = (await ownResponse.json()) as AmazonListingSnapshot | { error: string };
      if (!ownResponse.ok || "error" in ownPayload) {
        throw new Error("error" in ownPayload ? ownPayload.error : "Failed to load own listing.");
      }

      const loaded: AmazonListingSnapshot[] = [];
      for (const candidate of splitAsinCandidates(competitorInputs).slice(0, 4)) {
        const response = await fetch(
          `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(candidate)}`,
        );
        const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
        if (response.ok && !("error" in payload)) {
          loaded.push(payload);
        }
      }

      setOwnSnapshot(ownPayload);
      setCompetitors(loaded);
      const nextPlan = inferRepricingPlan(ownPayload, loaded, goal);
      const nextExecutionPlan = inferRepricingExecutionPlan({
        ownSnapshot: ownPayload,
        competitors: loaded,
        goal,
        netMarginRate: nextPlan.netMarginRate,
        minimumMarginRate: nextPlan.minimumMarginRate,
      });
      setFulfillmentMode(nextPlan.fulfillmentMode);
      setAutomationMode(nextExecutionPlan.automationMode);
      setPricePriority(nextExecutionPlan.pricePriority);
      setApprovalPace(nextExecutionPlan.approvalPace);
      if (!showMarginGuardrail) {
        setNetMarginRate(nextPlan.netMarginRate);
        setMinimumMarginRate(nextPlan.minimumMarginRate);
        setBreakEvenAcos(nextPlan.breakEvenAcos);
        setExpectedAcos(nextPlan.expectedAcos);
      }
    } catch (fetchError) {
      setOwnSnapshot(null);
      setCompetitors([]);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load repricing comparison.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(() => {
    const repricingExecutionPlan = inferRepricingActionPlan({
      ownSnapshot,
      competitorCount: competitors.length,
      netMarginRate,
      minimumMarginRate,
      automationMode,
      pricePriority,
      approvalPace,
      goal,
    });

    if (!ownSnapshot || !isSnapshotDecisionGrade(ownSnapshot)) {
      return {
        headline: !ownSnapshot
          ? "Repricing strategy is waiting on your live offer baseline"
          : "Repricing strategy needs a stronger own-offer read first",
        summary:
          "Use this repricing read to decide whether the next job is loading the live offer, locking margin floors, or refusing automation until the evidence is strong enough.",
        metrics: [
          {
            label: "Current result",
            value: !ownSnapshot ? "Own offer baseline missing" : "Own offer evidence is still thin",
            detail: !ownSnapshot
              ? "Load your ASIN or Amazon URL so repricing starts from the live offer."
              : "The own listing needs a stronger live read before any repricing behavior should be trusted.",
          },
          {
            label: "Execution call",
            value: repricingExecutionPlan.decision,
            detail: `${repricingExecutionPlan.owner} | ${repricingExecutionPlan.cadence} | ${repricingExecutionPlan.proofPriority}`,
          },
          {
            label: "First move",
            value: !ownSnapshot ? "Load the live offer first" : "Repair the own-offer baseline",
            detail: "Do not turn repricing into policy while the own-offer baseline is uncertain.",
          },
          {
            label: "Execution owner",
            value: repricingExecutionPlan.owner,
            detail: "One owner clears the first repricing blocker before automation posture expands.",
          },
        ],
        recommendations: [
          "Start from the live offer, not from a remembered price or old sheet.",
          "Do not discuss automation before your own offer and guardrails are believable.",
        ],
        status: {
          label: !ownSnapshot ? "Repricing baseline is incomplete" : "Own-offer evidence needs review",
          tone: "warning",
        },
        missingItems: [
          !ownSnapshot ? "Own PDP snapshot" : "Stronger own-offer evidence",
          competitors.length ? "" : "Competitor market pack",
        ].filter(Boolean),
        nextSteps: [
          !ownSnapshot ? "Load your own ASIN or Amazon URL." : "Reload the own offer and verify live evidence.",
          "Keep one owner on the first repricing blocker.",
          "Only then decide whether the next move is manual, guarded, or automated.",
        ],
        actionStance: {
          label: !ownSnapshot ? "Do not build repricing logic without your own live offer" : "Do not automate from weak own-offer evidence",
          tone: "warning",
          detail: !ownSnapshot
            ? "Keep repricing closed until the live offer exists and the first guardrail can be trusted."
            : "Weak own-offer evidence makes every repricing rule look more rational than it really is.",
        },
      } satisfies ToolEvaluation;
    }
    if (competitors.length === 0) {
      return {
        headline: "Repricing strategy needs a real market pack",
        summary:
          "Without competitor offers, repricing collapses into an internal floor exercise. The first useful answer is to build the market comparison set.",
        metrics: [
          {
            label: "Current result",
            value: "Competitor market pack missing",
            detail: "No live competitor offers are loaded yet.",
          },
          {
            label: "Execution call",
            value: repricingExecutionPlan.decision,
            detail: `${repricingExecutionPlan.owner} | ${repricingExecutionPlan.cadence} | ${repricingExecutionPlan.proofPriority}`,
          },
          {
            label: "First move",
            value: "Build a real competitor market pack",
            detail: "Load direct substitutes before debating floor, ceiling, or automation posture.",
          },
          {
            label: "Execution owner",
            value: repricingExecutionPlan.owner,
            detail: "One owner assembles the market pack before repricing rules go live.",
          },
        ],
        recommendations: [
          "Use direct substitutes buyers compare against, not a random competitor list.",
          "Do not let internal margin floors pretend to be market strategy.",
        ],
        status: {
          label: "Competitor market pack is incomplete",
          tone: "warning",
        },
        missingItems: ["Competitor market pack"],
        nextSteps: [
          "Load direct competitor ASINs.",
          "Keep one owner on market-pack quality.",
          "Re-run the repricing read once the comparison set is real.",
        ],
        actionStance: {
          label: "Do not automate repricing without market context",
          tone: "warning",
          detail: "Repricing without a real market pack is how teams create fast, tidy, and expensive mistakes.",
        },
      } satisfies ToolEvaluation;
    }
    const ownPrice = parseCurrencyAmount(ownSnapshot?.priceText);
    const competitorPrices = competitors.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const averageCompetitorPrice = competitorPrices.length
      ? competitorPrices.reduce((sum, value) => sum + value, 0) / competitorPrices.length
      : 0;
    const lowestCompetitorPrice = competitorPrices.length ? Math.min(...competitorPrices) : 0;
    const floorPrice = ownPrice * (1 - Math.max(0, (netMarginRate - minimumMarginRate) / 100));
    const ceilingPrice = averageCompetitorPrice > 0 ? Math.max(ownPrice, averageCompetitorPrice * 1.03) : ownPrice * 1.06;

    return evaluateRepricingStrategy({
      ownPrice,
      lowestCompetitorPrice,
      averageCompetitorPrice,
      competitorCount: competitorPrices.length,
      netMarginRate,
      minimumMarginRate,
      floorPrice,
      ceilingPrice,
      goal,
      fulfillmentMode,
    });
  }, [competitors, fulfillmentMode, goal, minimumMarginRate, netMarginRate, ownSnapshot]);

  const repricingDecisionRows = useMemo(
    () => {
      const ownPrice = parseCurrencyAmount(ownSnapshot?.priceText);
      const competitorPrices = competitors.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
      const low = competitorPrices.length ? Math.min(...competitorPrices) : 0;
      const priceDropPercent = ownPrice > 0 && low > 0 ? ((ownPrice - low) / ownPrice) * 100 : 0;
      const matchLowPriceImpact = netMarginRate > 0 ? netMarginRate - priceDropPercent : 0;

      return buildRepricingDecisionRows({
        ownSnapshot,
        competitorSnapshots: competitors,
        goal,
        fulfillmentMode,
        netMarginRate,
        minimumMarginRate,
        breakEvenAcos,
        expectedAcos,
        matchLowPriceImpact,
      });
    },
    [breakEvenAcos, competitors, expectedAcos, fulfillmentMode, goal, minimumMarginRate, netMarginRate, ownSnapshot],
  );

  const auditLines = useMemo(() => {
    const lines: string[] = [];
    if (ownSnapshot) {
      const evidenceStatus = getSnapshotEvidenceStatus(ownSnapshot);
      lines.push("Live ASIN mode loaded the current offer so price posture is anchored to the real PDP.");
      lines.push(`Evidence quality: ${evidenceStatus.label}. ${evidenceStatus.detail}`);
      if (evidenceStatus.level !== "complete") {
        lines.push("Do not turn this into an automated repricing rule until the own listing snapshot is decision-grade.");
      }
      lines.push("Fulfillment posture can sometimes be inferred from the live offer, but true margin guardrails still depend on your operating numbers.");
      lines.push(`System draft: ${repricingPlan.marketPosture}, ${repricingPlan.fulfillmentMode}, floor ${roundNumber(repricingPlan.minimumMarginRate, 1)}%, expected ACoS ${roundNumber(repricingPlan.expectedAcos, 1)}%.`);
    } else {
      lines.push("Start with a live ASIN so repricing logic uses current offer evidence, not only manual inputs.");
    }
    if (!competitors.length) {
      lines.push("Competitor ASINs are still missing. Without them, repricing becomes a floor exercise, not a market strategy.");
    }
    if (netMarginRate <= 0 || minimumMarginRate <= 0) {
      lines.push("Margin guardrails are still blank. Do not automate price moves until the floor is backed by real economics.");
    }
    return lines;
  }, [competitors.length, minimumMarginRate, netMarginRate, ownSnapshot, repricingPlan.expectedAcos, repricingPlan.fulfillmentMode, repricingPlan.marketPosture, repricingPlan.minimumMarginRate]);

  const repricingAuditRows = useMemo(() => {
    const ownPrice = parseCurrencyAmount(ownSnapshot?.priceText);
    const competitorPrices = competitors.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const low = competitorPrices.length ? Math.min(...competitorPrices) : 0;
    const avg = competitorPrices.length ? competitorPrices.reduce((sum, value) => sum + value, 0) / competitorPrices.length : 0;

    return [
      {
        label: "Own offer",
        value: ownSnapshot?.asin || "Missing",
        detail: ownPrice > 0 ? `${formatUsd(roundNumber(ownPrice))} live price on the current PDP` : "Load your live offer first",
      },
      {
        label: "Market read",
        value: competitorPrices.length ? `${formatUsd(roundNumber(low))} low / ${formatUsd(roundNumber(avg))} avg` : "No competitor prices yet",
        detail: `${competitors.length} competitors currently loaded into the repricing view`,
      },
      {
        label: "Goal / fulfillment",
        value: `${goal} / ${fulfillmentMode}`,
        detail: "Repricing posture changes materially based on whether the job is Buy Box, margin, or premium defense.",
      },
      {
        label: "Execution brief",
        value: `${automationMode.replace(/-/g, " ")} / ${pricePriority.replace(/-/g, " ")}`,
        detail: `${approvalPace.replace(/-/g, " ")} approval pace for the current repricing pass`,
      },
      {
        label: "Margin guardrail",
        value: netMarginRate > 0 && minimumMarginRate > 0 ? `${roundNumber(netMarginRate, 1)}% / ${roundNumber(minimumMarginRate, 1)}%` : "Not fully set",
        detail: "Current net margin versus minimum acceptable margin floor",
      },
    ];
  }, [approvalPace, automationMode, competitors, fulfillmentMode, goal, minimumMarginRate, netMarginRate, ownSnapshot, pricePriority]);

  const repricingExecutionPlan = useMemo(
    () =>
      inferRepricingActionPlan({
        ownSnapshot,
        competitorCount: competitors.length,
        netMarginRate,
        minimumMarginRate,
        automationMode,
        pricePriority,
        approvalPace,
        goal,
      }),
    [approvalPace, automationMode, competitors.length, goal, minimumMarginRate, netMarginRate, ownSnapshot, pricePriority],
  );

  const repricingActionQueueRows = useMemo(() => {
    return [
      {
        label: "First move",
        value: repricingExecutionPlan.decision,
        detail: repricingExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: repricingExecutionPlan.owner,
        detail: `${repricingExecutionPlan.proofPriority} is the proof to lock before changing price behavior.`,
      },
      {
        label: "Do not cross",
        value:
          competitors.length === 0
            ? "Do not automate repricing without a live market set"
            : netMarginRate > 0 && minimumMarginRate > 0
              ? `${roundNumber(minimumMarginRate, 1)}% margin floor is the stop line`
              : "Do not cut price before setting the margin floor",
        detail:
          competitors.length === 0
            ? "Repricing without real market context turns a neat rule into an expensive guess."
            : netMarginRate > 0 && minimumMarginRate > 0
              ? "No response rule should push the offer below the stated minimum contribution margin."
              : "The market can tell you what moved, but not whether following it is commercially allowed.",
      },
      {
        label: "Then do",
        value: repricingExecutionPlan.cadence,
        detail: "Use one explicit control step so margin and market goals stay tied together.",
      },
      {
        label: "Watch",
        value: automationMode.replace(/-/g, " "),
        detail: repricingExecutionPlan.watchout,
      },
    ];
  }, [automationMode, competitors.length, minimumMarginRate, netMarginRate, repricingExecutionPlan]);

  const repricingInputRows = useMemo(
    () => [
      ...repricingAuditRows,
      {
        label: "Execution call",
        value: repricingExecutionPlan.decision,
        detail: `${repricingExecutionPlan.owner} | ${repricingExecutionPlan.cadence} | ${repricingExecutionPlan.proofPriority}`,
      },
    ],
    [repricingAuditRows, repricingExecutionPlan],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_1fr_0.55fr_0.55fr_auto]">
        <Field label="Your ASIN or Amazon product URL">
          <TextInput
            value={ownAsinOrUrl}
            onChange={(e) => setOwnAsinOrUrl(e.target.value)}
            placeholder="Paste your ASIN or Amazon URL"
          />
        </Field>
        <Field label="Competitor ASINs or URLs">
          <TextAreaInput
            value={competitorInputs}
            onChange={(e) => setCompetitorInputs(e.target.value)}
            className="min-h-[7.5rem]"
            placeholder="One competitor ASIN or URL per line"
            spellCheck={false}
          />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <Field label="Goal">
          <SelectInput value={goal} onChange={(e) => setGoal(e.target.value)}>
            <option value="buy-box">Buy Box defense</option>
            <option value="margin">Margin protection</option>
            <option value="premium-defense">Premium positioning</option>
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadComparison} disabled={loading || !ownAsinOrUrl.trim()}>
            {loading ? "Loading..." : "Load live comparison"}
          </ActionButton>
        </div>
      </div>
      <div className="grid gap-2.5 md:grid-cols-[0.95fr_0.95fr_0.95fr]">
        <Field label="Automation mode">
          <SelectInput value={automationMode} onChange={(e) => setAutomationMode(e.target.value)}>
            <option value="manual-only">Manual only</option>
            <option value="guarded-response">Guarded response</option>
            <option value="controlled-automation">Controlled automation</option>
          </SelectInput>
        </Field>
        <Field label="Price priority">
          <SelectInput value={pricePriority} onChange={(e) => setPricePriority(e.target.value)}>
            <option value="protect-margin">Protect margin</option>
            <option value="close-market-gap">Close market gap</option>
            <option value="defend-buy-box">Defend Buy Box</option>
            <option value="protect-premium">Protect premium</option>
            <option value="hold-band">Hold band</option>
          </SelectInput>
        </Field>
        <Field label="Approval pace">
          <SelectInput value={approvalPace} onChange={(e) => setApprovalPace(e.target.value)}>
            <option value="same-day">Same day</option>
            <option value="this-cycle">This cycle</option>
            <option value="monitor">Monitor</option>
          </SelectInput>
        </Field>
      </div>
      <SnapshotPanel snapshot={ownSnapshot} error={error} loading={loading} />
      <AuditNote lines={auditLines} />
      <DistributionPanel title="Live repricing inputs" rows={repricingInputRows} />
      <DistributionPanel title="This repricing call" rows={repricingActionQueueRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Optional profit guardrail</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when you want to override fulfillment posture or test whether matching the market will cut below your minimum contribution margin.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowMarginGuardrail((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showMarginGuardrail ? "Hide margin guardrail" : "Test profit impact"}
          </button>
        </div>
        {showMarginGuardrail ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-5">
              <Field label="Fulfillment">
                <SelectInput value={fulfillmentMode} onChange={(e) => setFulfillmentMode(e.target.value as "FBA" | "FBM")}>
                  <option value="FBA">FBA</option>
                  <option value="FBM">FBM</option>
                </SelectInput>
              </Field>
              <Field label="Net margin %">
                <NumberInput value={netMarginRate} min="0" step="0.1" onChange={(e) => setNetMarginRate(Number(e.target.value))} />
              </Field>
              <Field label="Min margin %">
                <NumberInput value={minimumMarginRate} min="0" step="0.1" onChange={(e) => setMinimumMarginRate(Number(e.target.value))} />
              </Field>
              <Field label="Break-even ACoS %">
                <NumberInput value={breakEvenAcos} min="0" step="0.1" onChange={(e) => setBreakEvenAcos(Number(e.target.value))} />
              </Field>
              <Field label="Expected ACoS %">
                <NumberInput value={expectedAcos} min="0" step="0.1" onChange={(e) => setExpectedAcos(Number(e.target.value))} />
              </Field>
            </div>
          </div>
        ) : null}
      </div>
      <CompetitorBoard own={ownSnapshot} competitors={competitors} />
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title="Repricing verdict" rows={repricingDecisionRows.verdictRows} />
        <DistributionPanel title="Guardrails" rows={repricingDecisionRows.guardrailRows} />
        <DistributionPanel title="Decision order" rows={repricingDecisionRows.actionRows} />
      </div>
    </RuntimeShell>
  );
}

function BuyBoxRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [ownAsinOrUrl, setOwnAsinOrUrl] = useState("");
  const [competitorInputs, setCompetitorInputs] = useState("");
  const [responsePriority, setResponsePriority] = useState("defend-non-price");
  const [offerLeverage, setOfferLeverage] = useState("merch-proof");
  const [escalationCadence, setEscalationCadence] = useState("monitor");
  const [fulfillmentMode, setFulfillmentMode] = useState<"FBA" | "FBM">("FBA");
  const [sellerRating, setSellerRating] = useState(0);
  const [shippingSlaDays, setShippingSlaDays] = useState(0);
  const [stockReady, setStockReady] = useState(true);
  const [returnRate, setReturnRate] = useState(0);
  const [currentNetMarginRate, setCurrentNetMarginRate] = useState(0);
  const [minimumMarginRate, setMinimumMarginRate] = useState(0);
  const [ownSnapshot, setOwnSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [competitors, setCompetitors] = useState<AmazonListingSnapshot[]>([]);
  const [showOverrides, setShowOverrides] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const buyBoxPlan = useMemo(
    () => inferBuyBoxPlan(ownSnapshot, competitors),
    [competitors, ownSnapshot],
  );

  async function loadComparison() {
    try {
      setLoading(true);
      setError("");
      const ownResponse = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(ownAsinOrUrl)}`,
      );
      const ownPayload = (await ownResponse.json()) as AmazonListingSnapshot | { error: string };
      if (!ownResponse.ok || "error" in ownPayload) {
        throw new Error("error" in ownPayload ? ownPayload.error : "Failed to load own listing.");
      }

      const loaded: AmazonListingSnapshot[] = [];
      for (const candidate of splitAsinCandidates(competitorInputs).slice(0, 4)) {
        const response = await fetch(
          `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(candidate)}`,
        );
        const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
        if (response.ok && !("error" in payload)) {
          loaded.push(payload);
        }
      }

      setOwnSnapshot(ownPayload);
      setCompetitors(loaded);
      const nextPlan = inferBuyBoxPlan(ownPayload, loaded);
      setFulfillmentMode(nextPlan.fulfillmentMode);
      if (!showOverrides) {
        setSellerRating(nextPlan.sellerRating);
        setShippingSlaDays(nextPlan.shippingSlaDays);
        setStockReady(nextPlan.stockReady);
        setReturnRate(nextPlan.returnRate);
        setCurrentNetMarginRate(nextPlan.currentNetMarginRate);
        setMinimumMarginRate(nextPlan.minimumMarginRate);
      }
      const nextResponsePlan = inferBuyBoxResponsePlan({
        ownSnapshot: ownPayload,
        competitors: loaded,
        fulfillmentMode: nextPlan.fulfillmentMode,
        shippingSlaDays: showOverrides ? shippingSlaDays : nextPlan.shippingSlaDays,
        stockReady: showOverrides ? stockReady : nextPlan.stockReady,
        sellerSignalsAreEstimated: sellerRating <= 0,
        currentNetMarginRate: showOverrides ? currentNetMarginRate : nextPlan.currentNetMarginRate,
        minimumMarginRate: showOverrides ? minimumMarginRate : nextPlan.minimumMarginRate,
      });
      setResponsePriority(nextResponsePlan.responsePriority);
      setOfferLeverage(nextResponsePlan.offerLeverage);
      setEscalationCadence(nextResponsePlan.escalationCadence);
    } catch (fetchError) {
      setOwnSnapshot(null);
      setCompetitors([]);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load Buy Box comparison.");
    } finally {
      setLoading(false);
    }
  }

  const sellerSignalsAreEstimated = sellerRating <= 0;

  const result = useMemo(() => {
    const buyBoxExecutionPlan = inferBuyBoxExecutionPlan({
      ownSnapshot,
      competitorCount: competitors.length,
      stockReady,
      sellerSignalsAreEstimated,
      fulfillmentMode,
      shippingSlaDays,
      responsePriority,
      currentNetMarginRate,
      minimumMarginRate,
      priceGap: 0,
      escalationCadence,
      offerLeverage,
    });

    if (!ownSnapshot || !isSnapshotDecisionGrade(ownSnapshot)) {
      return {
        headline: !ownSnapshot
          ? "Buy Box check is waiting on your live offer baseline"
          : "Buy Box check needs a stronger own-offer read first",
        summary:
          "Use this Buy Box read to decide whether the first job is loading the live offer, confirming account or service signals, or refusing to change multiple levers from a weak baseline.",
        metrics: [
          {
            label: "Current result",
            value: !ownSnapshot ? "Own offer baseline missing" : "Own offer evidence is still thin",
            detail: !ownSnapshot
              ? "Load your ASIN or Amazon URL so Buy Box pressure starts from the live offer."
              : "The own listing needs a stronger live offer read before the Buy Box response should move.",
          },
          {
            label: "Execution call",
            value: buyBoxExecutionPlan.decision,
            detail: `${buyBoxExecutionPlan.owner} | ${buyBoxExecutionPlan.cadence} | ${buyBoxExecutionPlan.proofPriority}`,
          },
          {
            label: "First move",
            value: !ownSnapshot ? "Load the live offer first" : "Repair the own-offer baseline",
            detail: "Do not change price, service, and merchandising from a weak own-offer read.",
          },
          {
            label: "Execution owner",
            value: buyBoxExecutionPlan.owner,
            detail: "One owner clears the first Buy Box blocker before multiple teams start reacting.",
          },
          {
            label: "Do not cross",
            value: !ownSnapshot ? "Do not defend Buy Box before the live offer is loaded" : "Do not move three levers from a weak baseline",
            detail: !ownSnapshot
              ? "No Buy Box response gets approved until the live offer is visible."
              : "A weak own-offer read makes price, service, and merchandising all look guilty at once.",
          },
        ],
        recommendations: [
          "Start from the current live offer, not a memory of how the offer looked yesterday.",
          "Do not escalate Buy Box defense until the own-offer baseline is decision-grade.",
        ],
        status: {
          label: !ownSnapshot ? "Buy Box baseline is incomplete" : "Own-offer evidence needs review",
          tone: "warning",
        },
        missingItems: [
          !ownSnapshot ? "Own PDP snapshot" : "Stronger own-offer evidence",
          competitors.length ? "" : "Competitor offer set",
        ].filter(Boolean),
        nextSteps: [
          !ownSnapshot ? "Load your own ASIN or Amazon URL." : "Reload the own offer and verify live evidence.",
          "Keep one owner on the first Buy Box blocker until the same offer set is rechecked.",
          "Only then decide whether the next move is price, fulfillment, or non-price proof.",
        ],
        actionStance: {
          label: !ownSnapshot ? "Do not defend Buy Box without your own live offer" : "Do not overreact from weak own-offer evidence",
          tone: "warning",
          detail: !ownSnapshot
            ? "Keep Buy Box defense closed until the live offer is visible and the first response lever is grounded in live evidence."
            : "Weak own-offer evidence makes the team move fast without knowing which lever is actually losing the box.",
        },
      } satisfies ToolEvaluation;
    }
    if (competitors.length === 0) {
      return {
        headline: "Buy Box check needs a real competitor offer set",
        summary:
          "Without competitor offers, Buy Box work collapses into self-diagnosis. Build the comparison set first, then decide which lever deserves action.",
        metrics: [
          {
            label: "Current result",
            value: "Competitor offer set missing",
            detail: "No live competitor offers are loaded yet.",
          },
          {
            label: "Execution call",
            value: buyBoxExecutionPlan.decision,
            detail: `${buyBoxExecutionPlan.owner} | ${buyBoxExecutionPlan.cadence} | ${buyBoxExecutionPlan.proofPriority}`,
          },
          {
            label: "First move",
            value: "Build a real competitor offer set",
            detail: "Use direct alternatives buyers compare against before diagnosing Buy Box pressure.",
          },
          {
            label: "Execution owner",
            value: buyBoxExecutionPlan.owner,
            detail: "One owner builds the offer set before the team reacts to the symptom.",
          },
        ],
        recommendations: [
          "Track direct market alternatives, not just familiar ASINs.",
          "Do not let Buy Box defense become a solo internal story with no market context.",
        ],
        status: {
          label: "Competitor offer set is incomplete",
          tone: "warning",
        },
        missingItems: ["Competitor offer set"],
        nextSteps: [
          "Load direct competitor ASINs.",
          "Keep one owner on offer-set quality.",
          "Re-run the Buy Box read once the comparison set is real.",
        ],
        actionStance: {
          label: "Do not defend Buy Box without market context",
          tone: "warning",
          detail: "Fast Buy Box reactions only help when they are pointed at the actual pressure source, not guessed from inside the listing.",
        },
      } satisfies ToolEvaluation;
    }
    const ownPrice = parseCurrencyAmount(ownSnapshot?.priceText);
    const competitorPrices = competitors.map((item) => parseCurrencyAmount(item.priceText)).filter((value) => value > 0);
    const competitorRatings = competitors.map((item) => parseRatingValue(item.ratingText)).filter((value) => value > 0);
    const averageCompetitorPrice = competitorPrices.length ? competitorPrices.reduce((sum, value) => sum + value, 0) / competitorPrices.length : 0;
    const ownVisibleRating = parseRatingValue(ownSnapshot?.ratingText);
    const effectiveSellerRating = sellerRating > 0 ? sellerRating : ownVisibleRating;
    const competitorRating = competitorRatings.length
      ? competitorRatings.reduce((sum, value) => sum + value, 0) / competitorRatings.length
      : effectiveSellerRating;

    return evaluateBuyBox({
      ownPrice,
      averageCompetitorPrice,
      sellerRating: effectiveSellerRating,
      competitorRating,
      fulfillmentMode,
      shippingSlaDays,
      stockReady,
      returnRate,
      priceGap: ownPrice - averageCompetitorPrice,
    });
  }, [competitors, fulfillmentMode, ownSnapshot, returnRate, sellerRating, shippingSlaDays, stockReady]);

  const buyBoxDecisionRows = useMemo(
    () =>
      buildBuyBoxDecisionRows({
        ownSnapshot,
        competitorSnapshots: competitors,
        fulfillmentMode,
        sellerRating: sellerRating > 0 ? sellerRating : parseRatingValue(ownSnapshot?.ratingText),
        shippingSlaDays,
        stockReady,
        returnRate,
        sellerSignalsAreEstimated,
        currentNetMarginRate,
        minimumMarginRate,
      }),
    [competitors, currentNetMarginRate, fulfillmentMode, minimumMarginRate, ownSnapshot, returnRate, sellerRating, sellerSignalsAreEstimated, shippingSlaDays, stockReady],
  );

  const auditLines = useMemo(() => {
    const lines: string[] = [];
    if (ownSnapshot) {
      const evidenceStatus = getSnapshotEvidenceStatus(ownSnapshot);
      lines.push("Live ASIN mode loaded the current offer so Buy Box pressure starts from real PDP evidence.");
      lines.push(`Evidence quality: ${evidenceStatus.label}. ${evidenceStatus.detail}`);
      if (evidenceStatus.level !== "complete") {
        lines.push("Treat this as a partial pressure read only. Do not make a Buy Box call until the own listing snapshot is decision-grade.");
      }
      lines.push("The PDP read covers offer and merchandising pressure, but private account-health metrics still need confirmation.");
      const fulfillmentEvidence = getFulfillmentEvidence(ownSnapshot);
      if (fulfillmentEvidence.detail) {
        lines.push(`Fulfillment read: ${fulfillmentEvidence.detail}`);
      }
      lines.push(`System draft: ${buyBoxPlan.marketPosture}, ${buyBoxPlan.fulfillmentMode}, ${buyBoxPlan.shippingSlaDays}-day SLA, seller signal ${buyBoxPlan.sellerRating > 0 ? roundNumber(buyBoxPlan.sellerRating, 1) : "estimated"}.`);
    } else {
      lines.push("Load a live ASIN first. Buy Box strategy without a current offer read turns generic very quickly.");
    }
    if (!competitors.length) {
      lines.push("Competitor offers are still missing. Without them, price and fulfillment pressure are incomplete.");
    }
    if (sellerSignalsAreEstimated) {
      lines.push(
        ownSnapshot
          ? "Seller-health inputs are still estimated. PDP evidence is loaded, but private account metrics still need operator confirmation."
          : "Seller-health inputs are still estimated. Keep private seller assumptions out of the first decision until the live offer is loaded.",
      );
    }
    return lines;
  }, [buyBoxPlan.fulfillmentMode, buyBoxPlan.marketPosture, buyBoxPlan.sellerRating, buyBoxPlan.shippingSlaDays, competitors.length, ownSnapshot, sellerSignalsAreEstimated]);

  const buyBoxAuditRows = useMemo(
    () =>
      !ownSnapshot
        ? [
            {
              label: "Own PDP",
              value: "Missing",
              detail: "Load your live listing first",
            },
            {
              label: "Competitor set",
              value: `${competitors.length}`,
              detail: competitors.length ? "Loaded from live competitor PDPs" : "No live competitor set yet",
            },
            {
              label: "First blocker",
              value: "Own live offer baseline",
              detail: "Until your own offer is live, every Buy Box theory is still provisional.",
            },
            {
              label: "Decision owner",
              value: "Offer owner",
              detail: "One owner loads the live offer before pricing, fulfillment, or merch teams start guessing.",
            },
            {
              label: "Response brief",
              value: `${responsePriority.replace(/-/g, " ")} / ${offerLeverage.replace(/-/g, " ")}`,
              detail: `${escalationCadence.replace(/-/g, " ")} escalation cadence for the current Buy Box pass`,
            },
          ]
        : [
            {
              label: "Own PDP",
              value: ownSnapshot.asin || "Missing",
              detail: ownSnapshot.priceText || "Load your live listing first",
            },
            {
              label: "Competitor set",
              value: `${competitors.length}`,
              detail: competitors.length ? "Loaded from live competitor PDPs" : "No live competitor set yet",
            },
            {
              label: "Fulfillment read",
              value: fulfillmentMode,
              detail: "Inferred from the live listing when possible",
            },
            {
              label: "Seller-signal mode",
              value: sellerSignalsAreEstimated ? "Estimated" : "Confirmed",
              detail: sellerSignalsAreEstimated ? "Private seller-health metrics still need operator confirmation" : "Using operator-supplied private seller inputs",
            },
            {
              label: "Response brief",
              value: `${responsePriority.replace(/-/g, " ")} / ${offerLeverage.replace(/-/g, " ")}`,
              detail: `${escalationCadence.replace(/-/g, " ")} escalation cadence for the current Buy Box pass`,
            },
          ],
    [competitors.length, escalationCadence, fulfillmentMode, offerLeverage, ownSnapshot, responsePriority, sellerSignalsAreEstimated],
  );

  const buyBoxExecutionPlan = useMemo(() => {
    const ownPrice = parseCurrencyAmount(ownSnapshot?.priceText);
    const competitorPrices = competitors
      .map((item) => parseCurrencyAmount(item.priceText))
      .filter((value) => value > 0);
    const averageCompetitorPrice = competitorPrices.length
      ? competitorPrices.reduce((sum, value) => sum + value, 0) / competitorPrices.length
      : 0;
    const priceGap = ownPrice > 0 && averageCompetitorPrice > 0 ? ownPrice - averageCompetitorPrice : 0;

    return inferBuyBoxExecutionPlan({
      ownSnapshot,
      competitorCount: competitors.length,
      stockReady,
      sellerSignalsAreEstimated,
      fulfillmentMode,
      shippingSlaDays,
      responsePriority,
      currentNetMarginRate,
      minimumMarginRate,
      priceGap,
      escalationCadence,
      offerLeverage,
    });
  }, [
    competitors,
    currentNetMarginRate,
    escalationCadence,
    fulfillmentMode,
    minimumMarginRate,
    offerLeverage,
    ownSnapshot,
    responsePriority,
    sellerSignalsAreEstimated,
    shippingSlaDays,
    stockReady,
  ]);

  const buyBoxActionRows = useMemo(() => {
    return [
      {
        label: "First move",
        value: buyBoxExecutionPlan.decision,
        detail: `${buyBoxExecutionPlan.nextMove} Keep every non-primary lever closed until this first blocker is verified.`,
      },
      {
        label: "Execution owner",
        value: buyBoxExecutionPlan.owner,
        detail: `${buyBoxExecutionPlan.proofPriority} is the proof to lock before you start changing multiple levers.`,
      },
      {
        label: "Do not cross",
        value:
          !ownSnapshot
            ? "Do not defend Buy Box before loading your own live offer"
            : competitors.length === 0
              ? "Do not react to Buy Box pressure without a live competitor set"
              : sellerSignalsAreEstimated
                ? "Do not overfit the plan to guessed seller-health inputs"
                : "Do not change price, service, and merchandising all at once",
        detail:
          !ownSnapshot
            ? "Keep Buy Box reactions closed until the tool is reducing blind reaction rather than speeding it up."
            : competitors.length === 0
              ? "Without real competitor context, Buy Box defense collapses into self-diagnosis."
              : sellerSignalsAreEstimated
                ? "Public PDP evidence is useful, but private seller-health assumptions still need operator confirmation."
                : "One focused intervention is easier to learn from than a bundle of simultaneous offer changes.",
      },
      {
        label: "Then do",
        value: buyBoxExecutionPlan.cadence,
        detail: "Recheck the same offer set after the first fix lands. Do not open a second response lane before that read.",
      },
      {
        label: "Watch",
        value: offerLeverage.replace(/-/g, " "),
        detail: buyBoxExecutionPlan.watchout,
      },
    ];
  }, [buyBoxExecutionPlan, competitors.length, offerLeverage, ownSnapshot, sellerSignalsAreEstimated]);

  const buyBoxInputRows = useMemo(
    () => [
      ...buyBoxAuditRows,
      {
        label: "Execution call",
        value: buyBoxExecutionPlan.decision,
        detail: `${buyBoxExecutionPlan.owner} | ${buyBoxExecutionPlan.cadence} | ${buyBoxExecutionPlan.proofPriority}`,
      },
    ],
    [buyBoxAuditRows, buyBoxExecutionPlan],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_1fr_0.7fr_auto]">
        <Field label="Your ASIN or Amazon product URL">
          <TextInput
            value={ownAsinOrUrl}
            onChange={(e) => setOwnAsinOrUrl(e.target.value)}
            placeholder="Paste your ASIN or Amazon URL"
          />
        </Field>
        <Field label="Competitor ASINs or URLs">
          <TextAreaInput
            value={competitorInputs}
            onChange={(e) => setCompetitorInputs(e.target.value)}
            className="min-h-[7.5rem]"
            placeholder="One competitor ASIN or URL per line"
            spellCheck={false}
          />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadComparison} disabled={loading || !ownAsinOrUrl.trim()}>
            {loading ? "Loading..." : "Load live comparison"}
          </ActionButton>
        </div>
      </div>
      <div className="grid gap-2.5 md:grid-cols-[0.95fr_0.95fr_0.95fr]">
        <Field label="Response priority">
          <SelectInput value={responsePriority} onChange={(e) => setResponsePriority(e.target.value)}>
            <option value="stabilize-availability">Stabilize availability</option>
            <option value="confirm-account-health">Confirm account health</option>
            <option value="tighten-fulfillment">Tighten fulfillment</option>
            <option value="correct-price-gap">Correct price gap</option>
            <option value="defend-non-price">Defend non-price</option>
          </SelectInput>
        </Field>
        <Field label="Offer leverage">
          <SelectInput value={offerLeverage} onChange={(e) => setOfferLeverage(e.target.value)}>
            <option value="stock-stability">Stock stability</option>
            <option value="account-confidence">Account confidence</option>
            <option value="service-speed">Service speed</option>
            <option value="price-position">Price position</option>
            <option value="merch-proof">Merch / proof</option>
          </SelectInput>
        </Field>
        <Field label="Escalation cadence">
          <SelectInput value={escalationCadence} onChange={(e) => setEscalationCadence(e.target.value)}>
            <option value="same-day">Same day</option>
            <option value="this-cycle">This cycle</option>
            <option value="monitor">Monitor</option>
          </SelectInput>
        </Field>
      </div>
      <SnapshotPanel snapshot={ownSnapshot} error={error} loading={loading} />
      <AuditNote lines={auditLines} />
      <DistributionPanel title="Live Buy Box inputs" rows={buyBoxInputRows} />
      <DistributionPanel title="This Buy Box call" rows={buyBoxActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Private account inputs</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              These do not come from the public PDP. Only open this section when you want to pressure-test seller metrics or service assumptions.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-11 items-center justify-center rounded-lg border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide private inputs" : "Adjust private inputs"}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-4">
              <Field label="Fulfillment">
                <SelectInput value={fulfillmentMode} onChange={(e) => setFulfillmentMode(e.target.value as "FBA" | "FBM")}>
                  <option value="FBA">FBA</option>
                  <option value="FBM">FBM</option>
                </SelectInput>
              </Field>
              <Checkbox label="Stock is stable and ready" checked={stockReady} onChange={setStockReady} />
            </div>
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-3">
            <Field label="Seller rating">
              <NumberInput value={sellerRating} min="0" max="5" step="0.01" onChange={(e) => setSellerRating(Number(e.target.value))} />
            </Field>
            <Field label="Shipping SLA days">
              <NumberInput value={shippingSlaDays} min="0" step="1" onChange={(e) => setShippingSlaDays(Number(e.target.value))} />
            </Field>
            <Field label="Return rate">
              <NumberInput value={returnRate} min="0" max="1" step="0.01" onChange={(e) => setReturnRate(Number(e.target.value))} />
            </Field>
            <Field label="Current net margin %">
              <NumberInput value={currentNetMarginRate} min="0" step="0.1" onChange={(e) => setCurrentNetMarginRate(Number(e.target.value))} />
            </Field>
            <Field label="Minimum acceptable margin %">
              <NumberInput value={minimumMarginRate} min="0" step="0.1" onChange={(e) => setMinimumMarginRate(Number(e.target.value))} />
            </Field>
            </div>
          </div>
        ) : null}
      </div>
      <CompetitorBoard own={ownSnapshot} competitors={competitors} />
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title="Buy Box verdict" rows={buyBoxDecisionRows.verdictRows} />
        <DistributionPanel title="Pressure map" rows={buyBoxDecisionRows.pressureRows} />
        <DistributionPanel title="Decision order" rows={buyBoxDecisionRows.actionRows} />
      </div>
    </RuntimeShell>
  );
}

function DealFinderRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("B0GYRT3FNL");
  const [goal, setGoal] = useState("rank");
  const [promoDecision, setPromoDecision] = useState("run-contained-test");
  const [formatPressure, setFormatPressure] = useState("format-fit");
  const [launchCadence, setLaunchCadence] = useState("controlled-test");
  const [netMarginRate, setNetMarginRate] = useState(18);
  const [inventoryDays, setInventoryDays] = useState(42);
  const [promoWindowDays, setPromoWindowDays] = useState(7);
  const [discountRate, setDiscountRate] = useState(0.1);
  const [featuredOfferLikely, setFeaturedOfferLikely] = useState(true);
  const [dealQuantityReady, setDealQuantityReady] = useState(true);
  const [referencePriceReady, setReferencePriceReady] = useState(true);
  const [stackRisk, setStackRisk] = useState(false);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [showOverrides, setShowOverrides] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const dealPlan = useMemo(() => inferDealPlan(snapshot, goal), [goal, snapshot]);

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }
      setSnapshot(payload);
      if (!showOverrides) {
        const nextPlan = inferDealPlan(payload, goal);
        setNetMarginRate(nextPlan.netMarginRate);
        setInventoryDays(nextPlan.inventoryDays);
        setPromoWindowDays(nextPlan.promoWindowDays);
        setDiscountRate(nextPlan.discountRate);
        setFeaturedOfferLikely(nextPlan.featuredOfferLikely);
        setDealQuantityReady(nextPlan.dealQuantityReady);
        setReferencePriceReady(nextPlan.referencePriceReady);
        setStackRisk(nextPlan.stackRisk);
        const nextExecutionPlan = inferDealExecutionPlan({
          snapshot: payload,
          goal,
          netMarginRate: nextPlan.netMarginRate,
          inventoryDays: nextPlan.inventoryDays,
          promoWindowDays: nextPlan.promoWindowDays,
          discountRate: nextPlan.discountRate,
          featuredOfferLikely: nextPlan.featuredOfferLikely,
          dealQuantityReady: nextPlan.dealQuantityReady,
          referencePriceReady: nextPlan.referencePriceReady,
          stackRisk: nextPlan.stackRisk,
        });
        setPromoDecision(nextExecutionPlan.promoDecision);
        setFormatPressure(nextExecutionPlan.formatPressure);
        setLaunchCadence(nextExecutionPlan.launchCadence);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(() => {
    const price = parseCurrencyAmount(snapshot?.priceText);
    const recommendedDeal =
      goal === "margin"
        ? netMarginRate - discountRate * 100 >= 10 ? "coupon" : "hold"
        : goal === "clearance"
          ? inventoryDays >= 21 ? "ltd" : "coupon"
          : discountRate >= 0.12 ? "ltd" : "coupon";
    const urgencyScore = Math.min(100, Math.round((promoWindowDays / Math.max(inventoryDays, 1)) * 100 + (goal === "clearance" ? 25 : goal === "rank" ? 15 : 5)));

    return evaluateDealFinder({
      price,
      netMarginRate,
      inventoryDays,
      promoWindowDays,
      discountRate,
      goal,
      recommendedDeal,
      urgencyScore,
      featuredOfferLikely,
      dealQuantityReady,
      referencePriceReady,
      stackRisk,
    });
  }, [dealQuantityReady, discountRate, featuredOfferLikely, goal, inventoryDays, promoWindowDays, referencePriceReady, snapshot, stackRisk, netMarginRate]);

  const formatRows = useMemo(
    () => [
      { label: "Coupon", value: `${Math.round(discountRate * 100)}%`, detail: "Lighter discount, cleaner for margin defense" },
      { label: "Limited-time deal", value: `${Math.round((discountRate + 0.05) * 100)}%`, detail: "Use when rank or clearance matters more than contribution" },
      { label: "Prime-style discount", value: `${Math.round((discountRate + 0.03) * 100)}%`, detail: "Best when the event window is narrow and traffic is concentrated" },
    ],
    [discountRate],
  );

  const dealAuditRows = useMemo(
    () => [
      {
        label: "Live price",
        value: snapshot?.priceText || "Missing",
        detail: snapshot ? "Pulled from the current PDP" : "Load a live listing before trusting the promo math",
      },
      {
        label: "Goal",
        value: goal,
        detail: goal === "rank" ? "Traffic and visibility first" : goal === "clearance" ? "Inventory relief first" : "Contribution protection first",
      },
      {
        label: "Margin and stock",
        value: `${roundNumber(netMarginRate, 1)}% / ${inventoryDays} days`,
        detail: "These two numbers usually decide whether a deal is a growth move or a cleanup move",
      },
      {
        label: "Mode",
        value: snapshot ? "Live-first" : "Manual",
        detail: snapshot ? "PDP-backed deal planning" : "Manual planning mode until a live listing is loaded",
      },
      {
        label: "Deal brief",
        value: `${promoDecision.replace(/-/g, " ")} / ${formatPressure.replace(/-/g, " ")}`,
        detail: `${launchCadence.replace(/-/g, " ")} launch cadence for the current promo pass`,
      },
    ],
    [formatPressure, goal, inventoryDays, launchCadence, netMarginRate, promoDecision, snapshot],
  );

  const dealAuditLines = useMemo(() => {
    const lines: string[] = [];
    if (snapshot) {
      lines.push("Live listing loaded. The promo read starts from the actual PDP instead of a remembered sell price.");
      lines.push(`System draft: ${roundNumber(dealPlan.netMarginRate, 1)}% margin, ${dealPlan.inventoryDays} inventory days, ${dealPlan.promoWindowDays}-day window, ${Math.round(dealPlan.discountRate * 100)}% base discount.`);
    } else {
      lines.push("Load a live ASIN first so the deal format starts from the real offer, not a stale planning sheet.");
    }
    lines.push("Only open manual planning inputs when you want to pressure-test margin, stock cover, or promo depth.");
    return lines;
  }, [dealPlan.discountRate, dealPlan.inventoryDays, dealPlan.netMarginRate, dealPlan.promoWindowDays, snapshot]);

  const dealActionRows = useMemo(() => {
    const marginAfterDiscount = netMarginRate - discountRate * 100;
    const firstMove =
      !snapshot
        ? {
            label: "First move",
            value: "Load the live listing first",
            detail: "Deal math becomes more trustworthy when the current sell price comes from the live PDP instead of a planning sheet memory.",
          }
        : !featuredOfferLikely
          ? {
              label: "First move",
              value: "Fix Featured Offer readiness",
              detail: "Promo format selection is secondary if the offer is unlikely to surface cleanly in the first place.",
            }
          : !dealQuantityReady || !referencePriceReady
          ? {
              label: "First move",
              value: "Close the eligibility gaps",
              detail: "A good-looking discount plan still fails if quantity or reference-price support is not operationally ready.",
            }
            : promoDecision === "lighten-discount" || (goal === "margin" && marginAfterDiscount < 10)
              ? {
                  label: "First move",
                  value: "Reduce discount depth before choosing format",
                  detail: "The contribution floor is already under pressure, so the main job is margin survival rather than deal styling.",
                }
              : promoDecision === "push-clearance"
                ? {
                    label: "First move",
                    value: "Use the heavier clearance format on purpose",
                    detail: "Inventory pressure is strong enough that promo format should now serve stock liquidation rather than gentle testing.",
                  }
              : goal === "clearance" && inventoryDays < 21
                ? {
                    label: "First move",
                    value: "Use the lighter format first",
                    detail: "Inventory pressure is not severe enough yet to justify the heavier deal path.",
                  }
                : stackRisk
                  ? {
                      label: "First move",
                      value: "Remove promo stacking ambiguity",
                      detail: "Stacking risk can quietly turn a safe discount into a bad economics decision.",
                    }
                  : {
                      label: "First move",
                      value: "Run the format that matches the commercial job",
                      detail: "The inputs are clean enough now that the next question is deal role: rank lift, clearance, or margin defense.",
                    };

    return [
      firstMove,
      !snapshot
        ? {
            label: "Execution owner",
            value: "Promo owner",
            detail: "Deal planning should begin with the operator who can verify the current live offer instead of relying on stale price memory.",
          }
        : !featuredOfferLikely
          ? {
              label: "Execution owner",
              value: "Featured Offer owner",
              detail: "If the offer is unlikely to surface cleanly, the listing and offer owner should fix that before debating formats.",
            }
          : !dealQuantityReady || !referencePriceReady
          ? {
              label: "Execution owner",
              value: "Promotions ops owner",
              detail: "Eligibility gaps need one owner to clear quantity and reference-price readiness before launch.",
            }
            : promoDecision === "lighten-discount" || (goal === "margin" && marginAfterDiscount < 10)
              ? {
                  label: "Execution owner",
                  value: "Margin protection owner",
                  detail: "If discount depth is already cutting into contribution, finance or pricing should own the correction first.",
                }
              : promoDecision === "push-clearance"
                ? {
                    label: "Execution owner",
                    value: "Inventory liquidation owner",
                    detail: "Once the commercial job is clearly clearance, one owner should run the heavier format with stock relief as the primary metric.",
                  }
              : goal === "clearance" && inventoryDays < 21
                ? {
                    label: "Execution owner",
                    value: "Inventory owner",
                    detail: "Light clearance pressure means inventory ownership should choose whether a heavier deal is actually justified.",
                  }
                : stackRisk
                  ? {
                      label: "Execution owner",
                      value: "Promo governance owner",
                      detail: "Stacking ambiguity should be resolved by the person responsible for promotion rules and overlap control.",
                    }
                  : {
                      label: "Execution owner",
                      value: "Deal launch owner",
                      detail: "Once the inputs are clean, one operator should launch the format that matches the commercial job and watch the result.",
                    },
      {
        label: "Then do",
        value:
          launchCadence === "hold"
            ? "Do not launch until the gate problem is fixed"
            : launchCadence === "this-cycle"
              ? "Launch the chosen format this cycle"
              : "Run one contained promo test",
        detail:
          launchCadence === "hold"
            ? "A clean hold is more valuable than forcing a promo through broken gates."
            : launchCadence === "this-cycle"
              ? "When the commercial job is clear, do not blur it with an exploratory discount pattern."
              : "A contained test is better than an oversized promo when the economics are only moderately supportive.",
      },
      {
        label: "Watch",
        value: promoDecision.replace(/-/g, " "),
        detail: "Operators often debate format while the real blocker is offer readiness, quantity support, or reference-price cleanliness.",
      },
    ];
  }, [dealQuantityReady, discountRate, featuredOfferLikely, goal, inventoryDays, launchCadence, netMarginRate, promoDecision, referencePriceReady, snapshot, stackRisk]);

  const dealInputRows = useMemo(
    () => [
      ...dealAuditRows,
      {
        label: "Execution call",
        value: dealActionRows[0]?.value ?? "Pending",
        detail: `${dealActionRows[1]?.value ?? "Owner pending"} | ${dealActionRows[2]?.value ?? "Cadence pending"} | ${dealActionRows[3]?.value ?? "Risk pending"}`,
      },
    ],
    [dealActionRows, dealAuditRows],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_0.7fr_0.6fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <Field label="Goal">
          <SelectInput value={goal} onChange={(e) => setGoal(e.target.value)}>
            <option value="rank">Rank lift</option>
            <option value="margin">Margin defense</option>
            <option value="clearance">Clearance</option>
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <div className="grid gap-2.5 md:grid-cols-[0.95fr_0.95fr_0.95fr]">
        <Field label="Promo decision">
          <SelectInput value={promoDecision} onChange={(e) => setPromoDecision(e.target.value)}>
            <option value="fix-gates-first">Fix gates first</option>
            <option value="lighten-discount">Lighten discount</option>
            <option value="push-clearance">Push clearance</option>
            <option value="push-visibility">Push visibility</option>
            <option value="run-contained-test">Run contained test</option>
          </SelectInput>
        </Field>
        <Field label="Format pressure">
          <SelectInput value={formatPressure} onChange={(e) => setFormatPressure(e.target.value)}>
            <option value="stack-safety">Stack safety</option>
            <option value="inventory-risk">Inventory risk</option>
            <option value="margin-risk">Margin risk</option>
            <option value="format-fit">Format fit</option>
          </SelectInput>
        </Field>
        <Field label="Launch cadence">
          <SelectInput value={launchCadence} onChange={(e) => setLaunchCadence(e.target.value)}>
            <option value="hold">Hold</option>
            <option value="controlled-test">Controlled test</option>
            <option value="this-cycle">This cycle</option>
          </SelectInput>
        </Field>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote lines={dealAuditLines} />
      <DistributionPanel title="Live deal inputs" rows={dealInputRows} />
      <DistributionPanel title="This deal call" rows={dealActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Manual planning inputs</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when you want to pressure-test margin, stock cover, promo depth, or deal eligibility assumptions.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide planning inputs" : "Adjust deal assumptions"}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-4">
              <Field label="Net margin %">
                <NumberInput value={netMarginRate} min="0" step="0.1" onChange={(e) => setNetMarginRate(Number(e.target.value))} />
              </Field>
              <Field label="Inventory cover days">
                <NumberInput value={inventoryDays} min="1" step="1" onChange={(e) => setInventoryDays(Number(e.target.value))} />
              </Field>
              <Field label="Promo window days">
                <NumberInput value={promoWindowDays} min="1" step="1" onChange={(e) => setPromoWindowDays(Number(e.target.value))} />
              </Field>
              <Field label="Base discount rate">
                <NumberInput value={discountRate} min="0" max="1" step="0.01" onChange={(e) => setDiscountRate(Number(e.target.value))} />
              </Field>
            </div>
            <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-4">
              <Checkbox label="Featured Offer likely" checked={featuredOfferLikely} onChange={setFeaturedOfferLikely} />
              <Checkbox label="Deal quantity ready" checked={dealQuantityReady} onChange={setDealQuantityReady} />
              <Checkbox label="Reference price history clean" checked={referencePriceReady} onChange={setReferencePriceReady} />
              <Checkbox label="Other promos may stack" checked={stackRisk} onChange={setStackRisk} />
            </div>
          </div>
        ) : null}
      </div>
      <DistributionPanel title="Promo format comparison" rows={formatRows} />
    </RuntimeShell>
  );
}

function CouponStrategyRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("B0GYRT3FNL");
  const [objective, setObjective] = useState("conversion");
  const [couponDecision, setCouponDecision] = useState("run-single-job");
  const [audiencePriority, setAudiencePriority] = useState("all-customers");
  const [launchCadence, setLaunchCadence] = useState("monitor");
  const [netMarginRate, setNetMarginRate] = useState(18);
  const [couponRate, setCouponRate] = useState(0.08);
  const [inventoryDays, setInventoryDays] = useState(35);
  const [stackRisk, setStackRisk] = useState(false);
  const [professionalSeller, setProfessionalSeller] = useState(true);
  const [feedbackRating, setFeedbackRating] = useState(4.3);
  const [offerBuyable, setOfferBuyable] = useState(true);
  const [featuredOfferLikely, setFeaturedOfferLikely] = useState(true);
  const [audienceType, setAudienceType] = useState("all");
  const [brandRepresentative, setBrandRepresentative] = useState(true);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [showOverrides, setShowOverrides] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const couponPlan = useMemo(() => inferCouponPlan(snapshot, objective), [objective, snapshot]);

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }
      setSnapshot(payload);
      if (!showOverrides) {
        const nextPlan = inferCouponPlan(payload, objective);
        setNetMarginRate(nextPlan.netMarginRate);
        setCouponRate(nextPlan.couponRate);
        setInventoryDays(nextPlan.inventoryDays);
        setStackRisk(nextPlan.stackRisk);
        setProfessionalSeller(nextPlan.professionalSeller);
        setFeedbackRating(nextPlan.feedbackRating);
        setOfferBuyable(nextPlan.offerBuyable);
        setFeaturedOfferLikely(nextPlan.featuredOfferLikely);
        setAudienceType(nextPlan.audienceType);
        setBrandRepresentative(nextPlan.brandRepresentative);
        const nextExecutionPlan = inferCouponExecutionPlan({
          snapshot: payload,
          objective,
          netMarginRate: nextPlan.netMarginRate,
          couponRate: nextPlan.couponRate,
          inventoryDays: nextPlan.inventoryDays,
          stackRisk: nextPlan.stackRisk,
          feedbackRating: nextPlan.feedbackRating,
          offerBuyable: nextPlan.offerBuyable,
          featuredOfferLikely: nextPlan.featuredOfferLikely,
          audienceType: nextPlan.audienceType,
          brandRepresentative: nextPlan.brandRepresentative,
        });
        setCouponDecision(nextExecutionPlan.couponDecision);
        setAudiencePriority(nextExecutionPlan.audiencePriority);
        setLaunchCadence(nextExecutionPlan.launchCadence);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  const result = useMemo(() => {
    const price = parseCurrencyAmount(snapshot?.priceText);
    const couponAfterMargin = netMarginRate - couponRate * 100;
    return evaluateCouponStrategy({
      price,
      netMarginRate,
      discountRate: couponRate,
      inventoryDays,
      objective,
      stackRisk,
      couponAfterMargin,
      professionalSeller,
      feedbackRating,
      offerBuyable,
      featuredOfferLikely,
      audienceType,
      brandRepresentative,
    });
  }, [audienceType, brandRepresentative, couponRate, featuredOfferLikely, feedbackRating, inventoryDays, netMarginRate, objective, offerBuyable, professionalSeller, snapshot, stackRisk]);

  const couponAuditRows = useMemo(
    () => [
      {
        label: "Live price",
        value: snapshot?.priceText || "Missing",
        detail: snapshot ? "Pulled from the current PDP" : "Load a live listing before trusting coupon depth",
      },
      {
        label: "Objective",
        value: objective,
        detail: objective === "conversion" ? "Conversion first" : objective === "defense" ? "Competitive defense first" : "Clearance first",
      },
      {
        label: "Margin after coupon",
        value: `${roundNumber(netMarginRate - couponRate * 100, 1)}%`,
        detail: `${roundNumber(netMarginRate, 1)}% base margin with ${Math.round(couponRate * 100)}% coupon depth`,
      },
      {
        label: "Mode",
        value: snapshot ? "Live-first" : "Manual",
        detail: snapshot ? "PDP-backed coupon planning" : "Manual planning mode until a live listing is loaded",
      },
      {
        label: "Coupon brief",
        value: `${couponDecision.replace(/-/g, " ")} / ${audiencePriority.replace(/-/g, " ")}`,
        detail: `${launchCadence.replace(/-/g, " ")} launch cadence for the current coupon pass`,
      },
    ],
    [audiencePriority, couponRate, couponDecision, launchCadence, netMarginRate, objective, snapshot],
  );

  const couponAuditLines = useMemo(() => {
    const lines: string[] = [];
    if (snapshot) {
      lines.push("Live listing loaded. Coupon planning now starts from the current offer instead of a remembered sell price.");
      lines.push(`System draft: ${roundNumber(couponPlan.netMarginRate, 1)}% margin, ${Math.round(couponPlan.couponRate * 100)}% coupon, ${couponPlan.inventoryDays} inventory days, ${couponPlan.audienceType} audience.`);
    } else {
      lines.push("Load a live ASIN first so the coupon read starts from the real offer state.");
    }
    lines.push("Only open manual planning inputs when you want to test margin, stack risk, audience choice, or offer readiness.");
    return lines;
  }, [couponPlan.audienceType, couponPlan.couponRate, couponPlan.inventoryDays, couponPlan.netMarginRate, snapshot]);

  const couponActionRows = useMemo(() => {
    const marginAfterCoupon = netMarginRate - couponRate * 100;

    const firstMove =
      !snapshot
        ? {
            label: "First move",
            value: "Load the live listing first",
            detail: "Coupon planning gets more trustworthy when the current sell price comes from the live offer instead of a remembered number.",
          }
        : !offerBuyable || !featuredOfferLikely
          ? {
              label: "First move",
              value: "Fix offer readiness before discount depth",
              detail: "A coupon is not the main lever if the offer itself is not cleanly buyable or unlikely to hold the Featured Offer.",
            }
          : couponDecision === "fix-stacking" || stackRisk
            ? {
                label: "First move",
                value: "Remove stacking ambiguity",
                detail: "The fastest way to destroy coupon economics is letting it collide with ad spend or other promos unintentionally.",
              }
            : couponDecision === "reduce-depth" || marginAfterCoupon < 10
              ? {
                  label: "First move",
                  value: "Reduce coupon depth",
                  detail: "The discount is already eating too much contribution, so this is a margin problem before it is a promotion problem.",
                }
              : couponDecision === "push-clearance"
                ? {
                    label: "First move",
                    value: "Use the coupon as a real clearance lever",
                    detail: "Inventory pressure is strong enough that this coupon should serve stock relief instead of a soft conversion test.",
                  }
              : objective === "clearance" && inventoryDays < 21
                ? {
                    label: "First move",
                    value: "Do not over-discount a non-urgent inventory position",
                    detail: "Clearance logic is too aggressive when stock pressure is still moderate.",
                  }
                : couponDecision === "repair-trust-first" || (objective === "defense" && feedbackRating < 4)
                  ? {
                      label: "First move",
                      value: "Repair offer trust before couponing harder",
                      detail: "A weak feedback signal means extra discount may buy clicks without solving the conversion hesitation.",
                    }
                  : {
                      label: "First move",
                      value: "Run the coupon for one clear job",
                      detail: "The plan is strong enough that the next move is a focused coupon role: conversion, defense, or clearance, not a vague all-purpose discount.",
                    };

    return [
      firstMove,
      !snapshot
        ? {
            label: "Execution owner",
            value: "Coupon owner",
            detail: "Coupon planning should start with the operator who can verify the real live offer, not with a remembered price point.",
          }
        : !offerBuyable || !featuredOfferLikely
          ? {
              label: "Execution owner",
              value: "Offer readiness owner",
              detail: "If the offer itself is weak, the listing or offer owner should fix that before discounts take the blame.",
            }
          : couponDecision === "fix-stacking" || stackRisk
            ? {
                label: "Execution owner",
                value: "Promo governance owner",
                detail: "Stacking ambiguity belongs to the person managing promo overlap and economics hygiene.",
              }
            : couponDecision === "reduce-depth" || marginAfterCoupon < 10
              ? {
                  label: "Execution owner",
                  value: "Margin protection owner",
                  detail: "If the coupon is already hurting contribution, pricing or finance should own the correction first.",
                }
              : couponDecision === "push-clearance"
                ? {
                    label: "Execution owner",
                    value: "Inventory liquidation owner",
                    detail: "When the coupon is clearly doing clearance work, one owner should run it against stock relief instead of mixed KPIs.",
                  }
              : objective === "clearance" && inventoryDays < 21
                ? {
                    label: "Execution owner",
                    value: "Inventory owner",
                    detail: "Non-urgent inventory should not get clearance treatment without the inventory owner explicitly choosing it.",
                  }
                : couponDecision === "repair-trust-first" || (objective === "defense" && feedbackRating < 4)
                  ? {
                      label: "Execution owner",
                      value: "Trust / CX owner",
                      detail: "Weak offer trust should be fixed by the team improving proof and experience, not by coupon depth alone.",
                    }
                  : {
                      label: "Execution owner",
                      value: "Coupon launch owner",
                      detail: "Once the plan is coherent, one operator should run the coupon for one clear commercial job and monitor it.",
                    },
      {
        label: "Do not cross",
        value:
          !snapshot
            ? "Do not plan coupon depth from a remembered offer"
            : !offerBuyable || !featuredOfferLikely
              ? "Do not use discount depth to hide a weak offer state"
              : couponDecision === "fix-stacking" || stackRisk
                ? "Do not let coupon economics collide with promo stacking"
                : "Do not run a coupon without one clear commercial job",
        detail:
          !snapshot
            ? "Keep coupon planning closed until it starts from the live offer instead of memory."
            : !offerBuyable || !featuredOfferLikely
              ? "A cleaner discount does not fix a broken buy path."
              : couponDecision === "fix-stacking" || stackRisk
                ? "Stacking ambiguity is one of the fastest ways to destroy coupon contribution."
                : "A coupon that tries to do conversion, defense, and clearance at the same time usually does none of them well.",
      },
      {
        label: "Then do",
        value:
          launchCadence === "hold"
            ? "Do not launch until the offer is clean"
            : launchCadence === "this-cycle"
              ? "Launch the coupon for one job this cycle"
              : launchCadence === "controlled-test"
                ? "Run one controlled coupon test"
                : "Keep the coupon idle and monitor",
        detail:
          launchCadence === "hold"
            ? "A coupon with broken offer gates is noise, not leverage."
            : launchCadence === "this-cycle"
              ? "When the commercial job is explicit, avoid diluting it with extra discount experiments."
              : launchCadence === "controlled-test"
                ? "A single clean test is more useful than a broad coupon push when economics are only borderline."
                : "If urgency is low, preserving pricing discipline is better than inventing coupon activity.",
      },
      {
        label: "Watch",
        value: audiencePriority.replace(/-/g, " "),
        detail: "Coupon performance can look good short term while silently giving back too much margin or masking a weak offer state.",
      },
    ];
  }, [audiencePriority, couponDecision, couponRate, featuredOfferLikely, feedbackRating, inventoryDays, launchCadence, netMarginRate, objective, offerBuyable, snapshot, stackRisk]);

  const couponInputRows = useMemo(
    () => [
      ...couponAuditRows,
      {
        label: "Execution call",
        value: couponActionRows[0]?.value ?? "Pending",
        detail: `${couponActionRows[1]?.value ?? "Owner pending"} | ${couponActionRows[2]?.value ?? "Cadence pending"} | ${couponActionRows[3]?.value ?? "Risk pending"}`,
      },
    ],
    [couponActionRows, couponAuditRows],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_0.7fr_0.8fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <Field label="Objective">
          <SelectInput value={objective} onChange={(e) => setObjective(e.target.value)}>
            <option value="conversion">Conversion lift</option>
            <option value="defense">Competitive defense</option>
            <option value="clearance">Clearance</option>
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <div className="grid gap-2.5 md:grid-cols-[0.95fr_0.95fr_0.95fr]">
        <Field label="Coupon decision">
          <SelectInput value={couponDecision} onChange={(e) => setCouponDecision(e.target.value)}>
            <option value="fix-offer-first">Fix offer first</option>
            <option value="fix-stacking">Fix stacking</option>
            <option value="reduce-depth">Reduce depth</option>
            <option value="push-clearance">Push clearance</option>
            <option value="repair-trust-first">Repair trust first</option>
            <option value="run-single-job">Run single job</option>
          </SelectInput>
        </Field>
        <Field label="Audience priority">
          <SelectInput value={audiencePriority} onChange={(e) => setAudiencePriority(e.target.value)}>
            <option value="all-customers">All customers</option>
            <option value="prime-defense">Prime defense</option>
            <option value="broad-clearance">Broad clearance</option>
            <option value="brand-audience">Brand audience</option>
            <option value="permission-gap">Permission gap</option>
          </SelectInput>
        </Field>
        <Field label="Launch cadence">
          <SelectInput value={launchCadence} onChange={(e) => setLaunchCadence(e.target.value)}>
            <option value="hold">Hold</option>
            <option value="controlled-test">Controlled test</option>
            <option value="this-cycle">This cycle</option>
            <option value="monitor">Monitor</option>
          </SelectInput>
        </Field>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote lines={couponAuditLines} />
      <DistributionPanel title="Live coupon inputs" rows={couponInputRows} />
      <DistributionPanel title="This coupon call" rows={couponActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Manual planning inputs</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when you want to pressure-test coupon depth, audience, buyability, or stack risk assumptions.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide planning inputs" : "Adjust coupon assumptions"}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-6">
              <Field label="Net margin %">
                <NumberInput value={netMarginRate} min="0" step="0.1" onChange={(e) => setNetMarginRate(Number(e.target.value))} />
              </Field>
              <Field label="Coupon rate">
                <NumberInput value={couponRate} min="0" max="1" step="0.01" onChange={(e) => setCouponRate(Number(e.target.value))} />
              </Field>
              <Field label="Inventory cover days">
                <NumberInput value={inventoryDays} min="1" step="1" onChange={(e) => setInventoryDays(Number(e.target.value))} />
              </Field>
              <Field label="Seller feedback">
                <NumberInput value={feedbackRating} min="0" max="5" step="0.1" onChange={(e) => setFeedbackRating(Number(e.target.value))} />
              </Field>
              <Field label="Audience">
                <SelectInput value={audienceType} onChange={(e) => setAudienceType(e.target.value)}>
                  <option value="all">All customers</option>
                  <option value="prime">Prime only</option>
                  <option value="brand">Brand audience</option>
                </SelectInput>
              </Field>
              <Checkbox label="Coupon stacks with ads or other promos" checked={stackRisk} onChange={setStackRisk} />
            </div>
            <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-5">
              <Checkbox label="Professional seller" checked={professionalSeller} onChange={setProfessionalSeller} />
              <Checkbox label="Offer buyable now" checked={offerBuyable} onChange={setOfferBuyable} />
              <Checkbox label="Featured Offer likely" checked={featuredOfferLikely} onChange={setFeaturedOfferLikely} />
              <Checkbox label="Brand Representative ready" checked={brandRepresentative} onChange={setBrandRepresentative} />
            </div>
          </div>
        ) : null}
      </div>
    </RuntimeShell>
  );
}

function DaypartingStrategyRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [timezone, setTimezone] = useState("America/Los_Angeles");
  const [hourlyText, setHourlyText] = useState(
    "Hour\tSpend\tSales\tOrders\tClicks\tImpressions\n00\t12\t20\t1\t22\t3200\n08\t18\t140\t4\t28\t4100\n12\t25\t260\t6\t34\t5800\n18\t30\t90\t2\t40\t6200\n21\t10\t120\t3\t16\t2400",
  );
  const timezonePrefillRef = useRef(false);
  const [showOverrides, setShowOverrides] = useState(false);

  const rows = useMemo(() => parseHourlyPerformanceRows(hourlyText), [hourlyText]);
  const inferredTimezone = useMemo(() => inferTimezoneFromHourlyText(hourlyText), [hourlyText]);
  const windowRows = useMemo(() => buildDaypartingWindowRows(rows), [rows]);
  const daypartingPlan = useMemo(() => inferDaypartingPlan(rows), [rows]);

  useEffect(() => {
    if (timezonePrefillRef.current || !inferredTimezone) {
      return;
    }
    if (timezone === "America/Los_Angeles") {
      setTimezone(inferredTimezone);
    }
    timezonePrefillRef.current = true;
  }, [inferredTimezone, timezone]);

  const result = useMemo(() => {
    return evaluateDaypartingStrategy({
      rowCount: rows.length,
      highWasteHours: daypartingPlan.wasteHours,
      winnerHours: daypartingPlan.winnerHours,
      spend: daypartingPlan.totalSpend,
      sales: daypartingPlan.totalSales,
      acos: daypartingPlan.totalSales > 0 ? daypartingPlan.totalSpend / daypartingPlan.totalSales : 0,
      cvr: daypartingPlan.totalClicks > 0 ? daypartingPlan.totalOrders / daypartingPlan.totalClicks : 0,
      bestHourShare: daypartingPlan.bestHourShare,
      timezone,
    });
  }, [daypartingPlan, rows.length, timezone]);

  const hourRows = useMemo(() => {
    return rows.map((row) => {
      const acos = row.sales > 0 ? row.spend / row.sales : 999;
      const decision = row.sales <= 0 || acos > 0.4 ? "Cut" : acos <= 0.25 ? "Scale" : "Protect";
      return {
        label: row.hour,
        value: decision,
        detail: `${row.sales.toFixed(0)} sales | ${row.orders} orders | ${Math.round(acos * 100)}% ACoS`,
      };
    });
  }, [rows]);

  const daypartingAuditRows = useMemo(() => {
    return [
      {
        label: "Rows parsed",
        value: `${rows.length} hours`,
        detail: `${timezone} timezone schedule read from the current export`,
      },
      {
        label: "Spend / sales",
        value: `${formatUsd(roundNumber(daypartingPlan.totalSpend, 2))} / ${formatUsd(roundNumber(daypartingPlan.totalSales, 2))}`,
        detail: `${daypartingPlan.totalOrders} orders | ${daypartingPlan.totalClicks} clicks behind the current hourly view`,
      },
      {
        label: "Window split",
        value: `${daypartingPlan.winnerHours} scale / ${daypartingPlan.wasteHours} cut`,
        detail: "Winning hours sit under the ACoS guardrail; waste hours are sales-light or too expensive.",
      },
      {
        label: "Schedule blocks",
        value: `${windowRows.length}`,
        detail: windowRows.length
          ? `${windowRows[0].label} is the first contiguous operating block`
          : "Need more hourly coverage to compress into practical blocks",
      },
    ];
  }, [daypartingPlan, rows.length, timezone, windowRows]);

  const daypartingExecutionPlan = useMemo(
    () =>
      inferDaypartingExecutionPlan({
        rowCount: rows.length,
        bestHour: daypartingPlan.bestHour,
        worstHour: daypartingPlan.worstHour,
        winnerHours: daypartingPlan.winnerHours,
        wasteHours: daypartingPlan.wasteHours,
      }),
    [daypartingPlan.bestHour, daypartingPlan.wasteHours, daypartingPlan.winnerHours, daypartingPlan.worstHour, rows.length],
  );

  const daypartingActionRows = useMemo(() => {
    return [
      {
        label: "First move",
        value: daypartingExecutionPlan.decision,
        detail: daypartingExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: daypartingExecutionPlan.owner,
        detail: `${daypartingExecutionPlan.proofPriority} is the proof to lock before changing the schedule.`,
      },
      {
        label: "Then do",
        value: daypartingExecutionPlan.cadence,
        detail: "Hour-by-hour edits get noisy quickly; a small number of clean time blocks is easier to validate and maintain.",
      },
      {
        label: "Watch",
        value: "Low-volume false positives",
        detail: daypartingExecutionPlan.watchout,
      },
    ];
  }, [daypartingExecutionPlan]);

  const daypartingInputRows = useMemo(
    () => [
      ...daypartingAuditRows,
      {
        label: "Execution call",
        value: daypartingExecutionPlan.decision,
        detail: `${daypartingExecutionPlan.owner} | ${daypartingExecutionPlan.cadence} | ${daypartingExecutionPlan.proofPriority}`,
      },
    ],
    [daypartingAuditRows, daypartingExecutionPlan],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1.5fr_0.8fr]">
        <Field label="Hourly performance export">
          <TextAreaInput value={hourlyText} onChange={(e) => setHourlyText(e.target.value)} className="min-h-[10rem]" spellCheck={false} />
        </Field>
        <Field label="Timezone">
          <TextInput value={timezone} onChange={(e) => setTimezone(e.target.value)} />
        </Field>
      </div>
      <AuditNote
        lines={[
          `Parsed ${rows.length} hourly rows.`,
          "Accepted fields include hour, spend, sales, orders, clicks, and impressions.",
          inferredTimezone
            ? `System inference: ${inferredTimezone} looks like the timezone encoded in the export.`
            : "If the export does not name a timezone, confirm it once before scheduling real budget moves.",
          rows.length
            ? `System call: ${daypartingPlan.wasteHours > daypartingPlan.winnerHours ? "clean the weak hours first" : "protect and scale the winning hours first"}.`
            : "Paste one hourly export first so the page can draft a cut / protect / scale schedule.",
        ]}
      />
      <DistributionPanel title="Live dayparting inputs" rows={daypartingInputRows} />
      <DistributionPanel title="This dayparting call" rows={daypartingActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">{manualOverridesHeading(locale)}</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Keep the export paste as the main input. Only open this if the timezone inference is wrong.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((current) => !current)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide overrides" : "Adjust timezone"}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-2.5 xl:grid-cols-[1.5fr_0.8fr]">
            <Field label="Hourly performance export">
              <TextAreaInput value={hourlyText} onChange={(e) => setHourlyText(e.target.value)} className="min-h-[10rem]" spellCheck={false} />
            </Field>
            <Field label="Timezone">
              <TextInput value={timezone} onChange={(e) => setTimezone(e.target.value)} />
            </Field>
          </div>
        ) : null}
      </div>
      <div className="grid gap-3 xl:grid-cols-[1fr_1fr]">
        <DistributionPanel title="Hourly schedule map" rows={hourRows} />
        <DistributionPanel title="Compressed schedule blocks" rows={windowRows} />
      </div>
    </RuntimeShell>
  );
}

function DisplayAdsRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [budget, setBudget] = useState(1200);
  const [heroAsinCount, setHeroAsinCount] = useState(2);
  const [competitorCount, setCompetitorCount] = useState(6);
  const [budgetDecision, setBudgetDecision] = useState("run-split-roles");
  const [lanePriority, setLanePriority] = useState("warm-audience-recovery");
  const [executionCadence, setExecutionCadence] = useState("monitor");
  const [retargetingShare, setRetargetingShare] = useState(0.55);
  const [prospectingShare, setProspectingShare] = useState(0.3);
  const [creativeReady, setCreativeReady] = useState(true);
  const [audiences, setAudiences] = useState<string[]>(["views-retargeting", "purchases-retargeting", "competitor-product-targeting"]);
  const [showOverrides, setShowOverrides] = useState(false);
  const displayPlan = useMemo(
    () => inferDisplayAudiencePlan({ budget, heroAsinCount, competitorCount }),
    [budget, competitorCount, heroAsinCount],
  );

  useEffect(() => {
    if (showOverrides) {
      return;
    }
    setAudiences(displayPlan.audiences);
    setRetargetingShare(displayPlan.retargetingShare);
    setProspectingShare(displayPlan.prospectingShare);
    setCreativeReady(displayPlan.creativeReady);
    const nextExecutionPlan = inferDisplayExecutionPlan({
      budget,
      heroAsinCount,
      competitorCount,
      retargetingShare: displayPlan.retargetingShare,
      prospectingShare: displayPlan.prospectingShare,
      creativeReady: displayPlan.creativeReady,
      audiences: displayPlan.audiences,
    });
    setBudgetDecision(nextExecutionPlan.budgetDecision);
    setLanePriority(nextExecutionPlan.lanePriority);
    setExecutionCadence(nextExecutionPlan.executionCadence);
  }, [displayPlan, showOverrides]);

  const displayCoverageRows = useMemo(
    () =>
      buildDisplayCoverageRows({
        budget,
        heroAsinCount,
        competitorCount,
        retargetingShare,
        prospectingShare,
        creativeReady,
        audiences,
      }),
    [audiences, budget, competitorCount, creativeReady, heroAsinCount, prospectingShare, retargetingShare],
  );

  const result = useMemo(
    () =>
      evaluateDisplayAds({
        audienceCount: audiences.length,
        competitorCount,
        retargetingShare,
        prospectingShare,
        budget,
        heroAsinCount,
        creativeReady,
      }),
    [audiences.length, budget, competitorCount, creativeReady, heroAsinCount, prospectingShare, retargetingShare],
  );

  const audienceRows = useMemo(
    () =>
      audiences.map((item) => ({
        label: item,
        value: item.includes("retargeting") ? "Retargeting" : "Prospecting",
        detail: item.includes("competitor") ? "Use for competitor or product-targeting reach" : "Use for warmer audience recapture",
      })),
    [audiences],
  );

  const displayAuditRows = useMemo(
    () => [
      {
        label: "Budget",
        value: formatUsd(roundNumber(budget)),
        detail: `${heroAsinCount} hero ASINs and ${competitorCount} competitor targets in scope`,
      },
      {
        label: "Audience mix",
        value: `${audiences.length}`,
        detail: `${audiences.filter((item) => item.includes("retargeting")).length} retargeting lanes | ${audiences.filter((item) => !item.includes("retargeting")).length} prospecting lanes`,
      },
      {
        label: "Budget split",
        value: `${roundNumber(retargetingShare * 100, 0)}% / ${roundNumber(prospectingShare * 100, 0)}%`,
        detail: "Retargeting vs prospecting share in the current structure",
      },
      {
        label: "Creative readiness",
        value: creativeReady ? "Ready" : "Thin",
        detail: creativeReady ? "Display can support education and remarketing now" : "Creative support is too thin for aggressive prospecting",
      },
      {
        label: "System plan",
        value: `${displayPlan.audiences.length} lanes`,
        detail: `Default mix: ${displayPlan.audiences.join(", ")}`,
      },
      {
        label: "Execution brief",
        value: `${budgetDecision.replace(/-/g, " ")} / ${lanePriority.replace(/-/g, " ")}`,
        detail: `${executionCadence.replace(/-/g, " ")} cadence for the current display pass`,
      },
    ],
    [audiences, budget, budgetDecision, competitorCount, creativeReady, displayPlan.audiences, executionCadence, heroAsinCount, lanePriority, prospectingShare, retargetingShare],
  );

  const displayActionRows = useMemo(() => {
    const retargetingLanes = audiences.filter((item) => item.includes("retargeting")).length;
    const prospectingLanes = audiences.filter((item) => !item.includes("retargeting")).length;
    const firstMove =
      budgetDecision === "narrow-to-core-lanes" || budget < 500
        ? {
            label: "First move",
            value: "Narrow the audience plan",
            detail: "This budget is too thin for a broad display spread, so keep only the highest-value lane or two.",
          }
        : budgetDecision === "rebalance-warm-spend" || retargetingShare > 0.75
          ? {
              label: "First move",
              value: "Reduce retargeting concentration",
              detail: "Too much spend is trapped in retargeting, which limits new audience learning.",
            }
          : budgetDecision === "pause-broad-prospecting" || (prospectingShare > 0.55 && !creativeReady)
            ? {
                label: "First move",
                value: "Fix creative before scaling prospecting",
                detail: "Aggressive prospecting without enough asset support usually wastes budget.",
              }
            : budgetDecision === "set-hero-focus" || heroAsinCount < 1
              ? {
                  label: "First move",
                  value: "Set the hero ASIN focus",
                  detail: "Display structure is weak until each lane knows which product it is meant to support.",
                }
              : {
                  label: "First move",
                value: "Split retargeting and prospecting roles",
                detail: "Use clear audience jobs instead of letting one mixed structure do everything badly.",
              };

    return [
      firstMove,
      {
        label: "Execution owner",
        value:
          lanePriority === "creative-gap" || !creativeReady
            ? "Creative / design"
            : budgetDecision === "rebalance-warm-spend" || budgetDecision === "pause-broad-prospecting" || retargetingShare > 0.75 || prospectingShare > 0.55
              ? "Media buyer"
              : budgetDecision === "set-hero-focus" || heroAsinCount < 1
                ? "Catalog / offer strategy"
                : "Channel owner",
        detail: "The bottleneck should map to whoever controls asset readiness, budget mix, or ASIN focus.",
      },
      {
        label: "Then do",
        value:
          executionCadence === "this-cycle"
            ? "Fix the weakest lane mix this cycle"
            : executionCadence === "controlled-test"
              ? "Test one cleaner lane split"
              : "Keep the current mix and monitor pacing",
        detail:
          executionCadence === "this-cycle"
            ? "When the structure is obviously wrong, fix the lane mix before worrying about small bid nuance."
            : executionCadence === "controlled-test"
              ? "A single clearer lane split teaches more than tweaking every audience at once."
              : "If the structure is coherent, the next job is pacing and lane-role discipline, not endless restructuring.",
      },
      {
        label: "Watch",
        value: lanePriority.replace(/-/g, " "),
        detail: !creativeReady
          ? "Do not broaden the audience plan until creative support stops being the bottleneck."
          : retargetingLanes > prospectingLanes * 2
            ? "Too many warm-audience lanes can make the account look efficient while starving new demand creation."
            : "Once the structure is clean, watch whether budget is clustering too hard in one lane.",
      },
    ];
  }, [audiences, budget, budgetDecision, creativeReady, executionCadence, heroAsinCount, lanePriority, prospectingShare, retargetingShare]);

  const displayInputRows = useMemo(
    () => [
      ...displayAuditRows,
      {
        label: "Execution call",
        value: displayActionRows[0]?.value ?? "Pending",
        detail: `${displayActionRows[1]?.value ?? "Owner pending"} | ${displayActionRows[2]?.value ?? "Cadence pending"} | ${displayActionRows[3]?.value ?? "Risk pending"}`,
      },
    ],
    [displayActionRows, displayAuditRows],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-3">
        <Field label="Monthly budget">
          <NumberInput value={budget} min="0" step="50" onChange={(e) => setBudget(Number(e.target.value))} />
        </Field>
        <Field label="Hero ASINs">
          <NumberInput value={heroAsinCount} min="0" step="1" onChange={(e) => setHeroAsinCount(Number(e.target.value))} />
        </Field>
        <Field label="Competitor targets">
          <NumberInput value={competitorCount} min="0" step="1" onChange={(e) => setCompetitorCount(Number(e.target.value))} />
        </Field>
      </div>
      <div className="grid gap-2.5 md:grid-cols-[0.95fr_0.95fr_0.95fr]">
        <Field label="Budget decision">
          <SelectInput value={budgetDecision} onChange={(e) => setBudgetDecision(e.target.value)}>
            <option value="narrow-to-core-lanes">Narrow to core lanes</option>
            <option value="pause-broad-prospecting">Pause broad prospecting</option>
            <option value="rebalance-warm-spend">Rebalance warm spend</option>
            <option value="set-hero-focus">Set hero focus</option>
            <option value="run-split-roles">Run split roles</option>
          </SelectInput>
        </Field>
        <Field label="Lane priority">
          <SelectInput value={lanePriority} onChange={(e) => setLanePriority(e.target.value)}>
            <option value="catalog-focus">Catalog focus</option>
            <option value="creative-gap">Creative gap</option>
            <option value="lane-concentration">Lane concentration</option>
            <option value="cold-audience-learning">Cold-audience learning</option>
            <option value="warm-audience-recovery">Warm-audience recovery</option>
          </SelectInput>
        </Field>
        <Field label="Execution cadence">
          <SelectInput value={executionCadence} onChange={(e) => setExecutionCadence(e.target.value)}>
            <option value="this-cycle">This cycle</option>
            <option value="controlled-test">Controlled test</option>
            <option value="monitor">Monitor</option>
          </SelectInput>
        </Field>
      </div>
      <AuditNote
        lines={[
          "The page now drafts a default audience plan from budget, hero-ASIN count, and competitor breadth before asking for manual channel planning.",
          displayCoverageRows[3]?.detail ?? "Check whether the audience plan is over-allocated or missing explicit budget roles.",
        ]}
      />
      <DistributionPanel title="Live display inputs" rows={displayInputRows} />
      <DistributionPanel title="This display call" rows={displayActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Advanced planning overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Only open this when the default audience mix does not fit the actual launch brief.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide planning overrides" : "Adjust audience assumptions"}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-2">
              <Field label="Retargeting share">
                <NumberInput value={retargetingShare} min="0" max="1" step="0.05" onChange={(e) => setRetargetingShare(Number(e.target.value))} />
              </Field>
              <Field label="Prospecting share">
                <NumberInput value={prospectingShare} min="0" max="1" step="0.05" onChange={(e) => setProspectingShare(Number(e.target.value))} />
              </Field>
            </div>
            <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-4">
              {[
                { value: "views-retargeting", label: "Views retargeting" },
                { value: "purchases-retargeting", label: "Purchases retargeting" },
                { value: "competitor-product-targeting", label: "Competitor product targeting" },
                { value: "category-prospecting", label: "Category prospecting" },
              ].map((item) => (
                <Checkbox
                  key={item.value}
                  label={item.label}
                  checked={audiences.includes(item.value)}
                  onChange={(checked) =>
                    setAudiences((current) =>
                      checked ? Array.from(new Set([...current, item.value])) : current.filter((entry) => entry !== item.value),
                    )
                  }
                />
              ))}
              <Checkbox label="Creative assets are ready" checked={creativeReady} onChange={setCreativeReady} />
            </div>
          </div>
        ) : null}
      </div>
      <div className="grid gap-3 xl:grid-cols-[1fr_1fr]">
        <DistributionPanel title="Audience plan" rows={audienceRows} />
        <DistributionPanel title="Coverage and pacing" rows={displayCoverageRows} />
      </div>
    </RuntimeShell>
  );
}

function GlobalSellingRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [currentMarketplace, setCurrentMarketplace] = useState("US");
  const [targets, setTargets] = useState<string[]>(["CA", "UK", "DE"]);
  const [marketDecision, setMarketDecision] = useState("launch-the-lead-market");
  const [launchPriority, setLaunchPriority] = useState("launch-ca");
  const [sequencingCadence, setSequencingCadence] = useState("launch-next");
  const [marginReady, setMarginReady] = useState<string[]>(["CA", "UK"]);
  const [complianceReady, setComplianceReady] = useState<string[]>(["CA", "UK"]);
  const [localizationReady, setLocalizationReady] = useState<string[]>(["CA"]);
  const [taxReady, setTaxReady] = useState(false);
  const [supportReady, setSupportReady] = useState(false);
  const [buildInternationalListingsReady, setBuildInternationalListingsReady] = useState(true);
  const [showOverrides, setShowOverrides] = useState(false);
  const globalPlan = useMemo(
    () => inferGlobalSellingPlan({ currentMarketplace, targets }),
    [currentMarketplace, targets],
  );
  const globalLaunchDecisionPlan = useMemo(
    () =>
      inferGlobalLaunchDecisionPlan({
        targets,
        marketDecision,
        sequencingCadence,
        marginReady,
        complianceReady,
        localizationReady,
        taxReady,
        supportReady,
        buildInternationalListingsReady,
      }),
    [
      buildInternationalListingsReady,
      complianceReady,
      localizationReady,
      marginReady,
      marketDecision,
      sequencingCadence,
      supportReady,
      targets,
      taxReady,
    ],
  );

  useEffect(() => {
    if (showOverrides) {
      return;
    }
    setMarginReady(globalPlan.marginReady);
    setComplianceReady(globalPlan.complianceReady);
    setLocalizationReady(globalPlan.localizationReady);
    setTaxReady(globalPlan.taxReady);
    setSupportReady(globalPlan.supportReady);
    setBuildInternationalListingsReady(globalPlan.buildInternationalListingsReady);
    const nextExecutionPlan = inferGlobalExpansionExecutionPlan({
      targets,
      marginReady: globalPlan.marginReady,
      complianceReady: globalPlan.complianceReady,
      localizationReady: globalPlan.localizationReady,
      taxReady: globalPlan.taxReady,
      supportReady: globalPlan.supportReady,
    });
    setMarketDecision(nextExecutionPlan.marketDecision);
    setLaunchPriority(nextExecutionPlan.launchPriority);
    setSequencingCadence(nextExecutionPlan.sequencingCadence);
  }, [globalPlan, showOverrides]);

  const result = useMemo(
    () =>
      evaluateGlobalSelling({
        targetCount: targets.length,
        marginReadyCount: marginReady.length,
        complianceReadyCount: complianceReady.length,
        localizationReadyCount: localizationReady.length,
        nearestExpansionScore: targets.length ? Math.round((marginReady.length + complianceReady.length + localizationReady.length) / (targets.length * 3) * 100) : 0,
        currentMarketplace,
        taxReady,
        supportReady,
        buildInternationalListingsReady,
      }),
    [buildInternationalListingsReady, complianceReady.length, currentMarketplace, localizationReady.length, marginReady.length, supportReady, targets.length, taxReady],
  );

  const targetRows = useMemo(
    () =>
      targets.map((target) => ({
        label: target,
        value: `${marginReady.includes(target) ? "Margin" : "No margin"} / ${complianceReady.includes(target) ? "Compliance" : "Compliance gap"}`,
        detail: localizationReady.includes(target) ? "Localization inputs ready" : "Localization work still needed",
      })),
    [complianceReady, localizationReady, marginReady, targets],
  );

  const sequencingRows = useMemo(() => {
    return targets
      .map((market) => {
        const score =
          (marginReady.includes(market) ? 1 : 0) +
          (complianceReady.includes(market) ? 1 : 0) +
          (localizationReady.includes(market) ? 1 : 0) +
          (taxReady ? 0.5 : 0) +
          (supportReady ? 0.5 : 0);
        return {
          label: market,
          value: score >= 4 ? "Launch first" : score >= 3 ? "Prepare next" : "Hold",
          detail: `${marginReady.includes(market) ? "Margin ready" : "Margin gap"} | ${complianceReady.includes(market) ? "Compliance ready" : "Compliance gap"} | ${localizationReady.includes(market) ? "Localization ready" : "Localization gap"}`,
        };
      })
      .sort((a, b) => {
        const weight = (value: string) => (value === "Launch first" ? 2 : value === "Prepare next" ? 1 : 0);
        return weight(b.value) - weight(a.value);
      });
  }, [complianceReady, localizationReady, marginReady, supportReady, targets, taxReady]);

  const globalAuditRows = useMemo(
    () => [
      {
        label: "Target markets",
        value: `${targets.length}`,
        detail: `Starting from ${currentMarketplace}`,
      },
      {
        label: "Nearest-market fit",
        value: `${targets.length ? Math.round((marginReady.length + complianceReady.length + localizationReady.length) / (targets.length * 3) * 100) : 0}%`,
        detail: "Average readiness across margin, compliance, and localization for the current shortlist",
      },
      {
        label: "Support stack",
        value: `${taxReady ? "Tax ready" : "Tax gap"} / ${supportReady ? "Support ready" : "Support gap"}`,
        detail: buildInternationalListingsReady ? "Build International Listings path available" : "No clear Build International Listings operating path yet",
      },
      {
        label: "Readiness coverage",
        value: `${marginReady.length}/${complianceReady.length}/${localizationReady.length}`,
        detail: "Margin-ready / compliance-ready / localization-ready market counts",
      },
      {
        label: "System plan",
        value: `${globalPlan.marginReady.length}/${globalPlan.complianceReady.length}/${globalPlan.localizationReady.length}`,
        detail: "Default market-readiness inference before manual operating overrides",
      },
      {
        label: "Execution brief",
        value: `${marketDecision.replace(/-/g, " ")} / ${launchPriority.replace(/-/g, " ")}`,
        detail: `${sequencingCadence.replace(/-/g, " ")} sequencing cadence for the current expansion pass`,
      },
      {
        label: "Expansion call",
        value: globalLaunchDecisionPlan.expansionDecision,
        detail: `${globalLaunchDecisionPlan.proofPriority} | ${globalLaunchDecisionPlan.launchCadence}`,
      },
    ],
    [buildInternationalListingsReady, complianceReady.length, currentMarketplace, globalLaunchDecisionPlan, globalPlan.complianceReady.length, globalPlan.localizationReady.length, globalPlan.marginReady.length, launchPriority, localizationReady.length, marginReady.length, marketDecision, sequencingCadence, supportReady, targets.length, taxReady],
  );

  const globalActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: globalLaunchDecisionPlan.expansionDecision,
        detail: globalLaunchDecisionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: globalLaunchDecisionPlan.owner,
        detail: `${globalLaunchDecisionPlan.proofPriority} should have one accountable owner before more markets get added to the roadmap.`,
      },
      {
        label: "Then do",
        value: globalLaunchDecisionPlan.launchCadence,
        detail: "Lock the first real launch sequence before letting translation or ops work spread wider.",
      },
      {
        label: "Watch",
        value: globalLaunchDecisionPlan.proofPriority,
        detail: globalLaunchDecisionPlan.watchout,
      },
    ],
    [globalLaunchDecisionPlan],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-[0.7fr_1.6fr_auto]">
        <Field label="Current marketplace">
          <SelectInput value={currentMarketplace} onChange={(e) => setCurrentMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid gap-2 md:grid-cols-3 xl:grid-cols-6">
          {["CA", "UK", "DE", "FR", "JP", "AU"].map((market) => (
            <Checkbox
              key={market}
              label={`Target ${market}`}
              checked={targets.includes(market)}
              onChange={(checked) =>
                setTargets((current) =>
                  checked ? Array.from(new Set([...current, market])) : current.filter((item) => item !== market),
                )
              }
            />
          ))}
        </div>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide readiness overrides" : "Adjust readiness assumptions"}
          </button>
        </div>
      </div>
      <div className="grid gap-2.5 md:grid-cols-[0.95fr_0.95fr_0.95fr]">
        <Field label="Market decision">
          <SelectInput value={marketDecision} onChange={(e) => setMarketDecision(e.target.value)}>
            <option value="choose-one-market">Choose one market</option>
            <option value="fix-compliance-first">Fix compliance first</option>
            <option value="fix-margin-first">Fix margin first</option>
            <option value="close-ops-stack">Close ops stack</option>
            <option value="cut-the-shortlist">Cut the shortlist</option>
            <option value="launch-the-lead-market">Launch the lead market</option>
          </SelectInput>
        </Field>
        <Field label="Launch priority">
          <TextInput value={launchPriority} onChange={(e) => setLaunchPriority(e.target.value)} />
        </Field>
        <Field label="Sequencing cadence">
          <SelectInput value={sequencingCadence} onChange={(e) => setSequencingCadence(e.target.value)}>
            <option value="this-cycle">This cycle</option>
            <option value="tighten-now">Tighten now</option>
            <option value="launch-next">Launch next</option>
            <option value="monitor">Monitor</option>
          </SelectInput>
        </Field>
      </div>
      <div className="grid gap-2 md:grid-cols-3">
        <div className="rounded-lg border border-black/8 bg-slate-50 px-3 py-3 text-sm text-slate-700 md:col-span-3">
          Default readiness is inferred from the current target shortlist. Open overrides only if your real operating stack is stronger or weaker than the default read.
        </div>
      </div>
      <DistributionPanel title="Live expansion inputs" rows={globalAuditRows} />
      <DistributionPanel title="This expansion call" rows={globalActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Advanced readiness overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Only open this when the real margin, compliance, localization, tax, or support posture differs from the system plan.
            </p>
          </div>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2 md:grid-cols-3 xl:grid-cols-6">
              {targets.map((market) => (
                <Checkbox
                  key={`${market}-margin`}
                  label={`${market} margin ready`}
                  checked={marginReady.includes(market)}
                  onChange={(checked) =>
                    setMarginReady((current) =>
                      checked ? Array.from(new Set([...current, market])) : current.filter((item) => item !== market),
                    )
                  }
                />
              ))}
              {targets.map((market) => (
                <Checkbox
                  key={`${market}-compliance`}
                  label={`${market} compliance ready`}
                  checked={complianceReady.includes(market)}
                  onChange={(checked) =>
                    setComplianceReady((current) =>
                      checked ? Array.from(new Set([...current, market])) : current.filter((item) => item !== market),
                    )
                  }
                />
              ))}
              {targets.map((market) => (
                <Checkbox
                  key={`${market}-localization`}
                  label={`${market} localization ready`}
                  checked={localizationReady.includes(market)}
                  onChange={(checked) =>
                    setLocalizationReady((current) =>
                      checked ? Array.from(new Set([...current, market])) : current.filter((item) => item !== market),
                    )
                  }
                />
              ))}
            </div>
            <div className="grid gap-2 md:grid-cols-3">
              <Checkbox label="Tax and duty model ready" checked={taxReady} onChange={setTaxReady} />
              <Checkbox label="Local support and returns ready" checked={supportReady} onChange={setSupportReady} />
              <Checkbox
                label="Build International Listings ready"
                checked={buildInternationalListingsReady}
                onChange={setBuildInternationalListingsReady}
              />
            </div>
          </div>
        ) : null}
      </div>
      <div className="grid gap-3 xl:grid-cols-[1fr_1fr]">
        <DistributionPanel title="Expansion shortlist" rows={targetRows} />
        <DistributionPanel title="Launch order" rows={sequencingRows} />
      </div>
    </RuntimeShell>
  );
}

function ReviewStrategyRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("");
  const [responsePriority, setResponsePriority] = useState("scale-safe-channels");
  const [proofEngine, setProofEngine] = useState("compliant-scaling");
  const [launchCadence, setLaunchCadence] = useState("monitor");
  const [orderVolume, setOrderVolume] = useState(180);
  const [reviewCount, setReviewCount] = useState(22);
  const [reviewRate, setReviewRate] = useState(0.018);
  const [stage, setStage] = useState("launch");
  const [channels, setChannels] = useState<string[]>(["request-a-review", "insert-card-safe", "customer-service-followup"]);
  const [vineEligible, setVineEligible] = useState(true);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [showOverrides, setShowOverrides] = useState(false);

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }

      setSnapshot(payload);
      if (!showOverrides) {
        const nextPlan = inferReviewStrategyPlan(payload);
        setOrderVolume(nextPlan.orderVolume);
        setReviewCount(nextPlan.reviewCount);
        setReviewRate(nextPlan.reviewRate);
        setStage(nextPlan.stage);
        setVineEligible(nextPlan.vineEligible);
        const nextChannels = inferReviewChannels({
          orderVolume: nextPlan.orderVolume,
          reviewCount: nextPlan.reviewCount,
          reviewRate: nextPlan.reviewRate,
          stage: nextPlan.stage,
          vineEligible: nextPlan.vineEligible,
        });
        const nextExecutionPlan = inferReviewExecutionPlan({
          orderVolume: nextPlan.orderVolume,
          reviewCount: nextPlan.reviewCount,
          reviewRate: nextPlan.reviewRate,
          stage: nextPlan.stage,
          vineEligible: nextPlan.vineEligible,
          channels: nextChannels,
        });
        setResponsePriority(nextExecutionPlan.responsePriority);
        setProofEngine(nextExecutionPlan.proofEngine);
        setLaunchCadence(nextExecutionPlan.launchCadence);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  const reviewPlan = useMemo(() => inferReviewStrategyPlan(snapshot), [snapshot]);
  const channelPolicy = useMemo(
    () => ({
      "request-a-review": {
        verdict: "Compliant",
        detail: "Native Amazon workflow and the cleanest baseline for neutral review requests.",
      },
      "customer-service-followup": {
        verdict: "Compliant",
        detail: "Usable when the message stays service-oriented and does not pressure for positive reviews.",
      },
      "insert-card-safe": {
        verdict: "Conditional",
        detail: "Only safe when the language is neutral, non-incentivized, and not steering sentiment.",
      },
      "external-incentive": {
        verdict: "Remove",
        detail: "Incentive-based review requests conflict with Amazon review policy and should not stay in the plan.",
      },
    }),
    [],
  );

  const compliantChannels = useMemo(
    () => channels.filter((channel) => channelPolicy[channel as keyof typeof channelPolicy]?.verdict !== "Remove"),
    [channelPolicy, channels],
  );
  const inferredChannels = useMemo(
    () =>
      inferReviewChannels({
        orderVolume,
        reviewCount,
        reviewRate,
        stage,
        vineEligible,
      }),
    [orderVolume, reviewCount, reviewRate, stage, vineEligible],
  );

  useEffect(() => {
    if (showOverrides) {
      return;
    }
    setChannels(inferredChannels);
  }, [inferredChannels, showOverrides]);

  const result = useMemo(
    () =>
      evaluateReviewStrategy({
        orderVolume,
        reviewCount,
        reviewRate,
        channels,
        compliantChannels,
        stage,
        vineEligible,
      }),
    [channels, compliantChannels, orderVolume, reviewCount, reviewRate, stage, vineEligible],
  );

  const channelRows = useMemo(
    () =>
      channels.map((channel) => ({
        label: channel,
        value: channelPolicy[channel as keyof typeof channelPolicy]?.verdict ?? "Review",
        detail: channelPolicy[channel as keyof typeof channelPolicy]?.detail ?? "Needs manual policy review",
      })),
    [channelPolicy, channels],
  );

  const reviewAuditRows = useMemo(
    () => [
      {
        label: "Live listing base",
        value: snapshot ? `${snapshot.marketplace} / ${snapshot.asin}` : "No live listing loaded",
        detail: snapshot ? `${snapshot.reviewCountText || "No review count"} | ${snapshot.bestSellersRank || snapshot.subCategoryRank || "No rank"}` : "Load a live ASIN to draft review-growth posture from the real PDP.",
      },
      {
        label: "Recent orders",
        value: `${orderVolume}`,
        detail: `${reviewCount} reviews currently on the ASIN`,
      },
      {
        label: "Review conversion",
        value: `${roundNumber(reviewRate * 100, 2)}%`,
        detail: `${stage} stage review-growth posture`,
      },
      {
        label: "Allowed channels",
        value: `${compliantChannels.length}/${channels.length}`,
        detail: "System-classified channels that can stay in the plan without obvious policy conflict",
      },
      {
        label: "System plan",
        value: `${inferredChannels.length} default channels`,
        detail: inferredChannels.join(", "),
      },
      {
        label: "PDP-derived posture",
        value: `${reviewPlan.stage} / ${reviewPlan.vineEligible ? "Vine possible" : "Vine weak fit"}`,
        detail: `${reviewPlan.orderVolume} est. monthly orders | ${roundNumber(reviewPlan.reviewRate * 100, 2)}% review rate`,
      },
      {
        label: "Execution brief",
        value: `${responsePriority.replace(/-/g, " ")} / ${proofEngine.replace(/-/g, " ")}`,
        detail: `${launchCadence.replace(/-/g, " ")} cadence for the current review-growth pass`,
      },
    ],
    [channels.length, compliantChannels.length, inferredChannels, launchCadence, orderVolume, proofEngine, responsePriority, reviewCount, reviewPlan.orderVolume, reviewPlan.reviewRate, reviewPlan.stage, reviewPlan.vineEligible, reviewRate, snapshot, stage],
  );

  const reviewAuditLines = useMemo(
    () => [
      snapshot
        ? "Live PDP loaded. The tool drafted order volume, review base, stage posture, and Vine fit from the current listing before channel selection."
        : "This tool now drafts a default compliant channel plan before asking the operator to edit channel choices manually.",
      reviewRate < 0.01
        ? "Current review conversion is weak enough that adding more channels will not fix the underlying proof engine by itself."
        : "Review conversion is not broken, so the main job is keeping the plan compliant while scaling proof.",
      channels.includes("external-incentive")
        ? "The current plan includes a channel that should be removed outright."
        : "No outright banned channel is selected in the current plan.",
    ],
    [channels, reviewRate, snapshot],
  );

  const reviewActionRows = useMemo(() => {
    const bannedSelected = channels.includes("external-incentive");
    const conditionalSelected = channels.includes("insert-card-safe");

    const firstMove =
      responsePriority === "remove-risky-channel" || bannedSelected
        ? {
            label: "First move",
            value: "Remove the banned review channel",
            detail: "Policy-risk cleanup comes before any review-growth optimization because one bad channel can invalidate the whole plan.",
          }
        : responsePriority === "use-vine-proof" || responsePriority === "repair-proof-engine" || reviewRate < 0.01
          ? {
              label: "First move",
              value: vineEligible ? "Use Vine or improve post-purchase proof capture" : "Improve post-purchase proof capture",
              detail: "The review engine itself is too weak right now, so adding more channel complexity will not solve the underlying conversion gap.",
            }
          : responsePriority === "neutralize-conditional-copy" || conditionalSelected
            ? {
                label: "First move",
                value: "Rewrite the conditional channel to neutral language",
                detail: "The plan is close, but the insert-card path still needs stricter neutrality to stay commercially useful without policy drift.",
              }
            : responsePriority === "build-early-proof" || stage === "launch"
              ? {
                  label: "First move",
                  value: "Concentrate on clean early proof",
                  detail: "At launch, the job is not channel sprawl; it is getting enough legitimate proof to help conversion stabilize.",
                }
              : {
                  label: "First move",
                  value: "Scale only the compliant channels",
                  detail: "The review base is stable enough that the main job is disciplined scaling, not adding risky new mechanisms.",
                };

    return [
      firstMove,
      responsePriority === "remove-risky-channel" || bannedSelected
        ? {
            label: "Execution owner",
            value: "Review policy owner",
            detail: "A banned channel should be removed by the person accountable for keeping review capture inside policy boundaries.",
          }
        : responsePriority === "use-vine-proof" || responsePriority === "repair-proof-engine" || reviewRate < 0.01
          ? {
              label: "Execution owner",
              value: vineEligible ? "Proof-growth owner" : "Post-purchase owner",
              detail: "If the proof engine is weak, one owner needs to improve real review capture instead of adding channel noise.",
            }
          : responsePriority === "neutralize-conditional-copy" || conditionalSelected
            ? {
                label: "Execution owner",
                value: "Lifecycle messaging owner",
                detail: "Conditional channels need a named owner to neutralize the language and keep the plan usable.",
              }
            : responsePriority === "build-early-proof" || stage === "launch"
              ? {
                  label: "Execution owner",
                  value: "Launch proof owner",
                  detail: "Early-stage review growth should be owned by the person stabilizing legitimate social proof at launch.",
                }
              : {
                  label: "Execution owner",
                  value: "Review-growth owner",
                  detail: "Once the base is stable, one operator should scale only the compliant channels and keep policy discipline intact.",
                },
      {
        label: "Then do",
        value:
          launchCadence === "same-day"
            ? "Remove the unsafe path today"
            : launchCadence === "this-cycle"
              ? "Fix the weakest proof lever this cycle"
              : launchCadence === "controlled-test"
                ? "Run one clean proof-growth test"
                : "Hold the channel set steady and monitor",
        detail:
          launchCadence === "same-day"
            ? "Policy risk cleanup should outrun every other review-growth task."
            : launchCadence === "this-cycle"
              ? "When the proof engine is weak or wording is risky, fix that before widening channel coverage."
              : launchCadence === "controlled-test"
                ? "Early proof grows best when one compliant mechanism is isolated and measured."
                : "A stable compliant channel set is more useful than constant tactical churn.",
      },
      {
        label: "Watch",
        value: proofEngine.replace(/-/g, " "),
        detail: "When proof growth feels slow, the easiest mistake is reaching for channels that look faster but quietly create policy exposure.",
      },
    ];
  }, [channels, launchCadence, proofEngine, responsePriority, reviewRate, stage, vineEligible]);

  const reviewInputRows = useMemo(
    () => [
      ...reviewAuditRows,
      {
        label: "Execution call",
        value: reviewActionRows[0]?.value ?? "Pending",
        detail: `${reviewActionRows[1]?.value ?? "Owner pending"} | ${reviewActionRows[2]?.value ?? "Cadence pending"} | ${reviewActionRows[3]?.value ?? "Risk pending"}`,
      },
    ],
    [reviewActionRows, reviewAuditRows],
  );

  const operatingRows = useMemo(() => {
    const riskyCount = channels.filter(
      (channel) => channelPolicy[channel as keyof typeof channelPolicy]?.verdict === "Conditional",
    ).length;
    const bannedCount = channels.filter(
      (channel) => channelPolicy[channel as keyof typeof channelPolicy]?.verdict === "Remove",
    ).length;
    return [
      {
        label: "Compliant channels",
        value: `${compliantChannels.length}`,
        detail: compliantChannels.join(", ") || "No compliant channel selected yet",
      },
      {
        label: "Needs rewrite",
        value: `${riskyCount}`,
        detail: riskyCount ? "Some selected channels still need stricter neutral wording." : "No conditional channel is active right now.",
      },
      {
        label: "Remove now",
        value: `${bannedCount}`,
        detail: bannedCount ? "At least one selected channel creates avoidable policy exposure." : "No banned channel is currently selected.",
      },
    ];
  }, [channelPolicy, channels, compliantChannels]);

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 md:grid-cols-[1.4fr_0.8fr_auto] xl:grid-cols-[1.6fr_0.8fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} placeholder="Paste an ASIN or Amazon URL" />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <div className="grid gap-2.5 md:grid-cols-[0.95fr_0.95fr_0.95fr]">
        <Field label="Response priority">
          <SelectInput value={responsePriority} onChange={(e) => setResponsePriority(e.target.value)}>
            <option value="remove-risky-channel">Remove risky channel</option>
            <option value="use-vine-proof">Use Vine proof</option>
            <option value="repair-proof-engine">Repair proof engine</option>
            <option value="neutralize-conditional-copy">Neutralize conditional copy</option>
            <option value="build-early-proof">Build early proof</option>
            <option value="scale-safe-channels">Scale safe channels</option>
          </SelectInput>
        </Field>
        <Field label="Proof engine">
          <SelectInput value={proofEngine} onChange={(e) => setProofEngine(e.target.value)}>
            <option value="proof-capture">Proof capture</option>
            <option value="vine-support">Vine support</option>
            <option value="message-hygiene">Message hygiene</option>
            <option value="compliant-scaling">Compliant scaling</option>
          </SelectInput>
        </Field>
        <Field label="Launch cadence">
          <SelectInput value={launchCadence} onChange={(e) => setLaunchCadence(e.target.value)}>
            <option value="same-day">Same day</option>
            <option value="this-cycle">This cycle</option>
            <option value="controlled-test">Controlled test</option>
            <option value="monitor">Monitor</option>
          </SelectInput>
        </Field>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <DistributionPanel title="Live review inputs" rows={reviewInputRows} />
      <AuditNote lines={reviewAuditLines} />
      <DistributionPanel title="This review-growth call" rows={reviewActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Advanced channel overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Only open this when the default compliant channel plan does not match your actual lifecycle workflow.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide channel overrides" : "Adjust channel assumptions"}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-5">
              <Field label="Recent orders">
                <NumberInput value={orderVolume} min="0" step="1" onChange={(e) => setOrderVolume(Number(e.target.value))} />
              </Field>
              <Field label="Current reviews">
                <NumberInput value={reviewCount} min="0" step="1" onChange={(e) => setReviewCount(Number(e.target.value))} />
              </Field>
              <Field label="Review rate">
                <NumberInput value={reviewRate} min="0" max="1" step="0.001" onChange={(e) => setReviewRate(Number(e.target.value))} />
              </Field>
              <Field label="Stage">
                <SelectInput value={stage} onChange={(e) => setStage(e.target.value)}>
                  <option value="launch">Launch</option>
                  <option value="growth">Growth</option>
                  <option value="mature">Mature</option>
                </SelectInput>
              </Field>
              <Checkbox label="Vine is available" checked={vineEligible} onChange={setVineEligible} />
            </div>
            <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-4">
              {["request-a-review", "customer-service-followup", "insert-card-safe", "external-incentive"].map((channel) => (
                <Checkbox
                  key={channel}
                  label={channel}
                  checked={channels.includes(channel)}
                  onChange={(checked) =>
                    setChannels((current) =>
                      checked ? Array.from(new Set([...current, channel])) : current.filter((item) => item !== channel),
                    )
                  }
                />
              ))}
            </div>
          </div>
        ) : null}
      </div>
      <div className="grid gap-3 xl:grid-cols-[1fr_1fr]">
        <DistributionPanel title="Channel review" rows={channelRows} />
        <DistributionPanel title="Operating posture" rows={operatingRows} />
      </div>
    </RuntimeShell>
  );
}

function VineProgramRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("");
  const [reviewCount, setReviewCount] = useState(8);
  const [marginRate, setMarginRate] = useState(22);
  const [unitsAvailable, setUnitsAvailable] = useState(35);
  const [launchStage, setLaunchStage] = useState("launch");
  const [brandRegistered, setBrandRegistered] = useState(true);
  const [marketReady, setMarketReady] = useState(true);
  const [fbaReady, setFbaReady] = useState(true);
  const [detailPageReady, setDetailPageReady] = useState(true);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [showOverrides, setShowOverrides] = useState(false);
  const vineSnapshotPlan = useMemo(() => inferVineSnapshotPlan(snapshot), [snapshot]);
  const inferredVineReadiness = useMemo(
    () =>
      inferVineReadiness({
        reviewCount,
        marginRate,
        unitsAvailable,
        launchStage,
      }),
    [launchStage, marginRate, reviewCount, unitsAvailable],
  );
  const vineExecutionPlan = useMemo(
    () =>
      inferVineExecutionPlan({
        reviewCount,
        marginRate,
        unitsAvailable,
        launchStage,
        brandRegistered,
        marketReady,
        fbaReady,
        detailPageReady,
      }),
    [brandRegistered, detailPageReady, fbaReady, launchStage, marginRate, marketReady, reviewCount, unitsAvailable],
  );

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }

      setSnapshot(payload);
      if (!showOverrides) {
        const nextPlan = inferVineSnapshotPlan(payload);
        setReviewCount(nextPlan.reviewCount);
        setMarginRate(nextPlan.marginRate);
        setUnitsAvailable(nextPlan.unitsAvailable);
        setLaunchStage(nextPlan.launchStage);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    if (showOverrides) {
      return;
    }
    setBrandRegistered(inferredVineReadiness.brandRegistered);
    setMarketReady(inferredVineReadiness.marketReady);
    setFbaReady(inferredVineReadiness.fbaReady);
    setDetailPageReady(inferredVineReadiness.detailPageReady);
  }, [inferredVineReadiness, showOverrides]);

  const result = useMemo(
    () =>
      evaluateVineProgram({
        reviewCount,
        marginRate,
        unitsAvailable,
        launchStage,
        brandRegistered,
        marketReady,
        fbaReady,
        detailPageReady,
      }),
    [brandRegistered, detailPageReady, fbaReady, launchStage, marginRate, marketReady, reviewCount, unitsAvailable],
  );

  const vineAuditRows = useMemo(
    () => [
      {
        label: "Review count",
        value: `${reviewCount}`,
        detail: `${launchStage} stage proof level`,
      },
      {
        label: "Margin / units",
        value: `${roundNumber(marginRate, 1)}% / ${unitsAvailable}`,
        detail: "Economics and sample-unit buffer available for a clean Vine run",
      },
      {
        label: "Brand / ops stack",
        value: `${brandRegistered ? "Brand ready" : "Brand gap"} / ${marketReady ? "Offer ready" : "Offer gap"}`,
        detail: `${fbaReady ? "FBA live" : "FBA missing"} | ${detailPageReady ? "Detail page ready" : "Detail page gap"}`,
      },
      {
        label: "System posture",
        value: `${inferredVineReadiness.brandRegistered ? "Brand ready" : "Brand gap"} / ${inferredVineReadiness.fbaReady ? "FBA likely" : "FBA weak"}`,
        detail: "Default eligibility read before manual overrides",
      },
      {
        label: "Use-case fit",
        value: reviewCount < 15 ? "Strong" : reviewCount < 30 ? "Moderate" : "Weak",
        detail: "Vine is usually strongest when proof is still genuinely thin",
      },
      {
        label: "Enrollment call",
        value: vineExecutionPlan.vineDecision,
        detail: `${vineExecutionPlan.proofPriority} | ${vineExecutionPlan.enrollmentCadence}`,
      },
    ],
    [brandRegistered, detailPageReady, fbaReady, inferredVineReadiness, launchStage, marginRate, marketReady, reviewCount, unitsAvailable, vineExecutionPlan],
  );

  const vineActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: vineExecutionPlan.vineDecision,
        detail: vineExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: vineExecutionPlan.owner,
        detail: `${vineExecutionPlan.proofPriority} should be owned by the person who can actually change this SKU's launch posture.`,
      },
      {
        label: "Then do",
        value: vineExecutionPlan.enrollmentCadence,
        detail: "Keep Vine sized to the real proof gap instead of treating it like a default launch checkbox.",
      },
      {
        label: "Watch",
        value: vineExecutionPlan.proofPriority,
        detail: vineExecutionPlan.watchout,
      },
    ],
    [vineExecutionPlan],
  );

  const vineInputRows = useMemo(
    () => [
      ...vineAuditRows,
      {
        label: "Execution call",
        value: vineActionRows[0]?.value ?? "Pending",
        detail: `${vineActionRows[1]?.value ?? "Owner pending"} | ${vineActionRows[2]?.value ?? "Cadence pending"} | ${vineActionRows[3]?.value ?? "Risk pending"}`,
      },
    ],
    [vineActionRows, vineAuditRows],
  );

  const vineReadinessRows = useMemo(
    () => [
      {
        label: "Eligibility stack",
        value: `${brandRegistered ? "Brand" : "Brand gap"} / ${fbaReady ? "FBA" : "FBA gap"}`,
        detail: `${marketReady ? "Marketplace ready" : "Marketplace gap"} | ${detailPageReady ? "Detail page ready" : "Page gap"}`,
      },
      {
        label: "Proof urgency",
        value: reviewCount < 15 ? "High" : reviewCount < 30 ? "Moderate" : "Low",
        detail: reviewCount < 15 ? "The SKU still has a real proof deficit." : "The SKU already has enough proof that Vine must justify itself carefully.",
      },
      {
        label: "Economic room",
        value: `${roundNumber(marginRate, 1)}% / ${unitsAvailable} units`,
        detail: marginRate < 15 || unitsAvailable < 20
          ? "Economics or unit buffer are thin enough that Vine can become an expensive shortcut."
          : "Economics and unit buffer are healthy enough for a controlled run.",
      },
      {
        label: "Enrollment posture",
        value: vineExecutionPlan.proofPriority,
        detail: `${vineExecutionPlan.vineDecision} | ${vineExecutionPlan.enrollmentCadence}`,
      },
    ],
    [brandRegistered, detailPageReady, fbaReady, marginRate, marketReady, reviewCount, unitsAvailable, vineExecutionPlan],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 md:grid-cols-[1.4fr_0.8fr_auto] xl:grid-cols-[1.6fr_0.8fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} placeholder="Paste an ASIN or Amazon URL" />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote
        lines={[
          snapshot
            ? "The live PDP now drafts Vine proof urgency and operating posture before you touch eligibility overrides."
            : "Load a live ASIN first so Vine qualification starts from the real PDP instead of a guessed proof state.",
          `System draft: ${vineSnapshotPlan.reviewCount} reviews, ${roundNumber(vineSnapshotPlan.marginRate, 1)}% margin, ${vineSnapshotPlan.unitsAvailable} units, ${vineSnapshotPlan.launchStage} stage.`,
          "Open overrides only when the real Brand Registry, FBA, or detail-page readiness differs from the default read.",
        ]}
      />
      <DistributionPanel title="Live Vine inputs" rows={vineInputRows} />
      <DistributionPanel title="This Vine call" rows={vineActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Advanced readiness overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Only open this if your actual account or listing readiness is stronger or weaker than the system posture.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide readiness overrides" : "Adjust readiness assumptions"}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-4">
              <Field label="Current reviews">
                <NumberInput value={reviewCount} min="0" step="1" onChange={(e) => setReviewCount(Number(e.target.value))} />
              </Field>
              <Field label="Net margin %">
                <NumberInput value={marginRate} min="0" step="0.1" onChange={(e) => setMarginRate(Number(e.target.value))} />
              </Field>
              <Field label="Available units">
                <NumberInput value={unitsAvailable} min="0" step="1" onChange={(e) => setUnitsAvailable(Number(e.target.value))} />
              </Field>
              <Field label="Launch stage">
                <SelectInput value={launchStage} onChange={(e) => setLaunchStage(e.target.value)}>
                  <option value="launch">Launch</option>
                  <option value="relaunch">Relaunch</option>
                  <option value="mature">Mature</option>
                </SelectInput>
              </Field>
            </div>
            <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-4">
              <Checkbox label="Brand Registry is ready" checked={brandRegistered} onChange={setBrandRegistered} />
              <Checkbox label="Offer is operationally ready" checked={marketReady} onChange={setMarketReady} />
              <Checkbox label="Active FBA listing" checked={fbaReady} onChange={setFbaReady} />
              <Checkbox label="Image and description ready" checked={detailPageReady} onChange={setDetailPageReady} />
            </div>
          </div>
        ) : null}
      </div>
      <DistributionPanel title="Enrollment posture" rows={vineReadinessRows} />
    </RuntimeShell>
  );
}

function ProductBundlingRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [componentNames, setComponentNames] = useState("mirror, floor stand");
  const [bundleGoal, setBundleGoal] = useState("starter-kit");
  const [anchorItem, setAnchorItem] = useState("arched full length mirror");
  const [complementaryScore, setComplementaryScore] = useState(78);
  const [marginRate, setMarginRate] = useState(24);
  const [bundleDiscountRate, setBundleDiscountRate] = useState(0.08);
  const [clarityScore, setClarityScore] = useState(74);
  const [aovLiftScore, setAovLiftScore] = useState(22);
  const [brandRepresentative, setBrandRepresentative] = useState(true);
  const [fbaReady, setFbaReady] = useState(true);
  const [showOverrides, setShowOverrides] = useState(false);
  const componentList = useMemo(() => splitKeywordPhrases(componentNames), [componentNames]);
  const componentCount = componentList.length;
  const inferredBundlePlan = useMemo(
    () =>
      inferBundleConceptPlan({
        marketplace,
        componentNames: componentList,
        bundleGoal,
        anchorItem,
      }),
    [anchorItem, bundleGoal, componentList, marketplace],
  );
  const bundleExecutionPlan = useMemo(
    () =>
      inferBundleExecutionPlan({
        marketplace,
        componentCount,
        complementaryScore,
        marginRate,
        bundleDiscountRate,
        clarityScore,
        aovLiftScore,
        brandRepresentative,
        fbaReady,
        bundleGoal,
        anchorItem,
      }),
    [anchorItem, aovLiftScore, brandRepresentative, bundleDiscountRate, bundleGoal, clarityScore, componentCount, complementaryScore, fbaReady, marginRate, marketplace],
  );

  useEffect(() => {
    if (showOverrides) {
      return;
    }
    setComplementaryScore(inferredBundlePlan.complementaryScore);
    setBundleDiscountRate(inferredBundlePlan.bundleDiscountRate);
    setClarityScore(inferredBundlePlan.clarityScore);
    setAovLiftScore(inferredBundlePlan.aovLiftScore);
    setBrandRepresentative(inferredBundlePlan.brandRepresentative);
    setFbaReady(inferredBundlePlan.fbaReady);
  }, [inferredBundlePlan, showOverrides]);

  const result = useMemo(
    () =>
      evaluateProductBundling({
        marketplace,
        componentCount,
        complementaryScore,
        marginRate,
        bundleDiscountRate,
        clarityScore,
        aovLiftScore,
        brandRepresentative,
        fbaReady,
      }),
    [aovLiftScore, brandRepresentative, bundleDiscountRate, clarityScore, complementaryScore, componentCount, fbaReady, marginRate, marketplace],
  );

  const bundleRows = useMemo(
    () => [
      { label: "Complementarity", value: `${complementaryScore}%`, detail: "Do the items solve one shopper job together?" },
      { label: "Post-discount margin", value: `${roundNumber(marginRate - bundleDiscountRate * 100, 1)}%`, detail: "Margin left after bundle discounting" },
      { label: "Offer clarity", value: `${clarityScore}%`, detail: "How obvious the bundle value is on first glance" },
      { label: "AOV lift", value: `${aovLiftScore}%`, detail: "Estimated commercial upside vs single-item sale" },
    ],
    [aovLiftScore, bundleDiscountRate, clarityScore, complementaryScore, marginRate],
  );

  const bundlingAuditRows = useMemo(
    () => [
      {
        label: "Bundle brief",
        value: `${marketplace} / ${componentCount || 0} items`,
        detail: anchorItem.trim() ? `${anchorItem} anchors the bundle concept` : "Choose the hero item the bundle is meant to protect or extend",
      },
      {
        label: "Post-discount margin",
        value: `${roundNumber(marginRate - bundleDiscountRate * 100, 1)}%`,
        detail: `${roundNumber(bundleDiscountRate * 100, 1)}% discount against ${roundNumber(marginRate, 1)}% base margin`,
      },
      {
        label: "Eligibility stack",
        value: `${brandRepresentative ? "Brand ready" : "Brand gap"} / ${fbaReady ? "FBA ready" : "FBA gap"}`,
        detail: "Bundle access and component buyability readiness",
      },
      {
        label: "Offer clarity",
        value: `${clarityScore}%`,
        detail: `${aovLiftScore}% estimated AOV lift if the bundle lands cleanly`,
      },
      {
        label: "Bundle goal",
        value: bundleGoal.replace(/-/g, " "),
        detail: componentList.length ? componentList.join(", ") : "List the intended component ASINs or item roles first",
      },
      {
        label: "System concept",
        value: `${inferredBundlePlan.complementaryScore}% fit`,
        detail: "System read from the bundle brief before manual commercial overrides",
      },
      {
        label: "Launch call",
        value: bundleExecutionPlan.bundleDecision,
        detail: `${bundleExecutionPlan.lanePriority} | ${bundleExecutionPlan.approvalCadence}`,
      },
    ],
    [anchorItem, aovLiftScore, brandRepresentative, bundleDiscountRate, bundleExecutionPlan, bundleGoal, clarityScore, componentCount, componentList, fbaReady, inferredBundlePlan.complementaryScore, marginRate, marketplace],
  );

  const bundlingActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: bundleExecutionPlan.bundleDecision,
        detail: bundleExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: bundleExecutionPlan.owner,
        detail: `${bundleExecutionPlan.lanePriority} should sit with the operator who can actually clear the next launch constraint.`,
      },
      {
        label: "Then do",
        value: bundleExecutionPlan.approvalCadence,
        detail: "Once the next constraint is cleared, keep the bundle narrowed to one job and one hero-led offer.",
      },
      {
        label: "Watch",
        value: bundleExecutionPlan.lanePriority,
        detail: bundleExecutionPlan.watchout,
      },
    ],
    [bundleExecutionPlan],
  );

  const bundlingInputRows = useMemo(
    () => [
      ...bundlingAuditRows,
      {
        label: "Execution call",
        value: bundlingActionRows[0]?.value ?? "Pending",
        detail: `${bundlingActionRows[1]?.value ?? "Owner pending"} | ${bundlingActionRows[2]?.value ?? "Cadence pending"} | ${bundlingActionRows[3]?.value ?? "Risk pending"}`,
      },
    ],
    [bundlingActionRows, bundlingAuditRows],
  );

  const bundleDecisionRows = useMemo(
    () => [
      {
        label: "Commercial fit",
        value: complementaryScore >= 70 ? "Strong" : complementaryScore >= 60 ? "Borderline" : "Weak",
        detail: complementaryScore >= 70
          ? "The components look like they solve one shopper job together."
          : "The bundle still risks feeling like a value stack instead of a clean use-case offer.",
      },
      {
        label: "Margin after discount",
        value: `${roundNumber(marginRate - bundleDiscountRate * 100, 1)}%`,
        detail: marginRate - bundleDiscountRate * 100 < 10
          ? "The discount is already eating too much contribution."
          : "There is still enough contribution room to test the bundle honestly.",
      },
      {
        label: "Conversion clarity",
        value: clarityScore >= 70 ? "Clear" : clarityScore >= 60 ? "Needs tightening" : "Too vague",
        detail: `${aovLiftScore}% estimated AOV lift if the bundle lands cleanly.`,
      },
      {
        label: "Execution posture",
        value: bundleExecutionPlan.lanePriority,
        detail: `${bundleExecutionPlan.bundleDecision} | ${bundleExecutionPlan.approvalCadence}`,
      },
    ],
    [aovLiftScore, bundleDiscountRate, bundleExecutionPlan, clarityScore, complementaryScore, marginRate],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-[1.6fr_1fr_1fr_0.9fr]">
        <Field label="Bundle components">
          <TextInput value={componentNames} onChange={(e) => setComponentNames(e.target.value)} placeholder="mirror, floor stand, cleaning cloth" />
        </Field>
        <Field label="Bundle goal">
          <SelectInput value={bundleGoal} onChange={(e) => setBundleGoal(e.target.value)}>
            <option value="starter-kit">Starter kit</option>
            <option value="average-order-value">Raise AOV</option>
            <option value="giftable-set">Giftable set</option>
            <option value="problem-solver">Solve one use case</option>
          </SelectInput>
        </Field>
        <Field label="Hero item">
          <TextInput value={anchorItem} onChange={(e) => setAnchorItem(e.target.value)} placeholder="Main SKU that carries the bundle" />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
      </div>
      <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-4">
        <Field label="Net margin %">
          <NumberInput value={marginRate} min="0" step="0.1" onChange={(e) => setMarginRate(Number(e.target.value))} />
        </Field>
      </div>
      <AuditNote
        lines={[
          "The page now drafts a default bundle concept from the actual bundle brief before asking for manual merchandising scores.",
          componentList.length ? `System brief: ${componentList.join(", ")} with ${anchorItem || "no clear hero item"} as the bundle anchor.` : "List the intended components first so the system can tell whether this is a real bundle or just a loose idea.",
          "Open overrides only when the real complementarity, clarity, AOV lift, or access posture differs from the default concept read.",
        ]}
      />
      <DistributionPanel title="Live bundle inputs" rows={bundlingInputRows} />
      <DistributionPanel title="This bundle call" rows={bundlingActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Advanced bundle overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Only open this if your real bundle concept is materially different from the default system read.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide bundle overrides" : "Adjust bundle assumptions"}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-4">
              <Field label="Complementarity">
                <NumberInput value={complementaryScore} min="0" max="100" step="1" onChange={(e) => setComplementaryScore(Number(e.target.value))} />
              </Field>
              <Field label="Bundle discount rate">
                <NumberInput value={bundleDiscountRate} min="0" max="1" step="0.01" onChange={(e) => setBundleDiscountRate(Number(e.target.value))} />
              </Field>
              <Field label="Clarity score">
                <NumberInput value={clarityScore} min="0" max="100" step="1" onChange={(e) => setClarityScore(Number(e.target.value))} />
              </Field>
              <Field label="AOV lift score">
                <NumberInput value={aovLiftScore} min="0" max="100" step="1" onChange={(e) => setAovLiftScore(Number(e.target.value))} />
              </Field>
            </div>
            <div className="grid gap-2 md:grid-cols-2">
              <Checkbox label="Brand Representative ready" checked={brandRepresentative} onChange={setBrandRepresentative} />
              <Checkbox label="Active FBA inventory ready" checked={fbaReady} onChange={setFbaReady} />
            </div>
          </div>
        ) : null}
      </div>
      <div className="grid gap-3 xl:grid-cols-[1fr_1fr]">
        <DistributionPanel title="Bundle pressure test" rows={bundleRows} />
        <DistributionPanel title="Bundle verdict" rows={bundleDecisionRows} />
      </div>
    </RuntimeShell>
  );
}

function ListingImagesRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("B0GYRT3FNL");
  const [benefits, setBenefits] = useState("arched silhouette, shatter-resistant glass, anti-slip base, room-brightening reflection");
  const [objections, setObjections] = useState("Will it tip easily?\nIs the reflection clear?\nDoes it fit tight spaces?");
  const [differentiators, setDifferentiators] = useState("arched shape, gold frame, floor-standing design");
  const [imageJobs, setImageJobs] = useState<string[]>(["hero", "lifestyle", "dimensions", "comparison", "objection"]);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [showOverrides, setShowOverrides] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const imagePlan = useMemo(() => inferListingImagePlan(snapshot), [snapshot]);

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }

      const nextPlan = inferListingImagePlan(payload);
      setSnapshot(payload);
      if (!showOverrides) {
        if (nextPlan.benefits.length) {
          setBenefits(nextPlan.benefits.join(", "));
        }
        if (nextPlan.differentiators.length) {
          setDifferentiators(nextPlan.differentiators.join(", "));
        }
        setObjections(nextPlan.objections.join("\n"));
        setImageJobs(nextPlan.imageJobs);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  const benefitList = splitKeywordPhrases(benefits);
  const objectionList = objections.split(/\r?\n|,/).map((item) => item.trim()).filter(Boolean);
  const differentiatorList = splitKeywordPhrases(differentiators);
  const mobileReadyCount = imageJobs.filter((item) => ["hero", "benefit", "dimensions", "objection"].includes(item)).length;
  const infographicCount = imageJobs.filter((item) => ["dimensions", "comparison", "feature-proof"].includes(item)).length;

  const result = useMemo(
    () =>
      evaluateListingImages({
        existingImageCount: Math.max(snapshot?.imageUrls.length ?? 0, imageJobs.length),
        benefitCount: benefitList.length,
        objectionCount: objectionList.length,
        differentiatorCount: differentiatorList.length,
        mobileReadyCount,
        infographicCount,
      }),
    [benefitList.length, differentiatorList.length, imageJobs.length, infographicCount, mobileReadyCount, objectionList.length, snapshot?.imageUrls.length],
  );

  const imageRows = useMemo(
    () =>
      imageJobs.map((job, index) => ({
        label: `Image ${index + 1}`,
        value: job,
        detail:
          job === "hero"
            ? benefitList[0] || "Lead SKU promise"
            : job === "objection"
              ? objectionList[0] || "Resolve the main hesitation"
              : job === "comparison"
                ? differentiatorList[0] || "Show why this SKU stands apart"
                : benefitList[index % Math.max(benefitList.length, 1)] || "Support the sales story",
      })),
    [benefitList, differentiatorList, imageJobs, objectionList],
  );

  const imageAuditRows = useMemo(
    () => [
      {
        label: "Current image stack",
        value: `${snapshot?.imageUrls.length ?? 0} live / ${imageJobs.length} planned`,
        detail: snapshot ? "Live count is compared with the proposed conversion-focused sequence" : "Load a listing to compare current images with the planned sequence",
      },
      {
        label: "Benefit coverage",
        value: `${benefitList.length} angles`,
        detail: benefitList.length ? benefitList.join(", ") : "No benefit angles loaded yet",
      },
      {
        label: "Objection coverage",
        value: `${objectionList.length} objections`,
        detail: objectionList.length ? objectionList.join(", ") : "No buyer objections captured yet",
      },
      {
        label: "Differentiators",
        value: `${differentiatorList.length} claims`,
        detail: differentiatorList.length ? differentiatorList.join(", ") : "No differentiators loaded yet",
      },
    ],
    [benefitList, differentiatorList, imageJobs.length, objectionList, snapshot],
  );

  const imageAuditLines = useMemo(() => {
    const lines = [];
    if (snapshot) {
      lines.push(`Loaded ${snapshot.imageUrls.length} live images from the current listing before planning the next image sequence.`);
      lines.push("The tool prefilled benefit angles and differentiators from the live page so the image brief starts from the real listing state.");
    }
    lines.push(`System draft: ${benefitList.length} benefits, ${objectionList.length} objections, ${imageJobs.length} image jobs.`);
    lines.push("Only use manual overrides when you need to test a different creative angle or revise the planned image jobs.");
    return lines;
  }, [benefitList.length, imageJobs.length, objectionList.length, snapshot]);

  const imageActionRows = useMemo(() => {
    const firstMove =
      !snapshot
        ? {
            label: "First move",
            value: "Load the live PDP image stack",
            detail: "Image planning is much weaker when the tool cannot compare the proposed sequence against what is already live.",
          }
        : benefitList.length < 3
          ? {
              label: "First move",
              value: "Sharpen the top 3 benefit claims",
              detail: "Without a tight value hierarchy, the image set usually turns into generic visuals instead of a conversion asset.",
            }
          : objectionList.length < 2
            ? {
                label: "First move",
                value: "Add objection-handling images",
                detail: "If the gallery does not answer buyer hesitation, it leaves too much work for the bullets and reviews.",
              }
            : differentiatorList.length < 2
              ? {
                  label: "First move",
                  value: "Clarify what makes this SKU different",
                  detail: "A gallery that cannot defend the product gap will struggle to support price, clicks, and conversion.",
                }
              : imageJobs.length < 5
                ? {
                    label: "First move",
                    value: "Expand to a full conversion sequence",
                    detail: "The image plan is still too thin to cover hero, proof, dimensions, objections, and comparison work together.",
                  }
                : {
                    label: "First move",
                    value: "Execute the image sequence in commercial order",
                    detail: "The strategy is strong enough that the next gain comes from disciplined asset production, not more ideation.",
                  };

    return [
      firstMove,
      !snapshot
        ? {
            label: "Execution owner",
            value: "Creative owner",
            detail: "Image planning should start with the person who can inspect the live gallery before rewriting the next sequence.",
          }
        : benefitList.length < 3
          ? {
              label: "Execution owner",
              value: "Merchandising owner",
              detail: "Weak benefit hierarchy is a merchandising problem first; someone has to choose the top claims before art gets made.",
            }
          : objectionList.length < 2
            ? {
                label: "Execution owner",
                value: "Conversion owner",
                detail: "If objections are not covered, the next move belongs to the team lifting conversion support, not just aesthetics.",
              }
            : differentiatorList.length < 2
              ? {
                  label: "Execution owner",
                  value: "Positioning owner",
                  detail: "A gallery that cannot defend the product gap needs stronger positioning ownership before more asset production.",
                }
              : imageJobs.length < 5
                ? {
                    label: "Execution owner",
                    value: "Creative production owner",
                    detail: "A thin image plan needs one owner to expand the full conversion sequence, not scattered one-off asset requests.",
                  }
                : {
                    label: "Execution owner",
                    value: "Gallery execution owner",
                    detail: "Once the plan is strong, one operator should produce the assets in the right commercial order and keep the gallery honest.",
                  },
      {
        label: "Do not cross",
        value:
          !snapshot
            ? "Do not brief new images before reading the live gallery"
            : "Do not let aesthetics outrank proof",
        detail:
          !snapshot
            ? "A strong image plan starts by spotting what the current PDP is missing, not by inventing a new gallery from memory."
            : "If the sequence stops answering buyer questions, the gallery becomes prettier without becoming more commercially useful.",
      },
      {
        label: "Then do",
        value: "Give each image one sales job",
        detail: "Hero, feature proof, dimensions, comparison, and objection handling should each do a distinct part of the conversion work.",
      },
      {
        label: "Watch",
        value: "Pretty-gallery drift",
        detail: "It is easy for lifestyle art to crowd out scale, proof, and objection handling unless someone keeps the image stack commercially honest.",
      },
    ];
  }, [benefitList.length, differentiatorList.length, imageJobs.length, objectionList.length, snapshot]);

  const imageInputRows = useMemo(
    () => [
      ...imageAuditRows,
      {
        label: "Execution call",
        value: imageActionRows[0]?.value ?? "Pending",
        detail: `${imageActionRows[1]?.value ?? "Owner pending"} | ${imageActionRows[2]?.value ?? "Cadence pending"} | ${imageActionRows[3]?.value ?? "Risk pending"}`,
      },
    ],
    [imageActionRows, imageAuditRows],
  );

  const imagePriorityRows = useMemo(
    () =>
      buildImagePriorityRows({
        imageJobs,
        benefitList,
        objectionList,
        differentiatorList,
        snapshot,
      }),
    [benefitList, differentiatorList, imageJobs, objectionList, snapshot],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_0.7fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote lines={imageAuditLines} />
      <DistributionPanel title="Live listing-images analysis" rows={imageInputRows} />
      <DistributionPanel title="This image-sequence call" rows={imageActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">{manualOverridesHeading(locale)}</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Use this only to test a different creative strategy or revise the proposed image sequence.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((value) => !value)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {manualOverridesToggle(locale, showOverrides)}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 xl:grid-cols-[1.2fr_1fr_1fr]">
              <Field label="Benefit angles">
                <TextAreaInput value={benefits} onChange={(e) => setBenefits(e.target.value)} className="min-h-[6.5rem]" spellCheck={false} />
              </Field>
              <Field label="Buyer objections">
                <TextAreaInput value={objections} onChange={(e) => setObjections(e.target.value)} className="min-h-[6.5rem]" spellCheck={false} />
              </Field>
              <Field label="Differentiators">
                <TextAreaInput value={differentiators} onChange={(e) => setDifferentiators(e.target.value)} className="min-h-[6.5rem]" spellCheck={false} />
              </Field>
            </div>
            <div className="grid gap-2 md:grid-cols-3 xl:grid-cols-6">
              {[
                { value: "hero", label: "Hero" },
                { value: "benefit", label: "Benefit focus" },
                { value: "lifestyle", label: "Lifestyle" },
                { value: "dimensions", label: "Dimensions" },
                { value: "comparison", label: "Comparison" },
                { value: "objection", label: "Objection handler" },
                { value: "feature-proof", label: "Feature proof" },
              ].map((job) => (
                <Checkbox
                  key={job.value}
                  label={job.label}
                  checked={imageJobs.includes(job.value)}
                  onChange={(checked) =>
                    setImageJobs((current) =>
                      checked ? Array.from(new Set([...current, job.value])) : current.filter((item) => item !== job.value),
                    )
                  }
                />
              ))}
            </div>
          </div>
        ) : null}
      </div>
      <DistributionPanel title="Image sequence brief" rows={imageRows} />
      <DistributionPanel title="Image priorities" rows={imagePriorityRows} />
    </RuntimeShell>
  );
}

function ProductPhotographyRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("B0GYRT3FNL");
  const [useCases, setUseCases] = useState("bedroom corner styling, dressing check, apartment entryway");
  const [features, setFeatures] = useState("arched top, shatter-resistant glass, anti-slip base, slim frame");
  const [props, setProps] = useState<string[]>(["chair", "plant", "rug"]);
  const [retouchNeeds, setRetouchNeeds] = useState<string[]>(["dust cleanup", "reflection cleanup"]);
  const [studioReady, setStudioReady] = useState(true);
  const [showOverrides, setShowOverrides] = useState(false);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const photoPlan = useMemo(() => inferPhotographyPlan(snapshot), [snapshot]);

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }

      const nextPhotoPlan = inferPhotographyPlan(payload);
      setSnapshot(payload);
      if (!showOverrides) {
        if (nextPhotoPlan.features.length) {
          setFeatures(nextPhotoPlan.features.join(", "));
        }
        setUseCases(nextPhotoPlan.useCases.join(", "));
        setProps(nextPhotoPlan.props);
        setRetouchNeeds(nextPhotoPlan.retouchNeeds);
        setStudioReady(nextPhotoPlan.studioReady);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  const useCaseList = splitKeywordPhrases(useCases);
  const featureList = splitKeywordPhrases(features);
  const shotCount = Math.max((snapshot?.imageUrls.length ?? 0), featureList.length + useCaseList.length);

  const result = useMemo(
    () =>
      evaluateProductPhotography({
        shotCount,
        useCaseCount: useCaseList.length,
        featureCount: featureList.length,
        propCount: props.length,
        retouchNeedCount: retouchNeeds.length,
        studioReady,
      }),
    [featureList.length, props.length, retouchNeeds.length, shotCount, studioReady, useCaseList.length],
  );

  const photoAuditRows = useMemo(
    () => [
      {
        label: "Live listing base",
        value: snapshot ? `${snapshot.marketplace} / ${snapshot.asin}` : "No live listing loaded",
        detail: snapshot ? `${snapshot.imageUrls.length} current PDP images | ${snapshot.breadcrumbs[0] ?? "Category"} context detected` : "Load the live PDP first so the shot plan starts from the actual listing rather than guesses.",
      },
      {
        label: "Shot coverage",
        value: `${shotCount} planned shots`,
        detail: `${useCaseList.length} use cases | ${featureList.length} feature proof angles`,
      },
      {
        label: "Scene support",
        value: `${props.length} props / ${retouchNeeds.length} retouch tags`,
        detail: studioReady ? "Studio can execute a tighter shot sequence now" : "Production setup is still the main bottleneck.",
      },
    ],
    [featureList.length, props.length, retouchNeeds.length, shotCount, snapshot, studioReady, useCaseList.length],
  );

  const photoActionRows = useMemo(() => {
    const firstMove =
      !snapshot
        ? {
            label: "First move",
            value: "Load the live PDP",
            detail: "Without the current image stack, the new shoot risks repeating what is already live instead of fixing the missing proof.",
          }
        : useCaseList.length < 2
          ? {
              label: "First move",
              value: "Define the top buyer-use scenes",
              detail: "If the scene plan is vague, the shoot usually turns into generic lifestyle filler.",
            }
          : featureList.length < 3
            ? {
                label: "First move",
                value: "Prioritize 3 product-proof shots",
                detail: "The gallery needs concrete proof frames before it needs more styling ideas.",
              }
            : !studioReady
              ? {
                  label: "First move",
                  value: "Lock the shoot setup",
                  detail: "The bottleneck is production readiness, not more creative brainstorming.",
                }
              : {
                  label: "First move",
                  value: "Shoot hero, scale, and proof in one sequence",
                  detail: "The inputs are strong enough that execution order matters more than adding more shot types.",
                };

    return [
      firstMove,
      {
        label: "Execution owner",
        value:
          !snapshot
            ? "Creative lead"
            : useCaseList.length < 2
              ? "Creative strategist"
              : featureList.length < 3
                ? "Merchandising / PDP owner"
                : !studioReady
                  ? "Production manager"
                  : "Photo lead",
        detail: "The first bottleneck should belong to whoever controls the scene brief, proof hierarchy, or shoot execution.",
      },
      {
        label: "Then do",
        value: "Pair each shot with one claim",
        detail: "Every image should answer a shopper question or prove a feature instead of just adding visual variety.",
      },
      {
        label: "Watch",
        value: "Pretty-without-proof drift",
        detail: "Decorative scenes often crowd out scale, dimension, and usage proof unless someone defends the commercial hierarchy.",
      },
    ];
  }, [featureList.length, snapshot, studioReady, useCaseList.length]);

  const photoInputRows = useMemo(
    () => [
      ...photoAuditRows,
      {
        label: "Execution call",
        value: photoActionRows[0]?.value ?? "Pending",
        detail: `${photoActionRows[1]?.value ?? "Owner pending"} | ${photoActionRows[2]?.value ?? "Cadence pending"} | ${photoActionRows[3]?.value ?? "Risk pending"}`,
      },
    ],
    [photoActionRows, photoAuditRows],
  );

  const shootPriorityRows = useMemo(
    () => [
      {
        label: "Hero-first priority",
        value: useCaseList[0] || "Missing",
        detail: "The first frame should win the click before it tries to explain every feature.",
      },
      {
        label: "Top proof shot",
        value: featureList[0] || "Missing",
        detail: "This is the first feature claim the gallery should prove visually.",
      },
      {
        label: "Scale / reassurance",
        value: props[0] || "No prop selected",
        detail: "Use one scale anchor so the product feels believable in context, not abstract.",
      },
    ],
    [featureList, props, useCaseList],
  );

  const shotRows = useMemo(
    () =>
      Array.from({ length: Math.max(shotCount, 1) }).slice(0, 8).map((_, index) => ({
        label: `Shot ${index + 1}`,
        value: index < useCaseList.length ? "Use case" : index < useCaseList.length + featureList.length ? "Feature" : "Support",
        detail:
          useCaseList[index] ||
          featureList[index - useCaseList.length] ||
          props[index % Math.max(props.length, 1)] ||
          "Retouch-safe detail capture",
      })),
    [featureList, props, shotCount, useCaseList],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_0.7fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote
        lines={[
          snapshot
            ? "The live PDP now drafts the shot plan first, so you start from the current gallery gaps instead of a blank creative brief."
            : "Load a live ASIN first so the shot plan can start from the real gallery state.",
          `System draft: ${useCaseList.length} buyer scenes, ${featureList.length} proof angles, ${props.length} props.`,
          studioReady
            ? "Current setup is strong enough to move from planning into a commercial shot sequence."
            : "The main bottleneck is still production readiness, not more idea generation.",
        ]}
      />
      <DistributionPanel title="Live photo inputs" rows={photoInputRows} />
      <DistributionPanel title="This photography call" rows={photoActionRows} />
      <DistributionPanel title="Shoot priorities" rows={shootPriorityRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Creative overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Only open this when the live draft missed the real buyer scenes, proof shots, or production constraints.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((current) => !current)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide overrides" : "Adjust shot plan"}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 xl:grid-cols-[1fr_1fr]">
              <Field label="Use cases">
                <TextAreaInput value={useCases} onChange={(e) => setUseCases(e.target.value)} className="min-h-[6rem]" spellCheck={false} />
              </Field>
              <Field label="Feature priorities">
                <TextAreaInput value={features} onChange={(e) => setFeatures(e.target.value)} className="min-h-[6rem]" spellCheck={false} />
              </Field>
            </div>
            <div className="grid gap-2 md:grid-cols-3 xl:grid-cols-5">
              {["chair", "plant", "rug", "hand model", "measuring tape"].map((item) => (
                <Checkbox
                  key={item}
                  label={item}
                  checked={props.includes(item)}
                  onChange={(checked) =>
                    setProps((current) =>
                      checked ? Array.from(new Set([...current, item])) : current.filter((entry) => entry !== item),
                    )
                  }
                />
              ))}
              {["dust cleanup", "reflection cleanup", "color correction", "shadow cleanup"].map((item) => (
                <Checkbox
                  key={item}
                  label={item}
                  checked={retouchNeeds.includes(item)}
                  onChange={(checked) =>
                    setRetouchNeeds((current) =>
                      checked ? Array.from(new Set([...current, item])) : current.filter((entry) => entry !== item),
                    )
                  }
                />
              ))}
              <Checkbox label="Studio setup ready" checked={studioReady} onChange={setStudioReady} />
            </div>
          </div>
        ) : null}
      </div>
      <DistributionPanel title="Shot list" rows={shotRows} />
      <LowTokenAssistPanel
        toolSlug="amazon-product-photography"
        locale={locale}
        result={result}
        context={{
          useCases: useCaseList,
          featurePriorities: featureList,
          selectedProps: props,
          retouchNeeds,
          shotRows: summarizeDistributionRows(shotRows),
        }}
      />
    </RuntimeShell>
  );
}

function StorefrontDesignRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [catalogCount, setCatalogCount] = useState(18);
  const [collectionCount, setCollectionCount] = useState(4);
  const [navDepth, setNavDepth] = useState(2);
  const [seasonalReady, setSeasonalReady] = useState(true);
  const [brandStoryReady, setBrandStoryReady] = useState(true);
  const [storeLinkedFromBrandStory, setStoreLinkedFromBrandStory] = useState(true);
  const [experimentReady, setExperimentReady] = useState(false);
  const [segments, setSegments] = useState<string[]>(["new-to-brand", "best-seller shoppers", "style-led shoppers"]);
  const [trafficSources, setTrafficSources] = useState<string[]>(["brand-search", "sb-video", "social"]);
  const [showAdvanced, setShowAdvanced] = useState(false);
  const storefrontPlan = useMemo(() => inferStorefrontPlan(catalogCount), [catalogCount]);

  useEffect(() => {
    if (showAdvanced) {
      return;
    }
    setCollectionCount(storefrontPlan.collectionCount);
    setNavDepth(storefrontPlan.navDepth);
    setSeasonalReady(storefrontPlan.seasonalReady);
    setBrandStoryReady(storefrontPlan.brandStoryReady);
    setStoreLinkedFromBrandStory(storefrontPlan.storeLinkedFromBrandStory);
    setExperimentReady(storefrontPlan.experimentReady);
    setSegments(storefrontPlan.segments);
    setTrafficSources(storefrontPlan.trafficSources);
  }, [showAdvanced, storefrontPlan]);

  const result = useMemo(
    () =>
      evaluateStorefrontDesign({
        catalogCount,
        collectionCount,
        audienceSegmentCount: segments.length,
        trafficSourceCount: trafficSources.length,
        navDepth,
        seasonalReady,
        brandStoryReady,
        storeLinkedFromBrandStory,
        experimentReady,
      }),
    [
      brandStoryReady,
      catalogCount,
      collectionCount,
      experimentReady,
      navDepth,
      seasonalReady,
      segments.length,
      storeLinkedFromBrandStory,
      trafficSources.length,
    ],
  );

  const structureRows = useMemo(
    () =>
      Array.from({ length: Math.max(collectionCount, 1) }).slice(0, 6).map((_, index) => ({
        label: index === 0 ? "Homepage" : `Collection ${index}`,
        value: index === 0 ? "Route traffic" : segments[index % Math.max(segments.length, 1)] || "Category grouping",
        detail:
          index === 0
            ? `${trafficSources[0] || "Traffic"} landing role`
            : `${trafficSources[index % Math.max(trafficSources.length, 1)] || "Store"} traffic entry`,
      })),
    [collectionCount, segments, trafficSources],
  );

  const storefrontAuditRows = useMemo(
    () => [
      {
        label: "Catalog structure",
        value: `${catalogCount} ASINs / ${collectionCount} collections`,
        detail: `${navDepth} clicks deep before shoppers hit a leaf destination`,
      },
      {
        label: "Traffic posture",
        value: `${trafficSources.length} source lanes`,
        detail: `${segments.length} shopper segments currently mapped to the storefront`,
      },
      {
        label: "Readiness",
        value: `${brandStoryReady ? "Brand Story live" : "Brand Story gap"} / ${seasonalReady ? "Seasonal refresh ready" : "Seasonal gap"}`,
        detail: `${experimentReady ? "Experiment path open" : "No clean test path yet"} | ${storeLinkedFromBrandStory ? "Store linked" : "Link gap"}`,
      },
      {
        label: "System plan",
        value: `${storefrontPlan.collectionCount} collections / ${storefrontPlan.navDepth} depth`,
        detail: `Default draft: ${storefrontPlan.segments.join(", ")} via ${storefrontPlan.trafficSources.join(", ")}`,
      },
    ],
    [brandStoryReady, catalogCount, collectionCount, experimentReady, navDepth, seasonalReady, segments.length, storefrontPlan.collectionCount, storefrontPlan.navDepth, storefrontPlan.segments, storefrontPlan.trafficSources, storeLinkedFromBrandStory, trafficSources.length],
  );

  const storefrontActionRows = useMemo(() => {
    const firstMove =
      collectionCount < 2
        ? {
            label: "First move",
            value: "Split the store into clear collection lanes",
            detail: "A single broad storefront rarely converts mixed shopper intent well enough to justify media spend.",
          }
        : navDepth > 2
          ? {
              label: "First move",
              value: "Flatten the shopper path",
              detail: "Too much navigation depth burns paid traffic before buyers see the product set that matches their intent.",
            }
          : !storeLinkedFromBrandStory || !brandStoryReady
            ? {
                label: "First move",
                value: "Close the Brand Story to Store gap",
                detail: "You are paying for traffic and brand attention that currently does not route cleanly into the store experience.",
              }
            : !experimentReady
              ? {
                  label: "First move",
                  value: "Set one testable landing path",
                  detail: "Without a clean experiment lane, the store becomes a design artifact instead of a conversion system.",
                }
              : {
                  label: "First move",
                  value: "Assign traffic sources to collection intent",
                  detail: "The structure is good enough that the next gain comes from matching entry traffic to the right destination lane.",
                };

    return [
      firstMove,
      {
        label: "Execution owner",
        value:
          collectionCount < 2 || navDepth > 2
            ? "Storefront owner"
            : !storeLinkedFromBrandStory || !brandStoryReady
              ? "Brand content owner"
              : !experimentReady
                ? "Growth / CRO owner"
                : "Traffic strategist",
        detail: "The first repair should land with the person who controls store structure, brand routing, or landing-page testing.",
      },
      {
        label: "Do not cross",
        value:
          collectionCount < 2
            ? "Do not call one broad page a storefront strategy"
            : navDepth > 2
              ? "Do not bury paid traffic under navigation depth"
              : "Do not optimize modules before route clarity exists",
        detail:
          collectionCount < 2
            ? "A storefront with no real collection split still behaves like a catalog dump."
            : navDepth > 2
              ? "Traffic loses value fast when shoppers must click too far before finding the right leaf set."
              : "If entry lanes are unclear, more visual polish only hides the structural problem.",
      },
      {
        label: "Then do",
        value: "Give each collection one shopping job",
        detail: "Collections should separate discovery, best-seller proof, bundles, or gift intent instead of repeating the same catalog.",
      },
      {
        label: "Watch",
        value: "Homepage overload",
        detail: "Store homepages often try to explain everything and end up routing nobody well.",
      },
    ];
  }, [brandStoryReady, collectionCount, experimentReady, navDepth, storeLinkedFromBrandStory]);

  const storefrontInputRows = useMemo(
    () => [
      ...storefrontAuditRows,
      {
        label: "Execution call",
        value: storefrontActionRows[0]?.value ?? "Pending",
        detail: `${storefrontActionRows[1]?.value ?? "Owner pending"} | ${storefrontActionRows[2]?.value ?? "Cadence pending"} | ${storefrontActionRows[3]?.value ?? "Risk pending"}`,
      },
    ],
    [storefrontActionRows, storefrontAuditRows],
  );

  const routingRows = useMemo(
    () => [
      {
        label: "Homepage role",
        value: trafficSources[0] || "Unassigned",
        detail: "The home page should route the strongest traffic lane into the clearest next collection.",
      },
      {
        label: "Primary shopper lane",
        value: segments[0] || "Unassigned",
        detail: segments.length > 1 ? "The storefront can separate at least one key shopper intent from the rest." : "The store still needs a cleaner segmentation split.",
      },
      {
        label: "Navigation burden",
        value: navDepth <= 2 ? "Acceptable" : "Too deep",
        detail: `${navDepth} clicks before a shopper reaches a leaf destination.`,
      },
    ],
    [navDepth, segments, trafficSources],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <AuditNote
        lines={[
          "This page now drafts a store structure from catalog size first, so the operator starts with a usable routing plan instead of an empty architecture form.",
          `System draft: ${collectionCount} collections, ${navDepth} click depth, ${segments.length} audience lanes.`,
          experimentReady
            ? "The structure is good enough to think about landing-path testing next."
            : "The next big gain is still structural clarity, not prettier store modules.",
        ]}
      />
      <DistributionPanel title="Live storefront inputs" rows={storefrontInputRows} />
      <DistributionPanel title="This storefront call" rows={storefrontActionRows} />
      <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-3">
        <Field label="Catalog size">
          <NumberInput value={catalogCount} min="1" step="1" onChange={(e) => setCatalogCount(Number(e.target.value))} />
        </Field>
        <Checkbox label="Seasonal rotation ready" checked={seasonalReady} onChange={setSeasonalReady} />
        <Checkbox label="Experiment path ready" checked={experimentReady} onChange={setExperimentReady} />
      </div>
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Operating overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when the default structure does not match the real catalog shape, traffic mix, or brand-story routing.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowAdvanced((current) => !current)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showAdvanced ? "Hide overrides" : "Adjust structure assumptions"}
          </button>
        </div>
        {showAdvanced ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-3">
              <Field label="Collections">
                <NumberInput value={collectionCount} min="1" step="1" onChange={(e) => setCollectionCount(Number(e.target.value))} />
              </Field>
              <Field label="Nav depth">
                <NumberInput value={navDepth} min="1" step="1" onChange={(e) => setNavDepth(Number(e.target.value))} />
              </Field>
              <Checkbox label="Brand Story live" checked={brandStoryReady} onChange={setBrandStoryReady} />
              <Checkbox
                label="Store linked from Brand Story"
                checked={storeLinkedFromBrandStory}
                onChange={setStoreLinkedFromBrandStory}
              />
            </div>
            <div className="grid gap-2 md:grid-cols-3 xl:grid-cols-6">
              {["new-to-brand", "best-seller shoppers", "style-led shoppers", "bundle shoppers", "gift buyers"].map((item) => (
                <Checkbox
                  key={item}
                  label={item}
                  checked={segments.includes(item)}
                  onChange={(checked) =>
                    setSegments((current) =>
                      checked ? Array.from(new Set([...current, item])) : current.filter((entry) => entry !== item),
                    )
                  }
                />
              ))}
              {["brand-search", "sb-video", "social", "deals", "email"].map((item) => (
                <Checkbox
                  key={item}
                  label={item}
                  checked={trafficSources.includes(item)}
                  onChange={(checked) =>
                    setTrafficSources((current) =>
                      checked ? Array.from(new Set([...current, item])) : current.filter((entry) => entry !== item),
                    )
                  }
                />
              ))}
            </div>
          </div>
        ) : null}
      </div>
      <div className="grid gap-3 xl:grid-cols-[1fr_1fr]">
        <DistributionPanel title="Store structure" rows={structureRows} />
        <DistributionPanel title="Routing priorities" rows={routingRows} />
      </div>
      <LowTokenAssistPanel
        toolSlug="amazon-storefront-design"
        locale={locale}
        result={result}
        context={{
          catalogCount,
          collectionCount,
          navDepth,
          audienceSegments: segments,
          trafficSources,
          structureRows: summarizeDistributionRows(structureRows),
        }}
      />
    </RuntimeShell>
  );
}

function InternationalListingsRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("B0GYRT3FNL");
  const [sourceLocale, setSourceLocale] = useState("en-US");
  const [targetLocale, setTargetLocale] = useState("de-DE");
  const [keywordGoals, setKeywordGoals] = useState("arched mirror, bedroom mirror, floor mirror, entryway mirror");
  const [pricingReady, setPricingReady] = useState(false);
  const [localizationDepth, setLocalizationDepth] = useState(62);
  const [buildInternationalListingsReady, setBuildInternationalListingsReady] = useState(true);
  const [taxesReady, setTaxesReady] = useState(false);
  const [complianceCaveats, setComplianceCaveats] = useState<string[]>(["materials claims", "packaging language"]);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [showOverrides, setShowOverrides] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const internationalPlan = useMemo(
    () => inferInternationalListingPlan(snapshot, targetLocale),
    [snapshot, targetLocale],
  );

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }

      const nextPlan = inferInternationalListingPlan(payload, targetLocale);
      setSnapshot(payload);
      if (!showOverrides) {
        if (nextPlan.keywordGoals.length) {
          setKeywordGoals(nextPlan.keywordGoals.join(", "));
        }
        setComplianceCaveats(nextPlan.complianceCaveats);
        setLocalizationDepth(nextPlan.localizationDepth);
        setPricingReady(nextPlan.pricingReady);
        setTaxesReady(nextPlan.taxesReady);
        setBuildInternationalListingsReady(nextPlan.buildInternationalListingsReady);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  const keywordGoalList = splitKeywordPhrases(keywordGoals);
  const result = useMemo(
    () =>
      evaluateInternationalListings({
        keywordGoalCount: keywordGoalList.length,
        complianceCaveatCount: complianceCaveats.length,
        pricingReady,
        localizationDepth,
        targetLocale,
        sourceLocale,
        buildInternationalListingsReady,
        taxesReady,
      }),
    [buildInternationalListingsReady, complianceCaveats.length, keywordGoalList.length, localizationDepth, pricingReady, sourceLocale, targetLocale, taxesReady],
  );

  const adaptationRows = useMemo(
    () =>
      keywordGoalList.slice(0, 6).map((item, index) => ({
        label: item,
        value: index < complianceCaveats.length ? "Check compliance" : "Localize intent",
        detail: complianceCaveats[index] || `Adapt buyer language for ${targetLocale}`,
      })),
    [complianceCaveats, keywordGoalList, targetLocale],
  );

  const internationalAuditRows = useMemo(
    () => [
      {
        label: "Source / target",
        value: `${sourceLocale} -> ${targetLocale}`,
        detail: snapshot ? "Backed by a live source listing" : "Load the source listing first for a stronger localization baseline",
      },
      {
        label: "Keyword goals",
        value: `${keywordGoalList.length}`,
        detail: keywordGoalList.length ? "Current buyer-intent goals in scope for the target locale" : "Need stronger target-market keyword goals",
      },
      {
        label: "Pricing / tax stack",
        value: `${pricingReady ? "Pricing ready" : "Pricing gap"} / ${taxesReady ? "Tax ready" : "Tax gap"}`,
        detail: buildInternationalListingsReady ? "Build International Listings path available" : "Cross-market operating path still weak",
      },
      {
        label: "Localization depth",
        value: `${localizationDepth}%`,
        detail: `${complianceCaveats.length} compliance caveats currently tagged`,
      },
    ],
    [
      buildInternationalListingsReady,
      complianceCaveats.length,
      keywordGoalList.length,
      localizationDepth,
      pricingReady,
      snapshot,
      sourceLocale,
      targetLocale,
      taxesReady,
    ],
  );

  const internationalActionRows = useMemo(() => {
    const firstMove =
      !snapshot
        ? {
            label: "First move",
            value: "Load the live source listing first",
            detail: "Cross-market adaptation is weaker when keyword goals and claims are not grounded in the real source PDP.",
          }
        : !pricingReady
        ? {
            label: "First move",
            value: "Set local price, fee, and tax context",
            detail: "A well-translated page can still be commercially wrong if local economics are missing.",
          }
        : !taxesReady || complianceCaveats.length > 2
          ? {
              label: "First move",
              value: "Resolve policy and tax caveats",
              detail: "Cross-market copy that outruns compliance creates expensive cleanup later.",
            }
          : localizationDepth < 60
            ? {
                label: "First move",
                value: "Rewrite for local buyer intent",
                detail: "Shallow localization usually misses target-market search behavior and objections.",
              }
            : !buildInternationalListingsReady
              ? {
                  label: "First move",
                  value: "Fix the operating path",
                  detail: "A workable localized page still stalls if catalog sync and publishing flow are not ready.",
                }
              : {
                  label: "First move",
                  value: `Launch the ${targetLocale} draft`,
                  detail: "The remaining work is execution discipline rather than another broad localization pass.",
                };

    return [
      firstMove,
      {
        label: "Execution owner",
        value:
          !snapshot
            ? "Catalog / listing owner"
            : !pricingReady
              ? "Finance / marketplace ops"
              : !taxesReady || complianceCaveats.length > 2
                ? "Compliance / tax"
                : localizationDepth < 60
                  ? "Localization / content"
                  : "Catalog operations",
        detail: "The first blocker should belong to one owner before the team starts polishing copy in parallel.",
      },
      {
        label: "Then do",
        value: "QA the top keyword and claim layer",
        detail: "Check the highest-value search terms and strongest claims first before polishing smaller wording differences.",
      },
      {
        label: "Watch",
        value: !snapshot ? "Source-baseline drift" : "Literal-translation drift",
        detail: !snapshot
          ? "If the source PDP is weak or missing, the localized version can inherit bad claims and weak keyword priorities."
          : "Keep checking whether the page still sounds translated instead of natively targeted to the market.",
      },
    ];
  }, [buildInternationalListingsReady, complianceCaveats.length, localizationDepth, pricingReady, snapshot, targetLocale, taxesReady]);

  const internationalInputRows = useMemo(
    () => [
      ...internationalAuditRows,
      {
        label: "Execution call",
        value: internationalActionRows[0]?.value ?? "Localization decision pending",
        detail: internationalActionRows[1]?.value
          ? `${internationalActionRows[1].value} owns the first blocked step.`
          : "Assign one localization owner before expanding the market plan.",
      },
    ],
    [internationalActionRows, internationalAuditRows],
  );

  const marketReadinessRows = useMemo(
    () => [
      {
        label: "Localization readiness",
        value: localizationDepth >= 75 ? "Launchable" : localizationDepth >= 60 ? "Needs polish" : "Too shallow",
        detail: "This is a read on local buyer intent adaptation, not just literal translation.",
      },
      {
        label: "Policy / tax pressure",
        value: !taxesReady || complianceCaveats.length > 2 ? "Blocked" : "Workable",
        detail: `${complianceCaveats.length} compliance caveats currently tagged for the target locale.`,
      },
      {
        label: "Publishing path",
        value: buildInternationalListingsReady ? "Ready" : "Blocked",
        detail: "A strong localized draft still needs a clean catalog-sync and publishing path.",
      },
    ],
    [buildInternationalListingsReady, complianceCaveats.length, localizationDepth, taxesReady],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1fr_0.7fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote
        lines={[
          snapshot
            ? "The live source PDP now drafts target-market keyword goals and caveats before you touch localization planning."
            : "Load the live source listing first so localization starts from the real PDP instead of a guessed keyword brief.",
          `System draft: ${keywordGoalList.length} keyword goals, ${complianceCaveats.length} compliance caveats, ${localizationDepth}% localization depth.`,
          !pricingReady || !taxesReady
            ? "Commercial and regulatory readiness are still the main blockers, not phrasing polish."
            : "The next check is local-market fit, not raw translation completeness.",
        ]}
      />
      <DistributionPanel title="Live localization inputs" rows={internationalInputRows} />
      <DistributionPanel title="This localization call" rows={internationalActionRows} />
      <DistributionPanel title="Market readiness" rows={marketReadinessRows} />
      <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-[1fr_1fr_auto]">
        <Field label="Source locale">
          <SelectInput value={sourceLocale} onChange={(e) => setSourceLocale(e.target.value)}>
            <option value="en-US">en-US</option>
            <option value="zh-CN">zh-CN</option>
            <option value="de-DE">de-DE</option>
            <option value="ja-JP">ja-JP</option>
          </SelectInput>
        </Field>
        <Field label="Target locale">
          <SelectInput value={targetLocale} onChange={(e) => setTargetLocale(e.target.value)}>
            <option value="de-DE">de-DE</option>
            <option value="fr-FR">fr-FR</option>
            <option value="en-GB">en-GB</option>
            <option value="ja-JP">ja-JP</option>
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowOverrides((current) => !current)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide overrides" : "Adjust localization assumptions"}
          </button>
        </div>
      </div>
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Localization overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when the live source listing missed the true keyword goals, compliance caveats, or market-readiness assumptions.
            </p>
          </div>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-4">
              <Field label="Localization depth">
                <NumberInput value={localizationDepth} min="0" max="100" step="1" onChange={(e) => setLocalizationDepth(Number(e.target.value))} />
              </Field>
              <Checkbox label="Pricing context ready" checked={pricingReady} onChange={setPricingReady} />
              <Checkbox label="Build International Listings ready" checked={buildInternationalListingsReady} onChange={setBuildInternationalListingsReady} />
              <Checkbox label="Tax and regulation path ready" checked={taxesReady} onChange={setTaxesReady} />
            </div>
            <div className="grid gap-2.5 xl:grid-cols-[1.2fr_1fr]">
              <Field label="Keyword goals">
                <TextAreaInput value={keywordGoals} onChange={(e) => setKeywordGoals(e.target.value)} className="min-h-[6rem]" spellCheck={false} />
              </Field>
              <div className="grid gap-2 md:grid-cols-2">
                {["materials claims", "packaging language", "electrical standards", "restricted words"].map((item) => (
                  <Checkbox
                    key={item}
                    label={item}
                    checked={complianceCaveats.includes(item)}
                    onChange={(checked) =>
                      setComplianceCaveats((current) =>
                        checked ? Array.from(new Set([...current, item])) : current.filter((entry) => entry !== item),
                      )
                    }
                  />
                ))}
              </div>
            </div>
          </div>
        ) : null}
      </div>
      <DistributionPanel title="Adaptation checklist" rows={adaptationRows} />
      <LowTokenAssistPanel
        toolSlug="amazon-international-listings"
        locale={locale}
        result={result}
        context={{
          sourceLocale,
          targetLocale,
          keywordGoals: keywordGoalList,
          complianceCaveats,
          localizationDepth,
          pricingReady,
          liveTitle: snapshot?.title ?? "",
        }}
      />
    </RuntimeShell>
  );
}

function BrandTailoredPromotionsRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [productCount, setProductCount] = useState(3);
  const [discountBudget, setDiscountBudget] = useState(900);
  const [discountRate, setDiscountRate] = useState(0.15);
  const [retentionGoalScore, setRetentionGoalScore] = useState(76);
  const [audienceDataReady, setAudienceDataReady] = useState(true);
  const [audienceSize, setAudienceSize] = useState(3600);
  const [activePromotionCount, setActivePromotionCount] = useState(4);
  const [brandRepresentative, setBrandRepresentative] = useState(true);
  const [segments, setSegments] = useState<string[]>(["repeat-buyers", "lapsed-buyers", "high-aov"]);
  const [channels, setChannels] = useState<string[]>(["email", "manage-customer-engagement", "brand-followers"]);
  const [showOverrides, setShowOverrides] = useState(false);
  const promotionPlan = useMemo(
    () => inferBrandPromotionPlan({ productCount, audienceSize, activePromotionCount }),
    [activePromotionCount, audienceSize, productCount],
  );

  useEffect(() => {
    if (showOverrides) {
      return;
    }
    setDiscountBudget(promotionPlan.discountBudget);
    setDiscountRate(promotionPlan.discountRate);
    setRetentionGoalScore(promotionPlan.retentionGoalScore);
    setAudienceDataReady(promotionPlan.audienceDataReady);
    setBrandRepresentative(promotionPlan.brandRepresentative);
    setSegments(promotionPlan.segments);
    setChannels(promotionPlan.channels);
  }, [promotionPlan, showOverrides]);

  const result = useMemo(
    () =>
      evaluateBrandTailoredPromotions({
        segmentCount: segments.length,
        productCount,
        discountBudget,
        retentionGoalScore,
        audienceDataReady,
        channelCount: channels.length,
        audienceSize,
        discountRate,
        brandRepresentative,
        activePromotionCount,
      }),
    [activePromotionCount, audienceDataReady, audienceSize, brandRepresentative, channels.length, discountBudget, discountRate, productCount, retentionGoalScore, segments.length],
  );

  const segmentRows = useMemo(
    () =>
      segments.map((segment, index) => ({
        label: segment,
        value: `${Math.max(5, Math.round(discountBudget / Math.max(productCount, 1) / 10) * 10)} budget slice`,
        detail: `${channels[index % Math.max(channels.length, 1)] || "Email"} | retention focus ${retentionGoalScore}%`,
      })),
    [channels, discountBudget, productCount, retentionGoalScore, segments],
  );

  const promotionAuditRows = useMemo(
    () => [
      {
        label: "Audience base",
        value: `${audienceSize} people / ${segments.length} segments`,
        detail: audienceDataReady ? "Audience data exists, so segmentation can be operational instead of theoretical." : "Audience data is still thin, which makes offer targeting noisy.",
      },
      {
        label: "Offer pressure",
        value: `${Math.round(discountRate * 100)}% off / ${formatUsd(discountBudget)}`,
        detail: `${productCount} products in scope | ${activePromotionCount} active promotions already running`,
      },
      {
        label: "Delivery lanes",
        value: `${channels.length} channels`,
        detail: `${brandRepresentative ? "Brand role ready" : "Brand role gap"} | retention goal ${retentionGoalScore}%`,
      },
    ],
    [activePromotionCount, audienceDataReady, audienceSize, brandRepresentative, channels.length, discountBudget, discountRate, productCount, retentionGoalScore, segments.length],
  );

  const promotionActionRows = useMemo(() => {
    const firstMove =
      !audienceDataReady || audienceSize < 1000
        ? {
            label: "First move",
            value: "Fix audience quality before offer design",
            detail: "Weak audience definition makes discounting expensive and hard to learn from.",
          }
        : activePromotionCount > 5
          ? {
              label: "First move",
              value: "Reduce overlapping promotions",
              detail: "Too many concurrent offers blur incrementality and train shoppers to wait for discounts.",
            }
          : discountRate > 0.2
            ? {
                label: "First move",
                value: "Protect margin before going deeper",
                detail: "A broad discount can hide weak targeting while damaging contribution profit.",
              }
            : segments.length < 2
              ? {
                  label: "First move",
                  value: "Split one retention segment from one recovery segment",
                  detail: "Different buyer states need different promotional jobs and should not share the same message.",
                }
              : {
                  label: "First move",
                  value: "Launch one segment-channel pair first",
                  detail: "The setup is strong enough to run a controlled promo instead of planning endlessly in the abstract.",
                };

    return [
      firstMove,
      {
        label: "Execution owner",
        value:
          !audienceDataReady || audienceSize < 1000
            ? "CRM / audience ops"
            : activePromotionCount > 5
              ? "Promotion owner"
              : discountRate > 0.2
                ? "Margin / finance owner"
                : segments.length < 2
                  ? "Lifecycle marketer"
                  : "Retention lead",
        detail: "The first promotion blocker should belong to the team that owns audience quality, discount pressure, or segment design.",
      },
      {
        label: "Then do",
        value: "Hold out one clean control group",
        detail: "You need a believable baseline to know whether the promotion created lift or just subsidized existing demand.",
      },
      {
        label: "Watch",
        value: "Discount fatigue",
        detail: "Tailored promos stop feeling tailored once the same audience sees frequent broad discounts.",
      },
    ];
  }, [activePromotionCount, audienceDataReady, audienceSize, discountRate, segments.length]);

  const promotionInputRows = useMemo(
    () => [
      ...promotionAuditRows,
      {
        label: "Execution call",
        value: promotionActionRows[0]?.value ?? "Promotion decision pending",
        detail: promotionActionRows[1]?.value
          ? `${promotionActionRows[1].value} owns the first promo blocker until the same segment test is rechecked.`
          : "Put one retention owner on the first test before widening the segment plan.",
      },
    ],
    [promotionActionRows, promotionAuditRows],
  );

  const promoReadinessRows = useMemo(
    () => [
      {
        label: "Audience quality",
        value: !audienceDataReady || audienceSize < 1000 ? "Weak" : audienceSize >= 3000 ? "Strong" : "Borderline",
        detail: `${audienceSize} people across ${segments.length} segments in the current plan.`,
      },
      {
        label: "Discount pressure",
        value: discountRate > 0.2 ? "Too deep" : discountRate >= 0.12 ? "Moderate" : "Controlled",
        detail: `${activePromotionCount} active promotions are already competing for the same buyers.`,
      },
      {
        label: "Launch shape",
        value: segments.length >= 2 && channels.length >= 2 ? "Testable" : "Too narrow",
        detail: "Keep one segment-channel experiment easy to run and easy to judge before widening the retention plan.",
      },
    ],
    [activePromotionCount, audienceDataReady, audienceSize, channels.length, discountRate, segments.length],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <AuditNote
        lines={[
          "This page now drafts a default retention-promo structure from audience size, active-promo load, and product scope before asking for manual campaign design.",
          `System draft: ${segments.length} segments, ${channels.length} channels, ${Math.round(discountRate * 100)}% discount.`,
          !audienceDataReady
            ? "Audience quality is still the first blocker, so deeper promo design would be premature."
            : "The next job is controlled testing, not endlessly rearranging promo ideas.",
        ]}
      />
      <DistributionPanel title="Live promotion inputs" rows={promotionInputRows} />
      <DistributionPanel title="This promotion call" rows={promotionActionRows} />
      <DistributionPanel title="Promotion readiness" rows={promoReadinessRows} />
      <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-3">
        <Field label="Target products">
          <NumberInput value={productCount} min="0" step="1" onChange={(e) => setProductCount(Number(e.target.value))} />
        </Field>
        <Field label="Audience size">
          <NumberInput value={audienceSize} min="0" step="100" onChange={(e) => setAudienceSize(Number(e.target.value))} />
        </Field>
        <Field label="Active promos">
          <NumberInput value={activePromotionCount} min="0" step="1" onChange={(e) => setActivePromotionCount(Number(e.target.value))} />
        </Field>
      </div>
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Promotion overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when the real segment map, channel mix, or discount posture is materially different from the system draft.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((current) => !current)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide overrides" : "Adjust promo assumptions"}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-5">
              <Field label="Discount budget">
                <NumberInput value={discountBudget} min="0" step="50" onChange={(e) => setDiscountBudget(Number(e.target.value))} />
              </Field>
              <Field label="Discount rate">
                <NumberInput value={discountRate} min="0" max="1" step="0.01" onChange={(e) => setDiscountRate(Number(e.target.value))} />
              </Field>
              <Field label="Retention goal score">
                <NumberInput value={retentionGoalScore} min="0" max="100" step="1" onChange={(e) => setRetentionGoalScore(Number(e.target.value))} />
              </Field>
              <Checkbox label="Audience data ready" checked={audienceDataReady} onChange={setAudienceDataReady} />
              <Checkbox label="Brand Representative ready" checked={brandRepresentative} onChange={setBrandRepresentative} />
            </div>
            <div className="grid gap-2 md:grid-cols-3 xl:grid-cols-6">
              {["repeat-buyers", "lapsed-buyers", "high-aov", "recent-viewers", "brand-followers"].map((item) => (
                <Checkbox
                  key={item}
                  label={item}
                  checked={segments.includes(item)}
                  onChange={(checked) =>
                    setSegments((current) =>
                      checked ? Array.from(new Set([...current, item])) : current.filter((entry) => entry !== item),
                    )
                  }
                />
              ))}
              {["email", "manage-customer-engagement", "brand-followers", "coupon-audience"].map((item) => (
                <Checkbox
                  key={item}
                  label={item}
                  checked={channels.includes(item)}
                  onChange={(checked) =>
                    setChannels((current) =>
                      checked ? Array.from(new Set([...current, item])) : current.filter((entry) => entry !== item),
                    )
                  }
                />
              ))}
            </div>
          </div>
        ) : null}
      </div>
      <DistributionPanel title="Segment offer plan" rows={segmentRows} />
    </RuntimeShell>
  );
}

function SubscribeSaveRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [asinOrUrl, setAsinOrUrl] = useState("");
  const [productType, setProductType] = useState("consumable");
  const [repeatIntervalDays, setRepeatIntervalDays] = useState(30);
  const [currentDiscountRate, setCurrentDiscountRate] = useState(0.1);
  const [repeatOrderRate, setRepeatOrderRate] = useState(0.18);
  const [marginRate, setMarginRate] = useState(28);
  const [churnRiskScore, setChurnRiskScore] = useState(34);
  const [brandRepresentative, setBrandRepresentative] = useState(true);
  const [inStockRate, setInStockRate] = useState(96);
  const [offerBuyable, setOfferBuyable] = useState(true);
  const [fbmMetricsReady, setFbmMetricsReady] = useState(true);
  const [snapshot, setSnapshot] = useState<AmazonListingSnapshot | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [showOverrides, setShowOverrides] = useState(false);
  const subscribeSnapshotPlan = useMemo(() => inferSubscribeSnapshotPlan(snapshot), [snapshot]);
  const subscribePlan = useMemo(
    () => inferSubscribePlan({ productType, inStockRate, offerBuyable }),
    [inStockRate, offerBuyable, productType],
  );

  async function loadListing() {
    try {
      setLoading(true);
      setError("");
      const response = await fetch(
        `/api/amazon-listing?marketplace=${encodeURIComponent(marketplace)}&asinOrUrl=${encodeURIComponent(asinOrUrl)}`,
      );
      const payload = (await response.json()) as AmazonListingSnapshot | { error: string };
      if (!response.ok || "error" in payload) {
        throw new Error("error" in payload ? payload.error : "Failed to load live listing.");
      }

      setSnapshot(payload);
      if (!showOverrides) {
        const nextSnapshotPlan = inferSubscribeSnapshotPlan(payload);
        setProductType(nextSnapshotPlan.productType);
        setInStockRate(nextSnapshotPlan.inStockRate);
        setOfferBuyable(nextSnapshotPlan.offerBuyable);
      }
    } catch (fetchError) {
      setSnapshot(null);
      setError(fetchError instanceof Error ? fetchError.message : "Failed to load live listing.");
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    if (showOverrides) {
      return;
    }
    setRepeatIntervalDays(subscribePlan.repeatIntervalDays);
    setCurrentDiscountRate(subscribePlan.currentDiscountRate);
    setRepeatOrderRate(subscribePlan.repeatOrderRate);
    setMarginRate(subscribePlan.marginRate);
    setChurnRiskScore(subscribePlan.churnRiskScore);
    setBrandRepresentative(subscribePlan.brandRepresentative);
    setFbmMetricsReady(subscribePlan.fbmMetricsReady);
  }, [showOverrides, subscribePlan]);

  const result = useMemo(
    () =>
      evaluateSubscribeSave({
        repeatIntervalDays,
        currentDiscountRate,
        repeatOrderRate,
        marginRate,
        churnRiskScore,
        consumable: productType !== "one-off",
        brandRepresentative,
        inStockRate,
        offerBuyable,
        fbmMetricsReady,
      }),
    [brandRepresentative, churnRiskScore, currentDiscountRate, fbmMetricsReady, inStockRate, marginRate, offerBuyable, productType, repeatIntervalDays, repeatOrderRate],
  );

  const ladderRows = useMemo(
    () => [
      {
        label: "First subscribe touch",
        value: `${Math.round(currentDiscountRate * 100)}% off`,
        detail: repeatIntervalDays <= 45 ? "Prompt close to the reorder window" : "Delay harder until reorder intent is clearer",
      },
      {
        label: "Retention guardrail",
        value: `${Math.max(5, Math.round(marginRate - currentDiscountRate * 100))}% margin left`,
        detail: churnRiskScore > 60 ? "Prioritize churn control before deeper discounts" : "Margin can support a controlled retention offer",
      },
      {
        label: "Best target",
        value: productType === "consumable" ? "Repeat buyers" : "Only proven repeat cohorts",
        detail: `${Math.round(repeatOrderRate * 100)}% repeat baseline`,
      },
    ],
    [churnRiskScore, currentDiscountRate, marginRate, productType, repeatIntervalDays, repeatOrderRate],
  );

  const subscribeAuditRows = useMemo(
    () => [
      {
        label: "Offer fit",
        value: `${productType} / ${repeatIntervalDays} days`,
        detail: `${Math.round(repeatOrderRate * 100)}% repeat rate currently assumed`,
      },
      {
        label: "Economics",
        value: `${Math.round(currentDiscountRate * 100)}% off / ${marginRate}% margin`,
        detail: `${Math.max(0, Math.round(marginRate - currentDiscountRate * 100))}% margin left after the recurring discount`,
      },
      {
        label: "Operational risk",
        value: `${inStockRate}% in stock / churn ${churnRiskScore}`,
        detail: `${offerBuyable ? "Offer buyable" : "Buyability gap"} | ${brandRepresentative ? "Brand role ready" : "Brand role gap"} | ${fbmMetricsReady ? "Ops metrics ready" : "Ops data gap"}`,
      },
    ],
    [brandRepresentative, churnRiskScore, currentDiscountRate, fbmMetricsReady, inStockRate, marginRate, offerBuyable, productType, repeatIntervalDays, repeatOrderRate],
  );

  const subscribeActionRows = useMemo(() => {
    const firstMove =
      productType === "one-off"
        ? {
            label: "First move",
            value: "Do not force Subscribe & Save broadly",
            detail: "Low-repeat products rarely become healthier just because you add a recurring discount wrapper.",
          }
        : inStockRate < 92
          ? {
              label: "First move",
              value: "Fix in-stock reliability",
              detail: "Recurring enrollment with unstable availability creates churn and support damage faster than it creates LTV.",
            }
          : churnRiskScore > 60
            ? {
                label: "First move",
                value: "Stabilize the reorder experience",
                detail: "High churn means the retention problem sits in product or delivery experience before discount depth.",
              }
            : marginRate - currentDiscountRate * 100 < 12
              ? {
                  label: "First move",
                  value: "Protect contribution margin",
                  detail: "Recurring discounts with little remaining margin create the appearance of loyalty while weakening the business.",
                }
              : {
                  label: "First move",
                  value: "Target the highest-repeat cohort first",
                  detail: "The setup is workable enough to test enrollment where reorder intent already exists.",
                };

    return [
      firstMove,
      {
        label: "Execution owner",
        value:
          productType === "one-off"
            ? "Category / offer owner"
            : inStockRate < 92
              ? "Inventory / ops owner"
              : churnRiskScore > 60
                ? "CX / retention owner"
                : marginRate - currentDiscountRate * 100 < 12
                  ? "Finance / margin owner"
                  : "Lifecycle marketer",
        detail: "The first Subscribe & Save blocker should belong to the team that controls repeat fit, stock stability, retention, or margin guardrails.",
      },
      {
        label: "Then do",
        value: "Match the offer window to reorder timing",
        detail: "The enrollment prompt should appear near actual replenishment need, not just wherever traffic is highest.",
      },
      {
        label: "Watch",
        value: "Discount-led churn masking",
        detail: "A short-term lift can hide an offer that trains low-quality recurring subscribers.",
      },
    ];
  }, [churnRiskScore, currentDiscountRate, inStockRate, marginRate, productType]);

  const subscribeInputRows = useMemo(
    () => [
      ...subscribeAuditRows,
      {
        label: "Execution call",
        value: subscribeActionRows[0]?.value ?? "Subscription decision pending",
        detail: subscribeActionRows[1]?.value
          ? `${subscribeActionRows[1].value} owns the first enrollment blocker until the same recurring-offer baseline is rechecked.`
          : "Name one owner before widening the recurring-offer experiment.",
      },
    ],
    [subscribeActionRows, subscribeAuditRows],
  );

  const cohortRows = useMemo(
    () => [
      {
        label: "Repeat-fit verdict",
        value: productType === "one-off" ? "Weak" : repeatOrderRate >= 0.2 ? "Strong" : "Borderline",
        detail: productType === "one-off"
          ? "This product behaves more like a one-time purchase than a recurring habit."
          : `${Math.round(repeatOrderRate * 100)}% repeat baseline with a ${repeatIntervalDays}-day reorder rhythm.`,
      },
      {
        label: "Margin after discount",
        value: `${Math.max(0, Math.round(marginRate - currentDiscountRate * 100))}%`,
        detail: marginRate - currentDiscountRate * 100 < 12
          ? "The recurring discount is eating too much contribution."
          : "There is enough room to test a recurring incentive without immediately harming contribution.",
      },
      {
        label: "Retention risk",
        value: churnRiskScore > 60 ? "High" : churnRiskScore > 40 ? "Medium" : "Low",
        detail: inStockRate < 92
          ? "Inventory instability is still a more urgent risk than discount tuning."
          : "Current churn risk should shape how aggressive the first enrollment offer becomes.",
      },
    ],
    [churnRiskScore, currentDiscountRate, inStockRate, marginRate, productType, repeatIntervalDays, repeatOrderRate],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 md:grid-cols-[1.4fr_0.8fr_auto] xl:grid-cols-[1.6fr_0.8fr_auto]">
        <Field label="ASIN or Amazon product URL">
          <TextInput value={asinOrUrl} onChange={(e) => setAsinOrUrl(e.target.value)} placeholder="Paste an ASIN or Amazon URL" />
        </Field>
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <div className="grid content-end">
          <ActionButton type="button" onClick={loadListing} disabled={loading || !asinOrUrl.trim()}>
            {liveListingButtonLabel(locale, loading)}
          </ActionButton>
        </div>
      </div>
      <SnapshotPanel snapshot={snapshot} error={error} loading={loading} />
      <AuditNote
        lines={[
          snapshot
            ? "The live PDP now drafts product type, buyability, and stock posture before the recurring-offer logic kicks in."
            : "This page now drafts a default Subscribe & Save posture from product type, stock reliability, and buyability before asking for manual tuning.",
          snapshot
            ? `Snapshot draft: ${subscribeSnapshotPlan.productType}, ${subscribeSnapshotPlan.inStockRate}% in stock, ${subscribeSnapshotPlan.offerBuyable ? "offer buyable" : "buyability gap"}.`
            : "",
          `System draft: ${repeatIntervalDays}-day interval, ${Math.round(currentDiscountRate * 100)}% discount, ${Math.round(repeatOrderRate * 100)}% repeat baseline.`,
          churnRiskScore > 60
            ? "Retention risk is still the main blocker, so deeper discount tuning would be premature."
            : "The next question is cohort targeting quality, not raw enrollment mechanics.",
        ].filter(Boolean)}
      />
      <DistributionPanel title="Live subscription inputs" rows={subscribeInputRows} />
      <DistributionPanel title="This subscription call" rows={subscribeActionRows} />
      <DistributionPanel title="Cohort economics" rows={cohortRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Enrollment overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when the real reorder cadence, repeat baseline, churn profile, or margin guardrails differ from the system draft.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((current) => !current)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide overrides" : "Adjust enrollment assumptions"}
          </button>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-6">
              <Field label="Product type">
                <SelectInput value={productType} onChange={(e) => setProductType(e.target.value)}>
                  <option value="consumable">Consumable</option>
                  <option value="replenishable">Replenishable durable</option>
                  <option value="one-off">Mostly one-off</option>
                </SelectInput>
              </Field>
              <Field label="28d in-stock rate">
                <NumberInput value={inStockRate} min="0" max="100" step="1" onChange={(e) => setInStockRate(Number(e.target.value))} />
              </Field>
              <Checkbox label="Offer buyable now" checked={offerBuyable} onChange={setOfferBuyable} />
              <Field label="Repeat interval (days)">
                <NumberInput value={repeatIntervalDays} min="1" step="1" onChange={(e) => setRepeatIntervalDays(Number(e.target.value))} />
              </Field>
              <Field label="Current discount">
                <NumberInput value={currentDiscountRate} min="0" max="1" step="0.01" onChange={(e) => setCurrentDiscountRate(Number(e.target.value))} />
              </Field>
              <Field label="Repeat-order rate">
                <NumberInput value={repeatOrderRate} min="0" max="1" step="0.01" onChange={(e) => setRepeatOrderRate(Number(e.target.value))} />
              </Field>
              <Field label="Net margin %">
                <NumberInput value={marginRate} min="0" max="100" step="1" onChange={(e) => setMarginRate(Number(e.target.value))} />
              </Field>
              <Field label="Churn risk score">
                <NumberInput value={churnRiskScore} min="0" max="100" step="1" onChange={(e) => setChurnRiskScore(Number(e.target.value))} />
              </Field>
              <Checkbox label="Brand Representative ready" checked={brandRepresentative} onChange={setBrandRepresentative} />
              <Checkbox label="FBM metrics ready" checked={fbmMetricsReady} onChange={setFbmMetricsReady} />
            </div>
          </div>
        ) : null}
      </div>
      <DistributionPanel title="Enrollment ladder" rows={ladderRows} />
    </RuntimeShell>
  );
}

function PrivateLabelRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [idea, setIdea] = useState("arched full length mirror");
  const [wedge, setWedge] = useState("small apartments needing a full-length mirror with a low-footprint stand");
  const [differentiationAngle, setDifferentiationAngle] = useState("safer packaging, tighter footprint, and easier bedroom placement than bulky alternatives");
  const [sourcingRegion, setSourcingRegion] = useState("China");
  const [targetPriceBand, setTargetPriceBand] = useState("80-150");
  const [demandScore, setDemandScore] = useState(72);
  const [differentiationScore, setDifferentiationScore] = useState(61);
  const [sourcingConfidence, setSourcingConfidence] = useState(68);
  const [launchBudget, setLaunchBudget] = useState(9000);
  const [brandReady, setBrandReady] = useState(true);
  const [gtinExemptionReady, setGtinExemptionReady] = useState(true);
  const [permanentBrandingReady, setPermanentBrandingReady] = useState(true);
  const [complianceItems, setComplianceItems] = useState<string[]>(["fragile-packaging", "materials-claims"]);
  const [showOverrides, setShowOverrides] = useState(false);
  const compliancePrefillRef = useRef("");
  const privateLabelPlan = useMemo(
    () =>
      inferPrivateLabelLaunchPlan({
        idea,
        wedge,
        differentiationAngle,
        sourcingRegion,
        targetPriceBand,
      }),
    [differentiationAngle, idea, sourcingRegion, targetPriceBand, wedge],
  );
  const privateLabelDecisionPlan = useMemo(
    () =>
      inferPrivateLabelDecisionPlan({
        demandScore,
        differentiationScore,
        sourcingConfidence,
        launchBudget,
        complianceCount: complianceItems.length,
        brandReady,
        gtinExemptionReady,
        permanentBrandingReady,
      }),
    [
      brandReady,
      complianceItems.length,
      demandScore,
      differentiationScore,
      gtinExemptionReady,
      launchBudget,
      permanentBrandingReady,
      sourcingConfidence,
    ],
  );

  useEffect(() => {
    if (showOverrides || !idea.trim()) {
      return;
    }
    setDemandScore(privateLabelPlan.demandScore);
    setDifferentiationScore(privateLabelPlan.differentiationScore);
    setSourcingConfidence(privateLabelPlan.sourcingConfidence);
    setLaunchBudget(privateLabelPlan.launchBudget);
    setBrandReady(privateLabelPlan.brandReady);
    setGtinExemptionReady(privateLabelPlan.gtinExemptionReady);
    setPermanentBrandingReady(privateLabelPlan.permanentBrandingReady);
  }, [idea, privateLabelPlan, showOverrides]);

  const inferredComplianceItems = useMemo(
    () => inferPrivateLabelComplianceItems(`${idea} ${differentiationAngle}`),
    [differentiationAngle, idea],
  );

  useEffect(() => {
    if (!idea.trim() || !inferredComplianceItems.length) {
      return;
    }

    const currentKey = inferredComplianceItems.join("|");
    if (compliancePrefillRef.current === currentKey) {
      return;
    }

    setComplianceItems((current) => {
      const currentSet = new Set(current);
      const defaultSet = new Set(["fragile-packaging", "materials-claims"]);
      const stillDefault =
        current.length <= defaultSet.size &&
        current.every((item) => defaultSet.has(item));
      return stillDefault ? inferredComplianceItems : uniqueNonEmpty([...current, ...inferredComplianceItems]);
    });
    compliancePrefillRef.current = currentKey;
  }, [idea, inferredComplianceItems]);

  const result = useMemo(
    () =>
      evaluatePrivateLabel({
        demandScore,
        differentiationScore,
        sourcingConfidence,
        launchBudget,
        complianceCount: complianceItems.length,
        brandReady,
        gtinExemptionReady,
        permanentBrandingReady,
      }),
    [brandReady, complianceItems.length, demandScore, differentiationScore, gtinExemptionReady, launchBudget, permanentBrandingReady, sourcingConfidence],
  );

  const launchRows = useMemo(
    () => [
      {
        label: "Validation",
        value: `${demandScore}%`,
        detail: `${idea} demand proof`,
      },
      {
        label: "Differentiation",
        value: `${differentiationScore}%`,
        detail: differentiationScore < 55 ? "Strengthen offer gap before launch" : "Gap is usable enough for positioning",
      },
      {
        label: "Ops readiness",
        value: `${sourcingConfidence}%`,
        detail: brandReady ? "Brand path ready" : "Brand path still missing work",
      },
    ],
    [brandReady, demandScore, differentiationScore, idea, sourcingConfidence],
  );

  const privateLabelAuditRows = useMemo(
    () => [
      {
        label: "Idea posture",
        value: idea,
        detail: `${demandScore}% demand confidence | ${differentiationScore}% differentiation confidence`,
      },
      {
        label: "Launch wedge",
        value: wedge,
        detail: differentiationAngle,
      },
      {
        label: "Launch pressure",
        value: `${formatUsd(launchBudget)} / sourcing ${sourcingConfidence}%`,
        detail: `${complianceItems.length} compliance vectors already tagged${inferredComplianceItems.length ? ` | ${inferredComplianceItems.length} system-detected from the product idea` : ""}`,
      },
      {
        label: "Account readiness",
        value: `${brandReady ? "Brand path ready" : "Brand path gap"} / ${gtinExemptionReady ? "GTIN path ready" : "GTIN gap"}`,
        detail: `${sourcingRegion} sourcing | ${targetPriceBand} price band | ${permanentBrandingReady ? "Permanent branding plan exists" : "Permanent branding still unresolved"}`,
      },
      {
        label: "Launch call",
        value: privateLabelDecisionPlan.launchDecision,
        detail: `${privateLabelDecisionPlan.proofPriority} | ${privateLabelDecisionPlan.launchCadence}`,
      },
    ],
    [brandReady, complianceItems.length, demandScore, differentiationAngle, differentiationScore, gtinExemptionReady, idea, launchBudget, permanentBrandingReady, privateLabelDecisionPlan, sourcingConfidence, sourcingRegion, targetPriceBand, wedge],
  );

  const privateLabelActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: privateLabelDecisionPlan.launchDecision,
        detail: privateLabelDecisionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: privateLabelDecisionPlan.owner,
        detail: `${privateLabelDecisionPlan.proofPriority} should sit with the person who can actually clear the next launch blocker.`,
      },
      {
        label: "Then do",
        value: privateLabelDecisionPlan.launchCadence,
        detail: "Tie each compliance risk and launch dependency to a named owner before spend expands.",
      },
      {
        label: "Watch",
        value: privateLabelDecisionPlan.proofPriority,
        detail: privateLabelDecisionPlan.watchout,
      },
    ],
    [privateLabelDecisionPlan],
  );

  const privateLabelInputRows = useMemo(
    () => [
      ...privateLabelAuditRows,
      {
        label: "Execution call",
        value: privateLabelActionRows[0]?.value ?? "Launch decision pending",
        detail: privateLabelActionRows[1]?.value
          ? `${privateLabelActionRows[1].value} owns the first launch blocker until the same launch baseline is rechecked.`
          : "Assign a single launch owner before more budget gets committed.",
      },
    ],
    [privateLabelActionRows, privateLabelAuditRows],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <DistributionPanel title="Live launch inputs" rows={privateLabelInputRows} />
      <DistributionPanel title="This launch call" rows={privateLabelActionRows} />
      <AuditNote
        lines={[
          inferredComplianceItems.length
            ? `System inference: ${inferredComplianceItems.join(", ")} look like the first compliance vectors tied to this product idea.`
            : "If the product idea implies electrical, children's, hazmat, or fragile risk, tag it before launch planning gets too optimistic.",
          `System draft: demand ${demandScore}%, differentiation ${differentiationScore}%, sourcing ${sourcingConfidence}% with ${formatUsd(launchBudget)} launch budget.`,
          wedge.trim() ? `Launch wedge: ${wedge}.` : "Name one narrow buyer wedge, otherwise the tool cannot tell whether the idea is focused enough to launch.",
          "This tool is best used to kill weak private-label ideas early, before supplier work and launch spend create false commitment.",
        ]}
      />
      <div className="grid gap-2.5 xl:grid-cols-[1.2fr_1.4fr_auto]">
        <Field label="Product idea">
          <TextInput value={idea} onChange={(e) => setIdea(e.target.value)} />
        </Field>
        <Field label="Buyer wedge">
          <TextInput value={wedge} onChange={(e) => setWedge(e.target.value)} placeholder="Who is this for and what job does it solve?" />
        </Field>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowOverrides((current) => !current)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide overrides" : "Adjust launch assumptions"}
          </button>
        </div>
      </div>
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Launch overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when the real demand proof, moat strength, sourcing posture, or account readiness differs from the system read.
            </p>
          </div>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 xl:grid-cols-[1.6fr_1fr_1fr]">
              <Field label="Differentiation angle">
                <TextInput value={differentiationAngle} onChange={(e) => setDifferentiationAngle(e.target.value)} />
              </Field>
              <Field label="Sourcing region">
                <TextInput value={sourcingRegion} onChange={(e) => setSourcingRegion(e.target.value)} />
              </Field>
              <Field label="Target price band">
                <SelectInput value={targetPriceBand} onChange={(e) => setTargetPriceBand(e.target.value)}>
                  <option value="0-30">0-30</option>
                  <option value="30-80">30-80</option>
                  <option value="80-150">80-150</option>
                  <option value="150+">150+</option>
                </SelectInput>
              </Field>
            </div>
            <div className="grid gap-2.5 xl:grid-cols-[0.8fr_0.8fr_0.8fr_1fr]">
              <Field label="Demand score">
                <NumberInput value={demandScore} min="0" max="100" step="1" onChange={(e) => setDemandScore(Number(e.target.value))} />
              </Field>
              <Field label="Differentiation">
                <NumberInput value={differentiationScore} min="0" max="100" step="1" onChange={(e) => setDifferentiationScore(Number(e.target.value))} />
              </Field>
              <Field label="Sourcing confidence">
                <NumberInput value={sourcingConfidence} min="0" max="100" step="1" onChange={(e) => setSourcingConfidence(Number(e.target.value))} />
              </Field>
              <Field label="Launch budget">
                <NumberInput value={launchBudget} min="0" step="500" onChange={(e) => setLaunchBudget(Number(e.target.value))} />
              </Field>
            </div>
            <div className="grid gap-2 md:grid-cols-3 xl:grid-cols-6">
              {["fragile-packaging", "materials-claims", "electrical", "children-product", "hazmat"].map((item) => (
                <Checkbox
                  key={item}
                  label={item}
                  checked={complianceItems.includes(item)}
                  onChange={(checked) =>
                    setComplianceItems((current) =>
                      checked ? Array.from(new Set([...current, item])) : current.filter((entry) => entry !== item),
                    )
                  }
                />
              ))}
              <Checkbox label="Brand path ready" checked={brandReady} onChange={setBrandReady} />
              <Checkbox label="GTIN or exemption path ready" checked={gtinExemptionReady} onChange={setGtinExemptionReady} />
              <Checkbox
                label="Permanent brand marking ready"
                checked={permanentBrandingReady}
                onChange={setPermanentBrandingReady}
              />
            </div>
          </div>
        ) : null}
      </div>
      <DistributionPanel title="Launch sequence" rows={launchRows} />
    </RuntimeShell>
  );
}

function WholesaleSourcingRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [brandName, setBrandName] = useState("SimpleHouseware");
  const [channelType, setChannelType] = useState("distributor");
  const [supplierRegion, setSupplierRegion] = useState("US");
  const [quotedUnitCost, setQuotedUnitCost] = useState(18);
  const [targetSellPrice, setTargetSellPrice] = useState(39.99);
  const [supplierCount, setSupplierCount] = useState(5);
  const [authorizedSupplierCount, setAuthorizedSupplierCount] = useState(2);
  const [moqUnits, setMoqUnits] = useState(240);
  const [grossMarginRate, setGrossMarginRate] = useState(24);
  const [documentCount, setDocumentCount] = useState(3);
  const [ungatingReady, setUngatingReady] = useState(true);
  const [invoiceRecent, setInvoiceRecent] = useState(true);
  const [hasLoa, setHasLoa] = useState(true);
  const [brandRestricted, setBrandRestricted] = useState(false);
  const [showOverrides, setShowOverrides] = useState(false);
  const wholesalePlan = useMemo(
    () =>
      inferWholesaleDealPlan({
        brandName,
        channelType,
        supplierRegion,
        quotedUnitCost,
        targetSellPrice,
        brandRestricted,
      }),
    [brandName, brandRestricted, channelType, quotedUnitCost, supplierRegion, targetSellPrice],
  );
  const wholesaleExecutionPlan = useMemo(
    () =>
      inferWholesaleExecutionPlan({
        authorizedSupplierCount,
        moqUnits,
        grossMarginRate,
        documentCount,
        ungatingReady,
        invoiceRecent,
        hasLoa,
        brandRestricted,
        channelType,
      }),
    [
      authorizedSupplierCount,
      brandRestricted,
      channelType,
      documentCount,
      grossMarginRate,
      hasLoa,
      invoiceRecent,
      moqUnits,
      ungatingReady,
    ],
  );

  useEffect(() => {
    if (showOverrides) {
      return;
    }
    setAuthorizedSupplierCount(wholesalePlan.authorizedSupplierCount);
    setMoqUnits(wholesalePlan.moqUnits);
    setGrossMarginRate(wholesalePlan.grossMarginRate);
    setDocumentCount(wholesalePlan.documentCount);
    setUngatingReady(wholesalePlan.ungatingReady);
    setInvoiceRecent(wholesalePlan.invoiceRecent);
    setHasLoa(wholesalePlan.hasLoa);
    setSupplierCount(wholesalePlan.supplierCount);
  }, [showOverrides, wholesalePlan]);
  const readinessRows = useMemo(
    () =>
      buildWholesaleReadinessRows({
        supplierCount,
        authorizedSupplierCount,
        moqUnits,
        grossMarginRate,
        documentCount,
        ungatingReady,
        invoiceRecent,
        hasLoa,
        brandRestricted,
      }),
    [authorizedSupplierCount, brandRestricted, documentCount, grossMarginRate, hasLoa, invoiceRecent, moqUnits, supplierCount, ungatingReady],
  );

  const result = useMemo(
    () =>
      evaluateWholesaleSourcing({
        supplierCount,
        authorizedSupplierCount,
        moqUnits,
        grossMarginRate,
        documentCount,
        ungatingReady,
        invoiceRecent,
        hasLoa,
        brandRestricted,
      }),
    [authorizedSupplierCount, brandRestricted, documentCount, grossMarginRate, hasLoa, invoiceRecent, moqUnits, supplierCount, ungatingReady],
  );

  const sourcingRows = useMemo(
    () => [
      {
        label: "Deal brief",
        value: brandName || "Unnamed brand",
        detail: `${channelType} channel from ${supplierRegion || "unspecified region"}`,
      },
      {
        label: "MOQ pressure",
        value: `${moqUnits} units`,
        detail: grossMarginRate < 18 ? "Margin too thin for a large buy" : "Margin can support a controlled test buy",
      },
      {
        label: "Documents",
        value: `${documentCount}`,
        detail: ungatingReady ? "Ungating path ready" : "Ungating path incomplete",
      },
    ],
    [authorizedSupplierCount, brandName, channelType, documentCount, grossMarginRate, moqUnits, supplierRegion, ungatingReady],
  );

  const sourcingAuditRows = useMemo(
    () => [
      {
        label: "Brand / channel",
        value: `${brandName || "Unnamed"} / ${channelType}`,
        detail: `${supplierCount} total sources screened | ${authorizedSupplierCount} likely authorized`,
      },
      {
        label: "Unit economics",
        value: `${formatUsd(quotedUnitCost)} -> ${formatUsd(targetSellPrice)}`,
        detail: `${grossMarginRate}% gross margin before fee or price-pressure erosion`,
      },
      {
        label: "Document stack",
        value: `${documentCount}`,
        detail: `${invoiceRecent ? "Recent invoices" : "Invoice gap"} | ${hasLoa ? "LOA ready" : "LOA missing"}`,
      },
      {
        label: "Access posture",
        value: `${ungatingReady ? "Ungating ready" : "Ungating gap"} / ${brandRestricted ? "Restricted brand" : "Non-restricted brand"}`,
        detail: "Catalog-access path and restriction pressure for the current deal",
      },
      {
        label: "Deal call",
        value: wholesaleExecutionPlan.sourcingDecision,
        detail: `${wholesaleExecutionPlan.proofPriority} | ${wholesaleExecutionPlan.approvalCadence}`,
      },
    ],
    [authorizedSupplierCount, brandName, brandRestricted, channelType, documentCount, grossMarginRate, hasLoa, invoiceRecent, moqUnits, quotedUnitCost, supplierCount, targetSellPrice, ungatingReady, wholesaleExecutionPlan],
  );

  const sourcingActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: wholesaleExecutionPlan.sourcingDecision,
        detail: wholesaleExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: wholesaleExecutionPlan.owner,
        detail: `${wholesaleExecutionPlan.proofPriority} should belong to the operator who can actually clear the next money-moving blocker.`,
      },
      {
        label: "Then do",
        value: wholesaleExecutionPlan.approvalCadence,
        detail: "Keep authorization, paperwork, and economics assigned to named owners before inventory money moves.",
      },
      {
        label: "Watch",
        value: wholesaleExecutionPlan.proofPriority,
        detail: wholesaleExecutionPlan.watchout,
      },
    ],
    [wholesaleExecutionPlan],
  );

  const sourcingInputRows = useMemo(
    () => [
      ...sourcingAuditRows,
      {
        label: "Execution call",
        value: sourcingActionRows[0]?.value ?? "Deal decision pending",
        detail: sourcingActionRows[1]?.value
          ? `${sourcingActionRows[1].value} owns the first money-moving blocker until the same deal baseline is rechecked.`
          : "Put one sourcing owner on the next approval step before PO money moves.",
      },
    ],
    [sourcingActionRows, sourcingAuditRows],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[1.1fr_0.9fr_0.7fr_0.7fr_0.7fr]">
        <Field label="Brand">
          <TextInput value={brandName} onChange={(e) => setBrandName(e.target.value)} placeholder="Target brand" />
        </Field>
        <Field label="Supply channel">
          <SelectInput value={channelType} onChange={(e) => setChannelType(e.target.value)}>
            <option value="distributor">Authorized distributor</option>
            <option value="manufacturer">Direct manufacturer</option>
            <option value="liquidation">Liquidation / closeout</option>
          </SelectInput>
        </Field>
        <Field label="Supplier region">
          <TextInput value={supplierRegion} onChange={(e) => setSupplierRegion(e.target.value)} placeholder="US / China / EU" />
        </Field>
        <Field label="Quoted unit cost">
          <NumberInput value={quotedUnitCost} min="0" step="0.01" onChange={(e) => setQuotedUnitCost(Number(e.target.value))} />
        </Field>
        <Field label="Target sell price">
          <NumberInput value={targetSellPrice} min="0" step="0.01" onChange={(e) => setTargetSellPrice(Number(e.target.value))} />
        </Field>
      </div>
      <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-2">
        <Field label="Restricted brand checked">
          <Checkbox label="Brand restriction risk present" checked={brandRestricted} onChange={setBrandRestricted} />
        </Field>
      </div>
      <AuditNote
        lines={[
          "Use this sourcing read to decide whether the deal is safe to advance now, which authorization or document gap still blocks it, and whether cash should stay parked.",
          `System draft: ${authorizedSupplierCount} likely authorized sources, ${moqUnits} MOQ units, ${documentCount} key documents from the current deal brief.`,
          readinessRows[0]?.detail ?? "Authorization strength should become explicit before money moves.",
        ]}
      />
      <DistributionPanel title="Live sourcing inputs" rows={sourcingInputRows} />
      <DistributionPanel title="This sourcing call" rows={sourcingActionRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Deal overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when the real supplier proof, MOQ, or ungating path is materially different from the system draft.
            </p>
          </div>
          <button
            type="button"
            onClick={() => setShowOverrides((current) => !current)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide overrides" : "Adjust deal assumptions"}
          </button>
        </div>
        {showOverrides ? (
            <div className="mt-4 grid gap-4">
            <div className="grid gap-2.5 md:grid-cols-2 xl:grid-cols-5">
              <Field label="Supplier count">
                <NumberInput value={supplierCount} min="0" step="1" onChange={(e) => setSupplierCount(Number(e.target.value))} />
              </Field>
              <Field label="Authorized suppliers">
                <NumberInput value={authorizedSupplierCount} min="0" step="1" onChange={(e) => setAuthorizedSupplierCount(Number(e.target.value))} />
              </Field>
              <Field label="MOQ units">
                <NumberInput value={moqUnits} min="0" step="10" onChange={(e) => setMoqUnits(Number(e.target.value))} />
              </Field>
              <Field label="Gross margin %">
                <NumberInput value={grossMarginRate} min="0" max="100" step="1" onChange={(e) => setGrossMarginRate(Number(e.target.value))} />
              </Field>
              <Field label="Document count">
                <NumberInput value={documentCount} min="0" step="1" onChange={(e) => setDocumentCount(Number(e.target.value))} />
              </Field>
              <Checkbox label="Ungating ready" checked={ungatingReady} onChange={setUngatingReady} />
              <Checkbox label="Invoices within 180 days" checked={invoiceRecent} onChange={setInvoiceRecent} />
            </div>
            <div className="grid gap-2 md:grid-cols-2">
              <Checkbox label="LOA or distributor agreement" checked={hasLoa} onChange={setHasLoa} />
            </div>
          </div>
        ) : null}
      </div>
      <div className="grid gap-3 xl:grid-cols-[1fr_1fr]">
        <DistributionPanel title="Deal screen" rows={sourcingRows} />
        <DistributionPanel title="Readiness scorecard" rows={readinessRows} />
      </div>
    </RuntimeShell>
  );
}

function SuspensionAppealRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [issueType, setIssueType] = useState("product-compliance");
  const [enforcementStage, setEnforcementStage] = useState("listing-removed");
  const [evidenceStage, setEvidenceStage] = useState("partial");
  const [submissionLane, setSubmissionLane] = useState("recommended");
  const [noticeText, setNoticeText] = useState("Product removed for policy compliance concerns. Provide invoices, root cause, corrective actions, and prevention steps.");
  const [rootCauses, setRootCauses] = useState("Incorrect documentation routing\nListing claim mismatch");
  const [evidenceItems, setEvidenceItems] = useState("Supplier invoice\nUpdated compliance file\nRemoved risky claim");
  const [correctiveActions, setCorrectiveActions] = useState("Removed affected content\nUpdated document pack");
  const [preventionSteps, setPreventionSteps] = useState("Monthly compliance audit\nApproval gate before listing changes");
  const [submissionReady, setSubmissionReady] = useState(false);
  const [evidenceFresh, setEvidenceFresh] = useState(true);
  const [usesAccountHealthPath, setUsesAccountHealthPath] = useState(true);
  const [showOverrides, setShowOverrides] = useState(false);
  const appealPrefillRef = useRef("");
  const inferredIssueTypeRef = useRef("");

  const rootCauseList = rootCauses.split(/\r?\n/).map((item) => item.trim()).filter(Boolean);
  const evidenceList = evidenceItems.split(/\r?\n/).map((item) => item.trim()).filter(Boolean);
  const correctiveList = correctiveActions.split(/\r?\n/).map((item) => item.trim()).filter(Boolean);
  const preventionList = preventionSteps.split(/\r?\n/).map((item) => item.trim()).filter(Boolean);
  const inferredAppealDraft = useMemo(
    () => inferAppealDraft(issueType, noticeText),
    [issueType, noticeText],
  );
  const appealCasePlan = useMemo(
    () =>
      inferAppealCasePlan({
        issueType,
        noticeText,
        evidenceStage,
        enforcementStage,
        submissionLane,
      }),
    [enforcementStage, evidenceStage, issueType, noticeText, submissionLane],
  );

  useEffect(() => {
    const trimmedNotice = noticeText.trim();
    if (!trimmedNotice) {
      return;
    }

    const inferredType = inferIssueTypeFromNotice(trimmedNotice);
    const issueTypeLooksDefault =
      issueType === "product-compliance" ||
      inferredIssueTypeRef.current === issueType;

    if (issueTypeLooksDefault && inferredType !== issueType) {
      setIssueType(inferredType);
    }

    inferredIssueTypeRef.current = inferredType;
  }, [issueType, noticeText]);

  useEffect(() => {
    const prefillKey = `${issueType}::${noticeText.trim()}`;
    if (!noticeText.trim() || appealPrefillRef.current === prefillKey) {
      return;
    }

    if (!rootCauses.trim() || rootCauses.trim() === defaultAppealRootCauses) {
      setRootCauses(inferredAppealDraft.rootCauses.join("\n"));
    }
    if (!evidenceItems.trim() || evidenceItems.trim() === defaultAppealEvidenceItems) {
      setEvidenceItems(inferredAppealDraft.evidence.join("\n"));
    }
    if (!correctiveActions.trim() || correctiveActions.trim() === defaultAppealCorrectiveActions) {
      setCorrectiveActions(inferredAppealDraft.corrective.join("\n"));
    }
    if (!preventionSteps.trim() || preventionSteps.trim() === defaultAppealPreventionSteps) {
      setPreventionSteps(inferredAppealDraft.prevention.join("\n"));
    }

    appealPrefillRef.current = prefillKey;
  }, [
    correctiveActions,
    evidenceItems,
    inferredAppealDraft,
    issueType,
    noticeText,
    preventionSteps,
    rootCauses,
  ]);

  useEffect(() => {
    if (showOverrides) {
      return;
    }
    setEvidenceFresh(appealCasePlan.evidenceFresh);
    setSubmissionReady(appealCasePlan.submissionReady);
    setUsesAccountHealthPath(appealCasePlan.usesAccountHealthPath);
  }, [appealCasePlan, showOverrides]);

  const issueSeverity = appealCasePlan.issueSeverity;
  const hasAsinOrPolicyReference = appealCasePlan.hasSpecificReference;
  const appealExecutionPlan = useMemo(
    () =>
      inferAppealExecutionPlan({
        hasSpecificReference: hasAsinOrPolicyReference,
        evidenceCount: evidenceList.length,
        evidenceFresh,
        rootCauseCount: rootCauseList.length,
        correctiveActionCount: correctiveList.length,
        preventionCount: preventionList.length,
        usesAccountHealthPath,
        submissionReady,
        issueSeverity,
      }),
    [
      correctiveList.length,
      evidenceFresh,
      evidenceList.length,
      hasAsinOrPolicyReference,
      issueSeverity,
      preventionList.length,
      rootCauseList.length,
      submissionReady,
      usesAccountHealthPath,
    ],
  );

  const result = useMemo(
    () =>
      evaluateSuspensionAppeal({
        issueType,
        rootCauseCount: rootCauseList.length,
        evidenceCount: evidenceList.length,
        correctiveActionCount: correctiveList.length,
        preventionCount: preventionList.length,
        issueSeverity,
        submissionReady,
        hasAsinOrPolicyReference,
        evidenceFresh,
        usesAccountHealthPath,
      }),
    [
      correctiveList.length,
      evidenceFresh,
      evidenceList.length,
      hasAsinOrPolicyReference,
      issueSeverity,
      issueType,
      preventionList.length,
      rootCauseList.length,
      submissionReady,
      usesAccountHealthPath,
    ],
  );

  const poaRows = useMemo(
    () => [
      {
        label: "Notice focus",
        value: issueType,
        detail: noticeText.slice(0, 88) || "Paste the policy notice for tighter scope control",
      },
      {
        label: "Immediate fixes",
        value: `${correctiveList.length}`,
        detail: correctiveList[0] || "List what was already corrected",
      },
      {
        label: "Prevention",
        value: `${preventionList.length}`,
        detail: preventionList[0] || "List long-term controls",
      },
    ],
    [correctiveList, issueType, noticeText, preventionList],
  );

  const appealAuditRows = useMemo(
    () => [
      {
        label: "Case posture",
        value: `${enforcementStage} / ${evidenceStage}`,
        detail: submissionLane === "recommended" ? "Using system-recommended lane" : submissionLane,
      },
      {
        label: "Issue scope",
        value: hasAsinOrPolicyReference ? "Specific" : "Too vague",
        detail: issueType,
      },
      {
        label: "Root cause / evidence",
        value: `${rootCauseList.length} / ${evidenceList.length}`,
        detail: "Root-cause lines and evidence items currently backing the packet",
      },
      {
        label: "Corrective / prevention",
        value: `${correctiveList.length} / ${preventionList.length}`,
        detail: "Immediate fixes and long-term controls in the current draft",
      },
      {
        label: "Submission posture",
        value: submissionReady ? "Ready to submit" : "Not ready",
        detail: `${evidenceFresh ? "Fresh evidence" : "Evidence gap"} | ${usesAccountHealthPath ? "Correct path" : "Path unclear"}`,
      },
      {
        label: "Submission call",
        value: appealExecutionPlan.appealDecision,
        detail: `${appealExecutionPlan.proofPriority} | ${appealExecutionPlan.submissionCadence}`,
      },
    ],
    [
      appealExecutionPlan,
      correctiveList.length,
      evidenceFresh,
      evidenceList.length,
      enforcementStage,
      hasAsinOrPolicyReference,
      evidenceStage,
      issueType,
      preventionList.length,
      rootCauseList.length,
      submissionLane,
      submissionReady,
      usesAccountHealthPath,
    ],
  );

  const appealActionRows = useMemo(
    () => [
      {
        label: "First move",
        value: appealExecutionPlan.appealDecision,
        detail: appealExecutionPlan.nextMove,
      },
      {
        label: "Execution owner",
        value: appealExecutionPlan.owner,
        detail: `${appealExecutionPlan.proofPriority} should belong to the operator who can actually clear the next appeal blocker.`,
      },
      {
        label: "Then do",
        value: appealExecutionPlan.submissionCadence,
        detail: "Map each root cause to one fix and one control before the final packet is frozen.",
      },
      {
        label: "Watch",
        value: appealExecutionPlan.proofPriority,
        detail: appealExecutionPlan.watchout,
      },
    ],
    [appealExecutionPlan],
  );

  const appealInputRows = useMemo(
    () => [
      ...appealAuditRows,
      {
        label: "Execution call",
        value: appealActionRows[0]?.value ?? "Appeal decision pending",
        detail: appealActionRows[1]?.value
          ? `${appealActionRows[1].value} owns the first appeal blocker until the same packet is rechecked.`
          : "Name one appeal owner before the packet gets rewritten again.",
      },
    ],
    [appealActionRows, appealAuditRows],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[0.7fr_0.9fr_0.9fr_0.9fr]">
        <Field label="Issue type">
          <SelectInput value={issueType} onChange={(e) => setIssueType(e.target.value)}>
            <option value="product-compliance">Product compliance</option>
            <option value="inauthentic">Inauthentic complaint</option>
            <option value="restricted-product">Restricted product</option>
            <option value="account-health">Account health</option>
          </SelectInput>
        </Field>
        <Field label="Enforcement stage">
          <SelectInput value={enforcementStage} onChange={(e) => setEnforcementStage(e.target.value)}>
            <option value="warning">Warning only</option>
            <option value="listing-removed">Listing removed</option>
            <option value="account-at-risk">Account at risk</option>
          </SelectInput>
        </Field>
        <Field label="Evidence stage">
          <SelectInput value={evidenceStage} onChange={(e) => setEvidenceStage(e.target.value)}>
            <option value="missing">Still gathering evidence</option>
            <option value="partial">Partial packet</option>
            <option value="ready">Ready to submit</option>
          </SelectInput>
        </Field>
        <Field label="Submission lane">
          <SelectInput value={submissionLane} onChange={(e) => setSubmissionLane(e.target.value)}>
            <option value="recommended">System recommended</option>
            <option value="account-health">Account Health</option>
            <option value="case-log">Case log / support</option>
          </SelectInput>
        </Field>
      </div>
      <div className="grid gap-2.5 xl:grid-cols-[1.8fr_0.5fr]">
        <Field label="Paste notice text">
          <TextAreaInput value={noticeText} onChange={(e) => setNoticeText(e.target.value)} className="min-h-[5.5rem]" spellCheck={false} />
        </Field>
        <Checkbox label="Ready to submit" checked={submissionReady} onChange={setSubmissionReady} />
      </div>
      <AuditNote
        lines={[
          hasAsinOrPolicyReference
            ? "Notice text appears to name the ASIN or policy already."
            : "Notice text does not clearly name the ASIN or violated policy yet.",
          `Case draft: ${enforcementStage}, ${evidenceStage} evidence, ${appealCasePlan.usesAccountHealthPath ? "correct lane likely" : "lane risk visible"}.`,
          "The system drafts a first-pass POA skeleton from the notice so the operator starts from structure, not a blank page.",
        ]}
      />
      <DistributionPanel title="Live appeal inputs" rows={appealInputRows} />
      <DistributionPanel title="This appeal call" rows={appealActionRows} />
      <div className="grid gap-3 xl:grid-cols-4">
        <DistributionPanel
          title="Draft root causes"
          rows={inferredAppealDraft.rootCauses.map((item) => ({ label: "Root cause", value: item }))}
        />
        <DistributionPanel
          title="Draft evidence"
          rows={inferredAppealDraft.evidence.map((item) => ({ label: "Evidence", value: item }))}
        />
        <DistributionPanel
          title="Draft corrective actions"
          rows={inferredAppealDraft.corrective.map((item) => ({ label: "Corrective", value: item }))}
        />
        <DistributionPanel
          title="Draft prevention controls"
          rows={inferredAppealDraft.prevention.map((item) => ({ label: "Prevention", value: item }))}
        />
      </div>
      <div className="flex justify-end">
        <button
          type="button"
          onClick={() => setShowOverrides((current) => !current)}
          className="text-sm font-medium text-teal-700 transition hover:text-teal-800"
        >
          {showOverrides ? "Hide appeal overrides" : "Adjust packet details"}
        </button>
      </div>
      {showOverrides ? (
        <>
          <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-4">
            <Checkbox label="Evidence is current and usable" checked={evidenceFresh} onChange={setEvidenceFresh} />
            <Checkbox label="Appeal path matches Account Health guidance" checked={usesAccountHealthPath} onChange={setUsesAccountHealthPath} />
          </div>
          <div className="grid gap-2.5 xl:grid-cols-2">
            <Field label="Root causes">
              <TextAreaInput value={rootCauses} onChange={(e) => setRootCauses(e.target.value)} className="min-h-[6rem]" spellCheck={false} />
            </Field>
            <Field label="Evidence pack">
              <TextAreaInput value={evidenceItems} onChange={(e) => setEvidenceItems(e.target.value)} className="min-h-[6rem]" spellCheck={false} />
            </Field>
          </div>
          <div className="grid gap-2.5 xl:grid-cols-2">
            <Field label="Corrective actions">
              <TextAreaInput value={correctiveActions} onChange={(e) => setCorrectiveActions(e.target.value)} className="min-h-[6rem]" spellCheck={false} />
            </Field>
            <Field label="Prevention steps">
              <TextAreaInput value={preventionSteps} onChange={(e) => setPreventionSteps(e.target.value)} className="min-h-[6rem]" spellCheck={false} />
            </Field>
          </div>
        </>
      ) : null}
      <DistributionPanel title="POA structure" rows={poaRows} />
      <LowTokenAssistPanel
        toolSlug="amazon-suspension-appeal"
        locale={locale}
        result={result}
        context={{
          issueType,
          noticeText,
          rootCauses: rootCauseList,
          evidencePack: evidenceList,
          correctiveActions: correctiveList,
          preventionSteps: preventionList,
        }}
      />
    </RuntimeShell>
  );
}

function BrandAnalyticsRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [ownAsin, setOwnAsin] = useState("");
  const [objective, setObjective] = useState("balance");
  const [resourceLevel, setResourceLevel] = useState("medium");
  const [reportText, setReportText] = useState(
    "Search Term\tSearch Frequency Rank\tClicked ASIN\tConverted ASIN\narched full length mirror\t1240\tB0G6K4VXK7\tB0FX2PRMFR\nfloor mirror bedroom\t1880\tB0CLNLL9RZ\tB0H1AB2CD3",
  );
  const [confirmedAt, setConfirmedAt] = useState(0);

  const rows = useMemo(() => parseBrandAnalyticsRows(reportText), [reportText]);
  const inferredOwnAsin = useMemo(() => inferOwnAsinFromBrandAnalytics(rows), [rows]);

  useEffect(() => {
    if (!ownAsin.trim() && inferredOwnAsin) {
      setOwnAsin(inferredOwnAsin);
    }
  }, [inferredOwnAsin, ownAsin]);

  const analyticsPlan = useMemo(
    () =>
      inferBrandAnalyticsPlan({
        rows,
        ownAsin,
        objective,
        resourceLevel,
      }),
    [objective, ownAsin, resourceLevel, rows],
  );

  const asinStats = useMemo(() => {
    const own = ownAsin.trim().toUpperCase();
    const clickedCounts = new Map<string, number>();
    const convertedCounts = new Map<string, number>();
    const combinedCounts = new Map<string, number>();
    let ownAsinMentions = 0;

    for (const row of rows) {
      for (const asin of row.clickedAsins) {
        clickedCounts.set(asin, (clickedCounts.get(asin) ?? 0) + 1);
        combinedCounts.set(asin, (combinedCounts.get(asin) ?? 0) + 1);
        if (own && asin === own) {
          ownAsinMentions += 1;
        }
      }
      for (const asin of row.convertedAsins) {
        convertedCounts.set(asin, (convertedCounts.get(asin) ?? 0) + 1);
        combinedCounts.set(asin, (combinedCounts.get(asin) ?? 0) + 1);
        if (own && asin === own) {
          ownAsinMentions += 1;
        }
      }
    }

    const combinedEntries = Array.from(combinedCounts.entries()).sort((a, b) => b[1] - a[1]);
    const totalMentions = combinedEntries.reduce((sum, [, count]) => sum + count, 0);
    const concentrationShare = totalMentions
      ? combinedEntries.slice(0, Math.min(5, combinedEntries.length)).reduce((sum, [, count]) => sum + count, 0) / totalMentions
      : 0;
    const competitorAsinCount = combinedEntries.filter(([asin]) => asin !== own).length;

    return {
      ownAsinMentions,
      clickedAsinCount: clickedCounts.size,
      convertedAsinCount: convertedCounts.size,
      competitorAsinCount,
      concentrationShare,
      repeatedAsins: combinedEntries.slice(0, 8).map(([asin, count]) => ({
        label: asin,
        value: `${count}`,
        detail: own && asin === own ? "Your ASIN" : "Repeated clicked or converted winner",
      })),
      opportunityQueries: rows
        .map((row) => {
          const ownVisible =
            own.length > 0 &&
            [...row.clickedAsins, ...row.convertedAsins].some((asin) => asin === own);
          return {
            label: row.query,
            value: row.sfr ? `SFR ${Math.round(row.sfr).toLocaleString("en-US")}` : "No SFR",
            detail: ownVisible
              ? `Own ASIN visible | ${row.clickedAsins.length} clicked slots | ${row.convertedAsins.length} converted slots`
              : `Own ASIN absent | ${row.clickedAsins.join(", ") || "No clicked ASINs"}`,
          };
        })
        .sort((a, b) => parseReportNumber(a.value) - parseReportNumber(b.value))
        .slice(0, 8),
    };
  }, [ownAsin, rows]);

  const result = useMemo(() => {
    if (!rows.length) {
      return null;
    }

    const sfrValues = rows.map((row) => row.sfr).filter((value) => value > 0).sort((a, b) => a - b);
    const medianSfr = sfrValues.length
      ? sfrValues[Math.floor(sfrValues.length / 2)]
      : 0;

    return evaluateBrandAnalytics({
      rowCount: rows.length,
      topQueryCount: rows.length,
      clickedAsinCount: asinStats.clickedAsinCount,
      convertedAsinCount: asinStats.convertedAsinCount,
      ownAsinMentions: asinStats.ownAsinMentions,
      ownAsinProvided: ownAsin.trim().length > 0,
      competitorAsinCount: asinStats.competitorAsinCount,
      concentrationShare: asinStats.concentrationShare,
      medianSfr,
    });
  }, [asinStats, ownAsin, rows]);

  const brandDecisionRows = useMemo(
    () => buildBrandAnalyticsDecisionRows({ ownAsin, rows }),
    [ownAsin, rows],
  );
  const brandSummaryRows = useMemo(
    () => buildBrandAnalyticsSummaryRows({ ownAsin, rows }),
    [ownAsin, rows],
  );

  const brandAuditRows = useMemo(() => {
    const own = ownAsin.trim().toUpperCase();
    const sfrValues = rows.map((row) => row.sfr).filter((value) => value > 0).sort((a, b) => a - b);
    const ownVisibleCount = rows.filter((row) =>
      own ? [...row.clickedAsins, ...row.convertedAsins].includes(own) : false,
    ).length;

    return [
      {
        label: "Rows parsed",
        value: `${rows.length}`,
        detail: rows.length ? `${marketplace} Brand Analytics rows loaded into the current read` : "Paste an export to build the live query map",
      },
      {
        label: "Own ASIN coverage",
        value: own ? `${ownVisibleCount}/${rows.length || 0}` : "Not set",
        detail: own
          ? "Queries where your ASIN shows in clicked or converted slots"
          : inferredOwnAsin
            ? `System candidate: ${inferredOwnAsin}`
            : "Add your ASIN to split defense queries from gap queries",
      },
      {
        label: "Repeated winner set",
        value: `${asinStats.competitorAsinCount}`,
        detail: `${asinStats.clickedAsinCount} clicked-slot ASINs and ${asinStats.convertedAsinCount} converted-slot ASINs`,
      },
      {
        label: "Winner concentration",
        value: `${Math.round(asinStats.concentrationShare * 100)}%`,
        detail: "Share captured by the most repeated visible winners in this export",
      },
      {
        label: "Operating brief",
        value: `${objective} / ${resourceLevel}`,
        detail: `${analyticsPlan.primaryFocus} focus with ${analyticsPlan.defendCount} defend rows and ${analyticsPlan.attackCount} attack rows`,
      },
      {
        label: "Median SFR",
        value: sfrValues.length ? Math.round(sfrValues[Math.floor(sfrValues.length / 2)]).toLocaleString("en-US") : "Missing",
        detail: "Use lower SFR rows as the first battlefield before broadening outward",
      },
    ];
  }, [analyticsPlan.attackCount, analyticsPlan.defendCount, analyticsPlan.primaryFocus, asinStats.clickedAsinCount, asinStats.competitorAsinCount, asinStats.concentrationShare, asinStats.convertedAsinCount, inferredOwnAsin, marketplace, objective, ownAsin, resourceLevel, rows]);

  const actionQueueRows = useMemo(() => {
    const own = ownAsin.trim().toUpperCase();
    const sortedRows = [...rows]
      .filter((row) => row.sfr > 0)
      .sort((a, b) => a.sfr - b.sfr);
    const defend = sortedRows
      .filter((row) => own && [...row.clickedAsins, ...row.convertedAsins].includes(own))
      .slice(0, analyticsPlan.defendCount)
      .map((row) => ({
        label: row.query,
        value: "Defend now",
        detail: "Own ASIN is already visible here, so protect the existing query foothold first.",
      }));
    const attack = sortedRows
      .filter((row) => !own || ![...row.clickedAsins, ...row.convertedAsins].includes(own))
      .slice(0, analyticsPlan.attackCount)
      .map((row) => ({
        label: row.query,
        value: "Attack next",
        detail: `${row.clickedAsins[0] ?? row.convertedAsins[0] ?? "Competing ASIN"} is taking visible share while your ASIN is absent.`,
      }));
    const watch = sortedRows
      .slice(4, 6)
      .map((row) => ({
        label: row.query,
        value: "Watch",
        detail: "Keep this outside the first action wave until defense and priority gaps are handled.",
      }));

    const primaryAction =
      analyticsPlan.primaryFocus === "defend" && defend[0]
        ? {
            label: "Single first move",
            value: defend[0].label,
            detail: "Protect the highest-value query where your ASIN is already visible before spreading effort into colder gaps.",
          }
        : attack[0]
          ? {
              label: "Single first move",
              value: attack[0].label,
              detail: "This is the highest-priority absent query in the current export, so attack it before broadening the plan.",
            }
          : {
              label: "Single first move",
              value: "Load more rows",
              detail: "The export is too thin to set a confident first move yet.",
            };

    const executionOwner =
      analyticsPlan.primaryFocus === "defend" && defend[0]
        ? {
            label: "Execution owner",
            value: "Listing / defense owner",
            detail: "When your ASIN is already visible, the first job is protecting query position before widening the attack surface.",
          }
        : attack[0]
          ? {
              label: "Execution owner",
              value: "Growth / gap-closure owner",
              detail: "Missing-query attacks need someone explicitly accountable for ranking or offer-entry work.",
            }
          : {
              label: "Execution owner",
              value: "Analytics owner",
              detail: "The export is still too thin, so the immediate job is improving signal quality before acting on it.",
            };
    return [primaryAction, executionOwner, ...defend, ...attack, ...watch].slice(0, 7);
  }, [analyticsPlan, ownAsin, rows]);

  const brandActionRows = useMemo(() => {
    const own = ownAsin.trim().toUpperCase();
    const sortedRows = [...rows]
      .filter((row) => row.sfr > 0)
      .sort((a, b) => a.sfr - b.sfr);
    const defendLead = sortedRows.find((row) => own && [...row.clickedAsins, ...row.convertedAsins].includes(own));
    const attackLead = sortedRows.find((row) => !own || ![...row.clickedAsins, ...row.convertedAsins].includes(own));

    return [
      {
        label: "First move",
        value: actionQueueRows[0]?.value ?? "Load more rows",
        detail: actionQueueRows[0]?.detail ?? "A stronger export is needed before the first query-share action is obvious.",
      },
      {
        label: "Execution owner",
        value: actionQueueRows[1]?.value ?? "Analytics owner",
        detail:
          actionQueueRows[1]?.detail ??
          "One owner chooses whether the next query-share move is defense, attack, or better data collection.",
      },
      {
        label: "Do not cross",
        value:
          !rows.length
            ? "Do not call query strategy without a real export"
            : own
              ? "Do not chase new queries while defended queries are still leaking"
              : "Do not infer defense versus attack without naming your ASIN",
        detail:
          !rows.length
            ? "Read actual query-share rows, not abstract market stories."
            : own
              ? "If your ASIN is already visible on valuable queries, leaking them is usually more expensive than broadening into colder lanes."
              : "Without an own ASIN anchor, the page can spot pressure but cannot cleanly separate defend-now from attack-next.",
      },
      {
        label: "Then do",
        value:
          defendLead && analyticsPlan.primaryFocus === "defend"
            ? `Protect ${defendLead.query} first`
            : attackLead
              ? `Pressure-test ${attackLead.query} next`
              : "Expand the export sample",
        detail:
          defendLead && analyticsPlan.primaryFocus === "defend"
            ? "Once the first defended query is stable, only then widen into colder attacks."
            : attackLead
              ? "Use the top absent query as the next commercial test instead of opening many lanes at once."
              : "The current file is too thin to support a serious sequence.",
      },
      {
        label: "Watch",
        value: analyticsPlan.primaryFocus,
        detail: `${analyticsPlan.defendCount} defend rows / ${analyticsPlan.attackCount} attack rows in the current suggested split.`,
      },
    ];
  }, [actionQueueRows, analyticsPlan, ownAsin, rows]);

  const brandAnalyticsInputRows = useMemo(
    () => [
      ...brandAuditRows,
      {
        label: "Execution call",
        value: actionQueueRows[0]?.value ?? "Query-share decision pending",
        detail: actionQueueRows[1]?.value
          ? `${actionQueueRows[1].value} owns the first query-share move until the same export is rechecked.`
          : "Assign one owner before the export turns into a generic research document.",
      },
    ],
    [actionQueueRows, brandAuditRows],
  );

  const brandFocusRows = useMemo(
    () =>
      buildBrandAnalyticsFocusRows({
        ownAsin,
        rows,
      }),
    [ownAsin, rows],
  );

  const brandResultRows = useMemo(
    () => [
      {
        label: localeText(locale, "Current result", "当前结果"),
        value:
          result?.status.tone === "good"
            ? localeText(locale, "Ready to act", "可以动作")
            : result?.status.tone === "warning"
              ? localeText(locale, "Narrow the call", "需要收窄判断")
              : localeText(locale, "Need more evidence", "需要更多证据"),
        detail: result?.headline ?? localeText(locale, "Paste Brand Analytics rows first.", "请先粘贴 Brand Analytics 数据。"),
      },
      {
        label: localeText(locale, "Next move", "下一步"),
        value: brandActionRows[0]?.value ?? localeText(locale, "Load more rows", "补更多数据"),
        detail:
          brandActionRows[0]?.detail ??
          localeText(locale, "Use the export to separate defend-now queries from attack-next queries.", "用这份导出先分清哪些 query 要先守、哪些要后攻。"),
      },
    ],
    [brandActionRows, locale, result],
  );

  function confirmBrandAnalytics() {
    setConfirmedAt(Date.now());
    if (typeof window !== "undefined") {
      window.requestAnimationFrame(() => {
        document
          .getElementById("runtime-result-panel")
          ?.scrollIntoView({ behavior: "smooth", block: "start" });
      });
    }
  }

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[0.55fr_0.55fr_0.55fr_0.55fr_1.7fr]">
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <Field label="Own ASIN (optional)">
          <TextInput
            value={ownAsin}
            onChange={(e) => setOwnAsin(e.target.value.toUpperCase())}
            placeholder="B0..."
            spellCheck={false}
          />
        </Field>
        <Field label="Objective">
          <SelectInput value={objective} onChange={(e) => setObjective(e.target.value)}>
            <option value="balance">Balance defend and attack</option>
            <option value="defend">Defend visible query share</option>
            <option value="expand">Expand into missing queries</option>
          </SelectInput>
        </Field>
        <Field label="Resource level">
          <SelectInput value={resourceLevel} onChange={(e) => setResourceLevel(e.target.value)}>
            <option value="tight">Tight bandwidth</option>
            <option value="medium">Medium bandwidth</option>
            <option value="broad">Broad bandwidth</option>
          </SelectInput>
        </Field>
        <Field label="Paste Brand Analytics export">
          <TextAreaInput
            value={reportText}
            onChange={(e) => setReportText(e.target.value)}
            className="min-h-[8.5rem]"
            placeholder={"Paste columns such as Search Term, Search Frequency Rank, Clicked ASIN, and Converted ASIN"}
            spellCheck={false}
          />
        </Field>
      </div>
      <div className="flex flex-wrap items-center gap-3">
        <ActionButton type="button" onClick={confirmBrandAnalytics} disabled={!reportText.trim()}>
          {localeText(locale, "Analyze Brand Analytics and generate result", "分析 Brand Analytics 并生成结果")}
        </ActionButton>
        <p className="text-sm text-slate-500">
          {localeText(locale, "Confirm once, then read the current result and action plan below.", "确认后，先看下方的当前结果和行动建议。")}
        </p>
      </div>
      <AuditNote
        lines={[
          rows.length
            ? `Parsed ${rows.length} query rows for ${marketplace}.`
            : "Paste a Brand Analytics export first to map visible winners, missing queries, and defense opportunities.",
          ownAsin.trim()
            ? `System focus: use ${ownAsin.trim().toUpperCase()} as the default defense vs attack split.`
            : inferredOwnAsin
              ? `System candidate detected: ${inferredOwnAsin}.`
              : "Add your ASIN to separate defend-now queries from attack-next queries.",
          `Operating brief: ${objective} objective with ${resourceLevel} bandwidth. System focus is ${analyticsPlan.primaryFocus}.`,
          "Accepted columns include search term/query, search frequency rank, clicked ASINs, and converted/purchased ASINs.",
        ]}
      />
      <DistributionPanel title={localeText(locale, "Current result", "当前结果")} rows={brandResultRows} />
      <DistributionPanel title={localeText(locale, "Action plan", "行动建议")} rows={brandActionRows} />
      <DistributionPanel title="Live Brand Analytics inputs" rows={brandAnalyticsInputRows} />
      <DistributionPanel title="Query battle summary" rows={brandSummaryRows} />
      <div className="grid gap-3 xl:grid-cols-[1fr_1fr]">
        <DistributionPanel title="Repeated winner ASINs" rows={asinStats.repeatedAsins} />
        <DistributionPanel title="Priority query rows" rows={asinStats.opportunityQueries} />
      </div>
      {confirmedAt ? (
        <div className="rounded-xl border border-teal-200 bg-teal-50 px-4 py-3 text-sm text-teal-950">
          {localeText(locale, "The current result below is based on the latest Brand Analytics export on this page.", "下方当前结果已按本页最新 Brand Analytics 导出重新整理。")}
        </div>
      ) : null}
      <div className="grid gap-3 xl:grid-cols-3">
        <DistributionPanel title="Defend first" rows={brandDecisionRows.defenseRows} />
        <DistributionPanel title="Query pressure" rows={brandDecisionRows.pressureRows} />
        <DistributionPanel title="Follow-up" rows={brandDecisionRows.followupRows} />
      </div>
      <DistributionPanel title="Execution posture" rows={brandFocusRows} />
      <LowTokenAssistPanel
        toolSlug="amazon-brand-analytics"
        locale={locale}
        result={result}
        context={{
          ownAsin,
          parsedRows: rows.length,
          repeatedWinnerAsins: summarizeDistributionRows(asinStats.repeatedAsins),
          priorityQueries: summarizeDistributionRows(asinStats.opportunityQueries),
        }}
      />
    </RuntimeShell>
  );
}

function SeasonalPlanningRuntime({
  locale,
  title,
}: {
  locale: SupportedLocale;
  title: string;
}) {
  const [marketplace, setMarketplace] = useState("US");
  const [operatingMode, setOperatingMode] = useState("defend-nearest");
  const [executionBandwidth, setExecutionBandwidth] = useState("medium");
  const [leadTimeDays, setLeadTimeDays] = useState(55);
  const [inventoryCoverDays, setInventoryCoverDays] = useState(60);
  const [promoBudget, setPromoBudget] = useState(4000);
  const [monthsAhead, setMonthsAhead] = useState(6);
  const [selectedEvents, setSelectedEvents] = useState<string[]>(["prime-day", "black-friday", "cyber-monday"]);
  const [showOverrides, setShowOverrides] = useState(false);
  const seasonalPlan = useMemo(() => inferSeasonalPlan(monthsAhead), [monthsAhead]);
  const seasonalPriorityPlan = useMemo(
    () =>
      inferSeasonalPriorityPlan({
        monthsAhead,
        operatingMode,
        executionBandwidth,
      }),
    [executionBandwidth, monthsAhead, operatingMode],
  );

  useEffect(() => {
    if (showOverrides) {
      return;
    }
    setLeadTimeDays(seasonalPlan.leadTimeDays);
    setInventoryCoverDays(seasonalPlan.inventoryCoverDays);
    setPromoBudget(seasonalPlan.promoBudget);
    setSelectedEvents(seasonalPriorityPlan.selectedEvents.length ? seasonalPriorityPlan.selectedEvents : seasonalPlan.selectedEvents);
  }, [seasonalPlan, seasonalPriorityPlan, showOverrides]);

  const timeline = useMemo(() => {
    const now = new Date();
    const horizonEnd = new Date(now);
    horizonEnd.setMonth(horizonEnd.getMonth() + monthsAhead);
    const dangerWindow = leadTimeDays + 21;

    return seasonalEventOptions
      .filter((event) => selectedEvents.includes(event.id))
      .map((event) => {
        let eventDate = new Date(now.getFullYear(), event.month - 1, event.day);
        if (eventDate < now) {
          eventDate = new Date(now.getFullYear() + 1, event.month - 1, event.day);
        }
        const daysUntil = Math.ceil((eventDate.getTime() - now.getTime()) / 86400000);
        const inHorizon = eventDate <= horizonEnd;
        const sourceBy = new Date(eventDate);
        sourceBy.setDate(sourceBy.getDate() - leadTimeDays);
        const adPrepBy = new Date(eventDate);
        adPrepBy.setDate(adPrepBy.getDate() - 21);
        const urgent = daysUntil <= dangerWindow;
        const inventoryRisk = inventoryCoverDays < daysUntil;

        return {
          ...event,
          eventDate,
          daysUntil,
          inHorizon,
          urgent,
          inventoryRisk,
          sourceBy,
          adPrepBy,
        };
      })
      .filter((event) => event.inHorizon)
      .sort((a, b) => a.eventDate.getTime() - b.eventDate.getTime());
  }, [inventoryCoverDays, leadTimeDays, monthsAhead, selectedEvents]);

  const result = useMemo(
    () =>
      evaluateSeasonalPlanning({
        monthsAhead,
        leadTimeDays,
        inventoryCoverDays,
        promoBudget,
        eventCount: timeline.length,
        urgentEventCount: timeline.filter((event) => event.urgent).length,
        adMilestoneCount: timeline.length,
        reorderRiskCount: timeline.filter((event) => event.inventoryRisk).length,
      }),
    [inventoryCoverDays, leadTimeDays, monthsAhead, promoBudget, timeline],
  );

  const timelineRows = useMemo(
    () =>
      timeline.map((event) => ({
        label: event.label,
        value: `${event.daysUntil}d`,
        detail: `Source by ${event.sourceBy.toLocaleDateString("en-US")} | Ads by ${event.adPrepBy.toLocaleDateString("en-US")} | ${event.urgent ? "Urgent" : "Workable runway"}`,
      })),
    [timeline],
  );

  const riskRows = useMemo(
    () =>
      timeline.map((event) => ({
        label: event.label,
        value: event.inventoryRisk ? "Reorder risk" : "Covered",
        detail: `${inventoryCoverDays} cover days vs ${event.daysUntil} days until event`,
      })),
    [inventoryCoverDays, timeline],
  );

  const seasonalAuditRows = useMemo(
    () => [
      {
        label: "Events in range",
        value: `${timeline.length}`,
        detail: `${timeline.filter((event) => event.urgent).length} already inside the danger window`,
      },
      {
        label: "Lead time / cover",
        value: `${leadTimeDays} / ${inventoryCoverDays} days`,
        detail: `${timeline.filter((event) => event.inventoryRisk).length} event checkpoints currently look undercovered`,
      },
      {
        label: "Promo budget",
        value: formatUsd(roundNumber(promoBudget)),
        detail: `${monthsAhead} month planning horizon for ${marketplace}`,
      },
      {
        label: "Operating brief",
        value: `${operatingMode} / ${executionBandwidth}`,
        detail: `${seasonalPriorityPlan.planningFocus} focus across the selected events`,
      },
      {
        label: "Priority season",
        value: timeline[0]?.label ?? "No event selected",
        detail: timeline[0] ? `${timeline[0].daysUntil} days until the nearest event` : "Select at least one event to build the live calendar",
      },
    ],
    [executionBandwidth, inventoryCoverDays, leadTimeDays, marketplace, monthsAhead, operatingMode, promoBudget, seasonalPriorityPlan.planningFocus, timeline],
  );

  const seasonalActionRows = useMemo(() => {
    const nearestEvent = timeline[0];
    const firstMove =
      !timeline.length
        ? {
            label: "First move",
            value: "Choose the season",
            detail: "The calendar is still empty, so there is no commercial anchor yet.",
          }
        : seasonalPriorityPlan.planningFocus === "concentrate" && timeline.length > 1
          ? {
              label: "First move",
              value: `Protect ${nearestEvent?.label ?? "the nearest event"} only`,
              detail: "Current bandwidth is too thin to run multiple event windows well, so the first win is concentration, not coverage.",
            }
        : nearestEvent?.urgent
          ? {
              label: "First move",
              value: `Act on ${nearestEvent.label}`,
              detail: "The nearest event is already inside the danger window, so broad seasonal planning can wait.",
            }
          : leadTimeDays > inventoryCoverDays
            ? {
                label: "First move",
                value: "Fix the replenishment mismatch",
                detail: "Lead time is outrunning current cover, so the calendar will fail operationally before it fails strategically.",
              }
            : promoBudget <= 0
              ? {
                  label: "First move",
                  value: "Set the promo budget",
                  detail: "Without a real budget, ad and deal milestones are still only structural placeholders.",
                }
              : {
                  label: "First move",
                  value: `Lock ${nearestEvent?.label ?? "the nearest event"} milestones`,
                  detail: "Source date, ad-prep date, and replenishment checkpoints should be fixed before widening the calendar.",
                };

    return [
      firstMove,
      {
        label: "Execution owner",
        value:
          !timeline.length
            ? "Commercial planner"
            : seasonalPriorityPlan.planningFocus === "concentrate" && timeline.length > 1
              ? "Portfolio / calendar owner"
            : nearestEvent?.urgent
              ? "Event owner"
              : leadTimeDays > inventoryCoverDays
                ? "Inventory / supply owner"
                : promoBudget <= 0
                  ? "Budget owner"
                  : "Calendar owner",
        detail: "The nearest event only becomes real when one owner is accountable for the first blocked milestone.",
      },
      {
        label: "Then do",
        value: "Assign one owner per event window",
        detail: "Inventory timing, ad prep, and promo approval should each have explicit ownership on the next event.",
      },
      {
        label: "Watch",
        value: "Calendar sprawl",
        detail: "Do not keep adding events if the nearest one is already operationally fragile.",
      },
    ];
  }, [inventoryCoverDays, leadTimeDays, promoBudget, seasonalPriorityPlan.planningFocus, timeline]);

  const seasonalInputRows = useMemo(
    () => [
      ...seasonalAuditRows,
      {
        label: "Execution call",
        value: seasonalActionRows[0]?.value ?? "Seasonal decision pending",
        detail: seasonalActionRows[1]?.value
          ? `${seasonalActionRows[1].value} owns the first blocked milestone until the same event window is rechecked.`
          : "Put one calendar owner on the next event before the plan sprawls wider.",
      },
    ],
    [seasonalActionRows, seasonalAuditRows],
  );

  const seasonalFocusRows = useMemo(
    () =>
      buildSeasonalPlanningFocusRows({
        timeline,
        leadTimeDays,
        inventoryCoverDays,
        promoBudget,
        monthsAhead,
      }),
    [inventoryCoverDays, leadTimeDays, monthsAhead, promoBudget, timeline],
  );

  return (
    <RuntimeShell title={title} result={result} locale={locale}>
      <div className="grid gap-2.5 xl:grid-cols-[0.7fr_0.55fr_0.55fr_0.5fr_auto]">
        <Field label="Marketplace">
          <SelectInput value={marketplace} onChange={(e) => setMarketplace(e.target.value)}>
            {renderOptions(amazonMarketplaces)}
          </SelectInput>
        </Field>
        <Field label="Operating mode">
          <SelectInput value={operatingMode} onChange={(e) => setOperatingMode(e.target.value)}>
            <option value="defend-nearest">Defend nearest event</option>
            <option value="holiday-push">Holiday push</option>
            <option value="balanced">Balanced season</option>
          </SelectInput>
        </Field>
        <Field label="Execution bandwidth">
          <SelectInput value={executionBandwidth} onChange={(e) => setExecutionBandwidth(e.target.value)}>
            <option value="tight">Tight</option>
            <option value="medium">Medium</option>
            <option value="broad">Broad</option>
          </SelectInput>
        </Field>
        <Field label="Planning horizon (months)">
          <NumberInput value={monthsAhead} min="1" step="1" onChange={(e) => setMonthsAhead(Number(e.target.value))} />
        </Field>
        <div className="grid content-end">
          <button
            type="button"
            onClick={() => setShowOverrides((current) => !current)}
            className="inline-flex h-10 items-center rounded-full border border-black/10 bg-white px-4 text-sm font-semibold text-slate-900"
          >
            {showOverrides ? "Hide overrides" : "Adjust seasonal assumptions"}
          </button>
        </div>
      </div>
      <div className="grid gap-2 md:grid-cols-3 xl:grid-cols-5">
        {seasonalEventOptions.map((event) => (
          <Checkbox
            key={event.id}
            label={event.label}
            checked={selectedEvents.includes(event.id)}
            onChange={(checked) =>
              setSelectedEvents((current) =>
                checked ? Array.from(new Set([...current, event.id])) : current.filter((item) => item !== event.id),
              )
            }
          />
        ))}
      </div>
      <AuditNote
        lines={[
          `Planning for ${marketplace} over the next ${monthsAhead} months with ${timeline.length} selected events in range.`,
          `Operating brief: ${operatingMode} mode with ${executionBandwidth} bandwidth. System focus: ${seasonalPriorityPlan.planningFocus}.`,
          `System draft: ${leadTimeDays}d lead time, ${inventoryCoverDays}d cover, ${formatUsd(promoBudget)} budget.`,
          "Milestones are deterministic: source date = event date minus lead time, ad prep = event date minus 21 days.",
        ]}
      />
      <DistributionPanel title="Live seasonal inputs" rows={seasonalInputRows} />
      <DistributionPanel title="This seasonal call" rows={seasonalActionRows} />
      <DistributionPanel title="Planning posture" rows={seasonalFocusRows} />
      <div className="rounded-xl border border-black/8 bg-slate-50 px-4 py-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.16em] text-slate-500">Season overrides</p>
            <p className="mt-1 text-sm leading-6 text-slate-700">
              Open this only when the real lead time, inventory cover, or event set is materially different from the system draft.
            </p>
          </div>
        </div>
        {showOverrides ? (
          <div className="mt-4 grid gap-2.5 md:grid-cols-3 xl:grid-cols-3">
            <Field label="Lead time (days)">
              <NumberInput value={leadTimeDays} min="1" step="1" onChange={(e) => setLeadTimeDays(Number(e.target.value))} />
            </Field>
            <Field label="Inventory cover (days)">
              <NumberInput value={inventoryCoverDays} min="1" step="1" onChange={(e) => setInventoryCoverDays(Number(e.target.value))} />
            </Field>
            <Field label="Promo budget">
              <NumberInput value={promoBudget} min="0" step="100" onChange={(e) => setPromoBudget(Number(e.target.value))} />
            </Field>
          </div>
        ) : null}
      </div>
      <div className="grid gap-3 xl:grid-cols-[1fr_1fr]">
        <DistributionPanel title="Event timeline" rows={timelineRows} />
        <DistributionPanel title="Inventory checkpoints" rows={riskRows} />
      </div>
    </RuntimeShell>
  );
}

